# ========== CONVERSATION MEMORY ==========
conversation_history = defaultdict(list)
MAX_CONVERSATIONS = 1000  # Maximum number of conversations to keep in memory
MAX_CONVERSATION_AGE = 3600  # Maximum age of conversation in seconds (1 hour)
conversation_timestamps = {}  # Track last activity time for cleanup

CONVERSATIONS_FILE = Path(__file__).resolve().parent / "conversations.json"
_conversation_store_lock = RLock()


def _utc_now_iso() -> str:
    return datetime.now(timezone.utc).isoformat()


def _empty_conversation_store() -> dict:
    return {"conversations": []}


def _ensure_conversation_store_file() -> None:
    with _conversation_store_lock:
        if not CONVERSATIONS_FILE.exists():
            CONVERSATIONS_FILE.write_text(
                json.dumps(_empty_conversation_store(), indent=2),
                encoding="utf-8",
            )


def _load_conversation_store() -> dict:
    with _conversation_store_lock:
        _ensure_conversation_store_file()
        try:
            data = json.loads(CONVERSATIONS_FILE.read_text(encoding="utf-8") or "{}")
        except Exception:
            logger.exception("[CONV] failed to read conversation store; using empty store")
            data = _empty_conversation_store()
        if not isinstance(data, dict):
            data = _empty_conversation_store()
        conversations = data.get("conversations")
        if not isinstance(conversations, list):
            data["conversations"] = []
        return data


def _save_conversation_store(data: dict) -> None:
    with _conversation_store_lock:
        _ensure_conversation_store_file()
        tmp_path = CONVERSATIONS_FILE.with_suffix(".json.tmp")
        tmp_path.write_text(
            json.dumps(data, ensure_ascii=False, indent=2),
            encoding="utf-8",
        )
        tmp_path.replace(CONVERSATIONS_FILE)


def _find_conversation(data: dict, conversation_id: str) -> dict | None:
    for conversation in data.get("conversations", []) or []:
        if isinstance(conversation, dict) and conversation.get("id") == conversation_id:
            return conversation
    return None


def _conversation_title_from_text(text: str) -> str:
    words = re.findall(r"\S+", str(text or "").strip())
    if not words:
        return "New chat"
    title = " ".join(words[:8])
    if len(words) > 8:
        title += "..."
    return title[:80]


def create_conversation(title: str | None = None) -> dict:
    data = _load_conversation_store()
    now = _utc_now_iso()
    conversation = {
        "id": str(uuid.uuid4()),
        "title": (title or "New chat").strip() or "New chat",
        "messages": [],
        "created_at": now,
        "updated_at": now,
    }
    data["conversations"].insert(0, conversation)
    _save_conversation_store(data)
    logger.info("[CONV] created id=%s", conversation["id"])
    return conversation


def get_or_create_conversation(conversation_id: str | None = None) -> dict:
    data = _load_conversation_store()
    if conversation_id:
        existing = _find_conversation(data, conversation_id)
        if existing is not None:
            logger.info("[CONV] loaded id=%s", conversation_id)
            return existing
    return create_conversation()


def list_conversations_summary() -> list[dict]:
    data = _load_conversation_store()
    conversations = [c for c in data.get("conversations", []) if isinstance(c, dict)]
    conversations.sort(key=lambda c: str(c.get("updated_at") or ""), reverse=True)
    return [
        {
            "id": c.get("id"),
            "title": c.get("title") or "New chat",
            "updated_at": c.get("updated_at"),
        }
        for c in conversations
        if c.get("id")
    ]


def load_conversation_messages(conversation_id: str) -> list[dict]:
    data = _load_conversation_store()
    conversation = _find_conversation(data, conversation_id)
    if conversation is None:
        raise KeyError(conversation_id)
    logger.info("[CONV] loaded id=%s", conversation_id)
    messages = conversation.get("messages") or []
    return [m for m in messages if isinstance(m, dict)]


def append_conversation_message(conversation_id: str, role: str, text: str) -> dict:
    role_value = str(role or "").strip().lower()
    if role_value not in {"user", "assistant"}:
        raise ValueError("role must be 'user' or 'assistant'")
    text_value = str(text or "").strip()
    data = _load_conversation_store()
    conversation = _find_conversation(data, conversation_id)
    if conversation is None:
        raise KeyError(conversation_id)
    messages = conversation.setdefault("messages", [])
    messages.append({"role": role_value, "text": text_value})
    if role_value == "user" and (not conversation.get("title") or conversation.get("title") == "New chat"):
        conversation["title"] = _conversation_title_from_text(text_value)
    conversation["updated_at"] = _utc_now_iso()
    _save_conversation_store(data)
    logger.info("[CONV] message_added role=%s id=%s", role_value, conversation.get("id"))
    return conversation


def _conversation_summary(conversation: dict) -> dict:
    return {
        "id": conversation.get("id"),
        "title": conversation.get("title") or "New chat",
        "updated_at": conversation.get("updated_at"),
    }


def rename_conversation(conversation_id: str, title: str) -> dict:
    title_value = re.sub(r"\s+", " ", str(title or "")).strip()
    if not title_value:
        raise ValueError("title must not be empty")
    if len(title_value) > 80:
        title_value = title_value[:80].rstrip()
    data = _load_conversation_store()
    conversation = _find_conversation(data, conversation_id)
    if conversation is None:
        raise KeyError(conversation_id)
    conversation["title"] = title_value
    conversation["updated_at"] = _utc_now_iso()
    _save_conversation_store(data)
    logger.info("[CONV] renamed id=%s title=%s", conversation_id, title_value)
    return _conversation_summary(conversation)


def delete_conversation(conversation_id: str) -> None:
    data = _load_conversation_store()
    conversations = [c for c in data.get("conversations", []) if isinstance(c, dict)]
    remaining = [c for c in conversations if c.get("id") != conversation_id]
    if len(remaining) == len(conversations):
        raise KeyError(conversation_id)
    data["conversations"] = remaining
    _save_conversation_store(data)
    conversation_history.pop(conversation_id, None)
    last_answer_state.pop(conversation_id, None)
    recent_grounded_definition_concepts.pop(conversation_id, None)
    conversation_timestamps.pop(conversation_id, None)
    logger.info("[CONV] deleted id=%s", conversation_id)


def _history_from_conversation_messages(conversation_id: str) -> list[dict]:
    try:
        messages = load_conversation_messages(conversation_id)
    except KeyError:
        return []
    history: list[dict] = []
    for message in messages:
        role = message.get("role")
        text = message.get("text")
        if role in {"user", "assistant"}:
            history.append({"role": role, "content": str(text or "")})
    return history


def bind_conversation_memory(runtime_id: str, conversation_id: str) -> None:
    if not runtime_id or not conversation_id:
        return
    if conversation_id not in conversation_history:
        conversation_history[conversation_id] = _history_from_conversation_messages(conversation_id)
    conversation_history[runtime_id] = conversation_history[conversation_id]
    conversation_timestamps[runtime_id] = time.time()
    conversation_timestamps[conversation_id] = time.time()
    if conversation_id in last_answer_state:
        last_answer_state[runtime_id] = last_answer_state[conversation_id]
    else:
        last_answer_state.pop(runtime_id, None)
    if conversation_id in recent_grounded_definition_concepts:
        recent_grounded_definition_concepts[runtime_id] = recent_grounded_definition_concepts[conversation_id]
    else:
        recent_grounded_definition_concepts.pop(runtime_id, None)


def persist_runtime_memory(runtime_id: str, conversation_id: str) -> None:
    if not runtime_id or not conversation_id:
        return
    if runtime_id in conversation_history:
        conversation_history[conversation_id] = conversation_history[runtime_id]
    if runtime_id in last_answer_state:
        last_answer_state[conversation_id] = last_answer_state[runtime_id]
    else:
        last_answer_state.pop(conversation_id, None)
    if runtime_id in recent_grounded_definition_concepts:
        recent_grounded_definition_concepts[conversation_id] = recent_grounded_definition_concepts[runtime_id]
    else:
        recent_grounded_definition_concepts.pop(conversation_id, None)
    conversation_timestamps[conversation_id] = time.time()


class ConversationCaptureWebSocket:
    def __init__(self, websocket: WebSocket, conversation_id: str, runtime_id: str):
        self._websocket = websocket
        self._conversation_id = conversation_id
        self._runtime_id = runtime_id
        self._assistant_saved = False

    async def send_json(self, payload):
        if isinstance(payload, dict):
            payload.setdefault("conversation_id", self._conversation_id)
        await self._websocket.send_json(payload)
        if (
            isinstance(payload, dict)
            and payload.get("type") == "aiResponseDone"
            and not self._assistant_saved
        ):
            assistant_text = str(payload.get("fullText") or payload.get("text") or "").strip()
            if assistant_text:
                try:
                    append_conversation_message(self._conversation_id, "assistant", assistant_text)
                    self._assistant_saved = True
                except Exception:
                    logger.exception("[CONV] failed to persist assistant message id=%s", self._conversation_id)
            persist_runtime_memory(self._runtime_id, self._conversation_id)

    async def send_bytes(self, data):
        await self._websocket.send_bytes(data)

    def __getattr__(self, name: str):
        return getattr(self._websocket, name)

def cleanup_old_conversations():
    """Remove old conversations to prevent memory leak."""
    import time
    current_time = time.time()
    expired_ids = [
        conn_id for conn_id, last_time in conversation_timestamps.items()
        if current_time - last_time > MAX_CONVERSATION_AGE
    ]
    for conn_id in expired_ids:
        if conn_id in conversation_history:
            del conversation_history[conn_id]
        if conn_id in recent_grounded_definition_concepts:
            del recent_grounded_definition_concepts[conn_id]
        del conversation_timestamps[conn_id]


def clear_all_conversation_history():
    """Wipe every in-memory conversation so stale KB answers are never reused.

    Called automatically after a KB reindex to prevent the LLM from seeing
    old Q&A pairs that contradict the updated knowledge base.
    """
    count = len(conversation_history)
    conversation_history.clear()
    conversation_timestamps.clear()
    try:
        last_answer_state.clear()
    except Exception:
        pass
    try:
        recent_grounded_definition_concepts.clear()
    except Exception:
        pass
    if count:
        logger.info(f"Cleared {count} conversation(s) after KB reindex")


# ========== FOLLOW-UP / EXPLANATION MODE ==========
# Per-connection cache of the most recently grounded answer so that
# follow-up clarifications ("what do you mean?", "explain more",
# "simplify that") can be answered locally WITHOUT re-running heavy
# retrieval. The system stays strictly grounded in the previously
# retrieved chunks + the previous answer text — no open-domain leakage.
last_answer_state: dict = {}
recent_grounded_definition_concepts = defaultdict(list)
_FOLLOWUP_STATE_TTL = 1800  # seconds (30 min)
_FOLLOWUP_MAX_QUERY_LEN = 140
_FOLLOWUP_CHUNK_CHAR_BUDGET = 1800
_FOLLOWUP_KEEP_TOP_K = 3
_FOLLOWUP_SAVED_CHUNK_CHAR_LIMIT = 1800
# Loose grounding ratio: paraphrased explanations legitimately use connector
# words and synonyms, so we only require a modest overlap with the saved
# prior-answer + saved chunks. Open-domain hallucinations still fall well
# below this floor in practice.
_FOLLOWUP_GROUND_RATIO_MIN = 0.20

import re as _re_followup
# Generic, domain-agnostic intent patterns. They describe a request FOR
# clarification of a prior answer, not document content.
#
# Two tiers:
#  * STRONG: explicit clarification phrases that are unmistakable
#    follow-ups regardless of conversation history (e.g. "what do you
#    mean", "explain more", "rephrase that"). Always route as follow-up.
#  * CONTEXTUAL: clarification-shaped phrases that need an OBJECT and
#    only make sense as a follow-up when there IS a recent grounded
#    answer to clarify (e.g. "explain Money", "what does X mean",
#    "what about that", "tell me more about Y"). Routed as follow-up
#    ONLY when prior state exists for the connection.
#  * SHORT-CONTEXTUAL FALLBACK: a very short utterance (≤ 7 words) that
#    does NOT look like a brand-new question is treated as a follow-up
#    ONLY when prior state exists. Brand-new question shapes
#    ("what is X", "how", "why", "list ...", "define ...") are excluded
#    so a short standalone question still goes through full RAG.
_FOLLOWUP_PATTERNS = [
    _re_followup.compile(p, _re_followup.IGNORECASE) for p in [
        r"^\s*what\s+do\s+you\s+mean\b",
        r"^\s*what\s+are\s+you\s+saying\b",
        r"^\s*what\s+does\s+that\s+mean\b",
        r"^\s*explain\s+(more|further|that|it|again|please|this)\b",
        r"^\s*explain\s*[?.!]?\s*$",
        r"^\s*(can|could)\s+you\s+explain\b",
        r"^\s*tell\s+me\s+more\b",
        r"^\s*say\s+more\b",
        r"^\s*go\s+on\s*[?.!]?\s*$",
        r"^\s*continue\s*[?.!]?\s*$",
        r"^\s*more\s+(detail|details|info|information)\b",
        r"^\s*(give|show)\s+me\s+more\b",
        r"^\s*elaborate\b",
        r"^\s*clarify\b",
        r"^\s*simplify\b",
        r"^\s*make\s+it\s+(simpler|easier|clearer|shorter)\b",
        r"^\s*in\s+simpler\s+(terms|words)\b",
        r"^\s*rephrase\b",
        r"^\s*reword\b",
        r"^\s*break\s+(it|this|that)\s+down\b",
        r"^\s*(can|could)\s+you\s+(simplify|clarify|rephrase|elaborate|explain)\b",
        r"^\s*i\s+don'?t\s+(get|understand)\s*(it|that|this)?\s*[?.!]?\s*$",
    ]
]

# Contextual follow-up patterns. Match a clarification verb/phrase that
# carries an OBJECT referring back to the prior answer. They are only
# applied when the connection has a recent saved answer state.
_FOLLOWUP_CONTEXT_PATTERNS = [
    _re_followup.compile(p, _re_followup.IGNORECASE) for p in [
        # "explain Money", "explain what does Money means in this process",
        # "explain the second one", etc. (any "explain ..." form)
        r"^\s*explain\b",
        # "what does Money mean", "what does that mean", "what does X means"
        r"^\s*what\s+does\s+.+\bmean(s|ing)?\b",
        # "what about Money", "what about that"
        r"^\s*what\s+about\s+\S+",
        # "how about Money"
        r"^\s*how\s+about\s+\S+",
        # "tell me about Money", "tell me more about Money"
        r"^\s*tell\s+me\s+(more\s+)?about\s+\S+",
        # "simplify that", "rephrase that", "clarify that", "elaborate that"
        r"^\s*(simplify|rephrase|clarify|elaborate|reword)\s+\S+",
        # "and Money?", "and the second?"  — short anaphoric pivot
        r"^\s*and\s+\S+\s*\??\s*$",
        # P11A: ordinal-reference clarifications targeting a previously
        # listed item, e.g. "what is the second one?", "how does it
        # connect to the last one?", "tell me about the third item".
        # Strictly generic (no domain words). Requires prior state
        # because this is a CONTEXT pattern.
        r"\b(?:the\s+)?(?:first|second|third|fourth|fifth|sixth|seventh|eighth|ninth|tenth|last|previous|next|final|\d{1,2}(?:st|nd|rd|th))\s+(?:one|item|element|thing|point|step|function|part|option|reason|principle|stage|phase|category|type|kind)\b",
    ]
]

# Brand-new question shapes — used to EXCLUDE from the short-utterance
# contextual fallback so a standalone short question still gets full
# retrieval. Domain-agnostic.
_FOLLOWUP_NEW_QUESTION_PATTERNS = [
    _re_followup.compile(p, _re_followup.IGNORECASE) for p in [
        r"^\s*(what|which)\s+(is|are|was|were)\b",
        r"^\s*(how|why|when|where|who)\b",
        r"^\s*(list|name|enumerate)\b",
        r"^\s*(define|definition\s+of)\b",
        r"^\s*give\s+me\s+(a\s+)?(list|definition|example)\b",
    ]
]

_FOLLOWUP_SHORT_WORD_LIMIT = 7

_WEAK_GENERIC_REQUEST_RE = _re_followup.compile(
    r"^\s*(?:tell\s+me\s+about|about|explain|describe|overview\s+of|talk\s+about)\s+"
    r"(?:help|assistance|assist|support|ability|abilities|capability|capabilities|features?)\s*[?.!]*\s*$",
    _re_followup.IGNORECASE,
)


def _is_weak_generic_request(text: str) -> bool:
    return bool(_WEAK_GENERIC_REQUEST_RE.match(str(text or "").strip()))


def _has_recent_followup_state(connection_id) -> bool:
    """True iff there is a non-expired saved answer state for this conn
    AND that state actually contains a substantive prior answer.

    P8: previously the function only checked TTL, so an empty saved-state
    placeholder could still trigger anaphor (it/this/that) follow-ups even
    when there was nothing to follow up on.
    """
    if not connection_id:
        return False
    state = last_answer_state.get(connection_id)
    if not state:
        return False
    try:
        if (time.time() - float(state.get("ts", 0))) > _FOLLOWUP_STATE_TTL:
            return False
    except Exception:
        return False
    answer = str((state or {}).get("answer") or "").strip()
    items = (state or {}).get("items") or []
    if not answer and not items:
        return False
    if answer == RAG_NO_MATCH_RESPONSE:
        return False
    return True


# ---- Conversational definition normalization ----
# Rewrites natural conversational definition re-asks into the canonical
# "what is X?" form so the strong definition pipeline picks them up
# instead of the weak generic prose path. Strictly generic — no domain
# words, no entity allowlists.
_CONV_LEAD_STRIP = _re_followup.compile(
    r"^\s*(?:"
    r"ok(?:ay)?(?:\s+so)?|"
    r"so|well|now|actually|alright|right|hmm|hey|"
    r"i\s+mean|i\s+wanted\s+to\s+ask|"
    r"can\s+you\s+(?:please\s+)?tell\s+me|please\s+tell\s+me|tell\s+me|"
    r"could\s+you\s+(?:please\s+)?tell\s+me|"
    r"please|just"
    r")\b[\s,]*",
    _re_followup.IGNORECASE,
)
_CONV_TRAIL_STRIP = _re_followup.compile(
    r"\s+(?:exactly|really|then|though|now|please)\s*([?.!]*)\s*$",
    _re_followup.IGNORECASE,
)
# "what about (the )?(definition|meaning|concept|idea) of X"
# "what is the (definition|meaning|...) of X"
# "(definition|meaning|...) of X"
# "tell me (about )?the (definition|meaning) of X"
_CONV_DEF_RE_ASK_PATTERNS = [
    _re_followup.compile(p, _re_followup.IGNORECASE) for p in [
        r"^\s*what\s+about\s+(?:the\s+)?(?:definition|meaning|concept|idea|notion|sense)\s+of\s+(.+?)\s*\??\s*$",
        r"^\s*what\s+(?:is|was|'?s)\s+(?:the\s+)?(?:definition|meaning|concept|idea|notion|sense)\s+of\s+(.+?)\s*\??\s*$",
        r"^\s*(?:the\s+)?(?:definition|meaning|concept|idea|notion|sense)\s+of\s+(.+?)\s*\??\s*$",
        r"^\s*(?:can|could)\s+you\s+(?:please\s+)?(?:define|explain)\s+(.+?)\s*\??\s*$",
    ]
]


def _normalize_conversational_definition_query(text: str) -> str:
    """Rewrite conversational definition re-asks into canonical
    "what is X?" form. Returns the original text if no rewrite applies.
    Generic; no domain words.
    """
    if not text:
        return text
    t = text.strip()
    if _is_weak_generic_request(t):
        return text
    # Strip leading conversational fillers (possibly stacked).
    prev = None
    while prev != t:
        prev = t
        t = _CONV_LEAD_STRIP.sub("", t).strip()
    # Strip trailing intensifiers ("exactly?", "really?", "then?")
    m = _CONV_TRAIL_STRIP.search(t)
    if m:
        # Preserve the trailing punctuation
        tail_punc = m.group(1) or ""
        t = _CONV_TRAIL_STRIP.sub(tail_punc, t).strip()
    if not t:
        return text
    # Apply rewrite patterns: extract entity tail and produce "what is X?"
    for pat in _CONV_DEF_RE_ASK_PATTERNS:
        m = pat.match(t)
        if m:
            ent = (m.group(1) or "").strip().strip(" \t\n\r\"'`.,;:!?-")
            if len(ent) >= 2:
                return f"what is {ent}?"
    return t


# ---- About-entity standalone-question rewrite ----
# Detects "what about X / how about X / and X / tell me about X / explain X"
# (and Arabic equivalents) where X clearly introduces a NEW content phrase
# rather than referring back to the previous answer. When detected, the
# query is rewritten into a canonical standalone form ("What is X?" / "ما
# هي X؟") so it goes through normal RAG retrieval instead of being
# inherited by the contextual follow-up router.
#
# Strictly generic — no domain word lists, no document-specific terms.
_ABOUT_ENTITY_VAGUE_TOKENS = {
    # Anaphoric pronouns / demonstratives
    "it", "this", "that", "these", "those", "them", "they", "there",
    "above", "previous", "last", "next", "one", "ones", "another",
    "thing", "things",
    # Ordinals commonly used to pick from a previously listed set
    "first", "second", "third", "fourth", "fifth", "sixth", "seventh",
    "eighth", "ninth", "tenth",
    # Assistant / meta references
    "help", "ability", "abilities", "capability", "capabilities",
    "support", "assistance", "feature", "features", "function",
    "functions", "you", "yourself", "yours", "your", "me", "myself",
    "us", "we",
    # Document-meta references that ask for "more of the same" rather
    # than a brand-new entity (kept short and generic — no domain words).
    "more", "other", "others", "rest", "remainder", "details", "detail",
    "information", "info", "summary", "list", "lists", "items", "item",
    "parts", "part", "section", "sections", "step", "steps", "point",
    "points", "example", "examples",
    # Pure quantifiers
    "anything", "something", "nothing", "everything", "all", "some",
    "any", "many", "much", "few", "several",
}

_ABOUT_ENTITY_STOPWORDS = {
    "the", "a", "an", "of", "and", "or", "but", "to", "for",
    "in", "on", "at", "by", "with", "is", "are", "was", "were",
    "be", "been", "being", "do", "does", "did", "have", "has", "had",
    "what", "why", "how", "when", "where", "who", "which",
    "about", "please", "just", "really", "exactly",
}

_ABOUT_ENTITY_EN_PATTERNS = [
    _re_followup.compile(
        r"^\s*(?:and\s+)?what\s+about\s+(?:the\s+)?(.+?)\s*[?.!]*\s*$",
        _re_followup.IGNORECASE,
    ),
    _re_followup.compile(
        r"^\s*how\s+about\s+(?:the\s+)?(.+?)\s*[?.!]*\s*$",
        _re_followup.IGNORECASE,
    ),
    _re_followup.compile(
        r"^\s*tell\s+me\s+(?:more\s+)?about\s+(?:the\s+)?(.+?)\s*[?.!]*\s*$",
        _re_followup.IGNORECASE,
    ),
    _re_followup.compile(
        r"^\s*explain\s+(?:to\s+me\s+)?(?:the\s+)?(.+?)\s*[?.!]*\s*$",
        _re_followup.IGNORECASE,
    ),
    # Bare "and X?" pivot — kept last so the more specific patterns above
    # win. Constrained to <= 4 trailing tokens by the post-validation step
    # below (token count + vague-word filter).
    _re_followup.compile(
        r"^\s*and\s+(?:the\s+)?(.+?)\s*[?.!]*\s*$",
        _re_followup.IGNORECASE,
    ),
]

_ABOUT_ENTITY_AR_PATTERNS = [
    # وماذا عن X / ماذا عن X
    _re_followup.compile(r"^\s*و?\s*ماذا\s+عن\s+(.+?)\s*[؟?.!]*\s*$"),
    # طب و X / طيب و X (with space)
    _re_followup.compile(r"^\s*(?:طب|طيب)\s+و\s+(.+?)\s*[؟?.!]*\s*$"),
    # طب والX / طيب والX (و prefix attached)
    _re_followup.compile(r"^\s*(?:طب|طيب)\s+و(\S.+?)\s*[؟?.!]*\s*$"),
    # اشرح X / اشرح لي X
    _re_followup.compile(r"^\s*اشرح\s+(?:لي\s+)?(.+?)\s*[؟?.!]*\s*$"),
]

_ARABIC_CHAR_RE = _re_followup.compile(r"[\u0600-\u06FF]")
_NEW_QUESTION_HEAD_RE = _re_followup.compile(
    r"^\s*(?:"
    r"(?:what|which)\s+(?:is|are|was|were|'?s)\b"
    r"|why\b|when\b|where\b|who\b"
    r"|how\s+(?:do|does|did|can|could|should|would|will|is|are|much|many|long|often)\b"
    r"|list\b|name\b|enumerate\b|define\b|definition\s+of\b"
    r"|give\s+me\s+(?:a\s+)?(?:list|definition|example)\b"
    r")",
    _re_followup.IGNORECASE,
)


def _extract_about_entity_question(query: str) -> Optional[str]:
    """Detect a "what about X / how about X / and X / tell me about X /
    explain X" style query that introduces a NEW entity, and return a
    normalized standalone question for X ("What is X?" / "ما هي X؟").

    Returns ``None`` when X is missing, vague (pronoun / meta /
    document-relative), or otherwise not a content phrase. Strictly
    generic — no domain word lists.
    """
    raw = (query or "").strip()
    if not raw:
        logger.info("[ABOUT ENTITY ROUTE] detected=False reason=empty")
        return None
    # Skip clear standalone question shapes — they don't need rewriting.
    if _NEW_QUESTION_HEAD_RE.match(raw):
        return None
    # Skip weak generic / meta-help phrasings ("tell me about help").
    if _is_weak_generic_request(raw):
        logger.info("[ABOUT ENTITY ROUTE] detected=False reason=weak_generic query=%s", raw[:120])
        return None
    is_arabic = bool(_ARABIC_CHAR_RE.search(raw))
    patterns = _ABOUT_ENTITY_AR_PATTERNS if is_arabic else _ABOUT_ENTITY_EN_PATTERNS
    entity = None
    for pat in patterns:
        m = pat.match(raw)
        if not m:
            continue
        entity = (m.group(1) or "").strip().strip(" \t\n\r\"'`.,;:!?-؟،")
        if entity:
            break
    if not entity:
        logger.info("[ABOUT ENTITY ROUTE] detected=False reason=no_pattern query=%s", raw[:120])
        return None
    tokens = [tok for tok in _re_followup.split(r"\s+", entity) if tok]
    if not tokens or len(tokens) > 6:
        logger.info("[ABOUT ENTITY ROUTE] detected=False reason=bad_token_count entity=%s", entity)
        return None
    lowered = [tok.lower().strip(" \t\n\r\"'`.,;:!?-؟،") for tok in tokens]
    # Reject if every token is either vague/meta or a stopword.
    if all((tok in _ABOUT_ENTITY_VAGUE_TOKENS or tok in _ABOUT_ENTITY_STOPWORDS) for tok in lowered):
        logger.info("[ABOUT ENTITY ROUTE] detected=False reason=vague_or_stopword entity=%s", entity)
        return None
    # Reject if any vague/meta pronoun is mixed in — ambiguous reference.
    if any(tok in _ABOUT_ENTITY_VAGUE_TOKENS for tok in lowered):
        logger.info("[ABOUT ENTITY ROUTE] detected=False reason=contains_vague entity=%s", entity)
        return None
    # Require at least one real word token (>=3 chars, contains a letter).
    if not any(
        len(tok) >= 3 and _re_followup.search(r"[A-Za-z\u0600-\u06FF]", tok)
        for tok in lowered
    ):
        logger.info("[ABOUT ENTITY ROUTE] detected=False reason=no_word_token entity=%s", entity)
        return None
    rewritten = f"ما هي {entity}؟" if is_arabic else f"What is {entity}?"
    logger.info(
        "[ABOUT ENTITY ROUTE] detected=True entity=%s rewritten_query=%s",
        entity,
        rewritten,
    )
    return rewritten


def _maybe_rewrite_about_entity_question(text: str) -> str:
    """Apply the about-entity rewrite if it fires; otherwise return
    ``text`` unchanged. Shared preprocessing helper used by both the
    typed WebSocket path and the voice transcript path so the logic
    cannot drift between them.
    """
    try:
        rewritten = _extract_about_entity_question(text)
    except Exception:
        logger.exception("[ABOUT ENTITY ROUTE] extractor raised — leaving query unchanged")
        return text
    if not rewritten or rewritten == text:
        return text
    logger.info(
        "[ABOUT ENTITY ROUTE] applied original=%r rewritten=%r",
        (text or "")[:160],
        rewritten[:160],
    )
    return rewritten


def _is_followup_query(text: str, connection_id=None) -> bool:
    """Generic follow-up intent detector. Domain-agnostic.

    Tiering:
      1. STRONG patterns -> always follow-up (no context needed).
      2. CONTEXTUAL patterns -> follow-up ONLY if a recent saved answer
         state exists for ``connection_id``.
      3. SHORT-utterance fallback (≤ _FOLLOWUP_SHORT_WORD_LIMIT words)
         -> follow-up ONLY if prior state exists AND the utterance
         does NOT look like a brand-new question.
    Callers without a connection (e.g. plain helpers) may omit
    ``connection_id`` to use only the strong tier.
    """
    t = (text or "").strip()
    if not t or len(t) > _FOLLOWUP_MAX_QUERY_LEN:
        return False
    if _is_weak_generic_request(t):
        logger.info("[ANSWER PERMISSION] allowed=False reason=weak_generic_followup_candidate query=%s", t[:180])
        return False
    for pat in _FOLLOWUP_PATTERNS:
        if pat.search(t):
            return True
    if not _has_recent_followup_state(connection_id):
        return False
    for pat in _FOLLOWUP_CONTEXT_PATTERNS:
        if pat.search(t):
            return True
    if len(t.split()) <= _FOLLOWUP_SHORT_WORD_LIMIT:
        for pat in _FOLLOWUP_NEW_QUESTION_PATTERNS:
            if pat.search(t):
                return False
        state = _get_last_answer_state(connection_id)
        answer_text = str((state or {}).get("answer") or "")
        state_items = [str(item or "") for item in ((state or {}).get("items") or [])]
        _prev_is_list, extracted_items = _extract_followup_items_from_answer(answer_text)
        candidate_items = [item for item in (extracted_items or state_items) if item]
        if candidate_items:
            try:
                targeted_item, _target_reason = _select_followup_target_item(candidate_items, t)
                if targeted_item:
                    return True
            except Exception:
                pass
        if _re_followup.search(r"\b(?:it|this|that|these|those|them|there|above|previous|first|second|third|last|one|ones)\b", t, _re_followup.IGNORECASE):
            return True
        logger.info("[FOLLOWUP] short_fallback_rejected query=%s", t[:180])
        return False
    return False


def _classify_followup_intent(text: str) -> str:
    t = (text or "").lower()
    # P8: word-boundary checks so accidental substrings (e.g. "phrase" vs.
    # "rephrase", "shortage" vs. "shorter") cannot misroute intent.
    if re.search(r"\b(?:simpl\w*|easier|clearer|shorter)\b", t):
        return "simplify"
    if re.search(r"\b(?:rephrase|reword)\b", t) or re.search(r"\bbreak\b.*\bdown\b", t):
        return "rephrase"
    return "explain"


def _extract_followup_items_from_answer(answer: str) -> tuple[bool, list[str]]:
    """Extract list items from a prior answer using only generic structure."""
    answer_text = str(answer or "")
    if not answer_text.strip():
        return False, []

    # P4: include lettered list markers (a) b) A. B.) in addition to dashes,
    # bullets and digits. Generic across documents.
    _list_marker_re = r"(?:[-*\u2022]|\d+[.)]|[A-Za-z][.)])"

    def _dedup_items(items: list[str]) -> list[str]:
        # P4: dedup by normalized lowercase alnum form so "Planning",
        # "planning.", and "  planning " collapse to one entry.
        seen: set[str] = set()
        out: list[str] = []
        for it in items:
            key = re.sub(r"[^a-z0-9]+", " ", str(it or "").lower()).strip()
            if not key or key in seen:
                continue
            seen.add(key)
            out.append(it)
        return out

    list_lines = [
        line.strip() for line in answer_text.splitlines()
        if _re_followup.match(rf"^\s*{_list_marker_re}\s+\S", line)
    ]
    extracted_items: list[str] = []
    if len(list_lines) >= 2:
        for list_line in list_lines:
            item = _re_followup.sub(
                rf"^\s*{_list_marker_re}\s*", "", list_line
            ).strip()
            if item:
                extracted_items.append(item)
        if extracted_items:
            return True, _dedup_items(extracted_items)

    bullet_parts_raw = _re_followup.split(
        rf"(?:^|\s){_list_marker_re}\s+", answer_text
    )
    bullet_parts = [
        part.strip().rstrip(".")
        for part in bullet_parts_raw
        if part and part.strip()
    ]
    if len(bullet_parts) >= 3 and all(len(part) <= 60 for part in bullet_parts):
        return True, _dedup_items(bullet_parts)

    comma_parts = [
        part.strip().rstrip(".")
        for part in _re_followup.split(r"[,;]", answer_text)
        if part.strip()
    ]
    if len(comma_parts) >= 3 and all(len(part) <= 60 for part in comma_parts):
        first_item = comma_parts[0]
        intro_match = _re_followup.search(
            r"\b(?:are|include|includes|consist of|consists of|namely)\s+",
            first_item,
            _re_followup.IGNORECASE,
        )
        if intro_match:
            first_item = first_item[intro_match.end():].strip()
        if comma_parts:
            comma_parts[-1] = _re_followup.sub(
                r"^\s*and\s+", "", comma_parts[-1], flags=_re_followup.IGNORECASE
            ).strip()
        comma_parts[0] = first_item
        extracted_items = [part for part in comma_parts if part]
        if len(extracted_items) >= 3:
            return True, _dedup_items(extracted_items)

    return False, []


def _infer_followup_answer_type(query: str, answer: str) -> str:
    """Classify saved answer shape for later follow-up routing."""
    is_list_answer, _items = _extract_followup_items_from_answer(answer)
    try:
        query_is_list = _is_list_query(query)
    except Exception:
        query_is_list = False
    if is_list_answer or query_is_list:
        return "list"
    try:
        query_is_compare = _is_compare_query(query) or _is_bare_comparison_followup_query(query)
    except Exception:
        query_is_compare = False
    if query_is_compare:
        return "text"
    query_low = re.sub(r"\s+", " ", str(query or "").strip().lower())
    if _re_followup.match(
        r"^(?:what\s+(?:is|are|was|were)|define|definition\b)", query_low
    ):
        return "definition"
    return "text"


def _extract_definition_concept_from_query_surface(query: str) -> str:
    query_value = re.sub(r"\s+", " ", str(query or "").strip())
    if not query_value:
        return ""
    try:
        if _is_compare_query(query_value) or _is_bare_comparison_followup_query(query_value):
            return ""
    except Exception:
        pass
    match = re.match(
        r"^(?:what|who)\s+(?:is|are|was|were)\s+(.+?)\??$",
        query_value,
        flags=re.IGNORECASE,
    )
    if not match:
        match = re.match(
            r"^(?:define|definition\s+of)\s+(.+?)\??$",
            query_value,
            flags=re.IGNORECASE,
        )
    if not match:
        return ""
    concept = re.sub(r"\b(?:the|a|an)\b", " ", match.group(1), flags=re.IGNORECASE)
    concept = re.sub(r"\s+", " ", concept).strip(" \t\r\n.,;:!?()[]{}")
    tokens = [
        token for token in re.findall(r"[a-z0-9]{3,}", concept.lower())
        if token not in _EVIDENCE_STOPWORDS
    ]
    if not tokens or len(tokens) > 6:
        return ""
    return concept


def _format_compare_memory_concepts(concepts: list[str]) -> str:
    return "[" + ", ".join(str(concept or "").strip() for concept in concepts if str(concept or "").strip()) + "]"


def _save_last_answer_state(connection_id, query, answer, doc_dicts) -> None:
    """Persist the most recent grounded answer for follow-up explanations.

    Skips storage for empty answers. For the strict not-found response we
    actively CLEAR any previously saved state for this connection so that a
    later follow-up ("explain more", "what do you mean?") cannot leak the
    previous successful answer into a turn that ended in not-found.
    """
    try:
        if not connection_id:
            return
        ans = (answer or "").strip()
        if not ans:
            return
        try:
            if ans.lower() == RAG_NO_MATCH_RESPONSE.lower():
                # Latest turn produced a not-found result. Drop any stale
                # prior state so follow-ups have nothing to explain.
                if connection_id in last_answer_state:
                    last_answer_state.pop(connection_id, None)
                    logger.info(
                        "[FOLLOWUP] cleared stale state for connection_id=%s "
                        "(latest answer was not-found)",
                        connection_id,
                    )
                    logger.info("[SMART MEMORY] rejected_reason=not_found_clears_state")
                recent_grounded_definition_concepts.pop(connection_id, None)
                return
        except Exception:
            pass
        answer_is_list, answer_items = _extract_followup_items_from_answer(ans)
        answer_type = _infer_followup_answer_type(query, ans)
        doc_candidates = list(doc_dicts or [])
        if answer_is_list and answer_items:
            scored_candidates: list[tuple[float, int, dict]] = []
            for order, doc_dict in enumerate(doc_candidates):
                if not isinstance(doc_dict, dict):
                    continue
                doc_text = str(
                    doc_dict.get("text")
                    or doc_dict.get("page_content")
                    or doc_dict.get("content")
                    or ""
                ).strip()
                support_score = _followup_list_chunk_support_score(answer_items, doc_text)
                if support_score > 0:
                    scored_candidates.append((support_score, order, doc_dict))
            if scored_candidates:
                scored_candidates.sort(key=lambda row: (-row[0], row[1]))
                max_support = scored_candidates[0][0]
                min_support = 1.0
                if max_support >= 3.0:
                    min_support = max(3.0, max_support * 0.75)
                doc_candidates = [
                    doc_dict
                    for support_score, _order, doc_dict in scored_candidates
                    if support_score >= min_support
                ]
        kept = []
        for doc_dict in doc_candidates[:_FOLLOWUP_KEEP_TOP_K]:
            if not isinstance(doc_dict, dict):
                continue
            txt = str(
                doc_dict.get("text")
                or doc_dict.get("page_content")
                or doc_dict.get("content")
                or ""
            ).strip()
            if not txt:
                continue
            src = doc_dict.get("source")
            md = doc_dict.get("metadata")
            if (not src) and isinstance(md, dict):
                src = md.get("source") or md.get("doc_id") or md.get("file")
            kept_doc = {"text": txt[:_FOLLOWUP_SAVED_CHUNK_CHAR_LIMIT], "source": src}
            if isinstance(md, dict):
                kept_doc["metadata"] = {
                    "source": md.get("source"),
                    "doc_id": md.get("doc_id"),
                    "file": md.get("file"),
                    "page": md.get("page"),
                    "chunk_index": md.get("chunk_index"),
                }
            kept.append(kept_doc)
        next_state = {
            "query": (query or "").strip(),
            "answer": ans,
            "chunks": kept,
            "ts": time.time(),
            "answer_type": answer_type,
        }
        if answer_is_list and answer_items:
            next_state["items"] = answer_items
            next_state["list_query"] = (query or "").strip()
            next_state["list_answer"] = ans
        last_answer_state[connection_id] = next_state
        if answer_type == "list":
            logger.info("[COMPARE MEMORY] ignored=list_entity")
            logger.info("[SMART MEMORY] source=last_list rejected_reason=list_does_not_overwrite_concept_pair")
        if answer_type == "definition" and kept:
            concept = _extract_definition_concept_from_query_surface(query)
            if concept:
                recent_items = list(recent_grounded_definition_concepts.get(connection_id, []) or [])
                concept_key = concept.lower()
                recent_items = [item for item in recent_items if str((item or {}).get("concept") or "").lower() != concept_key]
                recent_items.append({"concept": concept, "ts": time.time()})
                recent_grounded_definition_concepts[connection_id] = recent_items[-4:]
                stable_concepts = [
                    str((item or {}).get("concept") or "")
                    for item in recent_grounded_definition_concepts[connection_id]
                    if str((item or {}).get("concept") or "").strip()
                ]
                logger.info("[COMPARE MEMORY] stable=%s", _format_compare_memory_concepts(stable_concepts))
                logger.info(
                    "[COMPARE FOLLOWUP STATE] connection_id=%s concepts=%s",
                    connection_id,
                    [str((item or {}).get("concept") or "") for item in recent_grounded_definition_concepts[connection_id]],
                )
                logger.info("[SMART MEMORY] source=last_definition resolved_reference=%s", concept)
    except Exception:
        logger.exception("[FOLLOWUP] failed to save last answer state")


def _get_last_answer_state(connection_id):
    state = last_answer_state.get(connection_id)
    if not state:
        return None
    try:
        if (time.time() - float(state.get("ts", 0))) > _FOLLOWUP_STATE_TTL:
            last_answer_state.pop(connection_id, None)
            return None
    except Exception:
        return None
    return state


def _is_bare_comparison_followup_query(query_text: str) -> bool:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return False
    has_comparison_intent = bool(
        re.search(r"\b(?:difference|differences|distinction)\b", q)
        or re.search(r"\b(?:different)\b", q)
        or re.search(r"\b(?:compare|comparison|contrast|contrasts)\b", q)
        or re.search(r"\b(?:differentiate|distinguish)\b", q)
        or re.search(r"\b(?:relationship|relation|relate|relates|related)\b", q)
        or re.search(r"\b(?:versus|vs\.?)\b", q)
        or re.search(r"(?:ما\s+)?الفرق|قارن|مقارنة", q)
    )
    if not has_comparison_intent:
        return False
    explicit_pair = bool(
        re.search(r"\bbetween\b.+\band\b", q)
        or re.search(r"\bcompare\b.+\band\b", q)
        or re.search(r"\b(?:relationship|relation)\b.+\bbetween\b.+\band\b", q)
        or re.search(r"\brelat(?:e|es|ed)\b.+\b(?:to|with)\b", q)
        or re.search(r"\b(?:versus|vs\.?)\b", q)
        or re.search(r"\bبين\b.+\bو\b", q)
    )
    return not explicit_pair


def _extract_recent_definition_concepts_from_history(history: list[dict], max_turns: int = 6) -> list[str]:
    concepts: list[str] = []
    seen: set[str] = set()
    if not history:
        return concepts
    for index in range(len(history) - 1, -1, -1):
        entry = history[index] if isinstance(history[index], dict) else {}
        if entry.get("role") != "user":
            continue
        user_text = str(entry.get("content") or "")
        try:
            if _is_list_query(user_text):
                logger.info("[COMPARE MEMORY] ignored=list_entity")
                continue
        except Exception:
            pass
        next_entry = history[index + 1] if index + 1 < len(history) and isinstance(history[index + 1], dict) else {}
        if next_entry.get("role") == "assistant":
            assistant_text = str(next_entry.get("content") or "").strip()
            if not assistant_text or assistant_text.lower() == RAG_NO_MATCH_RESPONSE.lower():
                continue
            answer_is_list, _answer_items = _extract_followup_items_from_answer(assistant_text)
            if answer_is_list:
                logger.info("[COMPARE MEMORY] ignored=list_entity")
                continue
        concept = _extract_definition_concept_from_query_surface(user_text)
        if not concept:
            continue
        concept_key = concept.lower()
        if concept_key in seen:
            continue
        seen.add(concept_key)
        concepts.append(concept)
        if len(concepts) >= max_turns:
            break
    return list(reversed(concepts))


def _rewrite_bare_comparison_query_from_history(query_text: str, history: list[dict], connection_id: str | None = None) -> str:
    if not _is_bare_comparison_followup_query(query_text):
        return str(query_text or "")
    concepts: list[str] = []
    if connection_id:
        recent_items = list(recent_grounded_definition_concepts.get(connection_id, []) or [])
        concepts = [
            str((item or {}).get("concept") or "").strip()
            for item in recent_items[-2:]
            if str((item or {}).get("concept") or "").strip()
        ]
        if concepts:
            logger.info("[COMPARE MEMORY] stable=%s", _format_compare_memory_concepts(concepts))
    if len(concepts) != 2:
        concepts = _extract_recent_definition_concepts_from_history(history)[-2:]
        if concepts:
            logger.info("[COMPARE MEMORY] stable=%s", _format_compare_memory_concepts(concepts))
    if len(concepts) != 2:
        logger.info(
            "[COMPARE FOLLOWUP REWRITE] skipped history_len=%d concepts=%s",
            len(history or []),
            concepts,
        )
        logger.info("[SMART MEMORY] rejected_reason=insufficient_stable_concepts_for_comparison concepts=%d", len(concepts))
        return str(query_text or "")
    left, right = concepts
    if not left or not right or left.lower() == right.lower():
        return str(query_text or "")
    logger.info("[COMPARE ENTITIES] left=%s right=%s source=history", left, right)
    logger.info("[SMART MEMORY] resolved_reference=comparison_pair source=last_comparison left=%s right=%s", left, right)
    return f"What is the difference between {left} and {right}?"


def _append_conversation_turn(connection_id: str, user_text: str, assistant_text: str) -> None:
    try:
        history = conversation_history[connection_id]
        history.append({"role": "user", "content": str(user_text or "").strip()})
        history.append({"role": "assistant", "content": str(assistant_text or "").strip()})
    except Exception:
        pass


# --------------- weak-evidence anti-inference guard helper ---------------
# Compiled once; used by _evidence_has_explicit_explanation.
_EXPLAIN_VERB_RE = _re_followup.compile(
    r"\b(?:"
    r"is|are|was|were|means?|refer(?:s|red|ring)?\s+to|"
    r"defin(?:e[ds]?|ing)\b|involv(?:e[ds]?|ing)|"
    r"represent(?:s|ed|ing)?|consist(?:s|ed|ing)?\s+of|"
    r"denot(?:e[ds]?|ing)|signif(?:ies|ied|ying)|"
    r"pertain(?:s|ed|ing)?\s+to|deal(?:s|t|ing)?\s+with|"
    r"describ(?:e[ds]?|ing)|provid(?:e[ds]?|ing)|"
    r"ensur(?:e[ds]?|ing)|focus(?:es|ed|ing)?\s+on|"
    r"entail(?:s|ed|ing)?|cover(?:s|ed|ing)?|"
    r"requir(?:e[ds]?|ing)|necessitat(?:e[ds]?|ing)"
    r")\b"
)
_FOLLOWUP_EXPLANATORY_CUE_RE = _re_followup.compile(
    r"\b(?:is|are|was|were|means?|refers?\s+to|defined\s+as|involv(?:e[sd]?|ing))\b",
    _re_followup.IGNORECASE,
)
_EVIDENCE_STOPWORDS = frozenset({
    "this", "that", "these", "those", "with", "from", "into", "than",
    "then", "have", "been", "being", "were", "they", "them", "their",
    "there", "which", "what", "when", "where", "while", "about", "also",
    "such", "some", "more", "most", "many", "much", "will", "would",
    "could", "should", "does", "done", "other", "each", "every", "only",
    "just", "very", "here", "well", "like", "same", "used", "make",
    "made", "take", "give", "need", "know", "keep", "even", "still",
    "back", "over", "under", "between", "work", "said", "says",
    "listed", "items", "item", "list", "above", "below", "following",
    "mentioned", "presents", "presented",
})


def _evidence_has_explicit_explanation(item_name: str, evidence_text: str) -> bool:
    """Return True when *evidence_text* contains a sentence that genuinely
    explains *item_name* — a definition, description, or substantive
    predicate about the item — rather than a passing mention or list
    membership.

    Heuristic signals (generic, no domain vocabulary):
      1. Item appears in a sentence with an explanatory verb within a
         proximity window AND >= 3 substantive content words nearby.
      2. Item appears in a window with >= 6 content words (high
         informational density even without an explicit verb).

    Bare-list sentences (>=3 bullet/dash/comma separators with low word
    density) are skipped automatically.
    """
    if not item_name or not evidence_text:
        return False
    item_low = item_name.strip().lower()
    if not item_low:
        return False
    ev_low = evidence_text.lower()
    item_re = _re_followup.compile(r"\b" + _re_followup.escape(item_low) + r"\b")
    if not item_re.search(ev_low):
        return False

    # Rough sentence splitting
    sents = _re_followup.split(r"(?<=[.!?:;])\s+|\n+|---+", ev_low)

    for sent in sents:
        sent = sent.strip()
        if len(sent) < 20 or not item_re.search(sent):
            continue
        # Skip bare-list sentences (many items separated by delimiters)
        seps = len(_re_followup.findall(r"(?:^|\s)[-*\u2022]\s|\s[-\u2013]\s|,\s", sent))
        words = _re_followup.findall(r"[a-z]{3,}", sent)
        if seps >= 3 and len(words) < seps * 5:
            continue

        for m in item_re.finditer(sent):
            ws = max(0, m.start() - 40)
            we = min(len(sent), m.end() + 120)
            window = sent[ws:we]

            has_verb = bool(_EXPLAIN_VERB_RE.search(window))
            # Count substantive content words (4+ chars, not stopwords,
            # not the item itself)
            win_words = _re_followup.findall(r"[a-z]{4,}", window)
            content = [
                w for w in win_words
                if w not in _EVIDENCE_STOPWORDS
                and w != item_low
                and not w.startswith(item_low[:min(4, len(item_low))])
            ]
            n = len(content)

            if has_verb and n >= 3:
                return True
            if n >= 6:
                return True
    return False


# ---- controlled-explanation mode (follow-up only) -----------------------
# Suffix appended to LLM-inferred explanations so the user can tell the
# explanation was reconstructed from context rather than quoted from the
# document verbatim.
_FOLLOWUP_INFERRED_SUFFIX = (
    "(The document mentions this concept but does not provide a detailed explanation.)"
)

# Minimum fraction of content words in an LLM-generated explanation that
# must appear (whole-word) in the retrieved chunks or previous answer.
# Below this threshold the explanation is considered ungrounded and is
# replaced by a cautious placeholder.  Generic — no domain vocabulary.
_FOLLOWUP_EXPL_GROUND_THRESHOLD = 0.60


def _compute_explanation_grounding_score(
    explanation: str, excerpts_block: str, last_a: str
) -> float:
    """Return the fraction of content words in *explanation* that appear
    (whole-word) in *excerpts_block* or *last_a*.

    Used as an anti-hallucination guard for the controlled-explanation
    mode.  Generic: only stopword filtering + whole-word matching.
    """
    _stop = {
        "the", "a", "an", "of", "and", "or", "to", "in", "on", "for",
        "with", "by", "from", "at", "is", "are", "was", "were", "be",
        "been", "being", "this", "that", "these", "those", "it", "its",
        "as", "but", "not", "also", "then", "when", "where", "which",
        "who", "what", "how", "if", "so", "do", "does", "did", "has",
        "have", "had", "will", "would", "can", "could", "should", "may",
        "might", "must", "shall", "such", "each", "more", "most", "some",
        "any", "all", "one", "two", "three", "their", "they", "them",
        "we", "you", "i", "my", "your", "our",
    }
    haystack = ((excerpts_block or "") + " " + (last_a or "")).lower()
    content_words = [
        w for w in re.findall(r"[a-z]{3,}", (explanation or "").lower())
        if w not in _stop
    ]
    if not content_words:
        return 1.0  # empty explanation: no content to check
    matched = sum(
        1 for w in content_words
        if re.search(rf"\b{re.escape(w)}\b", haystack)
    )
    return matched / len(content_words)


def _infer_previous_list_relation_phrase(previous_query: str) -> str:
    """Return a short generic phrase describing what the previous list was about.

    The phrase is derived only from the user's previous question, so follow-up
    explanations can say "one of the goals of X" without introducing any new
    domain knowledge.
    """
    q = re.sub(r"\s+", " ", str(previous_query or "").strip().strip("?!."))
    if not q:
        return "the listed items"
    patterns = (
        r"^\s*(?:what|which)\s+(?:are|were)\s+(?:the\s+)?(.+?)\s*$",
        r"^\s*(?:list|name|mention|identify|give)\s+(?:the\s+)?(.+?)\s*$",
    )
    phrase = ""
    for patt in patterns:
        m = re.search(patt, q, flags=re.IGNORECASE)
        if m:
            phrase = re.sub(r"\s+", " ", (m.group(1) or "")).strip(" ,;:-")
            break
    if not phrase:
        return "the listed items"
    phrase = re.sub(r"^(?:main|major|primary|basic|different|various)\s+", "", phrase, flags=re.IGNORECASE).strip()
    words = re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", phrase)
    if len(words) > 10:
        return "the listed items"
    if not re.match(r"^(?:the|a|an)\b", phrase, flags=re.IGNORECASE):
        phrase = "the " + phrase
    return phrase


def _join_short_item_names(items: list[str], max_items: int = 5) -> str:
    cleaned: list[str] = []
    for item in items:
        s = re.sub(r"\s+", " ", str(item or "").strip().strip(" .;:-"))
        if not s:
            continue
        words = re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", s)
        if not words or len(words) > 9:
            continue
        cleaned.append(s)
        if len(cleaned) >= max_items:
            break
    if not cleaned:
        return ""
    if len(cleaned) == 1:
        return cleaned[0]
    if len(cleaned) == 2:
        return f"{cleaned[0]} and {cleaned[1]}"
    return ", ".join(cleaned[:-1]) + f", and {cleaned[-1]}"


def _build_followup_list_context_mini_explanation(
    target_item: str,
    previous_items: list[str],
    previous_query: str,
) -> str | None:
    """Build a grounded follow-up explanation from the prior list only.

    This deliberately does not invent examples or domain details. It states the
    only relationship that is grounded when the document merely listed the item.
    """
    target = re.sub(r"\s+", " ", str(target_item or "").strip().strip(" .;:-"))
    if not target:
        return None
    items = [re.sub(r"\s+", " ", str(it or "").strip().strip(" .;:-")) for it in (previous_items or [])]
    items = [it for it in items if it]
    if target not in items:
        return None
    if len(items) < 2:
        return None

    relation_phrase = _infer_previous_list_relation_phrase(previous_query)
    others = [it for it in items if it != target]
    others_text = _join_short_item_names(others, max_items=5)

    sentences = [f"The document refers to this as {target}, one of {relation_phrase}."]
    if others_text:
        sentences.append(
            f"It appears in the same list with {others_text}, so the grounded context is the list relationship."
        )
    sentences.append("The document does not provide a detailed explanation for it.")
    return " ".join(sentences)


_FOLLOWUP_TARGET_STOPWORDS = _EVIDENCE_STOPWORDS | frozenset({
    "explain", "explains", "explained", "clarify", "clarifies", "clarified",
    "elaborate", "elaborates", "elaborated", "rephrase", "rephrases",
    "rephrased", "simplify", "simplifies", "simplified", "tell", "about",
    "please", "mean", "means", "meaning", "what", "does", "more", "detail",
    "details", "further",
})


def _followup_item_head(item: str) -> str:
    return re.sub(r"\s+", " ", str(item or "").split(":", 1)[0]).strip(" .;:-")


def _followup_content_tokens(value: str) -> list[str]:
    return [
        token for token in _re_followup.findall(r"[a-z0-9]{3,}", str(value or "").lower())
        if token not in _FOLLOWUP_TARGET_STOPWORDS
    ]


def _followup_query_surface_focus_phrase(item: str, user_text: str) -> str:
    item_tokens = set(_followup_content_tokens(_followup_item_head(item)))
    if not item_tokens:
        return ""
    text_value = str(user_text or "")
    token_matches = list(_re_followup.finditer(r"[a-z0-9]{3,}", text_value.lower()))
    matching_indexes = [
        index for index, match in enumerate(token_matches)
        if match.group(0) in item_tokens
    ]
    if not matching_indexes:
        return ""
    first_index = matching_indexes[0]
    last_index = matching_indexes[-1]
    if last_index - first_index > 7:
        return ""
    start = token_matches[first_index].start()
    end = token_matches[last_index].end()
    phrase = re.sub(r"\s+", " ", text_value[start:end]).strip(" \t\r\n.,;:!?()[]{}")
    if len(_followup_content_tokens(phrase)) < 1:
        return ""
    if len(phrase) > 90:
        return ""
    return phrase


def _followup_query_focus_phrase(item: str, user_text: str) -> str:
    item_head = _followup_item_head(item)
    surface_phrase = _followup_query_surface_focus_phrase(item_head, user_text)
    if surface_phrase:
        return surface_phrase
    item_tokens = _followup_content_tokens(item_head)
    query_tokens = set(_followup_content_tokens(user_text))
    overlap = [token for token in item_tokens if token in query_tokens]
    if overlap:
        return " ".join(overlap[:3]).strip()
    if len(item_tokens) > 6:
        return " ".join(item_tokens[:4]).strip() or item_head
    return item_head


def _followup_text_mentions_item(text: str, item: str) -> bool:
    text_low = str(text or "").lower()
    item_head = _followup_item_head(item)
    item_low = item_head.lower()
    if not text_low.strip() or not item_low:
        return False
    if _re_followup.search(r"\b" + _re_followup.escape(item_low) + r"\b", text_low):
        return True
    item_tokens = _followup_content_tokens(item_head)
    if not item_tokens:
        return False
    text_tokens = set(_re_followup.findall(r"[a-z0-9]{3,}", text_low))
    if len(item_tokens) == 1:
        return item_tokens[0] in text_tokens
    overlap = sum(1 for token in item_tokens if token in text_tokens)
    needed = max(2, int(math.ceil(len(item_tokens) * 0.55)))
    if overlap >= needed:
        return True
    first_token = item_tokens[0]
    return len(first_token) >= 5 and first_token in text_tokens


def _followup_list_chunk_support_score(items: list[str], text: str) -> float:
    """Score how strongly a chunk supports a previously returned list."""
    text_value = str(text or "")
    if not text_value.strip():
        return 0.0
    text_low = text_value.lower()
    score = 0.0
    matched_items = 0
    for item in items or []:
        item_head = _followup_item_head(item)
        item_low = item_head.lower()
        if not item_low:
            continue
        if _re_followup.search(r"\b" + _re_followup.escape(item_low) + r"\b", text_low):
            score += 2.0
            matched_items += 1
        elif _followup_text_mentions_item(text_value, item_head):
            score += 1.0
            matched_items += 1
    if matched_items >= 3:
        score += 3.0
    return score


def _followup_text_has_item_head_anchor(text: str, item: str) -> bool:
    """True when text contains the full item head or its first content token."""
    text_low = str(text or "").lower()
    item_head = _followup_item_head(item)
    item_low = item_head.lower()
    if not text_low.strip() or not item_low:
        return False
    if _re_followup.search(r"\b" + _re_followup.escape(item_low) + r"\b", text_low):
        return True
    item_tokens = _followup_content_tokens(item_head)
    if not item_tokens:
        return False
    first_token = item_tokens[0]
    if len(first_token) < 3:
        return False
    return bool(_re_followup.search(r"\b" + _re_followup.escape(first_token) + r"\b", text_low))


_FOLLOWUP_ORDINAL_WORDS: dict[str, int] = {
    "first": 1, "1st": 1,
    "second": 2, "2nd": 2,
    "third": 3, "3rd": 3,
    "fourth": 4, "4th": 4,
    "fifth": 5, "5th": 5,
    "sixth": 6, "6th": 6,
    "seventh": 7, "7th": 7,
    "eighth": 8, "8th": 8,
    "ninth": 9, "9th": 9,
    "tenth": 10, "10th": 10,
}
# "previous one" is ambiguous (could mean prior turn, not prior list item);
# "next one" is also ambiguous on a static list. We resolve only the
# unambiguous ordinals plus "last/final" -> tail of the list.
_FOLLOWUP_ORDINAL_RE = _re_followup.compile(
    r"\b(?:the\s+)?(first|1st|second|2nd|third|3rd|fourth|4th|fifth|5th|"
    r"sixth|6th|seventh|7th|eighth|8th|ninth|9th|tenth|10th|last|final)\b"
    r"(?:\s+(?:one|item|element|thing|point|step|function|part|option|reason|"
    r"principle|stage|phase|category|type|kind))?",
    _re_followup.IGNORECASE,
)


def _resolve_followup_ordinal(items: list[str], text: str) -> tuple[str | None, str]:
    """Return (item, reason) when the query contains an unambiguous ordinal
    reference into ``items``. Generic — no domain words.
    Returns (None, "") when no ordinal applies, ("", "ambiguous") when
    multiple distinct ordinals are mentioned (caller should fall through
    to other matching strategies), or ("", "out_of_range") when the
    ordinal exceeds the list length.
    """
    if not items:
        return None, ""
    matches = _FOLLOWUP_ORDINAL_RE.findall(str(text or ""))
    if not matches:
        return None, ""
    indices: list[int] = []
    for tok in matches:
        low = tok.lower()
        if low in ("last", "final"):
            indices.append(len(items))
        else:
            n = _FOLLOWUP_ORDINAL_WORDS.get(low)
            if n is not None:
                indices.append(n)
    indices = list(dict.fromkeys(indices))  # dedupe, preserve order
    if not indices:
        return None, ""
    if len(indices) > 1:
        # E.g. "how does the first one differ from the last one?" — the
        # query references multiple items; let the token-overlap path
        # decide instead of forcing a single pick.
        return "", "ambiguous"
    idx = indices[0]
    if idx < 1 or idx > len(items):
        return "", "out_of_range"
    return items[idx - 1], f"ordinal_{idx}"


def _select_followup_target_item(items: list[str], text: str) -> tuple[str | None, str]:
    """Return the single prior-list item referenced by a follow-up query."""
    cleaned_items = [
        re.sub(r"\s+", " ", str(item or "").strip().strip(" .;:-"))
        for item in (items or [])
    ]
    cleaned_items = [item for item in cleaned_items if item]
    if not cleaned_items:
        return None, "no_items"

    # P11A: try unambiguous ordinal resolution first ("the second one",
    # "the last function", "explain 2nd"). Falls through on no match,
    # ambiguity, or out-of-range so the existing token-overlap path runs.
    ord_item, ord_reason = _resolve_followup_ordinal(cleaned_items, text)
    if ord_item:
        return ord_item, ord_reason

    query_low = str(text or "").lower()
    query_tokens = {
        token for token in _re_followup.findall(r"[a-z0-9]{3,}", query_low)
        if token not in _FOLLOWUP_TARGET_STOPWORDS
    }
    if not query_tokens:
        return None, "no_query_tokens"

    token_owner_count: dict[str, int] = {}
    item_tokens_by_item: dict[str, list[str]] = {}
    for item in cleaned_items:
        tokens = _followup_content_tokens(_followup_item_head(item))
        item_tokens_by_item[item] = tokens
        for token in set(tokens):
            token_owner_count[token] = token_owner_count.get(token, 0) + 1

    candidates: list[tuple[float, str, str]] = []
    for item in cleaned_items:
        item_head = _followup_item_head(item)
        item_low = item_head.lower()
        item_tokens = item_tokens_by_item.get(item) or []
        if not item_low or not item_tokens:
            continue
        if _re_followup.search(r"\b" + _re_followup.escape(item_low) + r"\b", query_low):
            candidates.append((3.0, item, "phrase"))
            continue
        overlap_tokens = [token for token in item_tokens if token in query_tokens]
        if not overlap_tokens:
            continue
        if len(item_tokens) == 1:
            candidates.append((2.5, item, "single_token"))
            continue
        first_token = item_tokens[0]
        unique_first = (
            first_token in query_tokens
            and token_owner_count.get(first_token, 0) == 1
            and len(first_token) >= 5
        )
        if len(overlap_tokens) >= 2:
            score = 2.0 + (len(overlap_tokens) / max(1, len(item_tokens)))
            candidates.append((score, item, "token_overlap"))
        elif unique_first:
            candidates.append((1.8, item, "unique_head_token"))

    if not candidates:
        return None, "no_match"
    candidates.sort(key=lambda candidate: candidate[0], reverse=True)
    best_score, best_item, best_reason = candidates[0]
    tied = [candidate for candidate in candidates if abs(candidate[0] - best_score) < 0.01]
    if len(tied) > 1:
        return None, "ambiguous"
    return best_item, best_reason


def _sentence_mentions_many_followup_items(sentence: str, items: list[str]) -> bool:
    hits = 0
    for item in items or []:
        if _followup_text_mentions_item(sentence, item):
            hits += 1
        if hits >= 3:
            return True
    return False


def _split_followup_sentences(text: str) -> list[str]:
    pieces = _re_followup.split(r"(?<=[.!?:;])\s+|\n+|---+", str(text or ""))
    return [re.sub(r"\s+", " ", piece).strip() for piece in pieces if piece and piece.strip()]


def _split_followup_explanation_sentences(text: str) -> list[str]:
    pieces = _re_followup.split(r"(?<=[.!?])\s+|\n+|---+", str(text or ""))
    return [re.sub(r"\s+", " ", piece).strip() for piece in pieces if piece and piece.strip()]


_FOLLOWUP_COURSE_HEADER_RE = _re_followup.compile(
    r"^\s*"
    r"(?:(?i:Introduction\s+to)\s+[^.!?;:\n]{1,90}?\s+[\-\u2013\u2014]?\s*)?"
    r"[A-Z]{2,}\s*[\- ]?\d{2,}[A-Z0-9-]*\b"
    r"[\s,;:\-\u2013\u2014]*(?:[A-Z]{2,6}\b[\s,;:\-\u2013\u2014]*)?"
)
_FOLLOWUP_COPYRIGHT_PREFIX_RE = _re_followup.compile(
    r"^\s*(?:\u00a9\s*)?copyright\b[^.!?]{0,180}(?:[.!?]\s*|\s+|$)",
    _re_followup.IGNORECASE,
)
_FOLLOWUP_PAGE_PREFIX_RE = _re_followup.compile(
    r"^\s*(?:page\s*)?\d+\s*(?:of|/)\s*\d+\b[\s:;,\.\-]*",
    _re_followup.IGNORECASE,
)
_FOLLOWUP_ORPHAN_HEADER_TOKEN_RE = _re_followup.compile(
    r"^\s*[A-Z]{2,6}\b[\s,;:\-\u2013\u2014]+"
)
_FOLLOWUP_FRAGMENT_START_RE = _re_followup.compile(
    r"^\s*(?:and|or|but|which|who|whose|where|when|while|because|although|though|"
    r"of|from|to|into|by|with|than)\b",
    _re_followup.IGNORECASE,
)
_FOLLOWUP_FRAGMENT_CLAUSE_RE = _re_followup.compile(
    r"^[^.!?]{5,180}[;:]\s+(?:and\s+)?(?=(?:this|that|these|those|it|they|there|the|a|an)\b)",
    _re_followup.IGNORECASE,
)
_FOLLOWUP_LEADING_CONJUNCTION_RE = _re_followup.compile(
    r"^\s*(?:and|but|or)\s+(?=(?:this|that|these|those|it|they|there|the|a|an)\b)",
    _re_followup.IGNORECASE,
)
_FOLLOWUP_OCR_SPLIT_WORD_RE = _re_followup.compile(
    r"\b([a-z]{4,})\s+"
    r"(eved|ieved|tion|sion|ment|ments|ness|able|ible|ally|ance|ence|ive|ous|ful|less|ing|ed|ine)\b",
    _re_followup.IGNORECASE,
)
_OCR_MERGED_PREFIX_WORD_RE = _re_followup.compile(
    r"\b(the|and|for|from|with|into|onto|about|after|before)([a-z]{5,18})\b",
    _re_followup.IGNORECASE,
)
_OCR_PREFIX_REMAINDER_SUFFIX_RE = _re_followup.compile(
    r"(?:tion|sion|ment|ments|ness|ities|ity|ance|ence|ure|ures|ism|isms|ist|ists|ship|ships|logy|ology|graphy|ess)$",
    _re_followup.IGNORECASE,
)


def _followup_capitalize_sentence_start(value: str) -> str:
    if value and value[0].islower():
        return value[0].upper() + value[1:]
    return value


def _followup_strip_header_prefix(value: str) -> tuple[str, bool]:
    cleaned = str(value or "")
    changed = False
    for _ in range(3):
        before = cleaned
        cleaned = _FOLLOWUP_COPYRIGHT_PREFIX_RE.sub("", cleaned)
        cleaned = _FOLLOWUP_PAGE_PREFIX_RE.sub("", cleaned)
        cleaned = _FOLLOWUP_COURSE_HEADER_RE.sub("", cleaned)
        if cleaned != before:
            changed = True
            cleaned = cleaned.lstrip(" \t\r\n,;:-\u2013\u2014")
            cleaned = _FOLLOWUP_ORPHAN_HEADER_TOKEN_RE.sub("", cleaned).lstrip(" \t\r\n,;:-\u2013\u2014")
            continue
        break
    return cleaned, changed


def _followup_merge_safe_ocr_split_words(value: str) -> tuple[str, bool]:
    changed = False

    def _merge(match: re.Match) -> str:
        nonlocal changed
        left = match.group(1)
        right = match.group(2)
        if left.lower() in _EVIDENCE_STOPWORDS or right.lower() in _EVIDENCE_STOPWORDS:
            return match.group(0)
        combined = left + right
        if not (6 <= len(combined) <= 20):
            return match.group(0)
        if not re.search(r"[aeiou]", combined):
            return match.group(0)
        if re.search(r"([a-z])\1\1", combined):
            return match.group(0)
        changed = True
        return combined

    cleaned = _FOLLOWUP_OCR_SPLIT_WORD_RE.sub(_merge, str(value or ""))
    return cleaned, changed


def _split_safe_ocr_merged_prefix_words(value: str) -> tuple[str, bool]:
    changed = False

    def _split(match: re.Match) -> str:
        nonlocal changed
        prefix = match.group(1)
        remainder = match.group(2)
        combined = prefix + remainder
        if not (8 <= len(combined) <= 24):
            return match.group(0)
        if remainder.lower() in _EVIDENCE_STOPWORDS:
            return match.group(0)
        if not re.search(r"[aeiou]", remainder, flags=re.IGNORECASE):
            return match.group(0)
        if not _OCR_PREFIX_REMAINDER_SUFFIX_RE.search(remainder):
            return match.group(0)
        changed = True
        return f"{prefix} {remainder}"

    cleaned = _OCR_MERGED_PREFIX_WORD_RE.sub(_split, str(value or ""))
    return cleaned, changed


def _followup_salvage_fragment_clause(value: str) -> tuple[str, bool]:
    match = _FOLLOWUP_FRAGMENT_CLAUSE_RE.search(value or "")
    if not match:
        return value, False
    candidate = (value or "")[match.end():].strip(" \t\r\n,;:-\u2013\u2014")
    candidate = _FOLLOWUP_LEADING_CONJUNCTION_RE.sub("", candidate).strip()
    if not candidate:
        return value, False
    return _followup_capitalize_sentence_start(candidate), True


def _cleanup_followup_extracted_answer(
    sentence: str,
    target_item: str,
) -> tuple[str, bool, str]:
    """Clean an already-grounded follow-up sentence without adding content."""
    original = re.sub(r"\s+", " ", str(sentence or "")).strip(" \t\r\n-*\u2022")
    if not original:
        return "", False, "empty"

    cleaned, header_removed = _followup_strip_header_prefix(original)
    cleaned = re.sub(r"\s+", " ", cleaned).strip(" \t\r\n-*\u2022")
    cleaned, prefix_changed = _split_safe_ocr_merged_prefix_words(cleaned)
    cleaned, ocr_changed = _followup_merge_safe_ocr_split_words(cleaned)
    cleaned = re.sub(r"\s+([,.;:!?])", r"\1", cleaned)
    cleaned = re.sub(r"\s+", " ", cleaned).strip(" \t\r\n,;:-\u2013\u2014")

    fragment_changed = False
    if header_removed and cleaned and cleaned[0].islower():
        salvaged, fragment_changed = _followup_salvage_fragment_clause(cleaned)
        if fragment_changed:
            cleaned = salvaged
        elif not _followup_text_has_item_head_anchor(cleaned, target_item):
            return "", (cleaned != original or prefix_changed or ocr_changed), "fragment_after_header"

    if _FOLLOWUP_FRAGMENT_START_RE.match(cleaned):
        before = cleaned
        cleaned = _FOLLOWUP_LEADING_CONJUNCTION_RE.sub("", cleaned).strip()
        if cleaned == before:
            return "", (cleaned != original or prefix_changed or ocr_changed), "fragment_start"
        fragment_changed = True

    cleaned = _followup_capitalize_sentence_start(cleaned.strip())
    if target_item and not _followup_text_has_item_head_anchor(cleaned, target_item):
        return "", (cleaned != original or prefix_changed or ocr_changed or fragment_changed), "target_removed"
    if not cleaned:
        return "", (cleaned != original or prefix_changed or ocr_changed or fragment_changed), "empty_after_cleanup"
    if not re.search(r"[.!?]$", cleaned):
        cleaned += "."
    return cleaned[:1000].strip(), (cleaned != original or prefix_changed or ocr_changed or fragment_changed), ""


def _extract_followup_context_window(text: str, target_item: str, char_budget: int = 1800) -> str:
    """Return nearby sentences/paragraph text around a targeted list item."""
    if not text or not target_item:
        return ""
    paragraphs = [
        paragraph.strip()
        for paragraph in _re_followup.split(r"\n\s*\n|---+", str(text or ""))
        if paragraph and paragraph.strip()
    ]
    selected: list[str] = []
    for paragraph in paragraphs:
        if not _followup_text_mentions_item(paragraph, target_item):
            continue
        sentences = _split_followup_sentences(paragraph)
        if not sentences:
            selected.append(re.sub(r"\s+", " ", paragraph)[:char_budget])
            continue
        for index, sentence in enumerate(sentences):
            if not _followup_text_mentions_item(sentence, target_item):
                continue
            start_index = max(0, index - 2)
            end_index = min(len(sentences), index + 4)
            selected.append(" ".join(sentences[start_index:end_index]))
    if not selected:
        return ""
    compact = " ".join(dict.fromkeys(selected))
    return re.sub(r"\s+", " ", compact).strip()[:char_budget]


def _build_followup_excerpts(last_chunks: list[dict], target_item: str | None = None) -> str:
    """Build saved follow-up context, focused around the target when present."""
    excerpt_parts: list[str] = []
    total_chars = 0
    if target_item:
        for chunk in (last_chunks or [])[:_FOLLOWUP_KEEP_TOP_K]:
            if not isinstance(chunk, dict):
                continue
            chunk_text = str(chunk.get("text") or "").strip()
            focused = _extract_followup_context_window(chunk_text, target_item)
            if not focused:
                continue
            remaining = _FOLLOWUP_CHUNK_CHAR_BUDGET - total_chars
            if remaining <= 0:
                break
            excerpt_parts.append(focused[:remaining])
            total_chars += len(excerpt_parts[-1])
    if not excerpt_parts:
        for chunk in (last_chunks or [])[:_FOLLOWUP_KEEP_TOP_K]:
            if not isinstance(chunk, dict):
                continue
            chunk_text = str(chunk.get("text") or "").strip()
            if not chunk_text:
                continue
            remaining = _FOLLOWUP_CHUNK_CHAR_BUDGET - total_chars
            if remaining <= 0:
                break
            excerpt_parts.append(chunk_text[:remaining])
            total_chars += len(excerpt_parts[-1])
    return "\n\n---\n\n".join(excerpt_parts)


def _extract_followup_strong_explanation(
    target_item: str,
    excerpts_block: str,
    previous_items: list[str],
    emit_cleanup_logs: bool = True,
    apply_cleanup: bool = True,
) -> str:
    """Extract a coherent explanatory block for a targeted item, if present."""
    if not target_item or not excerpts_block:
        return ""
    best_block = ""
    best_raw_block = ""
    best_cleanup_changed = False
    best_score = -1
    sections = [
        re.sub(r"\s+", " ", section).strip()
        for section in _re_followup.split(r"\n\s*(?:---+|={3,}|\*{3,})\s*\n|\n\s*\n", excerpts_block)
        if section and section.strip()
    ] or [re.sub(r"\s+", " ", excerpts_block).strip()]

    def _sentence_content_tokens(sentence_value: str) -> list[str]:
        return [
            word for word in _re_followup.findall(r"[a-z0-9]{4,}", sentence_value.lower())
            if word not in _EVIDENCE_STOPWORDS
        ]

    def _sentence_is_noisy_list_fragment(sentence_value: str) -> bool:
        separators_local = len(_re_followup.findall(r"(?:^|\s)[-*\u2022]\s|\s[-\u2013]\s|,\s", sentence_value))
        words_local = _re_followup.findall(r"[a-z]{3,}", sentence_value.lower())
        if (
            _sentence_mentions_many_followup_items(sentence_value, previous_items)
            and separators_local >= 2
            and len(words_local) < separators_local * 7
        ):
            return True
        return bool(separators_local >= 3 and len(words_local) < separators_local * 5)

    def _sentence_is_ocr_fragment(sentence_value: str) -> bool:
        sentence_clean = re.sub(r"\s+", " ", str(sentence_value or "")).strip()
        if not sentence_clean:
            return True
        words_local = _re_followup.findall(r"[A-Za-z0-9][A-Za-z0-9'-]*", sentence_clean)
        if len(words_local) < 4:
            return True
        if _re_followup.search(r"(?:\b[A-Za-z]\s+){4,}[A-Za-z]\b", sentence_clean):
            return True
        if not _EXPLAIN_VERB_RE.search(sentence_clean.lower()) and len(words_local) < 7:
            return True
        return False

    def _sentence_content_count(sentence_value: str) -> int:
        return len(_sentence_content_tokens(sentence_value))

    def _definition_style_score(sentence_value: str) -> float:
        sentence_low = sentence_value.lower()
        score_local = 0.0
        if _FOLLOWUP_EXPLANATORY_CUE_RE.search(sentence_value):
            score_local += 6.0
        if _EXPLAIN_VERB_RE.search(sentence_low):
            score_local += 3.0
        if _re_followup.search(r"\b(?:because|therefore|thus|so|so that|in order to)\b", sentence_low):
            score_local += 1.5
        if _followup_text_has_item_head_anchor(sentence_value, target_item):
            score_local += 2.0
        if _sentence_content_count(sentence_value) >= 8:
            score_local += 1.0
        return score_local

    def _continuity_score(sentence_value: str, running_tokens: set[str], anchor_tokens: set[str]) -> float:
        sentence_tokens = set(_sentence_content_tokens(sentence_value))
        if not sentence_tokens:
            return -1.0
        overlap_running = len(sentence_tokens & running_tokens)
        overlap_anchor = len(sentence_tokens & anchor_tokens)
        connector = bool(
            _re_followup.match(
                r"^\s*(?:this|that|these|those|it|they|such|another|also|therefore|thus|because)\b",
                sentence_value,
                _re_followup.IGNORECASE,
            )
        )
        cue = bool(_FOLLOWUP_EXPLANATORY_CUE_RE.search(sentence_value) or _EXPLAIN_VERB_RE.search(sentence_value.lower()))
        score_local = 0.0
        score_local += min(3.0, float(overlap_running) * 1.25)
        score_local += min(2.0, float(overlap_anchor))
        if connector:
            score_local += 2.0
        if cue:
            score_local += 1.5
        return score_local

    for section in sections:
        sentences = _split_followup_explanation_sentences(section)
        for index, sentence in enumerate(sentences):
            if not _followup_text_has_item_head_anchor(sentence, target_item):
                continue
            if _sentence_is_noisy_list_fragment(sentence) or _sentence_is_ocr_fragment(sentence):
                continue
            has_verb = bool(_EXPLAIN_VERB_RE.search(sentence.lower()))
            content_count = _sentence_content_count(sentence)
            if not ((has_verb and content_count >= 3) or content_count >= 7):
                continue
            has_explanatory_cue = bool(_FOLLOWUP_EXPLANATORY_CUE_RE.search(sentence))
            complete_statement = bool(
                has_explanatory_cue
                and len(_re_followup.findall(r"[a-z0-9]{3,}", sentence.lower())) >= 8
            )

            anchor_tokens = set(_sentence_content_tokens(sentence))
            target_tokens = set(_followup_content_tokens(target_item))
            block_sentences = [sentence]

            if index > 0:
                previous_sentence = sentences[index - 1]
                if (
                    not _sentence_is_noisy_list_fragment(previous_sentence)
                    and not _sentence_is_ocr_fragment(previous_sentence)
                    and _sentence_content_count(previous_sentence) >= 4
                ):
                    previous_tokens = set(_sentence_content_tokens(previous_sentence))
                    previous_connected = bool(
                        (previous_tokens & (anchor_tokens | target_tokens))
                        or _FOLLOWUP_EXPLANATORY_CUE_RE.search(previous_sentence)
                        or _EXPLAIN_VERB_RE.search(previous_sentence.lower())
                    )
                    if previous_connected:
                        block_sentences.insert(0, previous_sentence)

            running_tokens = set()
            for block_sentence in block_sentences:
                running_tokens.update(_sentence_content_tokens(block_sentence))
            running_tokens.update(target_tokens)

            continuity_total = 0.0
            for next_sentence in sentences[index + 1:index + 4]:
                if len(block_sentences) >= 4:
                    break
                if _sentence_is_noisy_list_fragment(next_sentence) or _sentence_is_ocr_fragment(next_sentence):
                    break
                next_content_count = _sentence_content_count(next_sentence)
                if next_content_count < 4:
                    break
                continuation_score = _continuity_score(next_sentence, running_tokens, anchor_tokens | target_tokens)
                if continuation_score < 2.0:
                    break
                continuity_total += continuation_score
                block_sentences.append(next_sentence)
                running_tokens.update(_sentence_content_tokens(next_sentence))

            unique_sentence_count = len([s for s in dict.fromkeys(block_sentences) if s])
            if unique_sentence_count < 2:
                continue

            raw_block = " ".join(block_sentences)
            separators = len(_re_followup.findall(r"(?:^|\s)[-*\u2022]\s|\s[-\u2013]\s|,\s", raw_block))
            topic_consistency = 0.0
            for block_sentence in block_sentences:
                sentence_tokens = set(_sentence_content_tokens(block_sentence))
                if sentence_tokens:
                    topic_consistency += len(sentence_tokens & (anchor_tokens | target_tokens)) / max(1.0, float(len(sentence_tokens)))
            score = (
                content_count
                + (4 if has_verb else 0)
                + (6 if has_explanatory_cue else 0)
                + (2 if complete_statement else 0)
                + _definition_style_score(sentence)
                + continuity_total
                + (3 * (unique_sentence_count - 1))
                + (4.0 * topic_consistency)
                - (3 if separators >= 2 else 0)
            )
            cleanup_changed = False
            clean_block = raw_block
            if apply_cleanup:
                clean_block, cleanup_changed, reject_reason = _cleanup_followup_extracted_answer(
                    raw_block, target_item
                )
                if reject_reason:
                    if emit_cleanup_logs:
                        logger.info(
                            "[FOLLOWUP NOISY SENTENCE REJECTED] reason=%s sentence=%r",
                            reject_reason,
                            raw_block[:180],
                        )
                    continue
                clean_sentence_count = len(_split_followup_explanation_sentences(clean_block))
                if clean_sentence_count < 2 or clean_sentence_count > 4:
                    continue
                if not cleanup_changed:
                    score += 2
            if score > best_score:
                best_score = score
                best_block = clean_block
                best_raw_block = raw_block
                best_cleanup_changed = cleanup_changed
    if not best_block:
        return ""
    best_block = re.sub(r"\s+", " ", best_block).strip(" \t\r\n-*")
    if not re.search(r"[.!?]$", best_block):
        best_block += "."
    if emit_cleanup_logs and best_cleanup_changed:
        logger.info(
            "[FOLLOWUP CLEANUP APPLIED] before=%r after=%r",
            best_raw_block[:180],
            best_block[:180],
        )
    if emit_cleanup_logs:
        logger.info("[FOLLOWUP CLEAN ANSWER] %s", best_block[:240])
    return best_block[:1000].strip()


def _followup_explanation_candidate_score(
    target_item: str,
    candidate_text: str,
    previous_items: list[str] | None = None,
) -> float:
    """Score a follow-up candidate by generic explanatory sentence shape."""
    text_value = re.sub(r"\s+", " ", str(candidate_text or "")).strip()
    if not text_value or not _followup_text_mentions_item(text_value, target_item):
        return -1.0

    score = 0.0
    item_tokens = _followup_content_tokens(_followup_item_head(target_item))
    text_tokens = set(_re_followup.findall(r"[a-z0-9]{3,}", text_value.lower()))
    if item_tokens:
        overlap = 0
        for item_token in item_tokens:
            if item_token in text_tokens:
                overlap += 1
                continue
            if len(item_token) >= 5 and any(
                text_token.startswith(item_token) or item_token.startswith(text_token)
                for text_token in text_tokens
            ):
                overlap += 1
        score += min(8.0, overlap * 2.0)
        if len(item_tokens) >= 3 and overlap <= 1:
            score -= 8.0

    if _extract_followup_strong_explanation(
        target_item,
        text_value,
        previous_items or [],
        emit_cleanup_logs=False,
        apply_cleanup=False,
    ):
        score += 12.0
    if _evidence_has_explicit_explanation(target_item, text_value):
        score += 8.0

    for sentence in _split_followup_sentences(text_value):
        if not _followup_text_has_item_head_anchor(sentence, target_item):
            continue
        words = _re_followup.findall(r"[a-z0-9]{3,}", sentence.lower())
        separators = len(_re_followup.findall(r"(?:^|\s)[-*\u2022]\s|\s[-\u2013]\s|,\s", sentence))
        if _FOLLOWUP_EXPLANATORY_CUE_RE.search(sentence):
            score += 4.0
        if len(words) >= 8 and re.search(r"[.!?]$", sentence.strip()):
            score += 2.0
        if len(sentence) >= 80:
            score += 1.0
        if separators >= 3:
            score -= 4.0
        if previous_items and _sentence_mentions_many_followup_items(sentence, previous_items):
            score -= 3.0
    return score


def _followup_doc_text(candidate_doc: dict) -> str:
    return str(
        (candidate_doc or {}).get("text")
        or (candidate_doc or {}).get("page_content")
        or (candidate_doc or {}).get("content")
        or ""
    ).strip()


def _followup_doc_source(candidate_doc: dict) -> str:
    metadata = (candidate_doc or {}).get("metadata")
    source = (candidate_doc or {}).get("source")
    if (not source) and isinstance(metadata, dict):
        source = metadata.get("source") or metadata.get("doc_id") or metadata.get("file")
    return str(source or "").strip()


def _followup_doc_chunk_index(candidate_doc: dict) -> int | None:
    metadata = (candidate_doc or {}).get("metadata")
    raw_index = metadata.get("chunk_index") if isinstance(metadata, dict) else None
    if raw_index is None:
        raw_index = (candidate_doc or {}).get("chunk_index")
    if raw_index is None:
        return None
    try:
        return int(raw_index)
    except Exception:
        return None


def _followup_fetch_adjacent_chunk(
    source_name: str,
    chunk_index: int,
    target_item: str,
    allowed_sources: set[str],
) -> dict | None:
    try:
        collection = getattr(getattr(live_rag, "vs", None), "collection", None)
    except Exception:
        collection = None
    if collection is None or not source_name:
        return None

    rows = None
    where_candidates = [
        {"$and": [{"source": source_name}, {"chunk_index": int(chunk_index)}]},
        {"$and": [{"source": source_name}, {"chunk_index": str(chunk_index)}]},
    ]
    for where_clause in where_candidates:
        try:
            rows = collection.get(where=where_clause, include=["documents", "metadatas"])
        except Exception:
            rows = None
        if rows and rows.get("documents"):
            break
    if not rows or not rows.get("documents"):
        return None

    documents = rows.get("documents") or []
    metadatas = rows.get("metadatas") or []
    adjacent_text = str(documents[0] or "").strip() if documents else ""
    adjacent_metadata = dict(metadatas[0] or {}) if metadatas else {}
    adjacent_source = str(
        adjacent_metadata.get("source")
        or adjacent_metadata.get("doc_id")
        or adjacent_metadata.get("file")
        or source_name
        or ""
    ).strip()
    if allowed_sources and adjacent_source not in allowed_sources:
        return None
    if not adjacent_text or not _followup_text_mentions_item(adjacent_text, target_item):
        return None
    adjacent_focus = _extract_followup_context_window(adjacent_text, target_item) or adjacent_text
    return {"text": adjacent_focus[:600], "source": adjacent_source, "metadata": adjacent_metadata}


def _followup_expand_adjacent_chunks(
    seed_docs: list[dict],
    target_item: str,
    allowed_sources: set[str],
    previous_items: list[str],
) -> list[dict]:
    expanded: list[dict] = []
    seen_keys: set[tuple[str, int]] = set()
    for seed_doc in seed_docs or []:
        seed_source = _followup_doc_source(seed_doc)
        seed_index = _followup_doc_chunk_index(seed_doc)
        if not seed_source or seed_index is None:
            continue
        for adjacent_index in (seed_index - 1, seed_index + 1):
            adjacent_key = (seed_source, adjacent_index)
            if adjacent_key in seen_keys:
                continue
            seen_keys.add(adjacent_key)
            adjacent_doc = _followup_fetch_adjacent_chunk(
                seed_source, adjacent_index, target_item, allowed_sources
            )
            if adjacent_doc is None:
                continue
            expanded.append(adjacent_doc)
    expanded.sort(
        key=lambda candidate: _followup_explanation_candidate_score(
            target_item, _followup_doc_text(candidate), previous_items
        ),
        reverse=True,
    )
    return expanded[:2]


def _followup_lexical_explanation_rescue(
    focus_phrase: str,
    target_item: str,
    allowed_sources: set[str],
    previous_items: list[str],
    max_candidates: int = 16,
) -> list[dict]:
    """Find same-source chunks containing the focused item phrase.

    This is a bounded lexical rescue for follow-ups only. It uses the active
    Chroma collection as stored evidence, then applies the same generic
    explanatory sentence scoring used by semantic rescue.
    """
    phrase = re.sub(r"\s+", " ", str(focus_phrase or "").strip())
    if not phrase:
        return []
    try:
        collection = getattr(getattr(live_rag, "vs", None), "collection", None)
    except Exception:
        collection = None
    if collection is None:
        return []

    phrase_variants: list[str] = []
    for variant in (phrase, phrase.lower(), phrase.title()):
        if variant and variant not in phrase_variants:
            phrase_variants.append(variant)

    candidates: list[tuple[float, int, dict]] = []
    seen_keys: set[tuple[str, str]] = set()
    for phrase_variant in phrase_variants:
        try:
            rows = collection.get(
                where_document={"$contains": phrase_variant},
                include=["documents", "metadatas"],
                limit=max_candidates,
            )
        except TypeError:
            rows = collection.get(
                where_document={"$contains": phrase_variant},
                include=["documents", "metadatas"],
            )
        except Exception:
            logger.exception("[FOLLOWUP LEXICAL RESCUE] collection lookup failed")
            continue
        documents = (rows or {}).get("documents") or []
        metadatas = (rows or {}).get("metadatas") or []
        for order, document_text in enumerate(documents[:max_candidates]):
            text_value = str(document_text or "").strip()
            if not text_value:
                continue
            metadata = dict(metadatas[order] or {}) if order < len(metadatas) else {}
            source_value = str(
                metadata.get("source")
                or metadata.get("doc_id")
                or metadata.get("file")
                or ""
            ).strip()
            if allowed_sources and source_value not in allowed_sources:
                continue
            candidate_doc = {
                "text": text_value[:600],
                "source": source_value,
                "metadata": metadata,
            }
            if not _followup_text_mentions_item(text_value, focus_phrase):
                continue
            chunk_key = (source_value, str(metadata.get("chunk_index")))
            if chunk_key in seen_keys:
                continue
            seen_keys.add(chunk_key)
            score = _followup_explanation_candidate_score(
                target_item, text_value, previous_items
            )
            if score < 1.0:
                continue
            focused_text = (
                _extract_followup_context_window(text_value, focus_phrase)
                or _extract_followup_context_window(text_value, target_item)
                or text_value
            )
            candidate_doc["text"] = focused_text[:600]
            candidates.append((score, order, candidate_doc))

    candidates.sort(key=lambda row: (-row[0], row[1]))
    return [row[2] for row in candidates[:12]]


def _build_grounded_explanation(query, item, context_docs):
    logger.info("[FOLLOWUP EXPLANATION MODE] weak_evidence")

    item_text = _followup_item_head(item)
    if not item_text:
        logger.info("[FOLLOWUP EXPLANATION SOURCE] sentences_used=0")
        return RAG_NO_MATCH_RESPONSE

    if isinstance(context_docs, (str, bytes)) or context_docs is None:
        docs_iterable = [context_docs]
    else:
        try:
            docs_iterable = list(context_docs)
        except TypeError:
            docs_iterable = [context_docs]

    context_parts: list[str] = []
    for context_doc in docs_iterable:
        if context_doc is None:
            continue
        if isinstance(context_doc, dict):
            context_text = (
                context_doc.get("text")
                or context_doc.get("page_content")
                or context_doc.get("content")
                or ""
            )
        else:
            context_text = context_doc.decode("utf-8", errors="ignore") if isinstance(context_doc, bytes) else str(context_doc)
        context_text = re.sub(r"[ \t\r\f\v]+", " ", context_text or "")
        context_text = re.sub(r"\n{3,}", "\n\n", context_text).strip()
        if context_text:
            context_parts.append(context_text)

    context_text = "\n\n".join(context_parts)
    if not context_text:
        logger.info("[FOLLOWUP EXPLANATION SOURCE] sentences_used=0")
        return RAG_NO_MATCH_RESPONSE
    context_text = re.sub(r"(?m)(?:^|\s)[-*\u2022]\s+(?=[A-Za-z0-9])", "\n", context_text)
    context_text = re.sub(r"(?m)(?:^|\s)\d+[.)]\s+(?=[A-Za-z0-9])", "\n", context_text)

    strong_sentence = _extract_followup_strong_explanation(item_text, context_text, [])
    if strong_sentence:
        logger.info(
            "[FOLLOWUP EXPLANATION SOURCE] sentences_used=%d",
            max(1, len(_split_followup_explanation_sentences(strong_sentence))),
        )
        logger.info("[FOLLOWUP EXPLANATION LEVEL] weak_interpreted")
        return strong_sentence

    sentences = _split_followup_sentences(context_text)
    item_sentence_indexes = [
        index for index, sentence in enumerate(sentences)
        if _followup_text_has_item_head_anchor(sentence, item_text)
    ]
    if not item_sentence_indexes:
        logger.info("[FOLLOWUP EXPLANATION SOURCE] sentences_used=0")
        return RAG_NO_MATCH_RESPONSE

    query_tokens = set(_followup_content_tokens(query or ""))
    item_tokens = set(_followup_content_tokens(item_text))

    def _strip_marker(value: str) -> str:
        cleaned = re.sub(r"^\s*(?:[-*\u2022]|\d+[.)])\s*", "", value or "")
        return re.sub(r"\s+", " ", cleaned).strip(" \t\r\n.;")

    def _inline_phrase(value: str) -> str:
        phrase = _strip_marker(value).strip(" :")
        phrase = re.sub(
            r"\s+(?:are|were|is|was|include|includes|included|including|"
            r"consist(?:s|ed)?\s+of|comprise|comprises|contain|contains|"
            r"has|have)(?:\s+the\s+following)?\s*$",
            "",
            phrase,
            flags=re.IGNORECASE,
        ).strip(" :")
        if phrase.startswith("The "):
            phrase = "the " + phrase[4:]
        return phrase

    def _content_token_count(value: str) -> int:
        return len([
            token for token in _followup_content_tokens(value or "")
            if token not in item_tokens
        ])

    def _useful_phrase(value: str) -> bool:
        return bool(value and _content_token_count(value) > 0)

    def _relation_from_sentence(sentence: str) -> str:
        cleaned = _strip_marker(sentence)
        if not cleaned:
            return ""
        item_match = re.search(r"\b" + re.escape(item_text) + r"\b", cleaned, flags=re.IGNORECASE)
        before_item = cleaned[:item_match.start()] if item_match else cleaned
        relation_match = re.search(
            r"^(.+?)\s+(?:are|were|is|was|include|includes|included|including|"
            r"consist(?:s|ed)?\s+of|comprise|comprises|contain|contains|"
            r"has|have)(?:\s+the\s+following)?\b",
            before_item,
            flags=re.IGNORECASE,
        )
        if relation_match:
            phrase = _inline_phrase(relation_match.group(1))
            return phrase if _useful_phrase(phrase) else ""
        if cleaned.endswith(":") or re.search(
            r"\b(?:are|were|is|was|include|includes|included|including|"
            r"consist(?:s|ed)?\s+of|comprise|comprises|contain|contains|"
            r"has|have)\b",
            cleaned,
            flags=re.IGNORECASE,
        ):
            phrase = _inline_phrase(cleaned)
            return phrase if _useful_phrase(phrase) else ""
        return ""

    def _definition_fragment(sentence: str) -> str:
        cleaned = _strip_marker(sentence)
        item_match = re.search(r"\b" + re.escape(item_text) + r"\b", cleaned, flags=re.IGNORECASE)
        if not item_match:
            return ""
        after_item = cleaned[item_match.end():]
        fragment_match = re.match(r"\s*(?:[:\-\u2013\u2014]|is|are|means?|refers?\s+to)\s+(.+)$", after_item, flags=re.IGNORECASE)
        if not fragment_match:
            return ""
        fragment = _inline_phrase(fragment_match.group(1))
        return fragment if _useful_phrase(fragment) else ""

    selected_sentences: list[str] = []
    context_phrase = ""
    sibling_items: list[str] = []

    def _collect_sibling_items(item_index: int) -> list[str]:
        collected: list[str] = []
        sibling_window_start = max(0, item_index - 5)
        sibling_window_end = min(len(sentences), item_index + 6)
        for sibling_sentence in sentences[sibling_window_start:sibling_window_end]:
            sibling_label = _strip_marker(sibling_sentence)
            if not sibling_label or _followup_text_mentions_item(sibling_label, item_text):
                continue
            if len(_followup_content_tokens(sibling_label)) > 8:
                continue
            if re.search(r"[.!?]", sibling_label):
                continue
            collected.append(sibling_label)
            if len(collected) >= 3:
                break
        return collected

    relation_from_query = _infer_previous_list_relation_phrase(query or "")
    if relation_from_query and relation_from_query != "the listed items":
        first_item_index = item_sentence_indexes[0]
        context_phrase = relation_from_query
        selected_sentences = [sentences[first_item_index]]
        sibling_items = _collect_sibling_items(first_item_index)

    for item_index in item_sentence_indexes:
        if context_phrase:
            break
        item_sentence = sentences[item_index]
        selected_sentences.append(item_sentence)

        fragment = _definition_fragment(item_sentence)
        if fragment:
            context_phrase = fragment
            break

        for lookback_index in range(item_index, max(-1, item_index - 6), -1):
            candidate = sentences[lookback_index]
            relation = _relation_from_sentence(candidate)
            if relation:
                candidate_tokens = set(_followup_content_tokens(candidate))
                if not query_tokens or candidate_tokens.intersection(query_tokens) or lookback_index == item_index:
                    context_phrase = relation
                    if candidate not in selected_sentences:
                        selected_sentences.insert(0, candidate)
                    break
        if context_phrase:
            sibling_items = _collect_sibling_items(item_index)
            break

    if not context_phrase:
        for item_index in item_sentence_indexes:
            window_start = max(0, item_index - 1)
            window_end = min(len(sentences), item_index + 2)
            nearby = [_strip_marker(sentence) for sentence in sentences[window_start:window_end]]
            nearby = [sentence for sentence in nearby if sentence]
            joined = " ".join(dict.fromkeys(nearby)).strip()
            if _useful_phrase(joined):
                context_phrase = joined[:350].strip()
                selected_sentences = sentences[window_start:window_end]
                break

    if not _useful_phrase(context_phrase):
        logger.info("[FOLLOWUP EXPLANATION SOURCE] sentences_used=0")
        return RAG_NO_MATCH_RESPONSE

    if sibling_items:
        sibling_text = _join_short_item_names(sibling_items, max_items=3)
        if sibling_text:
            context_phrase = f"{context_phrase} in the same list as {sibling_text}"

    sentences_used = len([sentence for sentence in dict.fromkeys(selected_sentences) if sentence])
    logger.info("[FOLLOWUP EXPLANATION SOURCE] sentences_used=%d", sentences_used)
    logger.info("[FOLLOWUP EXPLANATION LEVEL] weak_interpreted")
    return f"This refers to {item_text}, which in the document is associated with {context_phrase}."


def _build_grounded_explanations_for_items(query, items, context_docs):
    explanations: list[str] = []
    for explanation_item in items or []:
        explanation = _build_grounded_explanation(query, explanation_item, context_docs)
        if explanation and explanation != RAG_NO_MATCH_RESPONSE:
            explanations.append(explanation)
    return "\n".join(explanations).strip()


def _build_followup_targeted_evidence_answer(
    target_item: str,
    previous_items: list[str],
    previous_query: str,
    previous_answer: str,
    excerpts_block: str,
) -> tuple[str, str]:
    """Three-level strict response for targeted list-item follow-ups."""
    anchored_items = _followup_items_anchored([target_item], excerpts_block, previous_answer)
    if not anchored_items:
        return RAG_NO_MATCH_RESPONSE, "no_evidence"

    strong_answer = _extract_followup_strong_explanation(
        target_item, excerpts_block, previous_items
    )
    if strong_answer:
        return strong_answer, "strong"

    return "", "weak"


def _followup_items_anchored(
    items: list[str], excerpts_block: str, last_a: str
) -> list[str]:
    """Return the subset of *items* whose name appears (whole-word) in the
    retrieved chunks (``excerpts_block``) or in the previous answer
    (which itself was generated from those chunks). Used as the safety
    gate for the controlled-explanation mode: an item that never appears
    in the document context is NEVER explained by the LLM.
    """
    if not items:
        return []
    haystack = ((excerpts_block or "") + "\n" + (last_a or "")).lower()
    if not haystack.strip():
        return []
    anchored: list[str] = []
    for it in items:
        head = _followup_item_head(it)
        if not head:
            continue
        if _followup_text_mentions_item(haystack, head):
            anchored.append(it)
    return anchored


async def _followup_controlled_explanation(
    items: list[str],
    last_q: str,
    last_a: str,
    excerpts_block: str,
    user_text: str,
) -> str:
    """Build controlled follow-up explanations from saved grounded text only."""
    if not items:
        return ""
    grounded_query = (last_q or user_text or "").strip()
    return _build_grounded_explanations_for_items(
        grounded_query,
        items,
        [{"text": excerpts_block}, {"text": last_a}],
    )


async def _handle_followup_query(text: str, connection_id: str):
    """Answer a follow-up clarification using ONLY the previous answer +
    a small window of the previously retrieved chunks. No new retrieval
    is performed in the primary path, keeping latency well below a normal
    query. Returns (answer_text, doc_dicts_list)."""
    if _is_weak_generic_request(text):
        logger.info("[ANSWER PERMISSION] allowed=False reason=weak_generic_followup_request")
        return (RAG_NO_MATCH_RESPONSE, [])
    state = _get_last_answer_state(connection_id)
    if not state:
        logger.info("[FOLLOWUP] no prior state for connection_id=%s -> not_found", connection_id)
        logger.info("[SMART MEMORY] rejected_reason=no_prior_grounded_answer")
        return (RAG_NO_MATCH_RESPONSE, [])

    followup_action = _classify_followup_intent(text)
    intent = "explanation"
    is_followup = True
    print("[FOLLOWUP MODE] list_lock_disabled=True")
    print("[FOLLOWUP MERGE] enabled=True")
    logger.info("[FOLLOWUP MODE] list_lock_disabled=True")
    logger.info("[FOLLOWUP MERGE] enabled=True")
    last_q = state.get("query", "") or ""
    last_a = state.get("answer", "") or ""
    last_chunks = state.get("chunks", []) or []
    base_list_q = state.get("list_query", "") or last_q
    base_list_a = state.get("list_answer", "") or last_a
    stored_items = [
        re.sub(r"\s+", " ", str(item or "").strip().strip(" .;:-"))
        for item in (state.get("items") or [])
    ]
    stored_items = [item for item in stored_items if item]
    excerpts_block = _build_followup_excerpts(last_chunks)

    # --- detect whether the current saved answer is a list ---
    prev_is_list, extracted_items = _extract_followup_items_from_answer(last_a)
    list_detected = prev_is_list
    if is_followup:
        list_detected = False
    target_item_pool = extracted_items if extracted_items else stored_items
    previous_list_items_all = list(extracted_items if extracted_items else stored_items)

    # --- single-item targeting -------------------------------------
    # If the user's follow-up query mentions exactly ONE of the items
    # we extracted from the previous answer, restrict the rest of the
    # follow-up flow to just that item. Matching is purely against the
    # previously extracted list items (no hardcoded vocabulary).
    targeted_item: str | None = None
    if target_item_pool:
        try:
            targeted_item, target_reason = _select_followup_target_item(
                target_item_pool, text
            )
            if targeted_item:
                logger.info(
                    "[FOLLOWUP ITEM DETECTION] item=%r reason=%s query=%r",
                    targeted_item, target_reason, (text or "")[:120],
                )
                logger.info(
                    "[FOLLOWUP ITEM TARGET] item=%r query=%r",
                    targeted_item, (text or "")[:120],
                )
            else:
                logger.info(
                    "[FOLLOWUP ITEM DETECTION] no_single_item reason=%s query=%r",
                    target_reason, (text or "")[:120],
                )
        except Exception:
            logger.exception("[FOLLOWUP ITEM TARGET] detection failed")
            targeted_item = None

    if targeted_item is not None and not extracted_items and stored_items:
        prev_is_list = True
        extracted_items = list(stored_items)
        previous_list_items_all = list(stored_items)
        last_q = base_list_q
        last_a = base_list_a

    # When a single item is targeted, narrow the working item list to
    # just that item. Everything downstream (prompt template, retry,
    # coverage check, deterministic placeholder) then operates on the
    # single item only.
    if targeted_item is not None:
        extracted_items = [targeted_item]
        excerpts_block = _build_followup_excerpts(last_chunks, targeted_item)
        logger.info(
            "[FOLLOWUP CONTEXT BUILD] target=%r chars=%d chunks=%d",
            targeted_item, len(excerpts_block or ""), len(last_chunks or []),
        )

    def _update_followup_state(answer_text: str) -> None:
        try:
            answer_is_list, answer_items = _extract_followup_items_from_answer(answer_text)
            preserved_items = list(stored_items or previous_list_items_all or [])
            next_state = {
                "query": (text or "").strip(),
                "answer": str(answer_text or "").strip(),
                "chunks": last_chunks,
                "ts": time.time(),
                "answer_type": "followup",
                "base_answer_type": state.get("base_answer_type") or state.get("answer_type"),
            }
            if preserved_items:
                next_state["items"] = preserved_items
                next_state["list_query"] = base_list_q
                next_state["list_answer"] = base_list_a
            elif answer_is_list and answer_items:
                next_state["items"] = answer_items
                next_state["list_query"] = (text or "").strip()
                next_state["list_answer"] = str(answer_text or "").strip()
                next_state["base_answer_type"] = "list"
            last_answer_state[connection_id] = next_state
        except Exception:
            logger.exception("[FOLLOWUP] failed to update follow-up state")

    # --- targeted micro-retrieval (item rescue) --------------------
    # When ONE item is targeted from a previous list answer and the
    # already-saved follow-up chunks do not mention that item, perform
    # a tiny same-source retrieval to give the LLM a chance to produce
    # a real grounded explanation instead of "(not described in the
    # source)". Bounded: top_k=3, scoped to the source(s) of the saved
    # chunks, no rerank, no cross-document leakage.
    if targeted_item is not None and prev_is_list:
        try:
            _item_head = _followup_item_head(targeted_item)
            # Only spend the round-trip when the saved excerpts clearly
            # don't carry an explanation for this specific item. If the
            # item name already appears alongside other content in the
            # saved excerpts, the existing prompt path is sufficient.
            _has_strong_local = bool(
                _extract_followup_strong_explanation(
                    targeted_item, excerpts_block, previous_list_items_all
                )
            )
            _needs_rescue = not _has_strong_local
            if _needs_rescue and _item_head:
                _query_focus_item = _followup_query_focus_phrase(targeted_item, text)
                # Scope to the source(s) of the previously saved chunks.
                _allowed_sources = {
                    (c.get("source") or "").strip()
                    for c in (last_chunks or [])
                    if isinstance(c, dict) and c.get("source")
                }
                if not _allowed_sources:
                    logger.info(
                        "[FOLLOWUP MICRO-RETRIEVAL] skipped item=%r reason=no_prior_source_scope",
                        targeted_item,
                    )
                    _raw_rescue = []
                    _seed_adjacent_rescue = []
                else:
                    _seed_adjacent_rescue = _followup_expand_adjacent_chunks(
                        last_chunks,
                        _query_focus_item,
                        _allowed_sources,
                        previous_list_items_all,
                    )
                    _rescue_query = f"{_query_focus_item} explanation".strip()
                    print(f"[FOLLOWUP QUERY] {_rescue_query}")
                    logger.info("[FOLLOWUP QUERY] %s", _rescue_query)
                    try:
                        _raw_rescue = live_rag.search(
                            query=_rescue_query,
                            top_k=3,
                            return_dicts=True,
                            enable_rerank=False,
                        ) or []
                    except Exception:
                        logger.exception("[FOLLOWUP MICRO-RETRIEVAL] search failed")
                        _raw_rescue = []
                    logger.info(
                        "[FOLLOWUP CONTEXT QUERY] query=%r",
                        _rescue_query[:180],
                    )
                _rescue_candidates: list[tuple[float, int, dict]] = []
                for _candidate_order, _candidate_doc in enumerate(_raw_rescue):
                    if not isinstance(_candidate_doc, dict):
                        continue
                    _txt = (
                        _candidate_doc.get("text")
                        or _candidate_doc.get("page_content")
                        or _candidate_doc.get("content")
                        or ""
                    ).strip()
                    if not _txt:
                        continue
                    _src = _candidate_doc.get("source")
                    _md = _candidate_doc.get("metadata")
                    if (not _src) and isinstance(_md, dict):
                        _src = _md.get("source") or _md.get("doc_id") or _md.get("file")
                    _src = (_src or "").strip()
                    # Same-document gate: only keep chunks from a source
                    # that was already part of the prior answer's chunks.
                    if _allowed_sources and _src not in _allowed_sources:
                        continue
                    # Require the targeted item name to actually appear in
                    # the rescue chunk; otherwise it is not a real rescue.
                    if not _followup_text_mentions_item(_txt, _query_focus_item):
                        continue
                    _candidate_score = _followup_explanation_candidate_score(
                        targeted_item, _txt, previous_list_items_all
                    )
                    if _candidate_score < 1.0:
                        continue
                    _focused_txt = (
                        _extract_followup_context_window(_txt, _query_focus_item)
                        or _extract_followup_context_window(_txt, targeted_item)
                        or _txt
                    )
                    _rescue_candidates.append((
                        _candidate_score,
                        _candidate_order,
                        {
                            "text": _focused_txt[:600],
                            "source": _src,
                            "metadata": dict(_md or {}) if isinstance(_md, dict) else {},
                        },
                    ))
                _rescue_candidates.sort(key=lambda row: (-row[0], row[1]))
                _kept_rescue = [row[2] for row in _rescue_candidates[:2]]
                _adjacent_rescue = []
                _lexical_rescue = []
                if _allowed_sources:
                    _adjacent_rescue = _followup_expand_adjacent_chunks(
                        _kept_rescue,
                        _query_focus_item,
                        _allowed_sources,
                        previous_list_items_all,
                    )
                    _lexical_rescue = _followup_lexical_explanation_rescue(
                        _query_focus_item,
                        targeted_item,
                        _allowed_sources,
                        previous_list_items_all,
                    )
                if _seed_adjacent_rescue or _adjacent_rescue or _lexical_rescue:
                    _last_chunk_indexes_by_source: dict[str, list[int]] = {}
                    for _last_doc in last_chunks or []:
                        if not isinstance(_last_doc, dict):
                            continue
                        _last_src = _followup_doc_source(_last_doc)
                        _last_idx = _followup_doc_chunk_index(_last_doc)
                        if _last_src and _last_idx is not None:
                            _last_chunk_indexes_by_source.setdefault(_last_src, []).append(_last_idx)

                    def _followup_rescue_distance(candidate: dict) -> int | None:
                        _cand_src = _followup_doc_source(candidate)
                        _cand_idx = _followup_doc_chunk_index(candidate)
                        if not (_cand_src and _cand_idx is not None):
                            return None
                        _anchor_indexes = _last_chunk_indexes_by_source.get(_cand_src) or []
                        if not _anchor_indexes:
                            return None
                        return min(abs(_cand_idx - _anchor_idx) for _anchor_idx in _anchor_indexes)

                    def _followup_rescue_sort_score(candidate: dict) -> float:
                        _base_score = _followup_explanation_candidate_score(
                            targeted_item,
                            _followup_doc_text(candidate),
                            previous_list_items_all,
                        )
                        _min_distance = _followup_rescue_distance(candidate)
                        if _min_distance is not None:
                            if _min_distance <= 1:
                                _base_score += 28.0
                            elif _min_distance <= 5:
                                _base_score += 22.0
                            elif _min_distance <= 12:
                                _base_score += 10.0
                            elif _min_distance <= 25:
                                _base_score -= 8.0
                            elif _min_distance < 50:
                                _base_score -= 14.0
                            elif _min_distance >= 50:
                                _base_score -= 18.0
                        return _base_score

                    _merged_rescue: list[dict] = []
                    _seen_rescue: set[tuple[str, str]] = set()
                    for _rescue_doc in (
                        _seed_adjacent_rescue
                        + _kept_rescue
                        + _adjacent_rescue
                        + _lexical_rescue
                    ):
                        _key = (
                            _followup_doc_source(_rescue_doc),
                            str(_followup_doc_chunk_index(_rescue_doc)),
                        )
                        if _key in _seen_rescue:
                            continue
                        _seen_rescue.add(_key)
                        _merged_rescue.append(_rescue_doc)
                    _merged_rescue.sort(key=_followup_rescue_sort_score, reverse=True)
                    _nearby_rescue = [
                        _rescue_doc for _rescue_doc in _merged_rescue
                        if (_followup_rescue_distance(_rescue_doc) or 9999) <= 12
                    ]
                    _strong_rescue = [
                        _rescue_doc for _rescue_doc in _merged_rescue
                        if _followup_explanation_candidate_score(
                            targeted_item,
                            _followup_doc_text(_rescue_doc),
                            previous_list_items_all,
                        ) >= 12.0
                    ]
                    _candidate_rescue_pool = list(_nearby_rescue or _merged_rescue)
                    _candidate_pool_has_strong = any(
                        _followup_explanation_candidate_score(
                            targeted_item,
                            _followup_doc_text(_rescue_doc),
                            previous_list_items_all,
                        ) >= 12.0
                        for _rescue_doc in _candidate_rescue_pool
                    )
                    if not _candidate_pool_has_strong:
                        _candidate_keys = {
                            (
                                _followup_doc_source(_rescue_doc),
                                str(_followup_doc_chunk_index(_rescue_doc)),
                            )
                            for _rescue_doc in _candidate_rescue_pool
                        }
                        for _rescue_doc in _strong_rescue:
                            _key = (
                                _followup_doc_source(_rescue_doc),
                                str(_followup_doc_chunk_index(_rescue_doc)),
                            )
                            if _key not in _candidate_keys:
                                _candidate_rescue_pool.append(_rescue_doc)
                                _candidate_keys.add(_key)
                    _candidate_rescue_pool.sort(key=_followup_rescue_sort_score, reverse=True)
                    _kept_rescue = _candidate_rescue_pool[:4]
                if _kept_rescue:
                    logger.info(
                        "[FOLLOWUP MICRO-RETRIEVAL] item=%r rescued=%d sources=%r",
                        targeted_item, len(_kept_rescue),
                        sorted({str(c.get("source")) for c in _kept_rescue if c.get("source")}),
                    )
                    # Append to excerpts_block (do not replace the prior
                    # context; just enrich it). Keeps the LLM grounded on
                    # everything we know.
                    _rescue_text = "\n\n---\n\n".join(c["text"] for c in _kept_rescue)
                    if excerpts_block:
                        excerpts_block = excerpts_block + "\n\n---\n\n" + _rescue_text
                    else:
                        excerpts_block = _rescue_text
                else:
                    logger.info(
                        "[FOLLOWUP MICRO-RETRIEVAL] item=%r no usable rescue chunks",
                        targeted_item,
                    )
        except Exception:
            logger.exception("[FOLLOWUP MICRO-RETRIEVAL] unexpected failure")

    if targeted_item is not None and prev_is_list and len(extracted_items) == 1:
        ai_text, evidence_level = _build_followup_targeted_evidence_answer(
            targeted_item,
            previous_list_items_all,
            last_q,
            last_a,
            excerpts_block,
        )
        logger.info(
            "[FOLLOWUP CONTROLLED LEVEL] level=%s item=%r",
            evidence_level, targeted_item,
        )
        if ai_text == RAG_NO_MATCH_RESPONSE:
            logger.info("[FOLLOWUP GROUNDING VERIFIED] level=no_evidence")
            try:
                last_answer_state.pop(connection_id, None)
            except Exception:
                pass
            return (RAG_NO_MATCH_RESPONSE, [])
        if evidence_level == "strong":
            logger.info("[FOLLOWUP STRONG EVIDENCE] item=%r", targeted_item)
        elif evidence_level == "weak":
            logger.info(
                "[FOLLOWUP STRICT MODE TRIGGERED] item=%r reason=no_explanatory_sentence list_lock_disabled=True",
                targeted_item,
            )
            logger.info("[FOLLOWUP GROUNDING VERIFIED] level=no_explanatory_evidence")
            try:
                last_answer_state.pop(connection_id, None)
            except Exception:
                pass
            return (RAG_NO_MATCH_RESPONSE, [])
        logger.info("[FOLLOWUP GROUNDING VERIFIED] level=%s", evidence_level)
        _update_followup_state(ai_text)
        logger.info(
            "[FOLLOWUP] answered locally | intent=%s prev_list=%s len=%d",
            intent, prev_is_list, len(ai_text),
        )
        return (ai_text, [])

    # --- build instruction by intent + prior-answer shape ---
    if prev_is_list and extracted_items:
        items_block = "\n".join(f"- {item}" for item in extracted_items)
        if followup_action == "simplify":
            instruction = (
                "The PREVIOUS ANSWER contains the following list items:\n\n"
                f"{items_block}\n\n"
                "OUTPUT REQUIREMENT: For EACH item above, output EXACTLY one line in this format:\n"
                "ItemName: one short plain-language clarification (max ~15 words)\n\n"
                "Rules:\n"
                "- Each line MUST start with the item name followed by a colon.\n"
                "- Use simpler language than the original.\n"
                "- Draw information ONLY from SOURCE EXCERPTS or PREVIOUS ANSWER.\n"
                "- Do NOT invent new items, names, numbers, or examples.\n"
                "- Do NOT skip any item.\n"
                "- If you do not explain each item individually, the answer is INCORRECT."
            )
        elif followup_action == "rephrase":
            instruction = (
                "The PREVIOUS ANSWER contains the following list items:\n\n"
                f"{items_block}\n\n"
                "OUTPUT REQUIREMENT: For EACH item above, output EXACTLY one line in this format:\n"
                "ItemName: one short rephrased description using different wording\n\n"
                "Rules:\n"
                "- Each line MUST start with the item name followed by a colon.\n"
                "- Use different wording than the original.\n"
                "- Draw information ONLY from SOURCE EXCERPTS or PREVIOUS ANSWER.\n"
                "- Do NOT add new items or facts.\n"
                "- Do NOT skip any item.\n"
                "- If you do not explain each item individually, the answer is INCORRECT."
            )
        else:  # explain
            instruction = (
                "The PREVIOUS ANSWER contains the following list items:\n\n"
                f"{items_block}\n\n"
                "OUTPUT REQUIREMENT: For EACH item above, output EXACTLY one line in this format:\n"
                "ItemName: brief explanation of what this item means (1-2 sentences max)\n\n"
                "Rules:\n"
                "- Each line MUST start with the item name followed by a colon.\n"
                "- Explain what the item MEANS, do NOT just repeat it.\n"
                "- Draw information ONLY from SOURCE EXCERPTS or PREVIOUS ANSWER.\n"
                "- Do NOT add any new item, name, number, or example not already present.\n"
                "- Do NOT skip any item.\n"
                "- Do NOT write a paragraph summary — explain EACH item separately.\n"
                "- If you do not explain each item individually, the answer is INCORRECT."
            )
    elif prev_is_list:
        # Fallback: we know it's a list but couldn't extract items cleanly.
        # Still force per-item format.
        if followup_action == "simplify":
            instruction = (
                "The PREVIOUS ANSWER is a list. For EACH item in the list, output one line:\n"
                "ItemName: short plain-language clarification (max ~15 words)\n\n"
                "Each line MUST start with the item name followed by a colon.\n"
                "Draw ONLY from SOURCE EXCERPTS or PREVIOUS ANSWER.\n"
                "Do NOT invent new items. Do NOT skip any item.\n"
                "If you do not explain each item individually, the answer is INCORRECT."
            )
        elif followup_action == "rephrase":
            instruction = (
                "The PREVIOUS ANSWER is a list. For EACH item in the list, output one line:\n"
                "ItemName: rephrased description in different wording\n\n"
                "Each line MUST start with the item name followed by a colon.\n"
                "Draw ONLY from SOURCE EXCERPTS or PREVIOUS ANSWER.\n"
                "Do NOT add new items. Do NOT skip any item.\n"
                "If you do not explain each item individually, the answer is INCORRECT."
            )
        else:  # explain
            instruction = (
                "The PREVIOUS ANSWER is a list. For EACH item in the list, output one line:\n"
                "ItemName: brief explanation of what this item means (1-2 sentences)\n\n"
                "Each line MUST start with the item name followed by a colon.\n"
                "Explain what each item MEANS — do NOT just repeat it.\n"
                "Draw ONLY from SOURCE EXCERPTS or PREVIOUS ANSWER.\n"
                "Do NOT add new items. Do NOT skip any item.\n"
                "If you do not explain each item individually, the answer is INCORRECT."
            )
    else:
        if followup_action == "simplify":
            instruction = (
                "Restate the PREVIOUS ANSWER in 2-4 short sentences using simpler, plainer "
                "language. Use ONLY information already present in the PREVIOUS ANSWER and "
                "SOURCE EXCERPTS. Do NOT add any fact, name, number, definition, or example "
                "that is not already there."
            )
        elif followup_action == "rephrase":
            instruction = (
                "Rephrase the PREVIOUS ANSWER in 2-4 sentences using clearer, different "
                "wording. Use ONLY information already present in the PREVIOUS ANSWER and "
                "SOURCE EXCERPTS. Do NOT introduce any new fact."
            )
        else:  # explain
            instruction = (
                "Briefly expand on the PREVIOUS ANSWER in 2-5 short sentences using ONLY the "
                "SOURCE EXCERPTS and the previous answer itself. Stay close to their wording. "
                "Do NOT introduce any new fact, name, number, definition, example, or concept "
                "that is not already present in those texts."
            )

    # IMPORTANT: do NOT instruct the LLM to write "Not found in the document."
    # itself — that often gets appended to otherwise-grounded explanations.
    # The grounding gate below decides not_found instead.
    system_prompt = (
        "You are a strict grounded clarification assistant. " + instruction +
        " Output ONLY the clarification text. Do NOT add disclaimers, meta-commentary, "
        "or phrases like 'Not found' / 'Based on the document' / 'According to the previous "
        "answer'. Do NOT invent content beyond the provided PREVIOUS ANSWER and SOURCE EXCERPTS."
    )

    context_text = (
        f"PREVIOUS USER QUESTION: {last_q}\n\n"
        f"PREVIOUS ANSWER:\n{last_a}\n\n"
        f"SOURCE EXCERPTS:\n{excerpts_block if excerpts_block else '(none)'}"
    )

    try:
        ai_text = await call_llm_with_context(text.strip(), context_text, system_prompt)
    except Exception:
        logger.exception("[FOLLOWUP] LLM call failed")
        ai_text = ""

    ai_text = (ai_text or "").strip()

    # ---- LIST-SHAPED RETRY -------------------------------------------
    # When the previous answer is a list AND we extracted item names,
    # require that the LLM output contains per-item "ItemName: ..."
    # lines for at least half the items. If not, retry once with an
    # even stricter prompt that pre-fills the item names. Lightweight:
    # no new retrieval — same saved chunks.
    def _per_item_coverage(out: str, items: list[str]) -> int:
        if not out or not items:
            return 0
        out_l = out.lower()
        hits = 0
        for it in items:
            head = (it.split(":", 1)[0]).strip().lower()
            if not head:
                continue
            # Look for "<item>:" on a line (allow leading bullets/whitespace)
            if _re_followup.search(
                r"(?m)^\s*(?:[-*\u2022]|\d+[.)])?\s*" + _re_followup.escape(head) + r"\s*:\s*\S",
                out_l,
            ):
                hits += 1
        return hits

    if prev_is_list and extracted_items:
        needed = min(len(extracted_items), max(2, (len(extracted_items) + 1) // 2))
        coverage = _per_item_coverage(ai_text, extracted_items)
        if coverage < needed:
            logger.info(
                "[FOLLOWUP LIST RETRY] coverage=%d/%d items=%d -> stricter retry",
                coverage, len(extracted_items), len(extracted_items),
            )
            stricter_items_block = "\n".join(
                f"{i+1}. {item}" for i, item in enumerate(extracted_items)
            )
            stricter_instruction = (
                "Your previous response was REJECTED because it did not follow the "
                "required format.\n\n"
                "You MUST output one line per item below, in the SAME ORDER, using "
                "EXACTLY this format (no preamble, no summary, no extra text):\n\n"
                f"{stricter_items_block}\n\n"
                "Replace each numbered line with:\n"
                "ItemName: <one short grounded explanation, 1-2 sentences>\n\n"
                "Hard rules:\n"
                "- Output EXACTLY one line per item, in the order listed above.\n"
                "- Each line MUST start with the item name followed by ': '.\n"
                "- Use ONLY information from PREVIOUS ANSWER and SOURCE EXCERPTS.\n"
                "- Do NOT add a header, intro, conclusion, or summary paragraph.\n"
                "- Do NOT skip, merge, rename, or invent items.\n"
                "- If a source does not explain an item, write: "
                "'<ItemName>: (not described in the source)' for that one line."
            )
            stricter_system = (
                "You are a strict grounded clarification assistant. "
                + stricter_instruction
                + " Output ONLY the per-item lines."
            )
            try:
                retry_text = await call_llm_with_context(
                    text.strip(), context_text, stricter_system
                )
            except Exception:
                logger.exception("[FOLLOWUP LIST RETRY] LLM call failed")
                retry_text = ""
            retry_text = (retry_text or "").strip()
            if retry_text:
                retry_coverage = _per_item_coverage(retry_text, extracted_items)
                # Quick local grounding check so we do not swap a grounded
                # paragraph for a per-item retry that hallucinates content
                # not present in the source. Same token math as the gate
                # below; kept inline to keep the swap decision local.
                def _local_ground_ratio(_t: str) -> float:
                    _toks = _re_followup.findall(r"[a-zA-Z0-9]{4,}", (_t or "").lower())
                    _content = [
                        w for w in _toks if w not in {
                            "this","that","these","those","with","from","into","than","then",
                            "have","been","being","were","they","them","their","there","which",
                            "what","when","where","while","about","also","such","some","more",
                            "most","many","much","your","would","could","should","will","shall",
                            "does","doing","done","answer","previous","above","below","thus",
                            "because","however","therefore","based","means","meaning","refers",
                            "include","includes","including","example","examples","simply",
                            "essentially","namely","specifically","respectively","various",
                            "different","important","things","thing","people","person","each",
                            "every","another","other",
                        }
                    ]
                    if not _content:
                        return 1.0
                    _corpus = (last_a + " " + excerpts_block).lower()
                    _hit = sum(1 for w in _content if w in _corpus)
                    return _hit / max(1, len(_content))
                retry_ground = _local_ground_ratio(retry_text)
                orig_ground = _local_ground_ratio(ai_text)
                logger.info(
                    "[FOLLOWUP LIST RETRY] retry_coverage=%d/%d retry_ground=%.2f orig_ground=%.2f",
                    retry_coverage, len(extracted_items), retry_ground, orig_ground,
                )
                # Only swap to the retry when it (a) materially improves
                # coverage AND (b) does not regress grounding below the
                # acceptance threshold and not worse than the original.
                if (
                    (retry_coverage >= needed or retry_coverage > coverage)
                    and retry_ground >= _FOLLOWUP_GROUND_RATIO_MIN
                    and retry_ground >= orig_ground - 0.05
                ):
                    ai_text = retry_text

        # Final per-item enforcement: if neither attempt produced per-item
        # coverage at or above the threshold, try the controlled
        # explanation mode (LLM, anchored to the document's domain) for
        # the items that actually appear in the retrieved chunks before
        # falling back to a deterministic placeholder.
        final_coverage = _per_item_coverage(ai_text, extracted_items)
        if final_coverage < needed:
            logger.info(
                "[FOLLOWUP LIST DETERMINISTIC] final_coverage=%d/%d -> attempt controlled explanation",
                final_coverage, len(extracted_items),
            )
            _anchored = _followup_items_anchored(
                extracted_items, excerpts_block, last_a
            )
            _ce = ""
            if _anchored:
                logger.info("[FOLLOWUP EXPLANATION MODE TRIGGERED]")
                for _it in _anchored:
                    logger.info("[FOLLOWUP EXPLANATION ITEM = %s]", _it)
                _ce = await _followup_controlled_explanation(
                    _anchored, last_q, last_a, excerpts_block, text
                )
            if _ce:
                _expl_score_d = _compute_explanation_grounding_score(
                    _ce, excerpts_block, last_a
                )
                logger.info(
                    "[FOLLOWUP GROUNDING SCORE] score=%.2f threshold=%.2f",
                    _expl_score_d, _FOLLOWUP_EXPL_GROUND_THRESHOLD,
                )
                if _expl_score_d < _FOLLOWUP_EXPL_GROUND_THRESHOLD:
                    logger.info(
                        "[FOLLOWUP STRICT MODE TRIGGERED] score=%.2f -> limited explanation",
                        _expl_score_d,
                    )
                    logger.info("[FOLLOWUP LIMITED EXPLANATION]")
                    ai_text = _build_grounded_explanations_for_items(
                        last_q,
                        extracted_items,
                        [{"text": excerpts_block}, {"text": last_a}],
                    )
                    if not ai_text:
                        return (RAG_NO_MATCH_RESPONSE, [])
                else:
                    logger.info(
                        "[FOLLOWUP EXPLANATION SOURCE = inferred_from_context]"
                    )
                    ai_text = _ce.rstrip() + "\n\n" + _FOLLOWUP_INFERRED_SUFFIX
            elif targeted_item is not None and len(extracted_items) == 1:
                ai_text = _build_grounded_explanation(
                    last_q,
                    extracted_items[0],
                    [{"text": excerpts_block}, {"text": last_a}],
                )
                if ai_text == RAG_NO_MATCH_RESPONSE:
                    return (RAG_NO_MATCH_RESPONSE, [])
            else:
                ai_text = _build_grounded_explanations_for_items(
                    last_q,
                    extracted_items,
                    [{"text": excerpts_block}, {"text": last_a}],
                )
                if not ai_text:
                    return (RAG_NO_MATCH_RESPONSE, [])

    # Strip a trailing not-found sentinel that the model sometimes appends
    # despite the instruction. Done BEFORE the empty/not-found check so a
    # genuinely good explanation isn't thrown away.
    _nf = RAG_NO_MATCH_RESPONSE.strip()
    _nf_re = _re_followup.compile(
        r"\s*" + _re_followup.escape(_nf).replace(r"\.", r"\.?") + r"\s*$",
        _re_followup.IGNORECASE,
    )
    cleaned_ai = _nf_re.sub("", ai_text).strip()
    # Also handle a stray leading not-found.
    cleaned_ai = _nf_re.sub("", cleaned_ai).strip()
    if cleaned_ai and cleaned_ai.lower() != _nf.lower():
        ai_text = cleaned_ai

    if (not ai_text) or ai_text.lower() == _nf.lower():
        logger.info("[FOLLOWUP] empty/not-found from LLM -> strict not_found")
        return (RAG_NO_MATCH_RESPONSE, [])

    # Lightweight grounding check: a modest portion of the answer's content
    # tokens must appear in the combined corpus of (previous answer + source
    # excerpts). Threshold is loose so paraphrased clarifications pass; open-
    # domain hallucinations still fall below it because they introduce many
    # foreign content words.
    grounded_corpus = (last_a + " " + excerpts_block).lower()
    ans_tokens = _re_followup.findall(r"[a-zA-Z0-9]{4,}", ai_text.lower())
    _FU_STOPWORDS = {
        "this", "that", "these", "those", "with", "from", "into", "than", "then",
        "have", "been", "being", "were", "they", "them", "their", "there", "which",
        "what", "when", "where", "while", "about", "also", "such", "some", "more",
        "most", "many", "much", "your", "would", "could", "should", "will", "shall",
        "does", "doing", "done", "answer", "previous", "above", "below", "thus",
        "because", "however", "therefore", "based", "means", "meaning", "refers",
        "include", "includes", "including", "example", "examples", "simply", "essentially",
        "namely", "specifically", "respectively", "various", "different", "important",
        "things", "thing", "people", "person", "each", "every", "another", "other",
    }
    content_tokens = [w for w in ans_tokens if w not in _FU_STOPWORDS]
    if content_tokens:
        overlap = sum(1 for w in content_tokens if w in grounded_corpus)
        ratio = overlap / max(1, len(content_tokens))
        if ratio < _FOLLOWUP_GROUND_RATIO_MIN:
            # If the previous answer was a list and we have explicit items,
            # honour the per-item shape. First try a controlled explanation
            # (LLM, anchored to the document's domain) for the items that
            # actually appear in the retrieved chunks; only fall back to a
            # deterministic placeholder when no item is anchored or the LLM
            # produces nothing usable.
            if prev_is_list and extracted_items:
                logger.info(
                    "[FOLLOWUP LIST FALLBACK] grounding_ratio=%.2f -> attempt controlled explanation for %d items",
                    ratio, len(extracted_items),
                )
                _anchored = _followup_items_anchored(
                    extracted_items, excerpts_block, last_a
                )
                _ce = ""
                if _anchored:
                    logger.info("[FOLLOWUP EXPLANATION MODE TRIGGERED]")
                    for _it in _anchored:
                        logger.info("[FOLLOWUP EXPLANATION ITEM = %s]", _it)
                    _ce = await _followup_controlled_explanation(
                        _anchored, last_q, last_a, excerpts_block, text
                    )
                if _ce:
                    _expl_score_w = _compute_explanation_grounding_score(
                        _ce, excerpts_block, last_a
                    )
                    logger.info(
                        "[FOLLOWUP GROUNDING SCORE] score=%.2f threshold=%.2f",
                        _expl_score_w, _FOLLOWUP_EXPL_GROUND_THRESHOLD,
                    )
                    if _expl_score_w < _FOLLOWUP_EXPL_GROUND_THRESHOLD:
                        logger.info(
                            "[FOLLOWUP STRICT MODE TRIGGERED] score=%.2f -> limited explanation",
                            _expl_score_w,
                        )
                        logger.info("[FOLLOWUP LIMITED EXPLANATION]")
                        logger.info("[FOLLOWUP GROUNDING VERIFIED]")
                        ai_text = _build_grounded_explanations_for_items(
                            last_q,
                            extracted_items,
                            [{"text": excerpts_block}, {"text": last_a}],
                        )
                        if not ai_text:
                            return (RAG_NO_MATCH_RESPONSE, [])
                    else:
                        logger.info(
                            "[FOLLOWUP EXPLANATION SOURCE = inferred_from_context]"
                        )
                        ai_text = _ce.rstrip() + "\n\n" + _FOLLOWUP_INFERRED_SUFFIX
                elif targeted_item is not None and len(extracted_items) == 1:
                    ai_text = _build_grounded_explanation(
                        last_q,
                        extracted_items[0],
                        [{"text": excerpts_block}, {"text": last_a}],
                    )
                    if ai_text == RAG_NO_MATCH_RESPONSE:
                        return (RAG_NO_MATCH_RESPONSE, [])
                else:
                    ai_text = _build_grounded_explanations_for_items(
                        last_q,
                        extracted_items,
                        [{"text": excerpts_block}, {"text": last_a}],
                    )
                    if not ai_text:
                        return (RAG_NO_MATCH_RESPONSE, [])
            else:
                logger.info(
                    "[FOLLOWUP GROUNDING WEAK] overlap_ratio=%.2f threshold=%.2f -> not_found",
                    ratio, _FOLLOWUP_GROUND_RATIO_MIN,
                )
                return (RAG_NO_MATCH_RESPONSE, [])
        else:
            logger.info("[FOLLOWUP GROUNDING OK] overlap_ratio=%.2f", ratio)

    # --- weak-evidence anti-inference guard (targeted items only) ----------
    # Even after grounding passes, the LLM may over-explain an item from
    # evidence that merely *mentions* it (incidental co-occurrence) rather
    # than truly *explaining* it.  When the evidence lacks a real
    # explanatory sentence about the targeted item we no longer collapse
    # straight to a placeholder; instead we enter a controlled
    # explanation mode that gives the user a useful, contextual answer
    # while clearly disclosing it was inferred from context.
    if (
        targeted_item is not None
        and prev_is_list
        and len(extracted_items) == 1
        and not _evidence_has_explicit_explanation(targeted_item, excerpts_block)
    ):
        _itm = extracted_items[0]
        # When the retrieved evidence only lists the item without an
        # explanatory sentence, do not fall back to a list-relationship
        # explanation. Follow-up explanation mode must be grounded in
        # descriptive document text or fail strictly.
        logger.info(
            "[FOLLOWUP STRICT MODE TRIGGERED] item=%r no_explicit_evidence list_lock_disabled=True",
            _itm,
        )
        logger.info("[FOLLOWUP GROUNDING VERIFIED] level=no_explanatory_evidence")
        try:
            last_answer_state.pop(connection_id, None)
        except Exception:
            pass
        return (RAG_NO_MATCH_RESPONSE, [])

    # Update state so successive "explain more" works on the latest explanation,
    # but PRESERVE the original chunks (never broaden the grounding window).
    _update_followup_state(ai_text)

    logger.info(
        "[FOLLOWUP] answered locally | intent=%s prev_list=%s len=%d",
        intent, prev_is_list, len(ai_text),
    )
    return (ai_text, [])


async def flush_ollama_cache():
    """Unload the Ollama model from GPU memory to flush its internal KV cache.

    Ollama caches the model + KV state in VRAM.  After a KB change the old
    cached context can cause the LLM to repeat stale answers even though the
    RAG context is fresh.  Sending keep_alive=0 forces Ollama to unload the
    model; it will be reloaded automatically on the next query with a clean
    KV cache.
    """
    try:
        import aiohttp as _aiohttp
        ollama_url = _build_ollama_url("/api/chat")
        payload = {
            "model": OLLAMA_MODEL,
            "messages": [],
            "keep_alive": "0"
        }
        logger.info("[OLLAMA CALL] endpoint=%s model=%s query_type=cache_flush", ollama_url, OLLAMA_MODEL)
        async with _aiohttp.ClientSession() as _sess:
            async with _sess.post(ollama_url, json=payload, timeout=_aiohttp.ClientTimeout(total=10)) as resp:
                logger.info("[OLLAMA CALL RESULT] status=%s endpoint=%s", resp.status, ollama_url)
                logger.info(f"Ollama cache flush: status={resp.status} (model will reload on next query)")
    except Exception as e:
        logger.warning(f"Ollama cache flush failed (non-fatal): {e}")


async def _check_ollama_connectivity() -> None:
    tags_url = _build_ollama_url("/api/tags")
    local_session_created = False
    _sess = llm_session
    if _sess is None or getattr(_sess, "closed", False):
        local_session_created = True
        _sess = aiohttp.ClientSession(timeout=aiohttp.ClientTimeout(total=8, connect=3, sock_read=5))

    try:
        async with _sess.get(tags_url) as resp:
            body_preview = (await resp.text())[:160]
            if resp.status == 200:
                logger.info("[OLLAMA CONNECTIVITY] success url=%s status=%s", tags_url, resp.status)
            else:
                logger.warning("[OLLAMA CONNECTIVITY] failed url=%s status=%s body=%s", tags_url, resp.status, body_preview)
    except Exception as exc:
        logger.warning("[OLLAMA CONNECTIVITY] failed url=%s reason=%s", tags_url, exc)
    finally:
        if local_session_created and _sess and not _sess.closed:
            await _sess.close()


# ========== REAL-TIME KB EVENT BROADCAST ==========
# All active user WebSocket connections (keyed by connection_id → WebSocket)
_active_ws_connections: dict = {}
# Admin KB-events subscribers (connected to /ws/kb-events)
_kb_event_subscribers: set = set()
# Global KB version counter — incremented on every mutation
_kb_global_version: int = 0


async def broadcast_kb_event(action: str, filename: str = "*",
                              chunks_added: int = 0, chunks_deleted: int = 0,
                              triggered_by: str = "admin"):
    """Broadcast a KB mutation event to all connected sockets.

    Sends:
      - A ``kb_updated`` message to every active user chat session so the
        frontend can show a "new information available" notice.
      - The full event payload to every admin KB-events subscriber.
    """
    global _kb_global_version
    _kb_global_version += 1
    event = {
        "type": "kb_updated",
        "action": action,
        "filename": filename,
        "chunks_added": chunks_added,
        "chunks_deleted": chunks_deleted,
        "kb_version": _kb_global_version,
        "triggered_by": triggered_by,
        "timestamp": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()),
    }

    # Persist the event to the analytics DB
    log_kb_event(
        action=action,
        filename=filename,
        chunks_added=chunks_added,
        chunks_deleted=chunks_deleted,
        kb_version=_kb_global_version,
        triggered_by=triggered_by,
    )

    # Notify every active user session (chat WebSocket)
    dead_conns = []
    for conn_id, ws in list(_active_ws_connections.items()):
        try:
            await ws.send_json({
                "type": "kb_updated",
                "message": "Knowledge base was updated — your next reply will use the latest information.",
                "kb_version": _kb_global_version,
                "timestamp": event["timestamp"],
            })
        except Exception:
            dead_conns.append(conn_id)
    for conn_id in dead_conns:
        _active_ws_connections.pop(conn_id, None)

    # Broadcast full event to admin KB-events subscribers
    dead_subs = []
    for ws in list(_kb_event_subscribers):
        try:
            await ws.send_json(event)
        except Exception:
            dead_subs.append(ws)
    for ws in dead_subs:
        _kb_event_subscribers.discard(ws)

    logger.info(f"KB broadcast: action={action} file={filename} v{_kb_global_version} "
                f"→ {len(_active_ws_connections)} user sessions, "
                f"{len(_kb_event_subscribers)} admin subscribers")


async def invalidate_all_caches(action: str = "cache_clear", filename: str = "*",
                                 chunks_added: int = 0, chunks_deleted: int = 0,
                                 triggered_by: str = "admin"):
    """Nuclear option: clear conversation history + flush Ollama KV cache + broadcast.

    Call this after any KB mutation (upload, edit, delete, reindex) to
    guarantee the next user query gets a fully fresh answer.
    """
    clear_all_conversation_history()
    await flush_ollama_cache()
    await broadcast_kb_event(action=action, filename=filename,
                              chunks_added=chunks_added, chunks_deleted=chunks_deleted,
                              triggered_by=triggered_by)

_active_doc_registry: dict = {
    "mode": RAG_DOC_MODE,
    "active_sources": set(),
}

# Explicit ID of the single currently active document (normalized filename).
# Set to "" at startup; updated whenever a document is successfully indexed.
# Used as the single source of truth for the anti-leak source guard.
_current_active_doc_id: str = ""

_kb_pipeline_state: dict = {
    "state": "ready",  # uploading | processing | ready | failed
    "stage": "ready",  # uploading | extracting | chunking | embedding | writing | activating | ready | failed
    "message": "ready",
    "filename": None,
    "updated_at": time.time(),
    "started_at": None,
    "ready_at": None,
    "stage_timings": {},  # name -> seconds since started_at
    "last_total_seconds": None,
    "last_bottleneck": None,
    "indexed_chunks": 0,
    "total_chunks": 0,
    "percent": 100,
}


def _set_kb_pipeline_state(state: str, message: str = "", filename: Optional[str] = None) -> None:
    normalized = str(state or "").strip().lower()
    if normalized not in {"uploading", "processing", "ready", "failed"}:
        normalized = "processing"
    _kb_pipeline_state["state"] = normalized
    _kb_pipeline_state["stage"] = "uploading" if normalized == "uploading" else ("ready" if normalized == "ready" else ("failed" if normalized == "failed" else _kb_pipeline_state.get("stage", "processing")))
    _kb_pipeline_state["message"] = str(message or normalized)
    _kb_pipeline_state["filename"] = filename
    _kb_pipeline_state["updated_at"] = time.time()
    if normalized == "uploading":
        # Reset per-upload timing on a fresh upload start.
        _kb_pipeline_state["started_at"] = time.time()
        _kb_pipeline_state["ready_at"] = None
        _kb_pipeline_state["stage_timings"] = {}
        _kb_pipeline_state["last_total_seconds"] = None
        _kb_pipeline_state["last_bottleneck"] = None
        _kb_pipeline_state["indexed_chunks"] = 0
        _kb_pipeline_state["total_chunks"] = 0
        _kb_pipeline_state["percent"] = 0
    elif normalized == "ready":
        now = time.time()
        _kb_pipeline_state["ready_at"] = now
        _kb_pipeline_state["percent"] = 100
        started = _kb_pipeline_state.get("started_at") or now
        _kb_pipeline_state["last_total_seconds"] = round(now - started, 3)
        timings = _kb_pipeline_state.get("stage_timings") or {}
        if timings:
            # Largest per-stage delta is the bottleneck.
            ordered = sorted(timings.items(), key=lambda kv: kv[1])
            deltas = []
            prev = 0.0
            for name, t in ordered:
                deltas.append((name, round(t - prev, 3)))
                prev = t
            if deltas:
                _kb_pipeline_state["last_bottleneck"] = max(deltas, key=lambda kv: kv[1])
    logger.info(
        "KB pipeline state | state=%s filename=%s message=%s",
        normalized,
        filename,
        _kb_pipeline_state["message"],
    )


def _record_kb_stage(stage: str) -> None:
    """Record a named pipeline stage timestamp (seconds since 'uploading' start)."""
    started = _kb_pipeline_state.get("started_at")
    if not started:
        return
    timings = _kb_pipeline_state.setdefault("stage_timings", {})
    timings[str(stage)] = round(time.time() - float(started), 3)


def _set_kb_pipeline_stage(
    stage: str,
    message: str = "",
    filename: Optional[str] = None,
    indexed: Optional[int] = None,
    total: Optional[int] = None,
    percent: Optional[int] = None,
) -> None:
    normalized_stage = str(stage or "").strip().lower()
    if normalized_stage not in {"uploading", "extracting", "chunking", "embedding", "writing", "activating", "ready", "failed"}:
        normalized_stage = "processing"
    if normalized_stage == "ready":
        _set_kb_pipeline_state("ready", message=message or "ready", filename=filename)
    elif normalized_stage == "failed":
        _set_kb_pipeline_state("failed", message=message or "failed", filename=filename)
    elif normalized_stage == "uploading":
        _set_kb_pipeline_state("uploading", message=message or "uploading", filename=filename)
    else:
        _kb_pipeline_state["state"] = "processing"
        _kb_pipeline_state["stage"] = normalized_stage
        _kb_pipeline_state["message"] = str(message or normalized_stage)
        if filename is not None:
            _kb_pipeline_state["filename"] = filename
        _kb_pipeline_state["updated_at"] = time.time()
    if indexed is not None:
        _kb_pipeline_state["indexed_chunks"] = int(indexed)
    if total is not None:
        _kb_pipeline_state["total_chunks"] = int(total)
    if percent is not None:
        _kb_pipeline_state["percent"] = max(0, min(100, int(percent)))
    _record_kb_stage(normalized_stage)


def _on_ingest_progress(event: dict, filename: str) -> None:
    stage = str((event or {}).get("stage") or "").strip().lower()
    if stage == "complete":
        return
    status_stage = "writing" if stage == "writing" else (stage if stage in {"chunking", "embedding"} else "processing")
    indexed = (event or {}).get("indexed")
    total = (event or {}).get("total")
    percent = (event or {}).get("percent")
    message = status_stage
    if total:
        message = f"{status_stage} {indexed or 0}/{total}"
    _set_kb_pipeline_stage(
        status_stage,
        message=message,
        filename=filename,
        indexed=int(indexed) if indexed is not None else None,
        total=int(total) if total is not None else None,
        percent=int(percent) if percent is not None else None,
    )


def _kb_is_ready_for_queries() -> Tuple[bool, str]:
    state = str(_kb_pipeline_state.get("state") or "ready").lower()
    if state == "ready":
        return True, "ready"
    return False, str(_kb_pipeline_state.get("message") or state)


def _normalize_source_label(value: str) -> str:
    import re as _re
    cleaned = str(value or "").strip()
    if not cleaned:
        return ""
    cleaned = _re.sub(r"^[0-9a-fA-F]{8}_", "", cleaned)
    return cleaned.lower()


def _set_active_sources(sources: List[str], mode: Optional[str] = None) -> None:
    if mode:
        normalized_mode = (mode or "").strip().lower()
        if normalized_mode in {"single", "multi"}:
            _active_doc_registry["mode"] = normalized_mode
    normalized = {_normalize_source_label(s) for s in (sources or []) if _normalize_source_label(s)}
    _active_doc_registry["active_sources"] = normalized
    logger.info(
        "RAG active docs updated | mode=%s active_sources=%s",
        _active_doc_registry.get("mode"),
        sorted(_active_doc_registry.get("active_sources") or []),
    )


def _register_active_source(source_name: str) -> None:
    normalized = _normalize_source_label(source_name)
    if not normalized:
        return
    mode = _active_doc_registry.get("mode", RAG_DOC_MODE)
    current = set(_active_doc_registry.get("active_sources") or set())
    if mode == "single":
        current = {normalized}
    else:
        current.add(normalized)
    _active_doc_registry["active_sources"] = current


def _get_active_sources() -> Set[str]:
    return set(_active_doc_registry.get("active_sources") or set())


def _metadata_source_keys(metadata: Optional[Dict[Any, Any]]) -> Set[str]:
    md = metadata or {}
    candidates = {
        str(md.get("source_doc_id") or "").strip(),
        str(md.get("source_name") or "").strip(),
        str(md.get("original_filename") or "").strip(),
        str(md.get("stored_filename") or "").strip(),
        str(md.get("normalized_filename") or "").strip(),
        str(md.get("source") or "").strip(),
        str(md.get("filename") or "").strip(),
        str(md.get("source_filename") or "").strip(),
        str(md.get("file") or "").strip(),
        str(md.get("doc_id") or "").strip(),
        str(md.get("document_id") or "").strip(),
        str(md.get("base_doc_id") or "").strip(),
    }
    keys = set()
    for c in candidates:
        n = _normalize_source_label(c)
        if n:
            keys.add(n)
    return keys


def _filter_results_to_active_sources(results: List[Dict[Any, Any]]) -> List[Dict[Any, Any]]:
    active_sources = _get_active_sources()
    if not active_sources:
        return results
    filtered = []
    items_without_source_keys = 0
    for item in results or []:
        md = (item or {}).get("metadata") or {}
        item_keys = _metadata_source_keys(md)
        if not item_keys:
            items_without_source_keys += 1
        if item_keys & active_sources:
            filtered.append(item)
    if filtered:
        return filtered
    if results and items_without_source_keys:
        logger.warning(
            "Active-source filter dropped unverifiable result(s): active_sources=%s total=%s missing_source_keys=%s",
            sorted(active_sources),
            len(results),
            items_without_source_keys,
        )
    return filtered
    logger.info("All caches invalidated (conversations + Ollama KV cache)")


_DOC_ROUTER_STOPWORDS: Set[str] = {
    "a", "an", "the", "and", "or", "but", "if", "then", "else", "of", "to", "in", "on", "at",
    "for", "from", "by", "with", "without", "within", "into", "onto", "as", "is", "are", "was",
    "were", "be", "being", "been", "do", "does", "did", "can", "could", "should", "would", "may",
    "might", "must", "will", "shall", "what", "which", "who", "whom", "whose", "when", "where",
    "why", "how", "during", "about", "regarding", "concerning", "between", "among", "against",
    "tell", "show", "give", "name", "mention", "identify", "list", "define", "explain", "describe",
    "please", "me", "we", "you", "they", "he", "she", "it", "this", "that", "these", "those",
    "document", "documents", "source", "sources", "file", "files", "pdf", "pdfs", "both", "all", "each",
    "combine", "combined", "synthesize", "synthesise", "summarize", "summarise", "summary", "info",
    "information", "details", "based", "using", "provided", "context",
}

_DOC_ROUTER_VAGUE_TERMS: Set[str] = {
    "policy", "rule", "rules", "procedure", "procedures", "guideline", "guidelines", "requirement",
    "requirements", "topic", "subject", "section", "chapter", "overview", "summary", "detail", "details",
    "information", "document", "source", "file", "item", "items", "thing", "things",
}

_DOC_ROUTER_COMPARISON_OPERATORS: Set[str] = {
    "difference", "differences", "different", "differentiate", "distinguish",
    "compare", "compared", "comparison", "contrast", "contrasts", "distinction",
    "versus", "vs",
}


def _doc_router_text(doc: Dict[str, Any]) -> str:
    return str(
        (doc or {}).get("page_content")
        or (doc or {}).get("text")
        or (doc or {}).get("content")
        or ""
    )


def _doc_router_score(doc: Dict[str, Any]) -> float:
    for key in ("score", "final_score", "similarity", "_boosted_score"):
        if key in (doc or {}):
            try:
                return float((doc or {}).get(key) or 0.0)
            except Exception:
                return 0.0
    md = dict((doc or {}).get("metadata") or {})
    try:
        return float(md.get("_score") or 0.0)
    except Exception:
        return 0.0


def _doc_router_source_key(doc: Dict[str, Any]) -> str:
    md = dict((doc or {}).get("metadata") or {})
    active_sources = _get_active_sources()
    keys = _metadata_source_keys(md)
    active_hits = sorted(keys & active_sources)
    if active_hits:
        return active_hits[0]
    for field in ("filename", "source_filename", "file", "doc_id", "source", "id"):
        raw = str(md.get(field) or "").strip()
        normalized = _normalize_source_label(raw)
        if normalized:
            return normalized
    return "unknown"


def _doc_router_display_source(doc: Dict[str, Any], source_key: str) -> str:
    md = dict((doc or {}).get("metadata") or {})
    for field in ("filename", "source_filename", "file", "doc_id", "source", "title"):
        raw = str(md.get(field) or "").strip()
        if raw and _normalize_source_label(raw) not in {"upload", "watcher"}:
            return raw
    return source_key or "unknown"


def _filter_doc_dicts_to_active_sources(doc_dicts: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    active_sources = _get_active_sources()
    if not active_sources:
        return list(doc_dicts or [])
    kept: List[Dict[str, Any]] = []
    dropped = 0
    unverifiable = 0
    for doc in doc_dicts or []:
        md = dict((doc or {}).get("metadata") or {})
        keys = _metadata_source_keys(md)
        if not keys:
            unverifiable += 1
            dropped += 1
            continue
        if keys & active_sources:
            kept.append(doc)
        else:
            dropped += 1
    if dropped:
        logger.info(
            "[DOC ROUTER] stale_source_filter active_sources=%s kept=%s dropped=%s unverifiable=%s",
            sorted(active_sources),
            len(kept),
            dropped,
            unverifiable,
        )
    return kept


_SYMBOLIC_LIST_CARDINALS: Dict[str, int] = {
    "one": 1,
    "two": 2,
    "three": 3,
    "four": 4,
    "five": 5,
    "six": 6,
    "seven": 7,
    "eight": 8,
    "nine": 9,
    "ten": 10,
    "eleven": 11,
    "twelve": 12,
    "thirteen": 13,
    "fourteen": 14,
    "fifteen": 15,
    "sixteen": 16,
    "seventeen": 17,
    "eighteen": 18,
    "nineteen": 19,
    "twenty": 20,
}
_SYMBOLIC_LIST_NUMBER_WORDS: Dict[int, str] = {value: key for key, value in _SYMBOLIC_LIST_CARDINALS.items()}
_SYMBOLIC_LIST_CATEGORY_WORDS: Set[str] = {
    "step", "steps", "type", "types", "kind", "kinds", "form", "forms", "element", "elements",
    "principle", "principles", "function", "functions", "stage", "stages", "part", "parts",
    "component", "components", "factor", "factors", "feature", "features", "characteristic",
    "characteristics", "category", "categories", "branch", "branches", "method", "methods",
}
_SYMBOLIC_LIST_QUERY_STOPWORDS: Set[str] = {
    "what", "which", "name", "give", "mention", "identify", "list", "show", "tell", "me", "are", "is",
    "was", "were", "the", "a", "an", "of", "for", "in", "on", "to", "from", "by", "with", "and", "or",
    "about", "document", "chapter", "section", "main", "major", "important", "different", "various",
}


def _normalize_symbolic_list_surface(value: str) -> str:
    normalized = str(value or "").replace("’", "'").lower()
    normalized = re.sub(r"[^a-z0-9']+", " ", normalized)
    return re.sub(r"\s+", " ", normalized).strip()


def _symbolic_list_count_value(token: str) -> int | None:
    raw = str(token or "").strip().lower()
    if not raw:
        return None
    if raw.isdigit():
        try:
            value = int(raw)
        except Exception:
            return None
        return value if 1 <= value <= 20 else None
    return _SYMBOLIC_LIST_CARDINALS.get(raw)


def _symbolic_list_label_variants(label_text: str) -> Set[str]:
    raw = str(label_text or "").strip().replace("’", "'")
    compact = re.sub(r"[^A-Za-z0-9']+", "", raw).lower()
    if not compact:
        return set()
    variants: Set[str] = {compact, compact.replace("'", "")}
    letter_match = re.fullmatch(r"([a-z])(?:'?s)?", compact)
    if letter_match:
        letter = letter_match.group(1)
        variants.update({letter, f"{letter}s", f"{letter}'s", f"{letter} s"})
        return variants
    if compact.endswith("s") and len(compact) > 3:
        variants.add(compact[:-1])
    elif compact.isalpha() and len(compact) > 2:
        variants.add(f"{compact}s")
    return {re.sub(r"\s+", " ", variant).strip() for variant in variants if variant.strip()}


def _detect_short_symbolic_list_query(query_text: str) -> dict[str, Any] | None:
    raw_query = re.sub(r"\s+", " ", str(query_text or "").strip())
    if not raw_query:
        return None
    query_norm = _normalize_symbolic_list_surface(raw_query.strip(" ?.!,;:"))
    if not query_norm:
        return None
    query_tokens = re.findall(r"[a-z0-9']+", query_norm)
    if len(query_tokens) > 18:
        return None

    count_pattern = "|".join([re.escape(word) for word in _SYMBOLIC_LIST_CARDINALS] + [r"\d{1,2}"])
    category_pattern = "|".join(re.escape(word) for word in sorted(_SYMBOLIC_LIST_CATEGORY_WORDS, key=len, reverse=True))
    counted_category_match = re.search(
        rf"\b(?:(?P<qualifier>basic|main|major|key|primary|principal)\s+)?"
        rf"(?:(?P<count>{count_pattern})\s+)?"
        rf"(?P<head>{category_pattern})\s+(?:of|for|in|to)\s+(?:the\s+)?(?P<object>[a-z0-9][a-z0-9'\- ]{{1,80}})",
        query_norm,
        flags=re.IGNORECASE,
    )
    if counted_category_match:
        object_text = re.sub(
            r"\b(?:from|on|with|document|chapter|section)\b.*$",
            "",
            str(counted_category_match.group("object") or "").strip(),
        ).strip()
        object_tokens = [
            token for token in re.findall(r"[a-z0-9']+", object_text)
            if token not in _SYMBOLIC_LIST_QUERY_STOPWORDS and token not in _SYMBOLIC_LIST_CATEGORY_WORDS
        ]
        head_text = str(counted_category_match.group("head") or "").strip()
        category_variants = _symbolic_list_label_variants(head_text) or {head_text.lower()}
        count_value = _symbolic_list_count_value(str(counted_category_match.group("count") or ""))
        qualifier = str(counted_category_match.group("qualifier") or "").strip().lower()
        if head_text and object_tokens and (count_value is None or count_value >= 2):
            object_phrase = " ".join(object_tokens[:6])
            count_terms: Set[str] = set()
            if count_value is not None:
                count_terms.add(str(count_value))
                if count_value in _SYMBOLIC_LIST_NUMBER_WORDS:
                    count_terms.add(_SYMBOLIC_LIST_NUMBER_WORDS[count_value])

            phrase_variants: Set[str] = set()
            for category_variant in category_variants:
                if not category_variant:
                    continue
                phrase_variants.update({
                    _normalize_symbolic_list_surface(f"{category_variant} of {object_phrase}"),
                    _normalize_symbolic_list_surface(f"{category_variant} for {object_phrase}"),
                    _normalize_symbolic_list_surface(f"{object_phrase} {category_variant}"),
                    _normalize_symbolic_list_surface(f"basic {category_variant} of {object_phrase}"),
                    _normalize_symbolic_list_surface(f"basic {object_phrase} {category_variant}"),
                })
                for count_term in count_terms:
                    phrase_variants.update({
                        _normalize_symbolic_list_surface(f"{count_term} {category_variant}"),
                        _normalize_symbolic_list_surface(f"{count_term} {category_variant} of {object_phrase}"),
                        _normalize_symbolic_list_surface(f"{count_term} {object_phrase} {category_variant}"),
                        _normalize_symbolic_list_surface(f"{count_term} basic {category_variant}"),
                        _normalize_symbolic_list_surface(f"{count_term} basic {category_variant} of {object_phrase}"),
                        _normalize_symbolic_list_surface(f"these {count_term} basic {category_variant}"),
                    })
            if qualifier:
                for category_variant in category_variants:
                    phrase_variants.add(_normalize_symbolic_list_surface(f"{qualifier} {category_variant} of {object_phrase}"))

            return {
                "kind": "counted_category" if count_value is not None else "category",
                "count": count_value,
                "phrase": f"{head_text} of {object_phrase}",
                "phrase_variants": sorted({variant for variant in phrase_variants if variant}),
                "label_variants": sorted(category_variants),
                "category_terms": sorted(category_variants),
                "object_terms": object_tokens,
                "focus_terms": list(dict.fromkeys([head_text] + sorted(category_variants) + object_tokens)),
                "qualifier": qualifier,
                "counted_list_rescue": True,
            }

    counted_match = re.search(
        rf"\b(?P<count>{count_pattern})\s+(?P<label>[a-z](?:'?s)?|[a-z0-9][a-z0-9'\-]{{1,30}}s)\b",
        query_norm,
        flags=re.IGNORECASE,
    )
    if counted_match:
        count_value = _symbolic_list_count_value(counted_match.group("count"))
        label_text = str(counted_match.group("label") or "").strip()
        if count_value is not None and count_value >= 2 and label_text:
            label_variants = _symbolic_list_label_variants(label_text)
            count_terms = {str(count_value)}
            if count_value in _SYMBOLIC_LIST_NUMBER_WORDS:
                count_terms.add(_SYMBOLIC_LIST_NUMBER_WORDS[count_value])
            phrase_variants: Set[str] = set()
            for count_term in count_terms:
                for label_variant in label_variants or {label_text.lower()}:
                    phrase_variants.add(_normalize_symbolic_list_surface(f"{count_term} {label_variant}"))
            focus_terms = [
                token for token in query_tokens
                if token not in _SYMBOLIC_LIST_QUERY_STOPWORDS
                and token not in _SYMBOLIC_LIST_CARDINALS
                and not token.isdigit()
            ]
            focus_terms.extend(sorted(label_variants))
            return {
                "kind": "counted",
                "count": count_value,
                "phrase": re.sub(r"\s+", " ", counted_match.group(0)).strip(),
                "phrase_variants": sorted({variant for variant in phrase_variants if variant}),
                "label_variants": sorted(label_variants),
                "focus_terms": list(dict.fromkeys([term for term in focus_terms if term])),
            }

    category_match = re.search(
        rf"\b(?P<head>{category_pattern})\s+(?:of|for|in|to)\s+(?:the\s+)?(?P<object>[a-z0-9][a-z0-9'\- ]{{1,80}})",
        query_norm,
        flags=re.IGNORECASE,
    )
    if category_match:
        object_text = re.sub(
            r"\b(?:from|in|on|for|with|document|chapter|section)\b.*$",
            "",
            str(category_match.group("object") or "").strip(),
        ).strip()
        object_tokens = [
            token for token in re.findall(r"[a-z0-9']+", object_text)
            if token not in _SYMBOLIC_LIST_QUERY_STOPWORDS and token not in _SYMBOLIC_LIST_CATEGORY_WORDS
        ]
        if object_tokens:
            head_text = str(category_match.group("head") or "").strip()
            phrase = f"{head_text} of {' '.join(object_tokens[:6])}"
            phrase_variants = {
                _normalize_symbolic_list_surface(phrase),
                _normalize_symbolic_list_surface(f"{head_text} for {' '.join(object_tokens[:6])}"),
                _normalize_symbolic_list_surface(f"{' '.join(object_tokens[:6])} {head_text}"),
            }
            return {
                "kind": "category",
                "count": None,
                "phrase": phrase,
                "phrase_variants": sorted({variant for variant in phrase_variants if variant}),
                "label_variants": [head_text],
                "focus_terms": list(dict.fromkeys([head_text] + object_tokens)),
            }
    return None


_SPOKEN_SINGLE_LETTER_NAMES: Dict[str, str] = {
    "a": "a", "ay": "a",
    "b": "b", "bee": "b", "be": "b",
    "c": "c", "see": "c", "sea": "c",
    "d": "d", "dee": "d",
    "e": "e", "ee": "e",
    "f": "f", "ef": "f",
    "g": "g", "gee": "g",
    "h": "h", "aitch": "h", "hache": "h",
    "i": "i", "eye": "i",
    "j": "j", "jay": "j",
    "k": "k", "kay": "k",
    "l": "l", "el": "l", "ell": "l",
    "m": "m", "em": "m",
    "n": "n", "en": "n",
    "o": "o", "oh": "o",
    "p": "p", "pee": "p",
    "q": "q", "cue": "q", "queue": "q",
    "r": "r", "ar": "r", "are": "r",
    "s": "s", "ess": "s",
    "t": "t", "tee": "t", "tea": "t",
    "u": "u", "you": "u",
    "v": "v", "vee": "v",
    "w": "w", "doubleyou": "w", "doubleu": "w",
    "x": "x", "ex": "x",
    "y": "y", "why": "y",
    "z": "z", "zee": "z", "zed": "z",
}


def _normalize_symbolic_count_letter_list_query_before_retrieval(query_text: str) -> tuple[str, str]:
    raw_query = re.sub(r"\s+", " ", str(query_text or "").strip())
    if not raw_query or _detect_language(raw_query) == "ar":
        return raw_query, ""

    query_norm = _normalize_query_for_router(raw_query)
    if not query_norm:
        return raw_query, ""
    if not re.match(r"^\s*(?:(?:what|which)\s+(?:is|are)|list|name|give|mention|identify)\b", query_norm):
        return raw_query, ""

    tokens = query_norm.split()
    if not tokens:
        return raw_query, ""

    question_has_list_shape = bool(
        re.match(r"^\s*(?:(?:what|which)\s+are|list|name|give|mention|identify)\b", query_norm)
    )
    allowed_tail_starters = {"in", "of", "for", "about", "within", "to"}
    measurement_tail_terms = {
        "length", "height", "width", "depth", "distance", "meter", "meters", "metre", "metres",
        "mile", "miles", "kilometer", "kilometers", "kilometre", "kilometres", "feet", "foot",
    }

    def _letter_from_token(token: str) -> str:
        cleaned_token = re.sub(r"[^a-z]+", "", str(token or "").lower())
        if len(cleaned_token) == 1:
            return cleaned_token
        if cleaned_token.endswith("s") and cleaned_token[:-1] in _SPOKEN_SINGLE_LETTER_NAMES:
            return _SPOKEN_SINGLE_LETTER_NAMES[cleaned_token[:-1]]
        return _SPOKEN_SINGLE_LETTER_NAMES.get(cleaned_token, "")

    for token_index, token in enumerate(tokens):
        count_value: int | None = None
        letter_value = ""
        consume_until = token_index + 1

        compact_match = re.fullmatch(r"(?P<count>\d{1,2})(?P<letter>[a-z])s?", token)
        if compact_match:
            count_value = _symbolic_list_count_value(compact_match.group("count"))
            letter_value = compact_match.group("letter")
            if consume_until < len(tokens) and tokens[consume_until] == "s":
                consume_until += 1
        else:
            count_value = _symbolic_list_count_value(token)
            if count_value is None or token_index + 1 >= len(tokens):
                continue
            letter_value = _letter_from_token(tokens[token_index + 1])
            if not letter_value:
                continue
            consume_until = token_index + 2
            if consume_until < len(tokens) and tokens[consume_until] == "s":
                consume_until += 1

        if count_value is None or not (2 <= count_value <= 20) or not letter_value:
            continue

        tail_tokens = tokens[consume_until:]
        tail_starter = tail_tokens[0] if tail_tokens else ""
        has_allowed_tail = bool(tail_starter in allowed_tail_starters or not tail_tokens)
        if tail_starter == "in" and len(tail_tokens) >= 2 and tail_tokens[1] in measurement_tail_terms:
            continue
        if not (question_has_list_shape or has_allowed_tail):
            continue

        count_word = _SYMBOLIC_LIST_NUMBER_WORDS.get(count_value, str(count_value))
        label_text = f"{letter_value.upper()}s"
        tail_text = " ".join(tail_tokens).strip()
        normalized_query = f"What are the {count_word} {label_text}"
        if tail_text:
            normalized_query = f"{normalized_query} {tail_text}"
        normalized_query = normalized_query.strip() + "?"
        return normalized_query, f"{count_word} {label_text}"

    return raw_query, ""


def _symbolic_list_active_allowed_sources(seed_docs: list[dict] | None = None) -> Set[str]:
    allowed_sources = set(_get_active_sources())
    if allowed_sources:
        return allowed_sources
    for seed_doc in seed_docs or []:
        metadata = dict((seed_doc or {}).get("metadata") or {})
        allowed_sources.update(_metadata_source_keys(metadata))
    return allowed_sources


def _is_counted_category_list_query_info(query_info: dict[str, Any] | None) -> bool:
    if not isinstance(query_info, dict):
        return False
    return bool(query_info.get("counted_list_rescue") and query_info.get("category_terms") and query_info.get("object_terms"))


def _prepare_counted_list_rescue_text(text: str) -> str:
    cleaned = str(text or "").replace("•", " ")
    cleaned = cleaned.replace("–", "-").replace("—", "-").replace("’", "'")
    # Generic OCR repair for linearized diagrams/tables: insert boundaries before
    # glued all-caps headings and before numbered markers that touch words.
    cleaned = re.sub(r"([a-z])([A-Z]{2,})(?=\s|$)", r"\1 \2", cleaned)
    cleaned = re.sub(r"([A-Za-z])(?=\d{1,2}\s*[.)])", r"\1 ", cleaned)
    cleaned = re.sub(r"(\d{1,2})\s*([.)])\s*", r" \1\2 ", cleaned)
    cleaned = re.sub(r"\s+", " ", cleaned)
    return cleaned.strip()


def _clean_counted_list_label_item(raw_item: str) -> str:
    item = re.sub(r"\s+", " ", str(raw_item or "")).strip(" \t\r\n,;:-\"'")
    if not item:
        return ""
    item = re.sub(r"\b([A-Z][a-z])\s+([a-z]{4,})\b", r"\1\2", item)
    # Stop at sentence/list-table boundaries; if a later all-caps heading is glued
    # onto the final label, this keeps only the label text.
    item = re.split(r"[.;:]\s*(?=[A-Z0-9])|[.;:]$|\s+(?=[A-Z]{2,}\b)", item, maxsplit=1)[0]
    item = re.sub(r"\s+", " ", item).strip(" \t\r\n,;:-\"'")
    return item


def _is_clean_counted_label_item(item_text: str) -> bool:
    item = re.sub(r"\s+", " ", str(item_text or "")).strip(" ,;:-")
    if not item or len(item) > 80:
        return False
    if re.search(r"\d", item):
        return False
    if re.search(r"[.!?:;]", item):
        return False
    words = re.findall(r"[A-Za-z][A-Za-z'\-]*", item)
    if not (1 <= len(words) <= 6):
        return False
    if not item[0].isupper():
        return False
    if re.search(
        r"\b(?:is|are|was|were|be|been|being|has|have|had|include|includes|including|"
        r"consist|consists|comprise|comprises|means|refers|describe|describes|explain|explains)\b",
        item,
        flags=re.IGNORECASE,
    ):
        return False
    if re.match(r"^(?:and|or|the|a|an)\b", item, flags=re.IGNORECASE):
        return False
    return True


def _shape_counted_list_items(items: list[str]) -> str | None:
    cleaned_items: list[str] = []
    seen_norm: set[str] = set()
    for raw_item in items:
        item = _clean_counted_list_label_item(raw_item)
        if not _is_clean_counted_label_item(item):
            return None
        norm = re.sub(r"[^a-z0-9]+", " ", item.lower()).strip()
        if not norm or norm in seen_norm:
            return None
        seen_norm.add(norm)
        cleaned_items.append(item)
    if len(cleaned_items) < 2:
        return None
    return "\n".join(f"- {item}" for item in cleaned_items)


def _split_counted_inline_clause_items(clause: str, count_target: int | None = None) -> list[list[str]]:
    clean_clause = re.sub(r"\s+", " ", str(clause or "")).strip(" ,;:-")
    if not clean_clause:
        return []
    clean_clause = re.split(
        r"(?:\.\s+(?=[A-Z][a-z])|\b(?:These|This|The)\s+\w+\s+(?:basic|main|major|key|primary|principal)?\s*\w+\s+(?:which\s+are|are|include|includes)\b)",
        clean_clause,
        maxsplit=1,
    )[0].strip(" ,;:-")
    candidates: list[list[str]] = []
    comma_items = [part.strip(" ,;:-") for part in re.split(r"\s*,\s*", clean_clause) if part.strip(" ,;:-")]
    if len(comma_items) >= 2:
        candidates.append(comma_items)
        expanded: list[str] = []
        for index, item in enumerate(comma_items):
            if index == len(comma_items) - 1:
                expanded.extend(part.strip(" ,;:-") for part in re.split(r"\s+and\s+|\s+or\s+", item) if part.strip(" ,;:-"))
            else:
                expanded.append(item)
        if expanded != comma_items:
            candidates.append(expanded)
    connector_items = [part.strip(" ,;:-") for part in re.split(r"\s+and\s+|\s+or\s+", clean_clause) if part.strip(" ,;:-")]
    if len(connector_items) >= 2:
        candidates.append(connector_items)
    if isinstance(count_target, int) and count_target >= 2:
        exact = [items for items in candidates if len(items) == count_target]
        if exact:
            return exact
    return candidates


def _find_counted_list_anchor_spans(text: str, query_info: dict[str, Any]) -> list[tuple[int, int, str]]:
    prepared = _prepare_counted_list_rescue_text(text)
    spans: list[tuple[int, int, str]] = []
    variants = sorted(
        {str(v or "").strip() for v in (query_info.get("phrase_variants") or []) if str(v or "").strip()},
        key=len,
        reverse=True,
    )
    for variant in variants:
        words = re.findall(r"[a-z0-9']+", _normalize_symbolic_list_surface(variant))
        if len(words) < 2:
            continue
        pattern = r"\b" + r"\s+".join(re.escape(word) for word in words) + r"\b"
        for match in re.finditer(pattern, prepared, flags=re.IGNORECASE):
            spans.append((match.start(), match.end(), variant))
    spans.sort(key=lambda row: (row[0], -(row[1] - row[0])))
    deduped: list[tuple[int, int, str]] = []
    occupied: set[int] = set()
    for start, end, variant in spans:
        bucket = start // 10
        if bucket in occupied:
            continue
        occupied.add(bucket)
        deduped.append((start, end, variant))
    return deduped


def _extract_counted_list_labels_from_context(
    query_text: str,
    source_text: str,
    query_info: dict[str, Any] | None = None,
) -> str | None:
    query_info = query_info or _detect_short_symbolic_list_query(query_text) or {}
    if not _is_counted_category_list_query_info(query_info):
        return None
    prepared = _prepare_counted_list_rescue_text(source_text)
    if not prepared:
        return None
    count_target = query_info.get("count")
    if not isinstance(count_target, int) or count_target < 2:
        count_target = None

    anchors = _find_counted_list_anchor_spans(prepared, query_info)
    if not anchors:
        return None

    count_terms: set[str] = set()
    if isinstance(count_target, int) and count_target >= 2:
        count_terms.add(str(count_target))
        if count_target in _SYMBOLIC_LIST_NUMBER_WORDS:
            count_terms.add(_SYMBOLIC_LIST_NUMBER_WORDS[count_target])
    object_terms = {
        _normalize_symbolic_list_surface(str(term))
        for term in (query_info.get("object_terms") or [])
        if _normalize_symbolic_list_surface(str(term))
    }
    category_terms = {
        _normalize_symbolic_list_surface(str(term))
        for term in (query_info.get("category_terms") or [])
        if _normalize_symbolic_list_surface(str(term))
    }

    def _anchor_priority(anchor: tuple[int, int, str]) -> tuple[float, int]:
        start, _end, variant = anchor
        variant_norm = _normalize_symbolic_list_surface(variant)
        variant_tokens = set(re.findall(r"[a-z0-9']+", variant_norm))
        priority = 0.0
        if count_terms and (variant_tokens & count_terms):
            priority += 6.0
        if category_terms and (variant_tokens & category_terms):
            priority += 1.0
        if object_terms and (variant_tokens & object_terms):
            priority += 1.0
        if variant_tokens & {"basic", "main", "major", "key", "primary", "principal"}:
            priority += 1.0
        if "these" in variant_tokens:
            priority += 0.5
        return (-priority, start)

    ordered_anchors = sorted(anchors, key=_anchor_priority)

    best_items: list[str] = []
    best_answer: str | None = None
    for start, end, variant in ordered_anchors[:24]:
        segment = prepared[max(0, start - 80): min(len(prepared), end + 1800)]
        relative_end = min(len(segment), (end - max(0, start - 80)))
        segment_after_anchor = segment[relative_end:]
        marker_patterns = (
            (r"(?:^|\s)(\d{1,2})\s*[.)]\s*(.*?)(?=(?:\s+\d{1,2}\s*[.)]\s*)|$)", "number"),
            (r"(?:^|\s)([A-Ea-e])\s*[.)]\s*(.*?)(?=(?:\s+[A-Ea-e]\s*[.)]\s*)|$)", "letter"),
        )
        for marker_pattern, marker_kind in marker_patterns:
            marker_matches = list(re.finditer(marker_pattern, segment_after_anchor, flags=re.DOTALL))
            if not marker_matches:
                continue
            items: list[str] = []
            expected_number = 1
            started = False
            for marker in marker_matches:
                try:
                    marker_number = int(marker.group(1)) if marker_kind == "number" else (ord(marker.group(1).lower()) - ord("a") + 1)
                except Exception:
                    continue
                if not started:
                    if marker_number != 1:
                        continue
                    started = True
                    expected_number = 1
                if marker_number != expected_number:
                    break
                expected_number += 1
                item = _clean_counted_list_label_item(marker.group(2) or "")
                if not _is_clean_counted_label_item(item):
                    break
                items.append(item)
                if count_target is not None and len(items) >= count_target:
                    break
            shaped_marker = _shape_counted_list_items(items)
            if shaped_marker is None:
                continue
            if count_target is not None and len(items) != count_target:
                continue
            if count_target is None and len(items) < 3:
                continue
            if len(items) > len(best_items):
                best_items = items
                best_answer = shaped_marker

        inline_intro = re.search(
            r"\b(?:which\s+are|are|include|includes|included\s+are|consist\s+of|consists\s+of)\s*[:\-]?\s*(.{8,360})",
            segment_after_anchor,
            flags=re.IGNORECASE | re.DOTALL,
        )
        if inline_intro:
            inline_clause = inline_intro.group(1) or ""
            for inline_items in _split_counted_inline_clause_items(inline_clause, count_target):
                shaped_inline = _shape_counted_list_items(inline_items)
                if shaped_inline is None:
                    continue
                if count_target is not None and len(inline_items) != count_target:
                    continue
                if count_target is None and len(inline_items) < 3:
                    continue
                if len(inline_items) > len(best_items):
                    best_items = [_clean_counted_list_label_item(item) for item in inline_items]
                    best_answer = shaped_inline

    if len(best_items) < 2 or not best_answer:
        return None
    return best_answer


def _build_counted_list_rescue_context(
    query_text: str,
    query_info: dict[str, Any],
    anchor_doc: dict,
    all_chunks: list[dict],
    allowed_sources: Set[str],
) -> tuple[str, dict[str, Any]]:
    raw_anchor_text = str((anchor_doc or {}).get("page_content") or (anchor_doc or {}).get("text") or "")
    cleaned_anchor = _normalize_context_entities(query_text, _clean_ocr_artifacts(raw_anchor_text) or raw_anchor_text)
    if not _is_counted_category_list_query_info(query_info):
        focused_anchor = _focus_doc_to_query_window(query_text, cleaned_anchor, window=900) or cleaned_anchor
        return focused_anchor, {"selected_chunk_indexes": [dict((anchor_doc or {}).get("metadata") or {}).get("chunk_index")], "merged_extra_chunks_count": 0}

    anchor_md = dict((anchor_doc or {}).get("metadata") or {})
    anchor_sources = _metadata_source_keys(anchor_md) & allowed_sources
    try:
        raw_anchor_idx = anchor_md.get("chunk_index")
        if raw_anchor_idx is None:
            raise ValueError("missing chunk_index")
        anchor_idx = int(f"{raw_anchor_idx}")
    except Exception:
        anchor_idx = None
    if not anchor_sources or anchor_idx is None:
        focused_anchor = _focus_doc_to_query_window(query_text, cleaned_anchor, window=1600) or cleaned_anchor
        return focused_anchor, {"selected_chunk_indexes": [anchor_md.get("chunk_index")], "merged_extra_chunks_count": 0}

    focus_terms = [
        _normalize_symbolic_list_surface(str(term))
        for term in (query_info.get("focus_terms") or [])
        if _normalize_symbolic_list_surface(str(term))
    ]
    phrase_variants = [
        _normalize_symbolic_list_surface(str(variant))
        for variant in (query_info.get("phrase_variants") or [])
        if _normalize_symbolic_list_surface(str(variant))
    ]

    selected: list[tuple[int, dict]] = []
    for chunk in all_chunks:
        metadata = dict((chunk or {}).get("metadata") or {})
        chunk_sources = _metadata_source_keys(metadata)
        if not (chunk_sources & anchor_sources):
            continue
        try:
            raw_chunk_idx = metadata.get("chunk_index")
            if raw_chunk_idx is None:
                raise ValueError("missing chunk_index")
            chunk_idx = int(f"{raw_chunk_idx}")
        except Exception:
            continue
        distance = abs(chunk_idx - anchor_idx)
        if distance > 2:
            continue
        text = str((chunk or {}).get("page_content") or (chunk or {}).get("text") or "")
        normalized = _normalize_symbolic_list_surface(text)
        phrase_hit = any(re.search(rf"\b{re.escape(variant)}\b", normalized) for variant in phrase_variants if variant)
        focus_hits = sum(1 for term in dict.fromkeys(focus_terms) if term and _token_match_light(normalized, term))
        marker_hits = len(re.findall(r"(?:^|\s)\d{1,2}\s*[.)]\s*[A-Za-z]", _prepare_counted_list_rescue_text(text)))
        include_chunk = bool(
            distance == 0
            or (distance == 1 and (phrase_hit or focus_hits >= 1 or marker_hits >= 2))
            or (distance == 2 and phrase_hit and marker_hits >= 2)
        )
        if include_chunk:
            selected.append((chunk_idx, chunk))

    if not selected:
        selected = [(anchor_idx, anchor_doc)]
    selected = sorted(selected, key=lambda row: (abs(row[0] - anchor_idx), row[0]))[:3]
    selected.sort(key=lambda row: row[0])
    selected_indexes = [idx for idx, _ in selected]
    merged_text_parts: list[str] = []
    for _, chunk in selected:
        raw_text = str((chunk or {}).get("page_content") or (chunk or {}).get("text") or "")
        merged_text_parts.append(_normalize_context_entities(query_text, _clean_ocr_artifacts(raw_text) or raw_text))
    merged_text = "\n".join(part for part in merged_text_parts if part.strip())
    focused_text = merged_text if len(merged_text) <= 6500 else (_focus_doc_to_query_window(query_text, merged_text, window=3200) or merged_text)
    return focused_text, {
        "selected_chunk_indexes": selected_indexes,
        "merged_extra_chunks_count": max(0, len(selected_indexes) - 1),
        "strict_adjacent_merge_allowed": 1.0 if len(selected_indexes) <= 3 else 0.0,
    }


def _symbolic_list_candidate_item_count(query_text: str, source_text: str) -> int:
    query_info = _detect_short_symbolic_list_query(query_text)
    counted_candidate = _extract_counted_list_labels_from_context(query_text, source_text, query_info)
    if counted_candidate:
        lines = [line for line in counted_candidate.splitlines() if re.match(r"^\s*[-•*]\s+", line)]
        if lines:
            return len(lines)
    candidates: list[str] = []
    try:
        context_candidate = _extract_list_from_context(query_text, source_text, max_candidate_blocks=2)
        if context_candidate:
            candidates.append(str(context_candidate))
    except Exception:
        pass
    if not candidates:
        try:
            simple_candidate = _extract_simple_list_from_docs([{"page_content": source_text, "text": source_text, "metadata": {}}], query_text=query_text)
            if simple_candidate:
                candidates.append(str(simple_candidate))
        except Exception:
            pass
    for candidate in candidates:
        lines = [line for line in candidate.splitlines() if re.match(r"^\s*[-•*]\s+", line)]
        if lines:
            return len(lines)
    return 0


def _score_symbolic_list_candidate(query_text: str, query_info: dict[str, Any], doc: dict) -> tuple[float, dict[str, Any]] | None:
    source_text = str((doc or {}).get("page_content") or (doc or {}).get("text") or (doc or {}).get("content") or "")
    if not source_text.strip():
        return None
    normalized_text = _normalize_symbolic_list_surface(source_text)
    phrase_variants = [variant for variant in (query_info.get("phrase_variants") or []) if str(variant or "").strip()]
    phrase_hits: list[str] = []
    phrase_positions: list[int] = []
    for variant in phrase_variants:
        normalized_variant = _normalize_symbolic_list_surface(str(variant))
        if not normalized_variant:
            continue
        phrase_re = re.compile(rf"(?:^|\s){re.escape(normalized_variant)}(?:\s|$)", flags=re.IGNORECASE)
        for match in phrase_re.finditer(normalized_text):
            phrase_hits.append(normalized_variant)
            phrase_positions.append(match.start())
            break
    focus_terms = [
        _normalize_symbolic_list_surface(str(term)) for term in (query_info.get("focus_terms") or [])
        if _normalize_symbolic_list_surface(str(term))
    ]
    focus_hits = 0
    for term in dict.fromkeys(focus_terms):
        if len(term) <= 2:
            if re.search(rf"(?:^|\s){re.escape(term)}(?:\s|$)", normalized_text):
                focus_hits += 1
        elif re.search(rf"\b{re.escape(term)}[a-z0-9']*\b", normalized_text):
            focus_hits += 1

    if not phrase_hits and focus_hits < 2:
        return None

    anchor_pos = min(phrase_positions) if phrase_positions else 0
    window_start = max(0, anchor_pos - 180)
    window_end = min(len(normalized_text), anchor_pos + 520)
    near_window = normalized_text[window_start:window_end]
    raw_lower = source_text.lower()
    raw_window = raw_lower[max(0, min(anchor_pos, len(raw_lower)) - 180): min(len(raw_lower), min(anchor_pos, len(raw_lower)) + 640)]

    colon_near = bool(re.search(r"[:;]", raw_window))
    introducer_near = bool(re.search(r"\b(?:include|includes|including|consists?\s+of|comprises?|classified\s+as|are|is)\b", near_window))
    comma_count = min(8, raw_window.count(","))
    bullet_count = min(8, len(re.findall(r"(?m)^\s*(?:[-•*]|\d+[.)]|[A-Za-z][.)])\s+", source_text)))
    inline_list_density = min(1.0, (comma_count + bullet_count) / 6.0)
    item_count = 0
    count_value = query_info.get("count")
    if phrase_hits:
        item_count = _symbolic_list_candidate_item_count(query_text, source_text)

    score = 0.0
    score += 9.0 if phrase_hits else 0.0
    score += min(3, len(set(phrase_hits))) * 1.5
    score += min(5, focus_hits) * 0.75
    score += 1.8 if colon_near else 0.0
    score += 1.2 if introducer_near else 0.0
    score += min(4, comma_count) * 0.65
    score += min(4, bullet_count) * 0.55
    score += inline_list_density * 1.5
    if isinstance(count_value, int) and count_value >= 2 and item_count == count_value:
        score += 4.0
    elif isinstance(count_value, int) and count_value >= 2 and item_count >= 2:
        score += 1.0

    if not phrase_hits and score < 4.0:
        return None
    return score, {
        "phrase_hits": float(len(set(phrase_hits))),
        "focus_hits": float(focus_hits),
        "colon_near": 1.0 if colon_near else 0.0,
        "introducer_near": 1.0 if introducer_near else 0.0,
        "comma_count": float(comma_count),
        "bullet_count": float(bullet_count),
        "item_count": float(item_count),
    }


def _lexical_rescue_symbolic_list_chunk(query_text: str, seed_docs: list[dict] | None = None) -> tuple[dict | None, dict[str, Any]]:
    query_info = _detect_short_symbolic_list_query(query_text)
    if not query_info:
        return None, {"detected": False, "reason": "not_symbolic_list_query"}
    counted_category_mode = _is_counted_category_list_query_info(query_info)

    logger.info(
        "[SYMBOLIC LIST QUERY DETECTED] query=%s phrase=%s kind=%s count=%s",
        str(query_text or "")[:180],
        str(query_info.get("phrase") or "")[:120],
        query_info.get("kind"),
        query_info.get("count"),
    )
    if counted_category_mode:
        logger.info(
            "[COUNTED LIST QUERY DETECTED] query=%s phrase=%s kind=%s count=%s category=%s object=%s",
            str(query_text or "")[:180],
            str(query_info.get("phrase") or "")[:120],
            query_info.get("kind"),
            query_info.get("count"),
            query_info.get("category_terms") or [],
            query_info.get("object_terms") or [],
        )
    allowed_sources = _symbolic_list_active_allowed_sources(seed_docs)
    if not allowed_sources:
        logger.info(
            "[LEXICAL RESCUE] query=%s phrase=%s candidates=0 chosen_chunk=None",
            str(query_text or "")[:180],
            str(query_info.get("phrase") or "")[:120],
        )
        if counted_category_mode:
            logger.info(
                "[COUNTED LIST RESCUE] query=%s phrase=%s candidates=0 chosen_chunk=None",
                str(query_text or "")[:180],
                str(query_info.get("phrase") or "")[:120],
            )
        return None, {"detected": True, "reason": "no_active_sources", "query_info": query_info, "candidates": 0}

    chunks = _mpc15_load_full_corpus_chunks()
    scored: list[tuple[float, dict, dict[str, Any]]] = []
    for chunk in chunks:
        metadata = dict((chunk or {}).get("metadata") or {})
        source_keys = _metadata_source_keys(metadata)
        if not (source_keys & allowed_sources):
            continue
        scored_candidate = _score_symbolic_list_candidate(query_text, query_info, chunk)
        if scored_candidate is None:
            continue
        candidate_score, candidate_signals = scored_candidate
        if candidate_score <= 0.0:
            continue
        scored.append((candidate_score, chunk, candidate_signals))

    scored.sort(key=lambda row: row[0], reverse=True)
    chosen_doc: dict | None = None
    chosen_chunk: Any = None
    chosen_score = 0.0
    chosen_signals: dict[str, Any] = {}
    if scored:
        chosen_score, chosen_source_doc, chosen_signals = scored[0]
        metadata = dict((chosen_source_doc or {}).get("metadata") or {})
        focused_text, context_meta = _build_counted_list_rescue_context(
            query_text,
            query_info,
            chosen_source_doc,
            chunks,
            allowed_sources,
        )
        chosen_doc = {
            "page_content": focused_text,
            "text": focused_text,
            "content": focused_text,
            "metadata": metadata,
            "score": float(chosen_score),
            "_lexical_rescue_score": float(chosen_score),
            "_lexical_rescue_context_meta": context_meta,
        }
        chosen_signals = dict(chosen_signals or {})
        chosen_signals.update({
            "selected_chunks_count": float(len(context_meta.get("selected_chunk_indexes") or []) or 1),
            "merged_extra_chunks_count": float(context_meta.get("merged_extra_chunks_count", 0) or 0),
            "strict_adjacent_merge_allowed": float(context_meta.get("strict_adjacent_merge_allowed", 0.0) or 0.0),
        })
        chosen_chunk = metadata.get("chunk_index")

    logger.info(
        "[LEXICAL RESCUE] query=%s phrase=%s candidates=%s chosen_chunk=%s",
        str(query_text or "")[:180],
        str(query_info.get("phrase") or "")[:120],
        len(scored),
        chosen_chunk,
    )
    if counted_category_mode:
        logger.info(
            "[COUNTED LIST RESCUE] query=%s phrase=%s candidates=%s chosen_chunk=%s merged_extra=%s",
            str(query_text or "")[:180],
            str(query_info.get("phrase") or "")[:120],
            len(scored),
            chosen_chunk,
            int(float((chosen_signals or {}).get("merged_extra_chunks_count", 0.0) or 0.0)),
        )
    if chosen_doc is None or chosen_score < 8.0:
        return None, {
            "detected": True,
            "reason": "no_strong_lexical_candidate",
            "query_info": query_info,
            "candidates": len(scored),
            "chosen_chunk": chosen_chunk,
            "score": float(chosen_score),
        }
    return chosen_doc, {
        "detected": True,
        "reason": "candidate_selected",
        "query_info": query_info,
        "candidates": len(scored),
        "chosen_chunk": chosen_chunk,
        "score": float(chosen_score),
        "signals": chosen_signals,
    }


def _extract_symbolic_list_lexical_rescue_answer(query_text: str, seed_docs: list[dict] | None = None) -> tuple[str | None, int, dict | None, dict[str, Any], str]:
    rescued_doc, rescue_meta = _lexical_rescue_symbolic_list_chunk(query_text, seed_docs)
    query_info = dict(rescue_meta.get("query_info") or {}) if isinstance(rescue_meta, dict) else {}
    counted_category_mode = _is_counted_category_list_query_info(query_info)
    if rescued_doc is None:
        reason = str(rescue_meta.get("reason") or "no_candidate")
        if rescue_meta.get("detected"):
            logger.info("[LEXICAL RESCUE] accepted=False reason=%s", reason)
            if counted_category_mode:
                logger.info("[COUNTED LIST RESCUE] accepted=False reason=%s", reason)
        return None, 0, None, {}, reason

    rescue_text = str((rescued_doc or {}).get("page_content") or (rescued_doc or {}).get("text") or "")
    if not rescue_text.strip():
        logger.info("[LEXICAL RESCUE] accepted=False reason=empty_rescued_context")
        if counted_category_mode:
            logger.info("[COUNTED LIST RESCUE] accepted=False reason=empty_rescued_context")
        return None, 0, None, {}, "empty_rescued_context"

    rescue_support = _collect_local_window_support([rescued_doc])
    rescue_context_meta = dict((rescued_doc or {}).get("_lexical_rescue_context_meta") or {})
    rescue_selected_chunks = list(rescue_context_meta.get("selected_chunk_indexes") or [])
    rescue_support["selected_chunks_count"] = float(len(rescue_selected_chunks) or 1)
    rescue_support["merged_extra_chunks_count"] = float(rescue_context_meta.get("merged_extra_chunks_count", 0) or 0)
    rescue_support["strict_adjacent_merge_allowed"] = float(rescue_context_meta.get("strict_adjacent_merge_allowed", 0.0) or 0.0)
    rescue_support["used_single_window"] = 1.0
    rescue_support["validation_scope"] = "single_local_window"
    rescue_support["single_local_window_text"] = rescue_text[:7000] if counted_category_mode else rescue_text[:2400]
    rescue_support["lexical_rescue"] = 1.0
    if counted_category_mode:
        rescue_support["counted_list_rescue"] = 1.0
    rescue_signals = dict(rescue_meta.get("signals") or {})
    rescue_support["primary_phrase_hits"] = max(
        float(rescue_support.get("primary_phrase_hits", 0.0) or 0.0),
        float(rescue_signals.get("phrase_hits", 0.0) or 0.0),
    )
    rescue_support["primary_supp_list_evidence"] = max(
        float(rescue_support.get("primary_supp_list_evidence", 0.0) or 0.0),
        float(rescue_signals.get("colon_near", 0.0) or 0.0)
        + min(2.0, float(rescue_signals.get("comma_count", 0.0) or 0.0) / 3.0)
        + min(1.0, float(rescue_signals.get("bullet_count", 0.0) or 0.0) / 2.0),
    )

    rescue_candidates: list[str] = []
    counted_candidate = _extract_counted_list_labels_from_context(query_text, rescue_text, query_info)
    if counted_candidate:
        rescue_candidates.append(counted_candidate)
    for raw_candidate in (
        _extract_list_from_context(query_text, rescue_text, max_candidate_blocks=3),
        _extract_simple_list_from_docs([rescued_doc], query_text=query_text),
    ):
        candidate_text = str(raw_candidate or "").strip()
        if candidate_text:
            rescue_candidates.append(candidate_text)

    if not rescue_candidates:
        logger.info("[LEXICAL RESCUE] accepted=False reason=no_extractable_list")
        if counted_category_mode:
            logger.info("[COUNTED LIST RESCUE] accepted=False reason=no_extractable_list")
        return None, 0, None, {}, "no_extractable_list"

    last_reason = "coherence_failed"
    for candidate_text in rescue_candidates:
        rescue_ok, rescue_reason, rescue_shaped = _assess_list_coherence(
            query_text,
            _preclean_list_answer_for_assessment(candidate_text),
            strict_fast=True,
            local_support=rescue_support,
        )
        last_reason = str(rescue_reason or "coherence_failed")
        rescue_count = len([line for line in str(rescue_shaped or "").splitlines() if line.strip()])
        accepted = bool(rescue_ok and rescue_shaped and rescue_count >= 2)
        logger.info("[LEXICAL RESCUE] accepted=%s reason=%s", accepted, last_reason)
        if counted_category_mode:
            logger.info("[COUNTED LIST RESCUE] accepted=%s reason=%s", accepted, last_reason)
        if accepted:
            return rescue_shaped, rescue_count, rescued_doc, rescue_support, last_reason

    logger.info("[LEXICAL RESCUE] accepted=False reason=%s", last_reason)
    if counted_category_mode:
        logger.info("[COUNTED LIST RESCUE] accepted=False reason=%s", last_reason)
    return None, 0, None, {}, last_reason


def _doc_router_normalized_query_tokens(query_text: str) -> List[str]:
    q = re.sub(r"[^A-Za-z0-9\s'-]+", " ", str(query_text or "").lower())
    tokens: List[str] = []
    seen: Set[str] = set()
    for raw in re.findall(r"[a-z0-9][a-z0-9'-]*", q):
        cleaned = raw.strip("'-")
        if len(cleaned) < 2 or cleaned in _DOC_ROUTER_STOPWORDS:
            continue
        norm = _light_normalize_query_token(cleaned)
        if not norm or norm in _DOC_ROUTER_STOPWORDS or norm in seen:
            continue
        seen.add(norm)
        tokens.append(norm)
    return tokens[:12]


def _extract_doc_router_query_concepts(query_text: str) -> Tuple[List[str], List[str]]:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    query_tokens = _doc_router_normalized_query_tokens(q)
    comparison_intent = _doc_router_implies_comparison(q)
    if comparison_intent:
        query_tokens = [token for token in query_tokens if token not in _DOC_ROUTER_COMPARISON_OPERATORS]
    concepts: List[str] = []
    seen: Set[str] = set()

    boundary_re = re.compile(
        r"\b(?:of|during|about|regarding|concerning|between|among|versus|vs|against|while|when|where|"
        r"with|without|for|from|into|onto|and|or)\b",
        re.IGNORECASE,
    )
    for part in boundary_re.split(q):
        part_tokens = _doc_router_normalized_query_tokens(part)
        if comparison_intent:
            part_tokens = [token for token in part_tokens if token not in _DOC_ROUTER_COMPARISON_OPERATORS]
        if not part_tokens:
            continue
        phrase = " ".join(part_tokens[:5]).strip()
        if not phrase or phrase in seen:
            continue
        seen.add(phrase)
        concepts.append(phrase)

    if not concepts:
        concepts = list(query_tokens[:6])
    elif len(concepts) == 1 and len(query_tokens) > len(concepts[0].split()):
        for token in query_tokens:
            if token not in seen:
                seen.add(token)
                concepts.append(token)
            if len(concepts) >= 6:
                break

    return concepts[:6], query_tokens


def _doc_router_concept_hit(concept: str, text_l: str) -> bool:
    concept_tokens = [
        _light_normalize_query_token(t)
        for t in re.findall(r"[a-z0-9][a-z0-9'-]*", str(concept or "").lower())
    ]
    concept_tokens = [t for t in concept_tokens if t and t not in _DOC_ROUTER_STOPWORDS]
    if not concept_tokens or not text_l:
        return False
    if len(concept_tokens) > 1:
        phrase_re = r"\b" + r"\s+".join(re.escape(t) for t in concept_tokens) + r"\b"
        if re.search(phrase_re, text_l):
            return True
    token_hits = sum(1 for token in concept_tokens if _token_match_light(text_l, token))
    needed = 1 if len(concept_tokens) <= 2 else max(2, math.ceil(len(concept_tokens) * 0.60))
    return token_hits >= needed


def _doc_router_explicit_multi_source_request(query_text: str) -> bool:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return False
    source_noun = r"(?:documents?|sources?|files?|pdfs?)"
    return bool(
        re.search(rf"\b(?:both|all|each|multiple|several)\s+{source_noun}\b", q)
        or re.search(rf"\b(?:combine|synthesi[sz]e|summari[sz]e|compare|merge)\b.{0,80}\b{source_noun}\b", q)
        or re.search(rf"\bacross\s+{source_noun}\b", q)
    )


def _doc_router_implies_comparison(query_text: str) -> bool:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return False
    return bool(
        re.search(r"\b(?:difference|differences|distinction)\b", q)
        or re.search(r"\b(?:differentiate|distinguish)\s+between\b", q)
        or re.search(r"\b(?:compare|compared|comparison|contrast|contrasts)\b", q)
        or re.search(r"\b(?:relationship|relation)\b.+\bbetween\b.+\band\b", q)
        or re.search(r"\bhow\s+(?:does|do|is|are)\b.+\brelat(?:e|es|ed)\b.+\b(?:to|with)\b", q)
        or re.search(r"\b(?:versus|vs\.?)\b", q)
    )


def _doc_router_query_is_ambiguous(query_text: str, concepts: List[str], query_tokens: List[str], explicit_multi: bool) -> bool:
    if explicit_multi:
        return False
    if not query_tokens:
        return True
    if len(concepts or []) <= 1 and len(query_tokens) <= 2:
        return any(t in _DOC_ROUTER_VAGUE_TERMS for t in query_tokens)
    return False


def _doc_router_interleave_docs(
    doc_dicts: List[Dict[str, Any]],
    selected_sources: List[str],
    per_source_limit: int = 3,
    total_limit: int = 10,
) -> List[Dict[str, Any]]:
    selected_set = set(selected_sources or [])
    grouped: Dict[str, List[Dict[str, Any]]] = defaultdict(list)
    for doc in doc_dicts or []:
        source_key = _doc_router_source_key(doc)
        if source_key in selected_set:
            grouped[source_key].append(doc)

    ordered: List[Dict[str, Any]] = []
    seen_ids: Set[int] = set()
    for round_idx in range(max(1, per_source_limit)):
        for source in selected_sources or []:
            candidates = grouped.get(source) or []
            if round_idx >= len(candidates):
                continue
            doc = candidates[round_idx]
            doc_identity = id(doc)
            if doc_identity in seen_ids:
                continue
            seen_ids.add(doc_identity)
            ordered.append(doc)
            if len(ordered) >= total_limit:
                return ordered
    return ordered


def _route_multi_document_evidence(query_text: str, doc_dicts: List[Dict[str, Any]]) -> Dict[str, Any]:
    safe_docs = _filter_doc_dicts_to_active_sources(doc_dicts or [])
    concepts, query_tokens = _extract_doc_router_query_concepts(query_text)
    explicit_multi = _doc_router_explicit_multi_source_request(query_text)
    comparison_intent = _doc_router_implies_comparison(query_text)

    groups: Dict[str, List[Tuple[int, Dict[str, Any]]]] = defaultdict(list)
    source_display: Dict[str, str] = {}
    for rank, doc in enumerate(safe_docs):
        source_key = _doc_router_source_key(doc)
        if not source_key or source_key == "unknown":
            continue
        groups[source_key].append((rank, doc))
        source_display.setdefault(source_key, _doc_router_display_source(doc, source_key))

    stats: List[Dict[str, Any]] = []
    for source_key, ranked_docs in groups.items():
        scores = [_doc_router_score(doc) for _, doc in ranked_docs]
        group_text_l = "\n".join(_doc_router_text(doc)[:3500] for _, doc in ranked_docs[:8]).lower()
        token_hits = [token for token in query_tokens if _token_match_light(group_text_l, token)]
        concept_hits = [concept for concept in concepts if _doc_router_concept_hit(concept, group_text_l)]
        top_rank = min((rank for rank, _doc in ranked_docs), default=999)
        top_score = max(scores) if scores else 0.0
        avg_score = (sum(scores) / len(scores)) if scores else 0.0
        query_coverage = float(len(token_hits)) / max(1.0, float(len(query_tokens)))
        concept_coverage = float(len(concept_hits)) / max(1.0, float(len(concepts))) if concepts else 0.0
        rank_strength = 1.0 / (1.0 + float(top_rank))
        score_floor = max(0.0, top_score)
        router_score = (
            (3.0 * concept_coverage)
            + (1.5 * query_coverage)
            + (1.2 * rank_strength)
            + (0.20 * min(5.0, math.log1p(len(ranked_docs))))
            + (0.05 * score_floor)
        )
        stats.append({
            "source": source_key,
            "display_source": source_display.get(source_key, source_key),
            "top_score": float(top_score),
            "average_score": float(avg_score),
            "chunk_count": len(ranked_docs),
            "query_coverage": float(query_coverage),
            "concept_coverage": float(concept_coverage),
            "concept_hits": concept_hits,
            "token_hits": token_hits,
            "top_rank": int(top_rank),
            "router_score": float(router_score),
        })

    stats.sort(key=lambda row: (float(row.get("router_score", 0.0)), -int(row.get("top_rank", 999))), reverse=True)
    candidate_sources = [str(row.get("display_source") or row.get("source")) for row in stats]
    source_scores_log = {
        str(row.get("display_source") or row.get("source")): {
            "top_score": round(float(row.get("top_score") or 0.0), 4),
            "average_score": round(float(row.get("average_score") or 0.0), 4),
            "chunks": int(row.get("chunk_count") or 0),
            "query_coverage": round(float(row.get("query_coverage") or 0.0), 3),
            "concept_coverage": round(float(row.get("concept_coverage") or 0.0), 3),
            "concept_hits": list(row.get("concept_hits") or []),
        }
        for row in stats
    }

    mode = "single_source"
    reason = "single active retrieved source"
    selected_sources: List[str] = [str(stats[0].get("source"))] if stats else []

    if not stats:
        mode = "single_source"
        reason = "no verifiable active retrieved sources"
        selected_sources = []
    elif len(stats) == 1:
        mode = "single_source"
        reason = "only one verifiable source after active-source filtering"
    else:
        top = stats[0]
        second = stats[1]
        ambiguous = _doc_router_query_is_ambiguous(query_text, concepts, query_tokens, explicit_multi)
        top_cov = float(top.get("concept_coverage") or 0.0)
        second_cov = float(second.get("concept_coverage") or 0.0)
        top_query_cov = float(top.get("query_coverage") or 0.0)
        second_query_cov = float(second.get("query_coverage") or 0.0)
        top_router = float(top.get("router_score") or 0.0)
        second_router = float(second.get("router_score") or 0.0)
        top_concept_hits = set(top.get("concept_hits") or [])
        second_concept_hits = set(second.get("concept_hits") or [])
        top_token_hits = set(top.get("token_hits") or [])
        second_token_hits = set(second.get("token_hits") or [])

        def _concept_source_score(row: Dict[str, Any], concept: str) -> float:
            source_label = " ".join([
                str(row.get("source") or ""),
                str(row.get("display_source") or ""),
            ]).lower()
            label_bonus = 3.0 if _doc_router_concept_hit(concept, source_label) else 0.0
            return (
                label_bonus
                + (0.35 * float(row.get("top_score") or 0.0))
                + (0.75 * float(row.get("query_coverage") or 0.0))
                + (0.75 * float(row.get("concept_coverage") or 0.0))
                + (0.15 / (1.0 + float(row.get("top_rank") or 999)))
            )

        concept_best_sources: Dict[str, str] = {}
        for concept in concepts:
            concept_candidates = [row for row in stats if concept in set(row.get("concept_hits") or [])]
            if concept_candidates:
                concept_candidates = sorted(
                    concept_candidates,
                    key=lambda row: _concept_source_score(row, concept),
                    reverse=True,
                )
                concept_best_sources[concept] = str(concept_candidates[0].get("source"))
        union_concept_coverage = float(len(concept_best_sources)) / max(1.0, float(len(concepts))) if concepts else 0.0
        best_sources_for_concepts = list(dict.fromkeys(concept_best_sources.values()))
        second_has_meaningful_evidence = bool(
            second_router > 0.0
            and (
                second_cov >= max(0.34, min(0.75, top_cov * 0.70))
                or second_query_cov >= max(0.40, min(0.70, top_query_cov * 0.70))
                or bool(second_concept_hits)
            )
        )
        sources_overlap_query = bool(
            (top_concept_hits & second_concept_hits)
            or (top_token_hits & second_token_hits)
            or (second_cov >= 0.50)
            or (second_query_cov >= 0.50)
        )
        combined_top_two_concept_coverage = (
            float(len(top_concept_hits | second_concept_hits)) / max(1.0, float(len(concepts)))
            if concepts else 0.0
        )
        close_second_source = bool(
            top_router > 0.0
            and second_router >= (top_router * 0.82)
            and second_has_meaningful_evidence
            and sources_overlap_query
        )
        single_concept_competing_sources = bool(
            close_second_source
            and not explicit_multi
            and not comparison_intent
            and len(concepts or []) <= 1
            and len(query_tokens or []) <= 2
            and top_cov >= 0.50
            and second_cov >= 0.50
        )
        comparison_sources_are_strong = bool(
            comparison_intent
            and not ambiguous
            and len(stats) >= 2
            and second_has_meaningful_evidence
            and (
                (
                    len(best_sources_for_concepts) >= 2
                    and union_concept_coverage >= 0.75
                    and top_cov > 0.0
                    and second_cov > 0.0
                )
                or (
                    combined_top_two_concept_coverage >= 0.75
                    and top_cov > 0.0
                    and second_cov > 0.0
                )
                or (
                    close_second_source
                    and top_query_cov >= 0.34
                    and second_query_cov >= 0.34
                )
            )
        )

        if comparison_sources_are_strong:
            if len(best_sources_for_concepts) >= 2 and union_concept_coverage >= 0.75:
                selected_sources = best_sources_for_concepts[:3]
            else:
                selected_sources = [str(row.get("source")) for row in stats[:2]]
            mode = "multi_source_synthesis" if len(selected_sources) > 1 else "single_source"
            reason = "comparison query has two strong active sources with query evidence"
        elif comparison_intent and len(stats) >= 2:
            selected_sources = [str(row.get("source")) for row in stats[:2]]
            mode = "clarification"
            reason = "comparison query lacks two strong grounded source matches"
        elif explicit_multi:
            selected_sources = [str(top.get("source"))]
            mode = "single_source"
            reason = "multi-source request is not a grounded comparison; preserving strongest single-source evidence"
        elif ambiguous and (top_cov <= 0.75 or abs(top_router - second_router) < 1.25) and (second_cov > 0.0 or second_query_cov > 0.0):
            selected_sources = [str(row.get("source")) for row in stats[: min(3, len(stats))]]
            mode = "clarification"
            reason = "ambiguous query with multiple plausible active sources"
        elif top_cov >= 0.75 and (top_cov - second_cov >= 0.34 or top_router >= (second_router * 1.25) or second_query_cov < 0.25):
            selected_sources = [str(top.get("source"))]
            mode = "single_source"
            reason = "one source dominates and covers most query concepts"
        elif top_query_cov >= 0.60 and (top_query_cov - second_query_cov >= 0.35 or top_router >= (second_router * 1.30)):
            selected_sources = [str(top.get("source"))]
            mode = "single_source"
            reason = "one source has the strongest query coverage"
        elif single_concept_competing_sources:
            selected_sources = [str(row.get("source")) for row in stats[:2]]
            mode = "clarification"
            reason = "single-concept query has multiple close active sources"
        elif close_second_source:
            selected_sources = [str(top.get("source"))]
            mode = "single_source"
            reason = "close second source found, but query is not a comparison"
        elif second_cov > 0.0 and top_cov < 0.75 and union_concept_coverage > top_cov:
            selected_sources = [str(top.get("source"))]
            mode = "single_source"
            reason = "multiple sources cover concepts, but query is not a comparison"
        else:
            selected_sources = [str(top.get("source"))]
            mode = "single_source"
            reason = "preserving strongest single-source evidence"

    selected_docs = safe_docs
    if mode == "multi_source_synthesis":
        selected_docs = _doc_router_interleave_docs(safe_docs, selected_sources, per_source_limit=3, total_limit=10)
    elif mode == "single_source" and selected_sources:
        selected_docs = [doc for doc in safe_docs if _doc_router_source_key(doc) == selected_sources[0]]

    selected_display = [source_display.get(src, src) for src in selected_sources]
    logger.info("[DOC ROUTER] candidate_sources=%s", candidate_sources)
    logger.info("[DOC ROUTER] source_scores=%s", json.dumps(source_scores_log, sort_keys=True))
    logger.info("[DOC ROUTER] query_concepts=%s", concepts)
    logger.info("[DOC ROUTER] selected_sources=%s", selected_display)
    logger.info("[DOC ROUTER] mode=%s", mode)
    logger.info("[DOC ROUTER] reason=%s", reason)

    return {
        "mode": mode,
        "reason": reason,
        "query_concepts": concepts,
        "query_tokens": query_tokens,
        "candidate_sources": candidate_sources,
        "selected_sources": selected_sources,
        "selected_display_sources": selected_display,
        "source_scores": source_scores_log,
        "docs": selected_docs,
    }

# ========== ANALYTICS DB ==========
ANALYTICS_DB = str(ANALYTICS_DB)

# ========== FASTAPI APP INSTANCE (must come before decorators) ==========
app = FastAPI(title="Assistify RAG Voice Engine")

# Global aiohttp session for LLM requests (reuse connections)
llm_session: Optional[aiohttp.ClientSession] = None

# Global aiohttp session for TTS requests (reuse connections, avoids TCP
# handshake overhead on every query)
tts_session: Optional[aiohttp.ClientSession] = None

# Global faster-whisper model (typing-safe forward reference)
whisper_model: Optional['WhisperModel'] = None
# Multilingual faster-whisper model — loaded at startup when present, used for Arabic STT
whisper_model_multilingual: Optional['WhisperModel'] = None

# Path to multilingual model (sibling of english model dir)
# "small" (~244M) is used — fast enough on GPU (<0.5s) and much lighter than "medium" on CPU
_MULTILINGUAL_MODEL_PATH = Path(WHISPER_MODEL_PATH).parent / "faster-whisper-small"


def _resolve_multilingual_model_path() -> Path | None:
    """Return the best available multilingual Whisper model path, or None."""
    if _MULTILINGUAL_MODEL_PATH.exists() and any(_MULTILINGUAL_MODEL_PATH.iterdir()):
        return _MULTILINGUAL_MODEL_PATH
    hf_snapshots = _MULTILINGUAL_MODEL_PATH.parent / "models--Systran--faster-whisper-small" / "snapshots"
    if hf_snapshots.exists():
        snapshots = sorted(hf_snapshots.iterdir())
        if snapshots:
            return snapshots[-1]
    return None


def _load_multilingual_whisper_model_if_available() -> bool:
    """Load the multilingual Whisper model for Arabic STT if it is available."""
    global whisper_model_multilingual
    if whisper_model_multilingual is not None:
        return True
    if not WHISPER_AVAILABLE or WhisperModel is None:
        return False

    resolved_path = _resolve_multilingual_model_path()
    if resolved_path is None:
        return False

    try:
        ml_device = "cuda" if torch.cuda.is_available() else "cpu"
        ml_compute = "float16" if ml_device == "cuda" else "int8"
        ml_kwargs: dict[str, Any] = {"device": ml_device, "compute_type": ml_compute, "download_root": None}
        if ml_device == "cpu":
            cpu_threads = int(os.getenv("WHISPER_CPU_THREADS", str(min(os.cpu_count() or 4, 8))))
            ml_kwargs.update({"cpu_threads": cpu_threads, "num_workers": 1})
        whisper_model_multilingual = WhisperModel(str(resolved_path), **ml_kwargs)
        logger.info(
            "✓ Multilingual faster-whisper loaded for Arabic STT (path=%s, device=%s, compute=%s)",
            resolved_path,
            ml_device,
            ml_compute,
        )
        return True
    except Exception as exc:
        logger.warning(
            "Multilingual Whisper model is present but failed to load: %s — Arabic STT will not use English-only fallback",
            exc,
        )
        whisper_model_multilingual = None
        return False

