def _is_simple_factual_text_query(text: str) -> bool:
    cleaned = (text or "").strip().lower()
    if not cleaned:
        return False

    complex_markers = (
        "compare", "different", "perspective", "misconception", "evolved", "contribution",
        "explain",
    )
    if any(m in cleaned for m in complex_markers):
        return False
        
    words = cleaned.split()
    if len(words) > 12 or len(cleaned) > 80:
        return False
        
    factual_starts = (
        "what is", "what are", "who", "when", "where", "define", "list", "capital of", "give", "name", "ما هو", "من هو", "متى"
    )
    return cleaned.startswith(factual_starts)


def _detect_fact_query_type(query_text: str) -> str | None:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return None
    if _is_compare_query(q):
        return None
    if _is_targeted_list_question(q):
        return None
    has_who = bool(re.search(r"\bwho\b", q) or re.search(r"\bwho\s+(?:was|is|established|proposed|developed|founded|introduced)\b", q))
    has_when = bool(re.search(r"\b(?:when|in\s+what\s+year|what\s+year|which\s+year|on\s+what\s+date)\b", q))
    if has_who and has_when:
        return "who_when"
    if has_who:
        return "who"
    if has_when:
        return "when"
    if re.search(r"\bwhich\b", q):
        return "which"
    if re.search(r"\bwhere\b", q):
        return "where"
    return None


def _build_strict_fact_system_prompt(fact_type: str | None, allow_multi_chunk: bool = False) -> str:
    if allow_multi_chunk:
        base_prompt = (
            "You are extracting factual answers using multiple pieces of context.\n\n"
            "The answer may require combining information from different parts.\n"
            "Answer ONLY using the provided context.\n\n"
            "Return ONLY the final answer:\n"
            "- For WHO → return only the person name\n"
            "- For WHEN → return only the year\n\n"
            "Do NOT explain.\n"
            "Do NOT add extra text.\n\n"
            "If the answer cannot be confidently derived:\n"
            "return exactly:\n"
            "Not found in the document."
        )
    else:
        base_prompt = (
            "You are extracting factual answers.\n\n"
            "Answer ONLY using the provided context.\n\n"
            "Return ONLY the final answer:\n"
            "- For WHO → return only the person name\n"
            "- For WHEN → return only the year\n\n"
            "Do NOT explain.\n"
            "Do NOT add extra text.\n\n"
            "If the answer is not clearly present:\n"
            "return exactly:\n"
            "Not found in the document."
        )
    if fact_type == "who":
        return base_prompt + "\n\nExpected output format: a person name only."
    if fact_type == "when":
        return base_prompt + "\n\nExpected output format: a 4-digit year only."
    if fact_type == "who_when":
        return base_prompt + "\n\nExpected output format: Person Name, 4-digit year."
    return base_prompt


def _infer_fact_context_mode_from_docs(docs: list[dict]) -> str:
    for d in (docs or []):
        mode = str((d or {}).get("_fact_context_mode") or "").strip().lower()
        if mode in {"strict_relation", "multi_chunk"}:
            return mode
    return "strict_relation"


def _extract_multichunk_who_candidate(query_text: str, docs: list[dict]) -> Optional[str]:
    q_raw = re.sub(r"\s+", " ", str(query_text or "").strip())
    q_low = q_raw.lower()
    if not q_low or ("model" not in q_low and not re.search(r"\b[A-Z]{2,}\b", q_raw)):
        return None

    subject_terms = _extract_relation_subject_terms(q_raw, "who")
    if not subject_terms:
        return None

    subject_doc_idxs: list[int] = []
    for idx, d in enumerate(docs or []):
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
        low = txt.lower()
        if any(re.search(rf"\b{re.escape(tok)}\b", low) for tok in subject_terms):
            subject_doc_idxs.append(idx)

    if not subject_doc_idxs:
        return None

    def _normalize_name(name: str) -> str:
        parts = [p for p in re.findall(r"[A-Za-z]+", str(name or "")) if p]
        if len(parts) < 2:
            return ""
        bad_tokens = {
            "that", "this", "these", "those", "about", "other", "people", "objects", "events",
            "behaviors", "beliefs", "model", "models", "theory", "approach",
        }
        if any(p.lower() in bad_tokens for p in parts):
            return ""
        use = parts[:4]
        return " ".join(p.capitalize() for p in use)

    patterns = [
        re.compile(
            r"\b(?:developed|proposed|introduced|established|founded|created|coined)\s+by\s+([A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){1,3})\b",
            flags=re.IGNORECASE,
        ),
        re.compile(
            r"\b([A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){1,3})\b.{0,64}\b(?:developed|proposed|introduced|established|founded|created|coined)\b",
            flags=re.IGNORECASE,
        ),
    ]

    candidates: list[tuple[int, str]] = []
    for idx, d in enumerate(docs or []):
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
        if not txt.strip():
            continue
        for pat in patterns:
            for m in pat.finditer(txt):
                name = _normalize_name(m.group(1) or "")
                if re.fullmatch(r"[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}", name):
                    candidates.append((idx, name))

    if not candidates:
        return None

    best_name = None
    best_distance = 10**9
    for c_idx, c_name in candidates:
        local_best = min(abs(c_idx - s_idx) for s_idx in subject_doc_idxs)
        if local_best < best_distance:
            best_distance = local_best
            best_name = c_name

    return best_name


def _normalize_validated_fact_answer(fact_type: str | None, answer_text: str) -> str:
    candidate = re.sub(r"\s+", " ", str(answer_text or "")).strip(" .,:;!?")
    if not candidate:
        return RAG_NO_MATCH_RESPONSE

    no_match_norm = re.sub(r"\s+", " ", str(RAG_NO_MATCH_RESPONSE or "")).strip(" .,:;!?").lower()
    if candidate.lower() == no_match_norm:
        return RAG_NO_MATCH_RESPONSE

    if fact_type == "who":
        if re.fullmatch(r"[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}", candidate):
            return candidate
        return RAG_NO_MATCH_RESPONSE

    if fact_type == "when":
        y = re.search(r"\b(1[5-9]\d{2}|20\d{2})\b", candidate)
        return y.group(1) if y else RAG_NO_MATCH_RESPONSE

    if fact_type == "who_when":
        cleaned = re.sub(r"\b(?:\d\s+){3,}\d\b", lambda m: re.sub(r"\s+", "", m.group(0)), candidate)
        cleaned = re.sub(r"\s+", " ", cleaned).strip(" .,:;!?")
        year_match = re.search(r"\b(1[5-9]\d{2}|20\d{2})\b", cleaned)
        if not year_match:
            return RAG_NO_MATCH_RESPONSE
        year = year_match.group(1)
        name_match = re.search(r"\b([A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,2})\b", cleaned)
        if not name_match:
            return RAG_NO_MATCH_RESPONSE
        person = re.sub(r"\s+", " ", name_match.group(1)).strip(" .,:;!?")
        if not re.fullmatch(r"[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,2}", person):
            return RAG_NO_MATCH_RESPONSE
        return f"{person}, {year}"

    return candidate


def _build_compact_fact_context_docs(query_text: str, docs: list[dict], max_snippets: int = FACT_CONTEXT_MAX_SNIPPETS, max_chars: int = FACT_CONTEXT_MAX_CHARS) -> list[dict]:
    if not docs:
        return []

    q = re.sub(r"\s+", " ", str(query_text or "")).strip().lower()
    fact_type = _detect_fact_query_type(query_text)
    stop = {
        "what", "which", "who", "when", "where", "is", "was", "were", "the", "a", "an", "of", "in", "on", "at", "to", "for", "and", "or", "by", "it", "year",
    }
    q_terms = [t for t in re.findall(r"[a-z0-9]{3,}", q) if t not in stop]
    if not q_terms:
        q_terms = [t for t in re.findall(r"[a-z0-9]{3,}", q)]

    candidates: list[tuple[float, str, dict]] = []
    for d in (docs or [])[:8]:
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
        if not txt.strip():
            continue
        for sent in [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", txt) if str(s or "").strip()]:
            if len(sent) < 20 or len(sent) > 280:
                continue
            low = sent.lower()
            token_hits = sum(1 for t in q_terms if re.search(rf"\b{re.escape(t)}\b", low))
            if token_hits <= 0:
                continue
            score = float(token_hits)
            if fact_type in {"who", "who_when"} and re.search(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,2}\b", sent):
                score += 1.8
            if fact_type in {"when", "who_when"} and re.search(r"\b(1[5-9]\d{2}|20\d{2})\b", sent):
                score += 1.8
            if re.search(r"\b(?:established|founded|proposed|developed|introduced|created|coined)\b", low):
                score += 0.8
            candidates.append((score, sent, d))

    if not candidates:
        fallback_docs = []
        for d in (docs or [])[: max(1, min(2, max_snippets))]:
            raw = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not raw.strip():
                continue
            trimmed = raw[: min(320, max_chars)]
            d2 = dict(d or {})
            d2["page_content"] = trimmed
            d2["text"] = trimmed
            fallback_docs.append(d2)
        return fallback_docs

    candidates.sort(key=lambda x: x[0], reverse=True)
    selected: list[dict] = []
    seen_sent: set[str] = set()
    total_chars = 0
    for _score, sent, base_doc in candidates:
        norm = re.sub(r"\s+", " ", sent).strip().lower()
        if norm in seen_sent:
            continue
        if len(selected) >= max_snippets:
            break
        if total_chars + len(sent) > max_chars:
            break
        seen_sent.add(norm)
        total_chars += len(sent)
        d2 = dict(base_doc or {})
        d2["page_content"] = sent
        d2["text"] = sent
        selected.append(d2)

    return selected


def _extract_fact_from_context(query: str, context_chunks: List[str]) -> Optional[str]:
    fact_type = _detect_fact_query_type(query)

    def _is_compact_fact_answer(text: str) -> bool:
        if not fact_type:
            return False
        s = re.sub(r"\s+", " ", str(text or "")).strip(" .,:;!?\"'")
        if not s:
            return False

        person_like = bool(re.fullmatch(r"[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}", s))
        year_like = bool(re.fullmatch(r"(?:1[5-9]\d{2}|20\d{2})", s))
        date_like = bool(
            re.fullmatch(
                r"(?:jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|aug(?:ust)?|sep(?:tember)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)\s+\d{1,2},?\s+\d{4}",
                s,
                flags=re.IGNORECASE,
            )
        )
        location_like = bool(re.fullmatch(r"[A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){0,5}(?:,\s*[A-Z][A-Za-z]+)?", s))

        if fact_type == "when":
            return year_like or date_like
        if fact_type == "who":
            return person_like
        if fact_type == "who_when":
            return person_like and bool(re.search(r"\b(?:1[5-9]\d{2}|20\d{2})\b", s))
        if fact_type == "where":
            return location_like
        if fact_type == "which":
            return len(re.findall(r"[A-Za-z][A-Za-z\-']*", s)) <= 8 and not re.search(r"\b(?:is|are|was|were|means|refers|defines|describes)\b", s, flags=re.IGNORECASE)
        return False
    if not fact_type:
        return None

    q_low = re.sub(r"\s+", " ", str(query or "").strip().lower())
    is_who_when_query = fact_type == "who_when"
    subject_terms = _extract_relation_subject_terms(query, fact_type)
    query_terms = [t for t in re.findall(r"[a-z0-9]{3,}", q_low) if t not in {"what", "which", "who", "when", "where", "why", "how", "the", "a", "an", "of", "in", "on", "at", "to", "for", "from", "and", "or", "by", "it", "its", "is", "are", "was", "were", "year", "date", "time"}]

    person_name_re = re.compile(r"\b([A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3})\b")
    verb_person_re = re.compile(
        r"\b([A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3})(?:\s+in\s+[A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){0,2})?\s+(?:has\s+)?(?:established|proposed|developed|founded|introduced|created|coined)\b"
    )
    passive_person_re = re.compile(
        r"\b(?:established|proposed|developed|founded|introduced|created|coined)\s+by\s+([A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3})\b",
        flags=re.IGNORECASE,
    )
    father_re = re.compile(r"\b([A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3})\s+(?:is\s+)?(?:considered\s+)?the\s+father\s+of\b", flags=re.IGNORECASE)
    year_re = re.compile(r"\b(1[5-9]\d{2}|20\d{2})\b")
    date_re = re.compile(r"\b(?:on\s+)?((?:jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|aug(?:ust)?|sep(?:tember)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)\s+\d{1,2},?\s+\d{4})\b", flags=re.IGNORECASE)
    where_re = re.compile(r"\b(?:in|at|from)\s+([A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){0,4}(?:,\s*[A-Z][A-Za-z]+)?)\b")

    disallowed_name_tokens = {
        "Table", "Figure", "Chapter", "Unit", "Theory", "Model", "Approach", "Document", "Contents",
        "Germany", "England", "France", "Greek", "Greece", "Leipzig", "Brain", "Mind",
        "Known", "As", "Thought", "Copyright", "Virtual", "University", "Prevalent", "Models", "Observational", "Learning",
        "Introduction", "Lesson", "Given", "Schools", "School",
    }

    def _is_ocr_noisy(sentence: str) -> bool:
        s = str(sentence or "")
        if not s.strip():
            return True
        alnum = len(re.findall(r"[A-Za-z0-9]", s))
        junk = len(re.findall(r"[^A-Za-z0-9\s.,;:'\"()\-]", s))
        singletons = len(re.findall(r"\b[a-zA-Z]\b", s))
        if alnum <= 6:
            return True
        if junk > max(5, int(0.22 * max(1, len(s)))):
            return True
        if singletons >= 5:
            return True
        return False

    def _is_complete_sentence(sentence: str) -> bool:
        s = re.sub(r"\s+", " ", str(sentence or "")).strip()
        word_count = len(re.findall(r"\b\w+\b", s))
        if word_count < 4:
            return False
        if re.search(r"[.!?]$", s):
            return True
        return word_count >= 7

    def _keyword_overlap_score(sentence_low: str) -> float:
        if not query_terms:
            return 0.0
        hits = 0
        for tok in query_terms:
            if re.search(rf"\b{re.escape(tok)}\b", sentence_low):
                hits += 1
        return float(hits) / float(max(1, len(query_terms)))

    def _token_hit(sentence_low: str, tok: str) -> bool:
        if re.search(rf"\b{re.escape(tok)}\b", sentence_low):
            return True
        if len(tok) >= 5:
            root = re.escape(tok[:5])
            if re.search(rf"\b{root}[a-z]*\b", sentence_low):
                return True
        return False

    def _subject_hit_count(sentence_low: str) -> int:
        return sum(1 for tok in subject_terms if re.search(rf"\b{re.escape(tok)}\b", sentence_low))

    def _verb_hit_count(sentence_low: str) -> int:
        return sum(
            1
            for pat in (
                r"\bproposed\b",
                r"\bdeveloped\b",
                r"\bintroduced\b",
                r"\bestablished\b",
                r"\bfounded\b",
                r"\bcreated\b",
                r"\bcoined\b",
                r"\bconsidered\b",
                r"\bformed\b",
                r"\bstarted\b",
                r"\boriginated\b",
                r"\bemerged\b",
            )
            if re.search(pat, sentence_low)
        )

    def _cleanup_ocr_for_fact_text(raw_text: str) -> str:
        s = re.sub(r"\s+", " ", str(raw_text or "")).strip()
        if not s:
            return s

        # Join spaced digit runs like "1 8 7 9" -> "1879"
        s = re.sub(r"\b(?:\d\s+){3,}\d\b", lambda m: re.sub(r"\s+", "", m.group(0)), s)

        no_join_heads = {"In", "On", "At", "Of", "For", "And", "The", "A", "An", "Who", "When", "What", "Where"}
        no_join_tails = {"in", "of", "and", "by", "to", "for", "from", "the", "on", "at", "with", "as"}

        def _join_cap_split(m: re.Match) -> str:
            left = str(m.group(1) or "")
            right = str(m.group(2) or "")
            if left in no_join_heads:
                return f"{left} {right}"
            if right.lower() in no_join_tails:
                return f"{left} {right}"
            return f"{left}{right}"

        # Join OCR-split name fragments using capitalization shape only.
        s = re.sub(r"\b([A-Z][a-z]{1,4})\s+([a-z]{2,5})\b", _join_cap_split, s)
        # Join OCR-split surname fragments using capitalization shape only.
        s = re.sub(r"\b([A-Z])\s+([a-z]{2,5})\s+([a-z])\b", lambda m: f"{m.group(1)}{m.group(2)}{m.group(3)}", s)
        s = re.sub(r"\s+", " ", s).strip()
        return s

    def _normalize_person_name(name: str) -> str:
        parts = [p for p in re.findall(r"[A-Za-z]+", str(name or "")) if p]

        # Merge OCR-split fragments in names (generic, length-constrained)
        merged: List[str] = []
        i = 0
        while i < len(parts):
            tok = parts[i]
            if (
                i + 1 < len(parts)
                and tok[0].isupper()
                and tok[1:].islower()
                and len(tok) <= 4
                and parts[i + 1].islower()
                and 2 <= len(parts[i + 1]) <= 5
            ):
                combined = tok + parts[i + 1]
                i += 2
                if i < len(parts) and parts[i].islower() and len(parts[i]) == 1:
                    combined += parts[i]
                    i += 1
                merged.append(combined)
                continue
            if len(tok) == 1 and tok.islower() and merged:
                merged[-1] += tok
                i += 1
                continue
            merged.append(tok)
            i += 1

        parts = merged
        deduped: List[str] = []
        for p in parts:
            if not deduped or deduped[-1].lower() != p.lower():
                deduped.append(p)
        filtered = [w for w in deduped if w.capitalize() not in disallowed_name_tokens]
        use = filtered if filtered else deduped
        if len(use) > 3:
            use = use[-3:]
        return " ".join(w.capitalize() for w in use)

    def _person_candidate_rejection_reason(name: str) -> str | None:
        n = re.sub(r"\s+", " ", str(name or "")).strip(" .,:;!?")
        if not n:
            return "empty"
        parts = n.split()
        lowered = [p.lower() for p in parts]

        if len(parts) < 1 or len(parts) > 3:
            return "token_count"
        if len(parts) == 1 and len(parts[0]) < 4:
            return "single_token_too_short"
        if not all(re.match(r"^[A-Z][a-z]+$", p) for p in parts):
            return "name_shape"

        if any(p in disallowed_name_tokens for p in parts):
            return "disallowed_token"

        header_or_title_words = {
            "emergence", "schools", "thought", "important", "terminology", "introduction", "overview", "summary",
            "chapter", "lesson", "table", "figure", "contents", "model", "theory", "approach",
        }
        function_words = {"of", "and", "the", "in", "on", "for", "to", "from", "by", "with", "as"}

        if any(t in function_words for t in lowered):
            return "function_word_in_name"
        if any(t in header_or_title_words for t in lowered):
            return "header_word"
        if len(set(lowered)) < len(lowered):
            return "repeated_tokens"

        return None

    def _is_valid_person_name(name: str) -> bool:
        return _person_candidate_rejection_reason(name) is None

    def _validate_candidate(ftype: str, candidate: str) -> bool:
        c = re.sub(r"\s+", " ", str(candidate or "")).strip(" .,:;!?")
        if not c:
            return False
        if ftype == "who":
            rejection_reason = _person_candidate_rejection_reason(c)
            if rejection_reason:
                logger.info("[FACT PERSON VALIDATOR] action=reject candidate=%s reason=%s", c, rejection_reason)
                return False
            return True
        if ftype == "when":
            return bool(re.fullmatch(r"(?:1[5-9]\d{2}|20\d{2})", c) or date_re.search(c))
        if ftype == "where":
            return bool(re.match(r"^[A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){0,5}(?:,\s*[A-Z][A-Za-z]+)?$", c))
        if ftype == "which":
            if len(re.findall(r"\w+", c)) < 1:
                return False
            if _is_ocr_noisy(c):
                return False
            return True
        return False

    chunks = [str(c or "") for c in (context_chunks or []) if str(c or "").strip()]
    logger.info("[FACT EXTRACTION] type=%s query=%s total_chunks=%s", fact_type, (query or "")[:180], len(chunks))
    if not chunks:
        return None

    candidates: List[Dict[str, Any]] = []
    for chunk_idx, chunk in enumerate(chunks):
        chunk_clean = _cleanup_ocr_for_fact_text(chunk)
        if chunk_clean != chunk:
            logger.info(
                "[FACT OCR CLEANUP] chunk=%s applied=True before=%s after=%s",
                chunk_idx,
                re.sub(r"\s+", " ", chunk)[:120],
                re.sub(r"\s+", " ", chunk_clean)[:120],
            )
        sentences = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", chunk_clean) if str(s or "").strip()]
        for sent in sentences:
            s = _cleanup_ocr_for_fact_text(sent)
            s = re.sub(r"\s+", " ", s).strip()
            if len(s) < 8 or len(s) > 360:
                continue
            if _is_ocr_noisy(s):
                continue
            sl = s.lower()
            overlap = _keyword_overlap_score(sl)
            completeness_bonus = 0.35 if _is_complete_sentence(s) else 0.0
            clarity_bonus = 0.3 if not _is_ocr_noisy(s) else -1.2

            if fact_type in {"who", "who_when"}:
                requires_attribution_verb = bool(re.search(r"\b(established|proposed|developed|founded|introduced)\b", q_low))
                founder_query = bool(re.search(r"\bfounder\s+of\b", q_low))
                verb_hits = _verb_hit_count(sl)
                if requires_attribution_verb and verb_hits == 0 and not re.search(r"\bfather\s+of\b", sl):
                    continue

                who_patterns = [
                    verb_person_re,
                    passive_person_re,
                    re.compile(
                        r"\b([A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3})\b[^.\n]{0,120}\b(?:founder|creator|originator|establisher)\b",
                        flags=re.IGNORECASE,
                    ),
                ]
                for pat in who_patterns:
                    for m in pat.finditer(s):
                        cand_name = _normalize_person_name((m.group(1) or "").strip())
                        if _validate_candidate("who", cand_name):
                            candidates.append({
                                "type": "who",
                                "candidate": cand_name,
                                "score": 6.0 + (2.5 * _keyword_overlap_score(sl)) + (0.6 * float(_subject_hit_count(sl))) + (0.8 * float(verb_hits)) + completeness_bonus + clarity_bonus,
                                "sentence": s,
                                "chunk_idx": chunk_idx,
                            })

            if fact_type in {"when", "who_when"}:
                subj_hits = _subject_hit_count(sl)
                verb_hits = _verb_hit_count(sl)
                years = [m.group(1) for m in year_re.finditer(s)]
                dates = [m.group(1) for m in date_re.finditer(s)]
                for y in years:
                    if not _validate_candidate("when", y):
                        continue
                    if re.search(r"\b\d{4}\s*[-–]\s*\d{4}\b", s) or re.search(r"\(\s*\d{4}\s*[-–]", s):
                        continue
                    score = 2.0 + (2.0 * overlap) + completeness_bonus + clarity_bonus + (1.1 * float(subj_hits))
                    score += 0.8 * float(verb_hits)
                    if "emerge" in q_low:
                        if re.search(r"\b(emerge|emerged|emergence|began|started)\b", sl):
                            score += 1.8
                        elif re.search(r"\b(founded|introduced|originated)\b", sl):
                            score += 0.7
                        else:
                            score -= 0.8
                    if re.search(r"\b(in|established|founded|founded\s+in|was\s+founded\s+in|emerged|happened)\b", sl):
                        score += 1.0
                    candidates.append({
                        "type": "when",
                        "candidate": y,
                        "score": float(score),
                        "sentence": s,
                        "chunk_idx": chunk_idx,
                    })
                for dt in dates:
                    c = re.sub(r"\s+", " ", dt).strip(" .")
                    if not _validate_candidate("when", c):
                        continue
                    score = 2.2 + (2.0 * overlap) + completeness_bonus + clarity_bonus
                    candidates.append({
                        "type": "when",
                        "candidate": c,
                        "score": float(score),
                        "sentence": s,
                        "chunk_idx": chunk_idx,
                    })

            elif fact_type == "where":
                for m in where_re.finditer(s):
                    loc = re.sub(r"\s+", " ", m.group(1)).strip(" .,:;!?")
                    if not _validate_candidate("where", loc):
                        continue
                    score = 1.9 + (2.0 * overlap) + completeness_bonus + clarity_bonus
                    candidates.append({
                        "type": "where",
                        "candidate": loc,
                        "score": float(score),
                        "sentence": s,
                        "chunk_idx": chunk_idx,
                    })

            elif fact_type == "which":
                which_entity_re = re.compile(r"\b([A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){0,4}(?:\s+(?:theory|model|approach|school|method))?)\b")
                for m in which_entity_re.finditer(s):
                    ent = re.sub(r"\s+", " ", m.group(1)).strip(" .,:;!?")
                    if not _validate_candidate("which", ent):
                        continue
                    score = 1.4 + (2.4 * overlap) + completeness_bonus + clarity_bonus
                    if re.search(r"\b(theory|model|approach|school|method)\b", ent.lower()):
                        score += 0.9
                    candidates.append({
                        "type": "which",
                        "candidate": ent,
                        "score": float(score),
                        "sentence": s,
                        "chunk_idx": chunk_idx,
                    })

    if not candidates:
        logger.info("[FACT EXTRACTION] no_candidates type=%s query=%s", fact_type, (query or "")[:180])
        return None

    candidates.sort(key=lambda c: float(c.get("score") or 0.0), reverse=True)
    top_candidates = candidates[:6]
    logger.info("[FACT EXTRACTION] candidates_count=%s type=%s", len(candidates), fact_type)
    for idx, cand in enumerate(top_candidates, start=1):
        logger.info(
            "[FACT CANDIDATE] rank=%s type=%s chunk=%s score=%.3f candidate=%s sentence=%s",
            idx,
            cand.get("type"),
            cand.get("chunk_idx"),
            float(cand.get("score") or 0.0),
            str(cand.get("candidate") or "")[:120],
            str(cand.get("sentence") or "")[:220],
        )

    if fact_type == "who_when":
        who_best = next((c for c in top_candidates if c.get("type") == "who" and _validate_candidate("who", str(c.get("candidate") or ""))), None)
        when_best = next((c for c in top_candidates if c.get("type") == "when" and _validate_candidate("when", str(c.get("candidate") or ""))), None)
        if who_best and when_best:
            who_val = re.sub(r"\s+", " ", str(who_best.get("candidate") or "")).strip(" .,:;!?")
            when_val = re.sub(r"\s+", " ", str(when_best.get("candidate") or "")).strip(" .,:;!?")
            combined = f"{who_val}, {when_val}"
            logger.info(
                "[FACT DECISION] type=%s final=%s who_score=%.3f when_score=%.3f",
                fact_type,
                combined,
                float(who_best.get("score") or 0.0),
                float(when_best.get("score") or 0.0),
            )
            logger.info("[FACT ACCEPTED] value=%s", combined)
            return combined
        logger.info("[FACT EXTRACTION] best_candidate_rejected type=%s candidate=%s", fact_type, "missing_who_or_when")
        return None

    best = next((c for c in top_candidates if c.get("type") == fact_type), top_candidates[0])
    chosen = re.sub(r"\s+", " ", str(best.get("candidate") or "")).strip(" .,:;!?")
    if not _validate_candidate(fact_type, chosen):
        logger.info("[FACT EXTRACTION] best_candidate_rejected type=%s candidate=%s", fact_type, chosen)
        return None

    logger.info("[FACT DECISION] type=%s final=%s score=%.3f chunk=%s", fact_type, chosen, float(best.get("score") or 0.0), best.get("chunk_idx"))
    logger.info("[FACT ACCEPTED] value=%s", chosen)
    return chosen


def _rewrite_query_for_retrieval(query_text: str) -> str:
    # Disabled: preserve original user query exactly (no rewriting/injection).
    return query_text

def _extract_confident_factual_answer(query_text: str, retrieved_docs: list[dict]) -> str | None:
    return None


def _has_english_keyword_overlap(query_text: str, retrieved_docs: list[dict]) -> bool:
    """Return True when there is partial lexical overlap between query and retrieved context."""
    if not query_text or not retrieved_docs:
        return False

    stopwords = {
        "what", "which", "who", "when", "where", "why", "how", "the", "this", "that", "these", "those",
        "is", "are", "was", "were", "be", "to", "of", "in", "on", "for", "and", "or", "with", "from",
        "a", "an", "do", "does", "did", "can", "could", "should", "would", "about", "main", "only",
        "list", "explain", "define", "tell", "me",
    }
    tokens = [t for t in re.findall(r"[a-zA-Z]{3,}", (query_text or "").lower()) if t not in stopwords]
    if not tokens:
        return True

    corpus = "\n".join(str((d or {}).get("text") or "") for d in retrieved_docs).lower()
    def _variants(tok: str) -> set[str]:
        roots = {tok}
        for suf in ("ing", "ed", "es", "s", "ly", "ment", "tion", "al", "ical", "y"):
            if tok.endswith(suf) and len(tok) - len(suf) >= 4:
                roots.add(tok[: -len(suf)])
        return {r for r in roots if len(r) >= 3}

    matched = 0
    for tok in tokens:
        variants = _variants(tok)
        found = False
        for var in variants:
            if re.search(rf"\b{re.escape(var)}[a-z]*\b", corpus):
                found = True
                break
        if found:
            matched += 1

    if len(tokens) <= 4:
        return matched >= 1
    return matched >= 2


def _passes_hybrid_relevance_gate(query_text: str, retrieved_docs: list[dict]) -> bool:
    """Hybrid relevance gate: allow context-driven intents; reject only clear misses."""
    if not retrieved_docs:
        return False
    if _is_overview_query(query_text):
        return _has_meaningful_context(retrieved_docs)
    if _query_requires_structure(query_text):
        return _docs_have_structure_markers(retrieved_docs) or _has_meaningful_context(retrieved_docs)
    max_sim = _max_doc_similarity(retrieved_docs)
    
    # If reranked, trust the top candidate more even if semantic similarity is lower
    # (CrossEncoder often pulls up good chunks with low initial vector similarity)
    has_rerank_score = any("rerank_score" in d for d in retrieved_docs)
    if has_rerank_score:
        top_score = retrieved_docs[0].get("rerank_score", -999)
        if top_score > 0.0:  # CrossEncoder score > 0 is generally a decent signal
            return True

    semantic_ok = max_sim >= RAG_HYBRID_SEMANTIC_THRESHOLD
    lexical_ok = _has_english_keyword_overlap(query_text, retrieved_docs)
    return semantic_ok or lexical_ok


def _max_doc_similarity(retrieved_docs: list[dict]) -> float:
    if not retrieved_docs:
        return 0.0
    sims = []
    for d in retrieved_docs:
        sim = d.get("similarity", d.get("score", 0.0))
        try:
            sims.append(float(sim))
        except Exception:
            continue
    return max(sims) if sims else 0.0


def _query_requires_structure(query_text: str) -> bool:
    q = (query_text or "").strip().lower()
    if not q:
        return False
    if re.search(r"\blist\b", q):
        return True
    if re.match(r"^\s*(?:what|which)\s+are\b", q):
        return True
    if re.search(r"\b(?:chapter|section|unit|module|lesson|table of contents|contents|topics)\b", q):
        return True
    return False


def _is_overview_query(query_text: str) -> bool:
    q = (query_text or "").strip().lower()
    if not q:
        return False
    overview_markers = (
        "what is this document about",
        "what is this book about",
        "document about",
        "book about",
        "tell me about",
        "explain",
        "overview",
        "summary",
        "summarize",
        "main ideas",
        "topics covered",
        "purpose of this document",
    )
    if any(m in q for m in overview_markers):
        return True
    corrected = _lightweight_spelling_correction(q)
    if corrected and corrected != q:
        return any(m in corrected for m in overview_markers)
    return False


def _is_force_overview_paragraph_query(query_text: str) -> bool:
    q = (query_text or "").strip().lower()
    if not q:
        return False
    force_markers = ("tell me about", "explain", "overview")
    if any(m in q for m in force_markers):
        return True
    corrected = _lightweight_spelling_correction(q)
    if corrected and corrected != q:
        return any(m in corrected for m in force_markers)
    return False


def _lightweight_spelling_correction(query_text: str, seed_docs: list[dict] | None = None) -> str:
    q = str(query_text or "")
    logger.info("[FLOW] entering _lightweight_spelling_correction")
    logger.info("[FLOW] query_before = %s", (q or "")[:400])
    if not q.strip():
        return q

    query_core_vocab = {
        "what", "who", "define", "tell", "about", "explain", "overview", "summary",
        "chapter", "section", "list", "compare", "difference", "between", "process",
        "general", "meaning", "definition", "introduced", "known",
        "when", "year",
    }

    preserve_short_terms = set()

    def _edit_distance_leq(word_a: str, word_b: str, cap: int = 2) -> int:
        if word_a == word_b:
            return 0
        la, lb = len(word_a), len(word_b)
        if abs(la - lb) > cap:
            return cap + 1
        prev = list(range(lb + 1))
        for i, ca in enumerate(word_a, start=1):
            cur = [i] + [0] * lb
            row_min = cur[0]
            for j, cb in enumerate(word_b, start=1):
                cost = 0 if ca == cb else 1
                cur[j] = min(
                    prev[j] + 1,
                    cur[j - 1] + 1,
                    prev[j - 1] + cost,
                )
                if cur[j] < row_min:
                    row_min = cur[j]
            if row_min > cap:
                return cap + 1
            prev = cur
        return prev[lb]

    def _build_dynamic_vocab() -> tuple[set[str], Dict[str, int], Dict[str, list[str]], Dict[str, str]]:
        vocab_counter: Counter = Counter()
        source_map: Dict[str, str] = {}
        for tok in query_core_vocab:
            vocab_counter[tok] += 1
            source_map[tok] = "query_terms"

        cached_payload = getattr(_lightweight_spelling_correction, "_doc_vocab_cache", None)
        cache_key = None

        try:
            collection = getattr(getattr(live_rag, "vs", None), "collection", None)
            if collection is not None:
                collection_name = str(getattr(collection, "name", "") or "")
                try:
                    collection_count = int(collection.count())
                except Exception:
                    collection_count = 0
                cache_key = (collection_name, collection_count)
                if isinstance(cached_payload, dict) and cached_payload.get("key") == cache_key:
                    doc_freq = cached_payload.get("freq") or {}
                    for tok, freq in doc_freq.items():
                        if isinstance(tok, str):
                            vocab_counter[tok] += int(freq or 0)
                            source_map.setdefault(tok, "document_vocab")
                else:
                    payload = collection.get(include=["documents", "metadatas"], limit=min(max(collection_count, 1), 5000))
                    docs_blob = payload.get("documents") if isinstance(payload, dict) else None
                    metas_blob = payload.get("metadatas") if isinstance(payload, dict) else None
                    docs: list[str] = []
                    if isinstance(docs_blob, list):
                        for entry in docs_blob:
                            if isinstance(entry, str):
                                docs.append(entry)
                            elif isinstance(entry, list):
                                docs.extend(str(x) for x in entry if isinstance(x, str))
                    if isinstance(metas_blob, list):
                        for meta in metas_blob:
                            if isinstance(meta, dict):
                                docs.append(" ".join(str(v) for v in meta.values() if isinstance(v, (str, int, float))))
                    doc_counter: Counter = Counter()
                    for doc in docs:
                        for tok in re.findall(r"[a-z]{4,22}", doc.lower()):
                            doc_counter[tok] += 1
                    for tok, freq in doc_counter.items():
                        vocab_counter[tok] += freq
                        source_map.setdefault(tok, "document_vocab")
                    try:
                        setattr(_lightweight_spelling_correction, "_doc_vocab_cache", {"key": cache_key, "freq": dict(doc_counter)})
                    except Exception:
                        pass
        except Exception:
            pass

        for d in (seed_docs or [])[:4]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")[:3000]
            for tok in re.findall(r"[a-z]{4,22}", txt.lower()):
                vocab_counter[tok] += 1
                source_map[tok] = "retrieved_terms"

        filtered_vocab = {
            tok for tok, freq in vocab_counter.items()
            if len(tok) >= 4 and (freq >= 2 or tok in query_core_vocab)
        }
        if not filtered_vocab:
            filtered_vocab = set(query_core_vocab)

        by_initial: Dict[str, list[str]] = defaultdict(list)
        for tok in filtered_vocab:
            by_initial[tok[0]].append(tok)
        return filtered_vocab, dict(vocab_counter), by_initial, source_map

    vocab, freq_map, by_initial, source_map = _build_dynamic_vocab()

    q_low = re.sub(r"\s+", " ", q.strip().lower())
    list_query_mode = bool(
        _is_targeted_list_question(q_low)
        or re.match(r"^\s*(?:what|which)\s+are\b", q_low)
    )

    correction_events: list[dict] = []

    def _case_like(original: str, replacement: str) -> str:
        if original.isupper():
            return replacement.upper()
        if original[:1].isupper():
            return replacement.capitalize()
        return replacement

    def _is_inflection_only_variant(original: str, candidate: str) -> bool:
        original_low = str(original or "").lower()
        candidate_low = str(candidate or "").lower()
        if len(original_low) < 4 or len(candidate_low) < 4 or original_low == candidate_low:
            return False
        direct_variants = {
            original_low + "s",
            original_low + "es",
            original_low + "d",
            original_low + "ed",
            original_low + "ing",
        }
        if original_low.endswith("e"):
            direct_variants.add(original_low[:-1] + "ing")
        if candidate_low in direct_variants:
            return True
        for suffix in ("ing", "ed", "es", "s", "d"):
            if candidate_low.endswith(suffix):
                stem = candidate_low[:-len(suffix)]
                if stem == original_low:
                    return True
                if suffix in {"d", "ed", "ing"} and stem + "e" == original_low:
                    return True
        return False

    def _replace_token(m: re.Match) -> str:
        token = m.group(0)
        low = token.lower()
        if token.isupper() and len(token) >= 3:
            return token
        if list_query_mode and len(low) >= 5 and low.endswith("s"):
            return token
        if low in preserve_short_terms:
            return token
        if len(low) < 4 or low in query_core_vocab:
            return token
        low_freq = int(freq_map.get(low, 0) or 0)
        if low in vocab and low_freq >= 5:
            return token

        candidates = [cand for cand in by_initial.get(low[0], []) if abs(len(cand) - len(low)) <= 2]
        if not candidates:
            return token

        best = token
        best_dist = 3
        best_freq = -1
        second_dist = 3
        for cand in candidates:
            if cand == low:
                continue
            dist = _edit_distance_leq(low, cand, cap=2)
            if dist > 2:
                continue
            cand_freq = int(freq_map.get(cand, 0))
            if dist < best_dist or (dist == best_dist and cand_freq > best_freq):
                second_dist = best_dist
                best = cand
                best_dist = dist
                best_freq = cand_freq
            elif dist < second_dist:
                second_dist = dist

        if best_dist > 2:
            return token
        confidence = max(0.0, 1.0 - (best_dist / max(len(low), len(best), 1)))
        if best_freq >= 4:
            confidence = min(0.99, confidence + 0.04)
        if second_dist == best_dist and best_freq < 4:
            return token
        if confidence < 0.76:
            return token
        if low in vocab and best_freq < max(low_freq * 5, low_freq + 8):
            return token
        if _is_inflection_only_variant(low, best):
            return token
        correction_events.append({
            "before": token,
            "after": best,
            "confidence": confidence,
            "source": source_map.get(best, "document_vocab"),
        })
        return _case_like(token, best)

    corrected = re.sub(r"\b[a-zA-Z]{2,}\b", _replace_token, q)
    corrected = re.sub(r"\s+", " ", corrected).strip()
    for event in correction_events:
        logger.info(
            "[SPELLING CORRECTION] before=%s after=%s confidence=%.2f source=%s",
            event["before"],
            event["after"],
            event["confidence"],
            event["source"],
        )
    logger.info("[FLOW] query_after = %s", (corrected or "")[:400])
    return corrected or q


def _normalize_definition_query_before_retrieval(query_text: str) -> tuple[str, str]:
    """Lightweight pre-retrieval normalization for retrieval robustness.

    - Lowercase normalization
    - Fast typo correction (edit distance <= 2)
    Returns (normalized_query, corrected_entity_or_empty)
    """
    q_raw = str(query_text or "")
    logger.info("[FLOW] entering _normalize_definition_query_before_retrieval")
    logger.info("[FLOW] query_before = %s", (q_raw or "")[:400])
    q = re.sub(r"\s+", " ", q_raw).strip()
    if not q:
        return q_raw, ""

    symbolic_query, symbolic_concept = _normalize_symbolic_count_letter_list_query_before_retrieval(q)
    if symbolic_query and symbolic_query.strip().lower() != q.strip().lower():
        logger.info("[SYMBOLIC LIST NORM] '%s' -> '%s'", q[:120], symbolic_query[:120])
        logger.info("[FLOW] query_after = %s", (symbolic_query or "")[:400])
        return symbolic_query, symbolic_concept

    meaning_match = None
    meaning_patterns = [
        r"^\s*what\s+is\s+meant\s+by\s+(.+?)\s*\??\s*$",
        r"^\s*what\s+is\s+meant\s+with\s+(.+?)\s*\??\s*$",
        r"^\s*what\s+is\s+the\s+meaning\s+of\s+(.+?)\s*\??\s*$",
        r"^\s*meaning\s+of\s+(.+?)\s*\??\s*$",
        r"^\s*define\s+(.+?)\s*\??\s*$",
    ]
    for patt in meaning_patterns:
        meaning_match = re.match(patt, q, flags=re.IGNORECASE)
        if meaning_match:
            break

    if meaning_match:
        entity_raw = (meaning_match.group(1) or "").strip(" \t\n\r\"'`.,;:!?()[]{}")
        entity_l = entity_raw.lower()
        if not entity_l:
            return q, ""

        corrected_entity = _lightweight_spelling_correction(entity_l)
        corrected_entity = re.sub(r"\s+", " ", str(corrected_entity or "").strip())
        if not corrected_entity:
            corrected_entity = entity_l
        concept_aliases = {}
        corrected_entity = concept_aliases.get(corrected_entity, corrected_entity)

        normalized_query = f"what is {corrected_entity}".strip()
        if q.endswith("?"):
            normalized_query = f"{normalized_query}?"

        logger.info("[FLOW] normalized_meaning_query = %s", (normalized_query or "")[:400])
        logger.info("[FLOW] query_after = %s", (normalized_query or "")[:400])
        logger.info("[FLOW] normalized_entity = %s", (corrected_entity or "")[:160])

        if corrected_entity != entity_l:
            return normalized_query, corrected_entity
        return normalized_query, ""

    starter_m = re.match(r"^\s*(what\s+is|define|who\s+is)\b\s*(.+?)\s*\??\s*$", q, flags=re.IGNORECASE)
    if not starter_m:
        return q, ""

    starter = (starter_m.group(1) or "").strip().lower()
    entity_raw = (starter_m.group(2) or "").strip(" \t\n\r\"'`.,;:!?()[]{}")
    entity_l = entity_raw.lower()
    corrected_entity = _lightweight_spelling_correction(entity_l)
    corrected_entity = re.sub(r"\s+", " ", str(corrected_entity or "").strip())
    if not corrected_entity:
        corrected_entity = entity_l
    concept_aliases = {}
    corrected_entity = concept_aliases.get(corrected_entity, corrected_entity)

    normalized_query = f"{starter} {corrected_entity}".strip()
    if q.endswith("?"):
        normalized_query = f"{normalized_query}?"

    logger.info("[FLOW] query_after = %s", (normalized_query or "")[:400])
    logger.info("[FLOW] normalized_entity = %s", (corrected_entity or "")[:160])

    if corrected_entity != entity_l:
        return normalized_query, corrected_entity
    return normalized_query, ""


def _is_controlled_definition_entity_query(query_text: str) -> bool:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return False
    return q.startswith("what is") or q.startswith("define") or q.startswith("who is")


def _distance_threshold_for_query(query_text: str) -> float:
    base = float(RAG_STRICT_DISTANCE_THRESHOLD)
    if _is_overview_query(query_text):
        return max(base, 1.35)
    if _query_requires_structure(query_text):
        return max(base, 1.10)
    return max(base, 0.85)


def _overview_seed_query() -> str:
    return "document overview summary introduction table of contents units chapters key topics"


def _has_meaningful_context(retrieved_docs: list[dict]) -> bool:
    if not retrieved_docs:
        return False
    for d in retrieved_docs:
        md = (d or {}).get("metadata") or {}
        txt = str((d or {}).get("text") or "").strip()
        non_trivial_text = len(re.findall(r"\w+", txt)) >= 25
        has_structural_meta = bool(str(md.get("chapter") or "").strip() or str(md.get("section") or "").strip() or str(md.get("title") or "").strip())
        if non_trivial_text or has_structural_meta:
            return True
    return False


def _is_low_quality_doc(doc: dict) -> bool:
    md = (doc or {}).get("metadata") or {}
    txt = str((doc or {}).get("text") or "")
    section = str(md.get("section") or "")
    title = str(md.get("title") or "")
    chapter = str(md.get("chapter") or "")
    txt_l = txt[:900].lower()
    hay = f"{section}\n{chapter}\n{txt_l}".lower()
    if re.search(r"\b(commentary|further\s+reading|references?|bibliograph(?:y|ies)|works\s+cited|connections?\s+see\s+the)\b", txt_l):
        return True
    if re.search(r"\b(commentary|further\s+reading|references?|bibliograph(?:y|ies)|works\s+cited|connections?\s+see\s+the)\b", str(title).lower()):
        if len(txt.split()) < 120:
            return True
    if re.search(r"\b(self[-\s]*published|createspace|isbn|openstax|index)\b", hay):
        has_structure = bool(re.search(r"\bchapter\s+\d+\b", hay)) or bool(re.search(r"\b\d+\.\d+\b", hay))
        if not has_structure and (len(txt.split()) < 45 and len(re.findall(r"\([12][0-9]{3}\)|\[[0-9]{1,3}\]|https?://", hay)) >= 4):
            return True
    return False


def _docs_have_structure_markers(retrieved_docs: list[dict]) -> bool:
    for doc in retrieved_docs or []:
        md = (doc or {}).get("metadata") or {}
        txt = str((doc or {}).get("text") or "")[:1200]
        section = str(md.get("section") or "")
        title = str(md.get("title") or "")
        chapter = str(md.get("chapter") or "")
        unit = str(md.get("unit") or "")
        hay = f"{section}\n{title}\n{chapter}\n{unit}\n{txt}"
        if re.search(r"\b(?:chapter|unit)\s+\d+\b", hay, flags=re.IGNORECASE):
            return True
        if re.search(r"\b\d+(?:\.\d+){1,3}\b", hay):
            return True
        if any(marker in hay.lower() for marker in ("table of contents", "contents", "key terms", "introduction", "summary")):
            return True
    return False


def _retrieval_context_is_reliable(query_text: str, retrieved_docs: list[dict]) -> bool:
    if not retrieved_docs:
        return False

    cleaned = [d for d in retrieved_docs if not _is_low_quality_doc(d)]
    if not cleaned:
        return False

    if not _has_meaningful_context(cleaned):
        return False

    max_sim = _max_doc_similarity(cleaned)
    lexical_ok = _has_english_keyword_overlap(query_text, cleaned)
    overview_q = _is_overview_query(query_text)
    structure_q = _query_requires_structure(query_text)

    # Structure-sensitive questions require structure signals in context.
    if structure_q and not _docs_have_structure_markers(cleaned):
        return False

    # Overview/purpose requests should pass when meaningful context exists.
    if overview_q:
        noisy_ratio = 1.0 - (len(cleaned) / max(1, len(retrieved_docs)))
        return noisy_ratio <= 0.85

    # For topical non-overview questions, lexical grounding stays the primary guard.
    if (not structure_q) and (not lexical_ok):
        if max_sim < 0.15:
            return False

    if max_sim < 0.12 and not lexical_ok:
        return False

    # If nearly all docs look noisy, reject before LLM to prevent hallucination.
    noisy_ratio = 1.0 - (len(cleaned) / max(1, len(retrieved_docs)))
    if noisy_ratio > 0.90: # Loosened from 0.85
        return False

    return True

# (Dead code removed)



# Arabic STT is controlled by the explicit Whisper language lock, not by
# document- or domain-specific prompt priming.
_ARABIC_STT_INITIAL_PROMPT: str | None = None


def _has_arabic_script(text: str) -> bool:
    return any('\u0600' <= c <= '\u06FF' for c in str(text or ""))


def _looks_like_english_stt_garbage_for_arabic(text: str, segments: list[Any] | None = None) -> bool:
    """Detect Latin-only transcripts that should not enter RAG in Arabic voice mode."""
    value = re.sub(r"\s+", " ", str(text or "").strip())
    if not value or _has_arabic_script(value):
        return False
    latin_words = re.findall(r"[A-Za-z']+", value)
    if not latin_words:
        return False

    avg_logprobs: list[float] = []
    for segment in segments or []:
        raw_logprob = getattr(segment, "avg_logprob", None)
        if raw_logprob is None:
            continue
        try:
            avg_logprobs.append(float(raw_logprob))
        except (TypeError, ValueError):
            continue

    low_confidence = bool(avg_logprobs and (sum(avg_logprobs) / len(avg_logprobs)) < -0.45)
    short_latin_transcript = len(latin_words) <= 8 or len(value) <= 64
    return low_confidence or short_latin_transcript


def _arabic_stt_unclear(text: str, segments: list[Any] | None = None) -> bool:
    """Return True when an Arabic-mode STT transcript looks unintelligible.

    Generic and conservative — only fires when every signal indicates noise:
    extremely low average decoder log-probability OR a transcript that is
    effectively empty / too short to hold a real Arabic question. Real
    Arabic questions (>=2 Arabic words at normal confidence) pass through.
    """
    value = re.sub(r"\s+", " ", str(text or "").strip())
    if not value:
        return True

    avg_logprobs: list[float] = []
    no_speech_probs: list[float] = []
    for segment in segments or []:
        raw_logprob = getattr(segment, "avg_logprob", None)
        if raw_logprob is not None:
            try:
                avg_logprobs.append(float(raw_logprob))
            except (TypeError, ValueError):
                pass
        raw_no_speech = getattr(segment, "no_speech_prob", None)
        if raw_no_speech is not None:
            try:
                no_speech_probs.append(float(raw_no_speech))
            except (TypeError, ValueError):
                pass

    avg_logprob = (sum(avg_logprobs) / len(avg_logprobs)) if avg_logprobs else 0.0
    avg_no_speech = (sum(no_speech_probs) / len(no_speech_probs)) if no_speech_probs else 0.0

    arabic_chars = sum(1 for c in value if "\u0600" <= c <= "\u06FF")
    arabic_words = [w for w in value.split() if any("\u0600" <= c <= "\u06FF" for c in w)]

    # Treat as unclear if: very few Arabic chars AND not a real word, OR
    # high no-speech probability, OR very low log-probability with short text.
    if arabic_chars < 2:
        return True
    if avg_no_speech and avg_no_speech > 0.85:
        return True
    if avg_logprob and avg_logprob < -1.2 and len(arabic_words) <= 2:
        return True
    return False


def _normalize_context_entities(query: str, text: str) -> str:
    """Detect names in query and normalize fuzzy near-misses (OCR noise) in text to match exactly."""
    if not query or not text:
        return text
    
    # 1. Identify proper names from the raw query (Capitalized words)
    # Target multi-word names first (e.g., "Peter Drucker")
    query_entities = re.findall(r'\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+)+\b', query)
    if not query_entities:
        # Fallback to significant single names
        query_entities = [e for e in re.findall(r'\b[A-Z][a-z]{4,}\b', query) 
                          if e.lower() not in ["what", "which", "where", "when", "this", "that", "there"]]
    
    if not query_entities:
        return text

    from difflib import get_close_matches
    cleaned_text = text
    # Extract unique TitleCase words from context as candidates for normalization
    doc_words = set(re.findall(r'\b[A-Z][a-z]+\b', cleaned_text))
    
    for entity in query_entities:
        parts = entity.split()
        # Usually last name is the best anchor for OCR fixes
        anchor = parts[-1]
        
        # Find variants in document that are very close to our query name
        matches = get_close_matches(anchor, doc_words, n=3, cutoff=0.75)
        for m in matches:
            if m != anchor and len(m) >= 4:
                # Replace fuzzy variant with canonical anchor from query
                cleaned_text = re.sub(rf'\b{re.escape(m)}\b', anchor, cleaned_text)
                
    return cleaned_text


def _clean_ocr_artifacts(text: str) -> str:
    """Lightweight cleanup for common knowledge chunk OCR noise (merged words, line joins, junk)."""
    if not text:
        return text
    
    # 1. WHITESPACE: Normalize line joins and multiple spaces (very common in PDF columnar exports)
    text = re.sub(r'\r\n|\r', '\n', text)
    # Preserve basic line boundaries, collapse multiple blank lines
    lines = [l.strip() for l in text.splitlines()]

    # 2. Remove obvious boilerplate-ish lines (page headers/footers, urls, copyright)
    cleaned_lines = []
    for l in lines:
        if not l:
            continue
        low = l.lower()
        # page numbers or short digit-only footers
        if re.fullmatch(r'page\s*\d{1,4}', low) or re.fullmatch(r'\d{1,4}', low):
            continue
        if 'http://' in low or 'https://' in low or low.startswith('www.'):
            continue
        if 'copyright' in low or 'all rights reserved' in low:
            continue
        # very short lines that are unlikely to be meaningful headers
        if len(l) < 3:
            continue
        cleaned_lines.append(l)

    text = ' \n'.join(cleaned_lines)

    # 3. MERGED CAMELCASE: Split merged CamelCase: "ManagementPublished" -> "Management Published"
    text = re.sub(r'([a-z])([A-Z])', r'\1 \2', text)

    # 4. NOISE SUFFIXES: Separate common OCR-merged connectors (of, in, and, published, etc.)
    # P6: Removed domain-specific tokens (principles, management); kept only generic
    # function words and structural markers that apply across documents.
    merged_noise_suffixes = [
        'of', 'in', 'by', 'the', 'and', 'at', 'for', 'from', 'with', 'to',
        'published', 'about', 'chapter', 'unit'
    ]
    for suffix in merged_noise_suffixes:
        text = re.sub(fr'\b([A-Za-z]{{3,}})({re.escape(suffix)})\b', r'\1 \2', text, flags=re.IGNORECASE)

    # 5. OCR TOKEN REPAIR: Generic prefix/suffix repairs for common PDF spacing loss
    text, _prefix_split_changed = _split_safe_ocr_merged_prefix_words(text)
    text, _split_merge_changed = _followup_merge_safe_ocr_split_words(text)

    # 6. BROKEN TOKENS: Remove isolated noise letters usually seen in mis-spaced names or list headers
    text = re.sub(r'\b[A-Za-z]\b\s+([A-Z][a-z]+)', r'\1', text)

    # 7. COLLAPSE repeated adjacent phrases (e.g., "the the" or longer repeated spans)
    # Collapse simple word repeats
    text = re.sub(r'\b(\w+)(?:\s+\1){2,}\b', r'\1', text, flags=re.IGNORECASE)
    # Collapse longer repeated substring sequences (two-or-more repeats)
    text = re.sub(r'(\b[\w\s]{8,120}?\b)(?:\s+\1){1,}', r'\1', text, flags=re.IGNORECASE)

    # 8. REPEATED CHARS: Clean duplicated characters or punctuation (OCR artifacts)
    text = re.sub(r'([.,:;!?])\1+', r'\1', text)
    text = re.sub(r'([a-zA-Z])\1{3,}', r'\1', text)

    # 9. Normalize inner whitespace
    text = re.sub(r'\s+', ' ', text)

    return text.strip()


def _is_list_query(query: str) -> bool:
    return detect_query_intent(query) == "list"


def _is_list_or_process_query(query_text: str) -> bool:
    q = (query_text or "").strip().lower()
    if not q:
        return False
    if _is_targeted_list_question(q):
        return True
    if re.match(r"^\s*how\b", q):
        return True
    return False

def _is_compare_query(query_text: str) -> bool:
    q = (query_text or "").strip().lower()
    if not q:
        return False
    return bool(
        re.search(r"\b(?:difference|differences|different|distinction)\b", q)
        or re.search(r"\b(?:compare|compared|comparison|contrast|contrasts)\b", q)
        or re.search(r"\b(?:differentiate|distinguish)\b", q)
        or re.search(r"\b(?:relationship|relation)\b.+\bbetween\b.+\band\b", q)
        or re.search(r"\bhow\s+(?:does|do|is|are)\b.+\brelat(?:e|es|ed)\b.+\b(?:to|with)\b", q)
        or re.search(r"^\s*(?:what\s+is|define|explain)\s+.+?\s+(?:and|;)\s+(?:what\s+is|define|explain)\s+.+", q)
        or re.search(r"\b(?:versus|vs\.?)\b", q)
        or re.search(r"\bbetween\b.+\band\b", q)
    )


def _is_strict_overview_query(query_text: str) -> bool:
    q = (query_text or "").strip().lower()
    if not q:
        return False
    markers = (
        "what does this document talk about",
        "what is this document about",
        "what is this book about",
        "main sections",
        "document talk about",
        "overview",
        "summary",
        "main ideas",
        "topics covered",
    )
    return any(m in q for m in markers)


def _is_safe_definition_fast_path_query(query_text: str) -> bool:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return False
    if not (q.startswith("who is") or q.startswith("what is")):
        return False
    if _is_list_or_process_query(q):
        return False
    if _is_compare_query(q):
        return False
    if _is_strict_overview_query(q):
        return False
    if _classify_query_family(q) == "out_of_scope_candidate":
        return False
    return True


def _is_incomplete_fragment_sentence(sentence: str) -> bool:
    s = str(sentence or "").strip()
    if not s:
        return True
    if len(re.findall(r"[A-Za-z][A-Za-z\-']*", s)) < 6:
        return True
    if re.match(r"^\s*(and|but|or|so|because|therefore|thus|also|then|while|whereas)\b", s, flags=re.IGNORECASE):
        return True
    if re.match(r"^\s*(?:[-•*]|\d+[.)])\s+", s):
        return True
    if not re.search(r"[.!?]$", s):
        return True
    return False


def _is_feature_only_definition_sentence(sentence: str) -> bool:
    s = re.sub(r"\s+", " ", str(sentence or "")).strip()
    if not s:
        return True
    low = s.lower()
    if ":" in s:
        return True
    if re.match(r"^\s*[a-z][a-z\-]*(?:\s+[a-z][a-z\-]*){0,4}\b", s):
        if len(re.findall(r"[a-z][a-z\-']*", low)) <= 14:
            return True
    aspect_terms = {
        "division", "hierarchy", "specialization", "specialisation", "authority",
        "responsibility", "rules", "procedures", "impersonality", "unity", "span", "control",
    }
    aspect_hits = [t for t in aspect_terms if re.search(rf"\b{re.escape(t)}\b", low)]
    has_definition_verb = bool(re.search(r"\b(is|refers to|defined as)\b", low))
    has_explanatory_verb = bool(re.search(r"\b(involves|focuses on|aims to|includes)\b", low))
    if len(aspect_hits) == 1 and (not has_definition_verb) and (not has_explanatory_verb):
        if len(re.findall(r"[a-z][a-z\-']*", low)) <= 14:
            return True
    return False


def _concept_specific_signal_terms(entity_l: str) -> List[str]:
    return []
    return []


def _has_required_concept_specific_signal(sentence: str, entity_l: str) -> bool:
    signals = _concept_specific_signal_terms(entity_l)
    if not signals:
        return True
    low = re.sub(r"\s+", " ", str(sentence or "").strip().lower())
    if not low:
        return False
    for term in signals:
        term_re = re.escape(term).replace("\\ ", r"\\s+")
        if re.search(rf"\b{term_re}\b", low):
            return True
    return False


def _count_concept_specific_signals(sentence: str, entity_l: str) -> int:
    signals = _concept_specific_signal_terms(entity_l)
    if not signals:
        return 0
    low = re.sub(r"\s+", " ", str(sentence or "").strip().lower())
    if not low:
        return 0
    count = 0
    for term in signals:
        term_re = re.escape(term).replace("\\ ", r"\\s+")
        if re.search(rf"\b{term_re}\b", low):
            count += 1
    return count


def _is_over_generic_definition_template(sentence: str, entity_l: str) -> bool:
    # P3: Replaced hard-coded management-phrase blacklist with a generic, lexicon-free
    # "empty body" detector. A sentence is over-generic when it has a definition verb
    # but virtually no content after it once the entity itself and stopwords are removed.
    s = re.sub(r"\s+", " ", str(sentence or "").strip())
    if not s:
        return True
    low = s.lower()
    m = re.search(r"\b(?:is|was|refers\s+to|defined\s+as|means)\b", low)
    if not m:
        return False
    body = low[m.end():].strip(" .,:;!?\t")
    if entity_l:
        body = re.sub(rf"\b{re.escape(entity_l)}\b", " ", body)
    body_words = re.findall(r"[a-z][a-z\-']{2,}", body)
    generic_stop = {
        "a", "an", "the", "of", "to", "for", "in", "on", "at", "by", "with",
        "and", "or", "that", "this", "these", "those", "such", "kind", "type",
        "form", "way", "general", "various", "many", "some", "any",
    }
    content = [w for w in body_words if w not in generic_stop]
    if len(content) >= 3:
        return False
    if _has_required_concept_specific_signal(s, entity_l):
        return False
    return True


def _s_definition_sentence(sentence: str, entity_l: str, entity_tokens: List[str]) -> int:
    s = re.sub(r"\s+", " ", str(sentence or "")).strip()
    if not s:
        return -99
    low = s.lower()
    word_count = len(re.findall(r"[A-Za-z][A-Za-z\-']*", s))

    if re.match(r"^\s*(?:three\s+main|how\s+do\s+we\s+learn|basic\s+terminology|historical\s+background|introduction|overview|summary|contents?|table\s+of\s+contents|key\s+terms?)\b", low):
        return -99
    if re.match(r"^\s*[A-Z][A-Za-z0-9\s\-,:]{3,110}\s*$", s) and not re.search(r"[.!?]$", s):
        return -99

    if re.search(r"\b(this\s+course|students\s+will\s+learn|students\s+will|purpose\s+of\s+this\s+course|course\s+description|main\s+focus\s+is\s+to\s+help\s+students)\b", low):
        return -99

    if not re.search(r"[.!?]$", s):
        return -99

    def _ocr_noise_hits(txt: str) -> int:
        t = str(txt or "")
        hits = 0
        hits += len(re.findall(r"\b[a-z]\s+[a-z]\b", t.lower()))
        hits += len(re.findall(r"\bwil\s+helm\b|\bw\s*und\s*t\b|\bcont\s+rolling\b|\bbe\s+havior\b", t.lower()))
        hits += len(re.findall(r"(?:\b[A-Za-z]{1,2}\b\s+){3,}", t))
        return hits

    score = 0

    concept_clear = False
    if entity_l and re.search(rf"\b{re.escape(entity_l)}\b", low):
        concept_clear = True
    elif entity_tokens:
        token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low))
        root_hits = 0
        for t in entity_tokens:
            if len(t) >= 6 and re.search(rf"\b{re.escape(t[:6])}[a-z]*\b", low):
                root_hits += 1
        need = max(1, min(2, len(entity_tokens)))
        concept_clear = token_hits >= need or root_hits >= need

    if concept_clear and re.search(r"\b(is|refers to|defined as|means|includes|involves|consists of|characterized by|focused\s+upon|focused\s+on|focuses\s+on|grew\s+out\s+of)\b", low):
        score += 3

    full_phrase_matches = len(re.findall(rf"\b{re.escape(entity_l)}\b", low)) if entity_l else 0
    if full_phrase_matches >= 1:
        score += 2
    if full_phrase_matches >= 2:
        score += 1

    if re.search(r"\b(involves|focuses on|aims to|includes|consists of|characterized by|grew\s+out\s+of)\b", low):
        score += 2

    specific_signal_count = _count_concept_specific_signals(s, entity_l)

    if not concept_clear and specific_signal_count < 2:
        score -= 2

    if not re.search(r"\b(is|refers to|defined as|means|involves|focuses on|focused\s+upon|focused\s+on|aims to|includes|consists of|characterized by|grew\s+out\s+of)\b", low):
        score -= 1

    has_def_verb = bool(re.search(r"\b(is|refers to|defined as|means|involves|includes|consists of|characterized by|forms an association|associates)\b", low))
    if (":" in s or ";" in s or "•" in s or "|" in s or len(re.findall(r",", s)) >= 2) and (not has_def_verb):
        score -= 9
    if re.search(r"[•ò]\s*[A-Za-z]", s):
        score -= 10

    if _is_feature_only_definition_sentence(s):
        score -= 3

    aspect_terms = {
        "division", "hierarchy", "specialization", "specialisation", "authority",
        "responsibility", "rules", "procedures", "impersonality", "unity", "span", "control",
    }
    aspect_hits = [t for t in aspect_terms if re.search(rf"\b{re.escape(t)}\b", low)]
    if len(aspect_hits) == 1 and not re.search(r"\b(is|refers to|defined as|involves|focuses on|aims to|includes)\b", low):
        score -= 3

    if _has_required_concept_specific_signal(s, entity_l):
        score += 3
    elif _concept_specific_signal_terms(entity_l):
        score -= 4
    if specific_signal_count >= 2:
        score += 2

    if _is_over_generic_definition_template(s, entity_l):
        score -= 8

    if defines_other_concept(low, entity_l):
        score -= 12

    if re.match(r"^\s*(he|she|they|it|this)\b", low):
        score -= 8

    if re.search(r"\b(known\s+as\s+the\s+born|biography|worked\s+as)\b", low):
        score -= 10

    rubric_score = 0
    if re.search(r"\b(is|refers to|defined as|means)\b", low):
        rubric_score += 3
    if entity_l and re.search(rf"^\s*(?:the\s+)?{re.escape(entity_l)}\s+(?:is|refers\s+to|defined\s+as|means)\b", low):
        rubric_score += 2
    elif entity_l and re.search(rf"^\s*(?:the\s+)?{re.escape(entity_l)}\b", low):
        rubric_score += 1

    ocr_hits = _ocr_noise_hits(s)
    if ocr_hits == 0:
        rubric_score += 2
    else:
        rubric_score -= 3

    if 8 <= word_count <= 24:
        rubric_score += 1
    elif word_count > 35:
        rubric_score -= 1

    if re.search(r"\b(this\s+course|students\s+will|course\s+description|objectives?)\b", low):
        rubric_score -= 2

    if not concept_clear:
        rubric_score -= 2

    score += rubric_score

    return score


def _extract_best_scored_concept_sentence_from_docs(query_text: str, docs: list[dict], max_docs: int = 3) -> str | None:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not (q.startswith("what is") or q.startswith("define")):
        return None

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not has_entity or not entity_l:
        return None

    entity_tokens = [
        t for t in re.findall(r"[a-z0-9]{2,}", entity_l)
        if t not in {"the", "a", "an", "of", "and", "in", "to", "is", "are"}
    ]

    reject_re = re.compile(
        r"\b(?:criticism|criticisms|limitations?|drawbacks?|table|figure|isbn|contents?)\b",
        flags=re.IGNORECASE,
    )
    definition_verb_re = re.compile(
        r"\b(?:is|refers\s+to|means|defined\s+as|includes|involves|consists\s+of|characterized\s+by|focuses\s+on)\b",
        flags=re.IGNORECASE,
    )

    best: Tuple[float, str] | None = None
    for d in (docs or [])[:max(1, min(5, int(max_docs)))]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not src:
            continue

        for s in [x.strip() for x in re.split(r"(?<=[.!?])\s+|\n+", src) if x.strip()][:8]:
            low = s.lower()
            quality_reason = _definition_quality_rejected_reason(s, entity_l, require_definition_cue=True)
            if quality_reason:
                _log_definition_quality_rejection(s, quality_reason)
                continue
            if reject_re.search(low):
                _log_definition_quality_rejection(s, "heading_or_source_noise")
                continue
            if _looks_table_or_heading_like_chunk(s):
                _log_definition_quality_rejection(s, "table_or_heading_fragment")
                continue
            if defines_other_concept(low, entity_l):
                _log_definition_quality_rejection(s, "defines_other_concept")
                continue
            if not definition_verb_re.search(low):
                _log_definition_quality_rejection(s, "missing_definition_cue")
                continue

            token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low))
            if token_hits < max(1, min(2, len(entity_tokens))):
                _log_definition_quality_rejection(s, "missing_query_entity")
                continue

            score = float(_s_definition_sentence(s, entity_l, entity_tokens))
            if score <= 0:
                _log_definition_quality_rejection(s, "low_definition_score")
                continue
            if re.search(rf"\b{re.escape(entity_l)}\b", re.sub(r"[^a-z0-9 ]+", " ", low)):
                score += 1.0

            cleaned = re.sub(r"\s+", " ", s).strip()
            if best is None or score > best[0]:
                best = (score, cleaned)

    if not best:
        return None

    sentence = best[1]
    if not re.search(r"[.!?]$", sentence):
        sentence += "."
    logger.info("[DEF QUALITY] selected_sentence=%s", _preview_for_quality_log(sentence, 220))
    return sentence


def _extract_simple_definition_sentence(query_text: str, docs: list[dict]) -> str | None:
    if not docs:
        return None
    q = (query_text or "").strip().lower()
    if not (q.startswith("who is") or q.startswith("who was") or q.startswith("who introduced") or q.startswith("what is") or q.startswith("define")):
        return None
    is_who_query = q.startswith("who is") or q.startswith("who was") or q.startswith("who introduced")
    is_who_identity_query = q.startswith("who is") or q.startswith("who was")
    is_concept_query = q.startswith("what is") or q.startswith("define")
    is_person_attribution_query = q.startswith("who introduced") or q.startswith("who developed")

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = (entity or "").strip().lower()
    entity_tokens = [
        t for t in re.findall(r"[a-z0-9]{2,}", entity_l)
        if t not in {"the", "a", "an", "of", "and", "in", "to"}
    ]
    # P7: Removed "management" from generic_concept_tokens (domain-leak); the remaining
    # tokens are truly cross-domain generic concept words.
    generic_concept_tokens = {"theory", "process", "system", "approach", "concept", "method", "model"}
    required_concept_anchor_tokens = [t for t in entity_tokens if t not in generic_concept_tokens]

    entity_compact = re.sub(r"[^a-z0-9]+", "", entity_l)
    who_full_name_re = None
    if is_who_identity_query and len(entity_tokens) >= 2:
        parts = [re.escape(t) for t in entity_tokens]
        if len(parts) == 2:
            who_full_name_re = re.compile(
                rf"\b{parts[0]}(?:\s+[a-z]{{2,}}){{0,3}}\s+{parts[1]}\b",
                flags=re.IGNORECASE,
            )
        else:
            middle = ""
            for p in parts[1:-1]:
                middle += rf"(?:\s+[a-z]{{2,}}){{0,2}}\s+{p}"
            who_full_name_re = re.compile(
                rf"\b{parts[0]}{middle}(?:\s+[a-z]{{2,}}){{0,3}}\s+{parts[-1]}\b",
                flags=re.IGNORECASE,
            )

    def _concept_in_sentence(sentence_low: str, strict_mode: bool) -> bool:
        sentence_compact = re.sub(r"[^a-z0-9]+", "", sentence_low)
        if has_entity and entity_l and re.search(rf"\b{re.escape(entity_l)}\b", sentence_low):
            return True
        if entity_compact and entity_compact in sentence_compact:
            return True
        if entity_tokens:
            token_hits = 0
            for t in entity_tokens:
                root_hit = False
                if len(t) >= 6:
                    root = re.escape(t[:6])
                    root_hit = bool(re.search(rf"\b{root}[a-z]*\b", sentence_low))
                if re.search(rf"\b{re.escape(t)}\b", sentence_low) or t in sentence_compact or root_hit:
                    token_hits += 1
            if is_who_query:
                min_hits = 2 if strict_mode and len(entity_tokens) >= 2 else 1
                return token_hits >= min_hits
            return token_hits >= (2 if strict_mode and len(entity_tokens) >= 2 else 1)
        return False

    def _is_rejectable_sentence(sentence: str) -> bool:
        low = sentence.lower()
        allows_explanatory_concept_definition = bool(
            is_concept_query
            and _concept_in_sentence(low, strict_mode=False)
            and re.search(r"\b(refers to|includes|involves|consists of|characterized by)\b", low)
        )
        if len(sentence) > 260:
            return True
        if "the answers to all these questions can be found" in low:
            return True
        if re.search(r"\bwho\s+is\s+.+?\s+most\s+effective\s+with\b", low):
            return True
        if re.search(r"(?:©|copyright|virtual\s+university|\b[a-z]{2,5}\s*\d{3}\b)", sentence, flags=re.IGNORECASE):
            return True
        if sentence.count("•") >= 2:
            return True
        if re.search(r"[•ò]\s*[A-Za-z]", sentence):
            return True
        if re.search(r"\b(one\s+of\s+the\s+components?|listed\s+with|associating\s+model)\b", low):
            return True
        if re.search(r"\b(?:criticism|criticisms|limitations?|drawbacks?|red\s+tape)\b", low):
            return True
        if re.search(r"\b(?:table|figure)\b", low):
            return True
        if re.match(r"^\s*[A-Z][A-Za-z\s]{6,50}\s+\d{1,3}\b", sentence):
            return True
        if re.search(r"\b(?:fig|fig\.)\b", low):
            return True
        if re.search(r"\b(?:classification|contributors?)\b", low):
            return True
        # DISABLED_CHEATING_LOGIC: Domain-specific management-ideas row detector.
        # if re.search(r"\bmanagement\s+ideas\s+contributors\b", low):
        #     return True
        if re.search(r"\b\d+\.\s*[A-Z][A-Za-z\s\-]{2,50}\s+[A-Z][a-z]+\s+[A-Z][a-z]+\b", sentence):
            return True
        if re.search(r"^\s*[A-Z][A-Za-z0-9\s\-]{3,90}\s*:\s*(?:[-•*]|\d+[.)])\s+", sentence):
            return True
        if re.search(r"^\s*(?:introduction|overview|summary|contents?|table of contents|chapter\s+\d+|unit\s+\d+|learning objectives?|key terms?)\s*[:\-–—]?\s*$", sentence, flags=re.IGNORECASE):
            return True
        if "he thought" in low or "it can be said" in low or "he claimed" in low or "she claimed" in low:
            return True
        if re.match(r"^\s*(before|after|when|if|during|for\s+example|this\s+leads)\b", sentence, flags=re.IGNORECASE):
            return True
        if re.search(r"\b(first|second|third|step\s+\d+|should|must|need\s+to|you\s+can|to\s+do\s+this|follow\s+these|start\s+by)\b", low):
            return True
        if re.match(r"^\s*(?:[-•*]|\d+[.)])\s+", sentence):
            return True
        if re.match(r"^\s*(and|but|or|so|because|therefore|thus|also|then|while|whereas)\b", sentence, flags=re.IGNORECASE) and (not allows_explanatory_concept_definition):
            return True
        if "|" in sentence or "\t" in sentence:
            return True
        if re.search(r"(?:\b[A-Za-z]\s+){5,}\b", sentence):
            return True
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", sentence)
        caps = re.findall(r"\b[A-Z][a-z]{2,}\b", sentence)
        if len(words) <= 12 and len(caps) >= 4 and not re.search(r"\b(?:is|refers\s+to|means|defined\s+as)\b", low):
            return True
        if ":" in sentence and (not re.search(r"[.!?]$", sentence)) and (not allows_explanatory_concept_definition):
            return True
        # PATCH 4: reject short numbered row structures ("1. Concept Name")
        if re.match(r"^\s*\d+\.", sentence) and len(re.findall(r"[A-Za-z][A-Za-z\-']*", sentence)) <= 8:
            return True
        # PATCH 4: reject compact concept-person mapping fragments
        if re.match(r"^\s*[A-Z][A-Za-z\s\-]{3,30}\s+[A-Z][a-z]+\s+[A-Z][a-z]+\s*$", sentence.strip()):
            return True
        return False

    def _normalize_person_sentence(sentence: str) -> str:
        if not is_who_query or not has_entity or not entity_l:
            return sentence
        if is_who_identity_query:
            return sentence.strip()
        s = sentence.strip()
        s_low = s.lower()
        if re.search(rf"\b{re.escape(entity_l)}\b", s_low):
            return s
        if not entity_tokens:
            return s
        person_name = " ".join(w.capitalize() for w in entity_l.split())
        for tok in sorted(entity_tokens, key=len, reverse=True):
            if re.search(rf"\b{re.escape(tok)}\b", s_low):
                return re.sub(rf"\b{re.escape(tok)}\b", person_name, s, count=1, flags=re.IGNORECASE)
        return s

    def _extract_from_text(source_text: str) -> str | None:
        if not source_text:
            return None
        raw_sentences = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", source_text) if (s or "").strip()]
        if not raw_sentences:
            return None

        max_scan = min(12, len(raw_sentences))
        candidate_indices: List[int] = list(range(max_scan))

        if (not is_concept_query) and has_entity and entity_l:
            anchor = -1
            for i, s in enumerate(raw_sentences[:max_scan]):
                low = s.lower()
                compact = re.sub(r"[^a-z0-9]+", "", low)
                if re.search(rf"\b{re.escape(entity_l)}\b", low) or (entity_compact and entity_compact in compact):
                    anchor = i
                    break
            if anchor >= 0:
                local = [idx for idx in range(max(0, anchor - 2), min(len(raw_sentences), anchor + 10))]
                merged = []
                seen = set()
                for idx in local + candidate_indices:
                    if idx not in seen and len(merged) < 12:
                        seen.add(idx)
                        merged.append(idx)
                candidate_indices = merged

        definition_verbs = re.compile(r"\b(is|was|refers to|can be defined as|defined as|known as|introduced|means|consists of|includes|involves|characterized by|grew out of)\b")
        concept_definition_verbs = re.compile(r"\b(is\s+defined\s+as|refers\s+to|means|is\s+considered|is|includes|involves|consists\s+of|characterized\s+by|grew\s+out\s+of)\b", flags=re.IGNORECASE)
        concept_explanatory_verbs = re.compile(r"\b(focuses\s+on|involves|aims\s+to|uses|applies)\b", flags=re.IGNORECASE)
        attribution_verbs = re.compile(r"\b(introduced|developed|known as)\b")
        who_definition_verbs = re.compile(r"\b(is|was|known as|introduced|developed)\b")
        # PATCH 2: action verbs for entity query fallback
        who_action_verbs = re.compile(r"\b(said|proposed|described|developed|argued|believed|established|founded|formulated|advocated|contributed|emphasized|suggested|coined)\b")
        concept_person_attribution_re = re.compile(
            r"\b(?:introduced by|he\s+is\s+known\s+as|he\s+was\s+known\s+as|is\s+associated\s+with)\b",
            flags=re.IGNORECASE,
        )
        hard_def_verbs_re = re.compile(r"\b(?:is|refers to|defined as)\b", flags=re.IGNORECASE)
        concept_person_row_re = re.compile(
            r"^\s*(?:\d+[.)]?\s+)?[A-Z][A-Za-z\-]+(?:\s+[A-Za-z][A-Za-z\-]+){0,4}\s+[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\s*$"
        )
        # P1: Removed hard-coded surname allow-list (taylor|fayol|...). Biographical sentences
        # are filtered generically via concept_person_bio_re below.
        concept_person_bio_re = re.compile(
            r"\b(?:he|she|his|her|who|born|known\s+as|was\s+a|said|proposed|developed|introduced)\b",
            flags=re.IGNORECASE,
        )
        concept_example_or_list_re = re.compile(
            r"\b(?:for\s+example|such\s+as|e\.g\.|i\.e\.|example)\b",
            flags=re.IGNORECASE,
        )

        def _person_signal(sentence: str) -> bool:
            s = sentence.strip()
            s_low = s.lower()
            if re.search(r"\b(classification|contributors?|table|figure|chapter|unit|contents?)\b", s_low):
                return False
            if re.search(r"\b[A-Z][a-z]+\s+[A-Z][a-z]+\b", s):
                return True
            if re.search(r"\b[A-Z]\.\s*[A-Z]\.\s*[A-Z][a-z]+\b", s):
                return True
            return bool(re.search(r"\b(mr\.?|ms\.?|dr\.?|prof\.?|sir)\s+[A-Z][a-z]+\b", s))

        scored: List[Tuple[float, int, str]] = []

        immediate_concept_hit: Optional[str] = None

        def _collect_candidates(window_indices: List[int]) -> Tuple[List[Tuple[float, int, str]], List[Dict[str, Any]]]:
            nonlocal immediate_concept_hit
            local_scored: List[Tuple[float, int, str]] = []
            local_concept_candidates: List[Dict[str, Any]] = []
            for local_pos, idx in enumerate(window_indices):
                s = raw_sentences[idx]
                if is_concept_query:
                    s = re.sub(r",\s*in\s+the\s+words\s+of\s+[^,]{1,120},\s*", " ", s, flags=re.IGNORECASE)
                    s = re.sub(r'\b([A-Za-z][A-Za-z0-9\- ]{2,90})\s*["“”]\s*(is|refers\s+to|means|defined\s+as|is\s+defined\s+as|is\s+considered)\b', r'\1 \2', s, flags=re.IGNORECASE)
                    s = re.sub(r"\s+", " ", s).strip()
                low = s.lower()
                sentence_compact = re.sub(r"[^a-z0-9]+", "", low)
                if is_concept_query and entity_l and defines_other_concept(low, entity_l):
                    continue
                token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low)) if entity_tokens else 0
                full_entity_hit = bool(entity_l and re.search(rf"\b{re.escape(entity_l)}\b", low))
                compact_phrase_hit = bool(entity_compact and entity_compact in sentence_compact)
                classical_alias_hit = bool(
                    is_concept_query
                    and False
                    and re.search(r"\b(?:classical\s+management\s+theory|classical\s+method|classical\s+management)\b", low)
                )
                phrase_hit = full_entity_hit or compact_phrase_hit or classical_alias_hit
                table_like = _looks_table_or_heading_like_chunk(s)

                if _is_rejectable_sentence(s):
                    continue
                if len(re.findall(r"[A-Za-z][A-Za-z\-']*", s)) < 6:
                    continue
                if table_like:
                    continue
                if is_concept_query and not concept_definition_verbs.search(low):
                    continue
                if is_concept_query and not re.search(r"[.!?]$", s.strip()):
                    continue

                # PATCH 1: For concept queries, accept both strict definition and explanatory sentences
                if is_concept_query:
                    person_name_led = bool(re.match(r"^\s*[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\s+(?:is|was)\b", s))
                    full_entity_tokens_hit = bool(entity_tokens) and all(re.search(rf"\b{re.escape(tok)}\b", low) for tok in entity_tokens)
                    feature_label_only = bool(re.match(r"^\s*[A-Za-z][A-Za-z\s\-]{2,50}:\s+", s))
                    has_strict_concept_verb = bool(concept_definition_verbs.search(low))
                    has_explanatory_verb = bool(concept_explanatory_verbs.search(low))
                    explicit_concept_hit = bool(full_entity_hit or compact_phrase_hit)
                    if (not explicit_concept_hit) and required_concept_anchor_tokens:
                        explicit_concept_hit = all(
                            re.search(rf"\b{re.escape(tok)}\b", low) or tok in sentence_compact
                            for tok in required_concept_anchor_tokens
                        )

                    if concept_person_attribution_re.search(s):
                        continue
                    if _looks_table_or_heading_like_chunk(s):
                        continue
                    if concept_person_row_re.match(s.strip()):
                        continue
                    # P1: Removed surname-list filter; rely on generic biographical-verb detector below.
                    if concept_person_bio_re.search(s):
                        continue
                    if concept_example_or_list_re.search(s):
                        continue
                    cap_words = re.findall(r"\b[A-Z][a-z]{2,}\b", s)
                    if len(cap_words) >= 2 and (not hard_def_verbs_re.search(low)):
                        continue
                    if person_name_led and not full_entity_tokens_hit:
                        continue
                    if feature_label_only and not full_entity_tokens_hit:
                        continue
                    if not explicit_concept_hit:
                        continue
                    if required_concept_anchor_tokens and not any(
                        re.search(rf"\b{re.escape(tok)}\b", low) or tok in sentence_compact
                        for tok in required_concept_anchor_tokens
                    ):
                        continue
                    pronoun_start = bool(re.match(r"^\s*(he|she|they|this|it)\b", low))
                    # FINAL TUNING: keep strict pronoun blocking for concept definitions
                    if pronoun_start:
                        continue
                    # Additional filter: reject narrative pronoun claims for concept definitions
                    if pronoun_start and re.search(r"\b(claimed|argued|suggested|believed)\b", low):
                        continue
                    if (":" in s) and not (concept_definition_verbs.search(low) or concept_explanatory_verbs.search(low)):
                        continue
                    if not (has_strict_concept_verb or has_explanatory_verb):
                        continue

                    if _is_over_generic_definition_template(s, entity_l):
                        continue

                    concept_quality_score = _s_definition_sentence(s, entity_l, entity_tokens)
                    if concept_quality_score <= 0:
                        continue

                    if not _has_required_concept_specific_signal(s, entity_l):
                        continue

                    if explicit_concept_hit:
                        if re.search(rf"\b{re.escape(entity_l)}\b\s+is\b", low):
                            concept_quality_score += 4
                        elif re.search(rf"\b{re.escape(entity_l)}\b\s+refers\s+to\b", low):
                            concept_quality_score += 3
                        elif re.search(rf"\b{re.escape(entity_l)}\b\s+(?:focuses\s+on|involves|aims\s+to|uses|applies)\b", low):
                            concept_quality_score += 1

                if is_who_query:
                    if not _concept_in_sentence(low, strict_mode=True):
                        continue
                    # FINAL FIX: for "who is X", require full queried name in the selected sentence
                    if is_who_identity_query and has_entity:
                        full_name_present = bool(
                            (entity_l and re.search(rf"\b{re.escape(entity_l)}\b", low))
                            or (who_full_name_re and who_full_name_re.search(low))
                        )
                        if not full_name_present:
                            continue
                    # PATCH 2: Accept identity verbs OR action verbs for who queries
                    has_identity_verb = bool(who_definition_verbs.search(low))
                    has_action_verb = bool(who_action_verbs.search(low))
                    if not (has_identity_verb or has_action_verb):
                        continue
                    if not _person_signal(s):
                        continue

                if is_concept_query and full_entity_hit and bool(concept_definition_verbs.search(low)) and (not defines_other_concept(low, entity_l)):
                    immediate_concept_hit = s
                    return local_scored, local_concept_candidates

                strict_zone = local_pos < 5
                concept_ok = _concept_in_sentence(low, strict_mode=strict_zone)
                has_def_verb = bool(definition_verbs.search(low))

                bio_fragment = bool(re.search(r"\b(he|she|his|her)\b", low)) or bool(re.search(r"\b(born|worked as|engineer|biography)\b", low))
                alias_style = bool(re.search(r"\b(you can also call it|also called|also known as)\b", low))
                # DISABLED_CHEATING_LOGIC: Domain-specific management phrase penalty.
                # generic_ungrounded_concept = is_concept_query and ("management" in low) and (not phrase_hit)
                generic_ungrounded_concept = False

                score = 0.0
                if full_entity_hit:
                    score += 3.0
                elif compact_phrase_hit:
                    score += 2.6
                if token_hits:
                    score += min(1.8, 0.7 * token_hits)
                if has_def_verb and (phrase_hit or token_hits >= 1):
                    score += 2.8
                elif has_def_verb:
                    score += 0.8

                if re.match(r"^\s*(and|but|or|so|because|therefore|thus|also|then|while|whereas)\b", s, flags=re.IGNORECASE):
                    score -= 2.5
                if bio_fragment:
                    score -= 1.8
                if alias_style:
                    score -= 2.2
                if generic_ungrounded_concept:
                    score -= 3.0
                if table_like:
                    score -= 3.0

                if is_who_query:
                    local_neighbors = raw_sentences[max(0, idx - 1): min(len(raw_sentences), idx + 2)]
                    neighbor_text = " ".join(local_neighbors)
                    grounded = _person_signal(s) or _person_signal(neighbor_text)
                    if grounded:
                        score += 1.6
                    else:
                        score -= 2.0
                else:
                    grounded = False

                if is_person_attribution_query:
                    attribution_ok = bool(attribution_verbs.search(low))
                    token_grounded = token_hits >= max(1, min(2, len(entity_tokens))) if entity_tokens else bool(entity_l and entity_l in low)
                    if attribution_ok and (grounded or token_grounded):
                        score += 4.5
                    else:
                        score -= 5.0

                if concept_ok:
                    score += 0.8

                if is_concept_query:
                    has_strict_concept_verb = bool(concept_definition_verbs.search(low))
                    has_explanatory_verb = bool(concept_explanatory_verbs.search(low))
                    if has_explanatory_verb and not has_strict_concept_verb:
                        score -= 1.5
                    if re.search(rf"\b{re.escape(entity_l)}\b\s+is\b", low):
                        score += 2.5
                    elif re.search(rf"\b{re.escape(entity_l)}\b\s+refers\s+to\b", low):
                        score += 1.8
                    elif re.search(rf"\b{re.escape(entity_l)}\b\s+(?:focuses\s+on|involves|aims\s+to|uses|applies)\b", low):
                        score += 0.8
                    concept_quality_score = _s_definition_sentence(s, entity_l, entity_tokens)
                    if concept_quality_score <= 0:
                        continue
                    local_concept_candidates.append({
                        "idx": idx,
                        "sentence": s,
                        "score": score,
                        "concept_quality_score": concept_quality_score,
                        "phrase_hit": phrase_hit,
                        "token_hits": token_hits,
                        "has_concept_verb": has_strict_concept_verb,
                        "has_explanatory_verb": has_explanatory_verb,
                        "generic_ungrounded_concept": generic_ungrounded_concept,
                        "bio_fragment": bio_fragment,
                        "alias_style": alias_style,
                        "table_like": table_like,
                        "continuation": bool(re.match(r"^\s*(and|but|or|so|because|therefore|thus|also|then|while|whereas)\b", s, flags=re.IGNORECASE)),
                    })

                local_scored.append((score, idx, s))
            return local_scored, local_concept_candidates

        def _pick_concept_candidate(concept_candidates: List[Dict[str, Any]]) -> str | None:
            if not concept_candidates:
                return None
            ranked_matches: List[Tuple[int, float, int, str]] = []
            for c in concept_candidates:
                if not c["phrase_hit"]:
                    continue
                if c["continuation"] or c["alias_style"]:
                    continue
                quality_score = int(c.get("concept_quality_score", -99))
                if quality_score < 0:
                    continue
                if c.get("table_like"):
                    continue
                ranked_matches.append((quality_score, float(c.get("score", 0.0)), int(c.get("idx", 0)), str(c.get("sentence", ""))))

            if ranked_matches:
                ranked_matches.sort(key=lambda x: (x[0], x[1]), reverse=True)
                return ranked_matches[0][3]
            return None

        if is_concept_query:
            scan_cap = min(25, len(raw_sentences))
            phase1_end = min(12, scan_cap)
            phase1_indices = list(range(0, phase1_end))
            phase2_indices = list(range(phase1_end, scan_cap)) if scan_cap > phase1_end else []

            _scored1, concept_candidates1 = _collect_candidates(phase1_indices)
            if immediate_concept_hit:
                return immediate_concept_hit
            selected1 = _pick_concept_candidate(concept_candidates1)
            if selected1:
                return selected1

            if phase2_indices:
                _scored2, concept_candidates2 = _collect_candidates(phase2_indices)
                if immediate_concept_hit:
                    return immediate_concept_hit
                selected2 = _pick_concept_candidate(concept_candidates2)
                if selected2:
                    return selected2
            # PATCH 1: If strict and explanatory concept candidate both failed,
            # try one more scan collecting ALL explanatory sentences from all docs
            return None

        scored, _unused_concept_candidates = _collect_candidates(candidate_indices[:12])

        if not scored:
            return None

        scored.sort(key=lambda x: x[0], reverse=True)
        # HARD PRIORITY: prefer non-table/non-classification prose sentences
        prose_best = None
        for s, i, t in scored:
            if s >= 1.6 and not _looks_table_or_heading_like_chunk(t):
                prose_best = (s, i, t)
                break
        if prose_best:
            return _normalize_person_sentence(prose_best[2])

        # Fallback to table-like if no prose candidate qualifies
        best_score, _best_idx, best_sentence = scored[0]
        if best_score < 1.6:
            return None
        return _normalize_person_sentence(best_sentence)

    def _is_weak_definition_answer(sentence: str) -> bool:
        s = str(sentence or "").strip()
        if not s:
            return True
        if len(re.findall(r"[A-Za-z][A-Za-z\-']*", s)) <= 6:
            return True
        sl = s.lower()
        if re.search(r"\b(isbn|https?://|www\.|unit\s+\d+)\b", sl):
            return True
        if re.search(r"\b(table\s*\d+|contributors?|classification|contents?)\b", sl):
            return True
        if _is_rejectable_sentence(s):
            return True
        if is_concept_query and not re.search(r"\b(?:is|refers\s+to|means|defined\s+as|is\s+considered|focuses\s+on|involves|aims\s+to|uses|applies)\b", sl):
            return True
        if is_concept_query and required_concept_anchor_tokens:
            anchor_hit = any(re.search(rf"\b{re.escape(tok)}\b", sl) for tok in required_concept_anchor_tokens)
            if not anchor_hit:
                return True
        if is_concept_query and (not _has_required_concept_specific_signal(s, entity_l)):
            return True
        if _is_over_generic_definition_template(s, entity_l):
            return True
        return False

    top_text = str((docs[0] or {}).get("page_content") or (docs[0] or {}).get("text") or "")
    if not top_text:
        return None

    dense_answer = _extract_from_text(top_text)
    top_is_table_like = _looks_table_or_heading_like_chunk(top_text)
    dense_weak = _is_weak_definition_answer(dense_answer) if dense_answer else True

    if dense_answer and (not dense_weak) and ((is_concept_query) or (not top_is_table_like)):
        return dense_answer

    if len(docs) >= 2:
        for d in docs[1:8]:
            next_text = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not next_text:
                continue
            next_answer = _extract_from_text(next_text)
            next_is_table_like = _looks_table_or_heading_like_chunk(next_text)
            next_weak = _is_weak_definition_answer(next_answer) if next_answer else True
            if next_answer and (not next_weak) and ((is_concept_query) or (not next_is_table_like)):
                return next_answer

    should_try_bm25 = (dense_answer is None) or dense_weak or top_is_table_like
    if should_try_bm25:
        bm25_docs, bm25_ms = _search_bm25_definition_fallback(query_text, top_k=2)
        if bm25_docs:
            for bd in bm25_docs[:2]:
                bm25_text = str((bd or {}).get("page_content") or (bd or {}).get("text") or "")
                bm25_answer = _extract_from_text(bm25_text)
                if bm25_answer and not _is_weak_definition_answer(bm25_answer):
                    logger.info("BM25 rescue hit | query='%s' | bm25_ms=%.1f", query_text, bm25_ms)
                    return bm25_answer
            logger.info("BM25 rescue miss | query='%s' | bm25_ms=%.1f", query_text, bm25_ms)

    def _compose_definition_from_weak_signals(source_docs: list[dict]) -> str | None:
        if not is_concept_query or not has_entity or not entity_l:
            return None
        if not source_docs:
            return None

        stop_terms = {"the", "a", "an", "of", "and", "in", "to", "for", "with", "by", "on"}
        concept_tokens = [
            t for t in re.findall(r"[a-z0-9]{2,}", entity_l)
            if t not in stop_terms
        ]
        if not concept_tokens:
            return None

        # P7: Removed "management" from generic_concept_terms (domain-leak); rest are truly generic.
        generic_concept_terms = {
            "theory", "process", "system", "concept", "approach", "model", "method", "principle"
        }
        anchor_tokens = [t for t in concept_tokens if t not in generic_concept_terms]
        if not anchor_tokens:
            anchor_tokens = concept_tokens[:]

        # P2: Removed hard-coded management-domain keyword set. Evidence selection now relies
        # on generic concept/anchor coverage only (full_phrase_hit + anchor_hits below).

        def _token_or_root_hits(text_low: str, tokens: List[str]) -> set[str]:
            hits: set[str] = set()
            compact_words = re.findall(r"[a-z0-9]{2,}", text_low)
            for tok in tokens:
                if re.search(rf"\b{re.escape(tok)}\b", text_low):
                    hits.add(tok)
                    continue
                if len(tok) >= 5:
                    root = tok[:5]
                    if any(w.startswith(root) for w in compact_words):
                        hits.add(tok)
            return hits

        max_docs = min(5, len(source_docs))
        cleaned_sentences: List[Dict[str, Any]] = []
        seen_norm: set[str] = set()

        for d in source_docs[:max_docs]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            raw_sents = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", txt) if s.strip()]
            for s in raw_sents[:18]:
                clean = re.sub(r"\s+", " ", s).strip(" -•*|\t")
                clean = re.sub(r",\s*in\s+the\s+words\s+of\s+[^,]{1,120},\s*", " ", clean, flags=re.IGNORECASE)
                clean = re.sub(r'\b([A-Za-z][A-Za-z0-9\- ]{2,90})\s*["“”]\s*(is|refers\s+to|means|defined\s+as|is\s+defined\s+as|is\s+considered)\b', r'\1 \2', clean, flags=re.IGNORECASE)
                clean = re.sub(r"\s+", " ", clean).strip()
                if not clean:
                    continue
                low = clean.lower()
                if len(re.findall(r"[A-Za-z][A-Za-z\-']*", clean)) <= 6:
                    continue
                if _is_rejectable_sentence(clean):
                    continue
                if _looks_table_or_heading_like_chunk(clean):
                    continue
                if re.search(r"\b(table\s*\d+|isbn|https?://|unit\s+\d+)\b", low):
                    continue
                if re.search(r"\b(?:criticism|criticisms|limitations?|drawbacks?|red\s+tape)\b", low):
                    continue
                if re.search(r"\b(?:he|she|his|her|who|born|known\s+as|was\s+a|said|proposed|developed|introduced)\b", low):
                    continue
                # P1: Removed hard-coded surname rejection list; biographical-verb test above is generic.
                if re.search(r"^\s*[A-Z][A-Za-z0-9\s\-]{3,90}\s*:\s*(?:[-•*]|\d+[.)])\s+", clean):
                    continue
                if _s_definition_sentence(clean, entity_l, concept_tokens) <= 0:
                    continue
                if not _has_required_concept_specific_signal(clean, entity_l):
                    continue

                norm = re.sub(r"[^a-z0-9]+", " ", low).strip()
                if not norm or norm in seen_norm:
                    continue
                seen_norm.add(norm)

                full_phrase_hit = bool(re.search(rf"\b{re.escape(entity_l)}\b", low))
                anchor_hits = _token_or_root_hits(low, anchor_tokens)
                # P2: domain_hits removed (was hard-coded management lexicon).

                cleaned_sentences.append({
                    "sentence": clean,
                    "low": low,
                    "full_phrase_hit": full_phrase_hit,
                    "anchor_hits": anchor_hits,
                })

        if not cleaned_sentences:
            return None

        # Out-of-scope protection: if concept topic is absent from retrieved text, skip composition.
        concept_present = any(s["full_phrase_hit"] or bool(s["anchor_hits"]) for s in cleaned_sentences)
        if not concept_present:
            return None

        evidence: List[Dict[str, Any]] = []
        for s in cleaned_sentences:
            # P2: Dropped domain-keyword co-requirement (was a management lexicon).
            # Sentence qualifies as evidence on generic concept coverage alone.
            has_concept_or_related = s["full_phrase_hit"] or bool(s["anchor_hits"])
            if has_concept_or_related:
                evidence.append(s)

        # Strict evidence condition: usually need 2 strong sentences.
        # For specific concept definitions, allow 1 strong sentence to avoid false "Not found".
        min_evidence = 1 if bool(required_concept_anchor_tokens) else 2
        if len(evidence) < min_evidence:
            return None

        # Consistency condition: supporting evidence must point to same concept anchors.
        anchor_counter: Counter[str] = Counter()
        for s in evidence:
            for a in s["anchor_hits"]:
                anchor_counter[a] += 1
        consistent_anchor = next((a for a, c in anchor_counter.items() if c >= 2), None)
        if not consistent_anchor and not any(s["full_phrase_hit"] for s in evidence[:3]):
            return None

        def _score_evidence(s: Dict[str, Any]) -> float:
            score = 0.0
            if s["full_phrase_hit"]:
                score += 3.0
            if consistent_anchor and consistent_anchor in s["anchor_hits"]:
                score += 2.0
            score += min(1.5, 0.6 * len(s["anchor_hits"]))
            # P2: Removed score bonus from domain_hits (hard-coded management lexicon).
            if re.search(r"\b(is|was|refers to|defined as|known as|focuses on|deals with|includes)\b", s["low"]):
                score += 1.2
            return score

        ranked = sorted(evidence, key=_score_evidence, reverse=True)
        selected: List[str] = []
        for item in ranked:
            sent = str(item["sentence"]).strip()
            if not re.search(r"[.!?]$", sent):
                sent += "."
            if sent in selected:
                continue
            selected.append(sent)
            if len(selected) >= max(1, min_evidence):
                break

        if len(selected) < max(1, min_evidence):
            return None

        composed = " ".join(selected[:2]).strip()
        if len(re.findall(r"[A-Za-z][A-Za-z\-']*", composed)) < 12:
            return None
        return composed

    composed_answer = _compose_definition_from_weak_signals(docs[:5])
    if composed_answer:
        return composed_answer

    def _rescue_from_concept_signals(source_docs: list[dict]) -> str | None:
        # DISABLED_CHEATING_LOGIC: Domain-specific concept-signal rescue mapping.
        return None
        if not is_concept_query or not has_entity or not entity_l:
            return None
        signals = _concept_specific_signal_terms(entity_l)
        if not signals:
            return None
        canonical_map = {
            "scientific": "scientific principles",
            "science": "scientific principles",
            "standards": "standardization",
            "work": "work methods",
            "planning": "planning work",
            "division of work": "division of labor",
        }
        found: List[str] = []
        for d in (source_docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            parts = [p.strip() for p in re.split(r"(?<=[.!?])\s+|\n+", txt) if p.strip()]
            for p in parts[:40]:
                if _is_rejectable_sentence(p):
                    continue
                if _looks_table_or_heading_like_chunk(p):
                    continue
                low = p.lower()
                if re.search(r"\b(?:he|she|his|her|born|known\s+as|was\s+a|said|proposed|developed|introduced)\b", low):
                    continue
                for sig in signals:
                    sig_re = re.escape(sig).replace("\\ ", r"\\s+")
                    if re.search(rf"\b{sig_re}\b", low):
                        canonical = canonical_map.get(sig, sig)
                        if canonical not in found:
                            found.append(canonical)
                if len(found) >= 2:
                    break
            if len(found) >= 2:
                break
        if len(found) < 2:
            return None
        entity_title = " ".join(w.capitalize() for w in re.findall(r"[A-Za-z0-9]+", entity_l)) or entity
        candidate = f"{entity_title} is characterized by {found[0]} and {found[1]}."
        if _is_over_generic_definition_template(candidate, entity_l):
            return None
        return candidate

    signal_rescue = _rescue_from_concept_signals(docs[:5])
    if signal_rescue:
        return signal_rescue

    def _title_case_entity(e: str) -> str:
        return " ".join(w.capitalize() for w in re.findall(r"[A-Za-z0-9]+", e or ""))

    def _extract_concept_person_pair_from_line(line: str) -> Optional[Tuple[str, str]]:
        line_norm = re.sub(r"\s+", " ", str(line or "")).strip()
        if not line_norm:
            return None
        patterns = [
            re.compile(r"^\s*\d+[.)]?\s+([A-Za-z][A-Za-z\- ]{2,100}?)\s+(?:[-–—:|])\s*([A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3})\s*$"),
            re.compile(r"^\s*([A-Za-z][A-Za-z\- ]{2,100}?)\s+(?:[-–—:|])\s*([A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3})\s*$"),
            re.compile(r"(?:^|\s)(\d+)[.)]?\s+([A-Za-z][A-Za-z\- ]{2,80}?)\s+([A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,2})(?=\s+\d+[.)]?\s+|$)"),
        ]
        for pat in patterns:
            m = pat.search(line_norm)
            if not m:
                continue
            if m.lastindex == 3:
                concept_cell = (m.group(2) or "").strip()
                person_cell = (m.group(3) or "").strip()
            else:
                concept_cell = (m.group(1) or "").strip()
                person_cell = (m.group(2) or "").strip()
            if len(person_cell.split()) < 2:
                continue
            return concept_cell, person_cell
        return None

    def _extract_person_attribution_from_docs(source_docs: list[dict], allow_concept_fallback: bool = False) -> str | None:
        if not ((is_person_attribution_query or (allow_concept_fallback and is_concept_query)) and has_entity and entity_l):
            return None
        ent_need = max(1, min(2, len(entity_tokens))) if entity_tokens else 1
        banned_name_tokens = {"theory", "model", "approach", "school", "method", "system", "table", "figure", "chapter", "section", "contributors", "classification"}
        org_or_place_tokens = {"company", "corporation", "corp", "inc", "ltd", "limited", "university", "college", "states", "state", "industry", "industries", "steel"}
        role_tokens = {"chief", "engineer", "manager", "director", "officer", "president", "professor", "doctor", "dr", "mr", "ms", "mrs"}
        for d in (source_docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue

            # Strict same-line mapping only: concept and person must be in the same row/line.
            for line in txt.splitlines():
                line_norm = re.sub(r"\s+", " ", line or "").strip()
                if not line_norm:
                    continue
                pair = _extract_concept_person_pair_from_line(line_norm)
                if not pair:
                    continue
                concept_cell, name_cell = pair
                concept_low = concept_cell.lower()
                hit_count = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", concept_low)) if entity_tokens else 0
                name_tokens = [t for t in re.findall(r"[a-z]+", name_cell.lower()) if t]
                if any(t in banned_name_tokens for t in name_tokens):
                    continue
                if hit_count >= ent_need:
                    entity_title = _title_case_entity(entity_l) or entity
                    concept_title = re.sub(r"\s+", " ", str(concept_cell or "").strip())
                    if concept_title:
                        concept_title = " ".join(w.capitalize() for w in re.findall(r"[A-Za-z0-9]+", concept_title))
                    if not concept_title:
                        concept_title = entity_title
                    mapped_name = name_cell
                    mapped_name_tokens = [t.lower() for t in re.findall(r"[A-Za-z]{2,}", mapped_name)]
                    if any(t in org_or_place_tokens for t in mapped_name_tokens):
                        continue
                    if any(t in role_tokens for t in mapped_name_tokens):
                        continue
                    if q.startswith("who introduced"):
                        return f"{mapped_name} introduced {concept_title}."

            # Same-line loose fallback: concept tokens and person name in one line/chunk only.
            person_name_re = re.compile(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\b")
            banned_name_tokens = {
                "theory", "principles", "functions", "process", "organization", "organisation", "method",
                "system", "approach", "model", "table", "figure", "chapter", "section", "classification",
                "united", "states",
            }
            for line in txt.splitlines():
                line_norm = re.sub(r"\s+", " ", line or "").strip()
                if not line_norm:
                    continue
                low_line = line_norm.lower()
                hit_count = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low_line)) if entity_tokens else 0
                if hit_count < ent_need:
                    continue
                name_candidates = person_name_re.findall(line_norm)
                if not name_candidates:
                    continue
                mapped_name = None
                for candidate in reversed(name_candidates):
                    toks = [t.lower() for t in re.findall(r"[A-Za-z]{2,}", candidate)]
                    if len(toks) < 2:
                        continue
                    if any(t in banned_name_tokens for t in toks):
                        continue
                    if any(t in org_or_place_tokens for t in toks):
                        continue
                    if any(t in role_tokens for t in toks):
                        continue
                    mapped_name = candidate.strip()
                    break
                if not mapped_name:
                    continue
                concept_title = _title_case_entity(entity_l) or entity
                if q.startswith("who introduced"):
                    return f"{mapped_name} introduced {concept_title}."
            # FINAL FIX: no prose inference for attribution queries; same-line mapping only.
        return None

    attribution_answer = _extract_person_attribution_from_docs(docs[:5])
    if attribution_answer:
        return attribution_answer

    def _extract_person_identity_fallback_from_docs(source_docs: list[dict]) -> str | None:
        if not (is_who_query and (not is_person_attribution_query) and has_entity and entity_l):
            return None
        entity_words = [w for w in entity_l.split() if w]
        if not entity_words:
            return None
        full_name_tokens = [t for t in re.findall(r"[a-z]{2,}", entity_l) if t]
        full_name_re = None
        if len(full_name_tokens) >= 2:
            full_name_re = re.compile(
                rf"\b{re.escape(full_name_tokens[0])}\b(?:\s+[a-z]+){{0,3}}\s+\b{re.escape(full_name_tokens[-1])}\b",
                flags=re.IGNORECASE,
            )
        last_name = entity_words[-1]
        preferred_first = entity_words[0] if len(entity_words) >= 2 else ""
        entity_title = _title_case_entity(entity_l) or entity
        for d in (source_docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            # Table-like fallback: map person to concept in same row.
            for line in txt.splitlines():
                line_norm = re.sub(r"\s+", " ", line or "").strip()
                if not line_norm:
                    continue
                pair = _extract_concept_person_pair_from_line(line_norm)
                if not pair:
                    continue
                concept_cell, name_cell = pair
                low_name = name_cell.lower()
                if full_name_re and not full_name_re.search(low_name):
                    continue
                if not re.search(rf"\b{re.escape(last_name)}\b", low_name):
                    continue
                if preferred_first and (preferred_first not in low_name):
                    continue
                clean_concept = re.sub(r"\s+", " ", concept_cell).strip(" .")
                if clean_concept:
                    # FINAL FIX: fallback accepted only from strict same-line table mapping.
                    role = "scholar"
                    return f"{entity_title} is a {role} known for {clean_concept}."
        return None

    person_identity_fallback = _extract_person_identity_fallback_from_docs(docs[:5])
    if person_identity_fallback:
        return person_identity_fallback

    def _extract_who_action_fallback_from_docs(source_docs: list[dict]) -> str | None:
        if not (is_who_query and (not is_person_attribution_query)):
            return None
        action_re = re.compile(r"\b(said|proposed|described|developed|argued|believed|established|founded|formulated|advocated|contributed|emphasized|suggested|coined)\b", flags=re.IGNORECASE)
        person_name_re = re.compile(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\b")
        full_name_re = None
        if is_who_identity_query and len(entity_tokens) >= 2:
            first = re.escape(entity_tokens[0])
            last = re.escape(entity_tokens[-1])
            full_name_re = re.compile(rf"\b{first}(?:\s+[a-z]{{2,}}){{0,3}}\s+{last}\b", flags=re.IGNORECASE)
        for d in (source_docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            parts = [p.strip() for p in re.split(r"(?<=[.!?])\s+|\n+", txt) if p.strip()]
            for p in parts[:24]:
                if _is_rejectable_sentence(p):
                    continue
                if _looks_table_or_heading_like_chunk(p):
                    continue
                low = p.lower()
                if is_who_identity_query:
                    full_hit = bool(full_name_re.search(low)) if full_name_re else bool(entity_l and re.search(rf"\b{re.escape(entity_l)}\b", low))
                    token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low)) if entity_tokens else 0
                    if not (full_hit or token_hits >= max(2, min(3, len(entity_tokens)))):
                        continue
                if action_re.search(low) and person_name_re.search(p):
                    return _normalize_person_sentence(p)
        return None

    who_action_fallback = _extract_who_action_fallback_from_docs(docs[:5])
    if who_action_fallback:
        return who_action_fallback

    def _synthesize_concept_definition_from_evidence(source_docs: list[dict]) -> str | None:
        if not is_concept_query or not has_entity or not entity_l:
            return None
        ent_need = 1
        best_sentence = None
        best_score = -1.0
        concept_person_attribution_re = re.compile(
            r"\b(?:introduced by|he\s+is\s+known\s+as|he\s+was\s+known\s+as|is\s+associated\s+with)\b",
            flags=re.IGNORECASE,
        )
        concept_valid_verb_re = re.compile(
            r"\b(?:is|refers to|defined as|means|involves|consists of|includes|characterized by|focuses on|deals with)\b",
            flags=re.IGNORECASE,
        )
        for d in (source_docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            parts = [p.strip() for p in re.split(r"(?<=[.!?])\s+|\n+", txt) if p.strip()]
            for p in parts[:28]:
                if _is_rejectable_sentence(p):
                    continue
                if _looks_table_or_heading_like_chunk(p):
                    continue
                if _s_definition_sentence(p, entity_l, entity_tokens) <= 0:
                    continue
                low = p.lower()
                if concept_person_attribution_re.search(low):
                    continue
                if re.match(r"^\s*(he|she|they|it|this|that)\b", low):
                    continue
                if not concept_valid_verb_re.search(low):
                    continue
                if re.search(r"\b(claims?|argues?|in the words of|who claims)\b", low):
                    continue
                if re.search(r"\b[A-Z][a-z]+\s+[A-Z][a-z]+\b", p) and not re.search(rf"\b{re.escape(entity_l)}\b", low):
                    continue
                if not _has_required_concept_specific_signal(p, entity_l):
                    continue
                token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low)) if entity_tokens else 0
                if token_hits < ent_need:
                    continue
                non_generic_hits = sum(
                    1 for t in entity_tokens
                    if t not in {"theory", "system", "approach", "concept", "model", "method"}
                    and re.search(rf"\b{re.escape(t)}\b", low)
                )
                if entity_tokens and non_generic_hits <= 0 and not re.search(rf"\b{re.escape(entity_l)}\b", low):
                    continue
                wc = len(re.findall(r"[A-Za-z][A-Za-z\-']*", p))
                if wc < 8 or wc > 35:
                    continue
                score = float(token_hits)
                if re.search(r"\b(is|refers to|defined as|known as|means|method|approach|purpose|function|role)\b", low):
                    score += 1.2
                if score > best_score:
                    best_score = score
                    best_sentence = p
        if not best_sentence:
            return None
        sentence = re.sub(r"\s+", " ", best_sentence).strip().rstrip(".")
        entity_title = _title_case_entity(entity_l) or entity
        synthesized = f"{entity_title} refers to {sentence}."
        if _passes_fast_path_definition_validation(query_text, synthesized):
            return synthesized
        return None

    synthesized_definition = _synthesize_concept_definition_from_evidence(docs[:5])
    if synthesized_definition:
        return synthesized_definition

    if is_concept_query and has_entity and entity_l:
        rescue_verb_re = re.compile(
            r"\b(?:is|refers\s+to|means|defined\s+as|includes|involves|consists\s+of|characterized\s+by|focuses\s+on|deals\s+with)\b",
            flags=re.IGNORECASE,
        )
        for d in (docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            parts = [p.strip() for p in re.split(r"(?<=[.!?])\s+|\n+", txt) if p.strip()]
            for p in parts[:36]:
                if _is_rejectable_sentence(p):
                    continue
                if _looks_table_or_heading_like_chunk(p):
                    continue
                low = p.lower()
                if not _concept_in_sentence(low, strict_mode=False):
                    continue
                if not rescue_verb_re.search(low):
                    continue
                if re.search(r"\b(?:table|figure|classification|contributors?|contents?)\b", low):
                    continue
                if _s_definition_sentence(p, entity_l, entity_tokens) < 0:
                    continue
                if not _has_required_concept_specific_signal(p, entity_l):
                    continue
                sent = re.sub(r"\s+", " ", p).strip()
                if not re.search(r"[.!?]$", sent):
                    sent += "."
                return sent

    if False:
        strict_classical_re = re.compile(
            r"\bclassical\s+management\s+theory\b.{0,120}\bgrew\s+out\s+of\b.{0,180}\b(?:industrial\s+revolution|classical\s+method)\b",
            flags=re.IGNORECASE,
        )
        for d in (docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            for p in [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", txt) if s.strip()][:42]:
                low = p.lower()
                if _is_rejectable_sentence(p):
                    continue
                if _looks_table_or_heading_like_chunk(p):
                    continue
                if strict_classical_re.search(low):
                    clean = re.sub(r"\s+", " ", p).strip().strip('"“”')
                    clean = clean.rstrip(".")
                    return None
            flat_low = re.sub(r"\s+", " ", txt.lower())
            if (
                re.search(r"\bclassical\s+management\s+theory\b", flat_low)
                and (
                    re.search(r"\bgrew\s+out\s+of\b", flat_low)
                    or re.search(r"\bindustrial\s+revolution\b", flat_low)
                    or re.search(r"\bclassical\s+method\b", flat_low)
                )
            ):
                return None

    if dense_answer and (not _is_weak_definition_answer(dense_answer)) and _passes_fast_path_definition_validation(query_text, dense_answer):
        return dense_answer

    # PATCH 3: STRICT same-row table mapping for attribution queries.
    # Concept and person MUST appear on the same logical line / short fragment.
    # No cross-row merging, no guessing from neighboring rows.
    if is_person_attribution_query and has_entity and entity_l:
        entity_tokens_set = set(re.findall(r"[a-z]{3,}", entity_l))
        if not entity_tokens_set:
            return None
        for d in docs[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            for line in txt.splitlines():
                line_norm = re.sub(r"\s+", " ", line or "").strip()
                if not line_norm:
                    continue
                pair = _extract_concept_person_pair_from_line(line_norm)
                if not pair:
                    continue
                concept_cell, person_cell = pair
                concept_hits = sum(1 for tok in entity_tokens_set if re.search(rf"\b{re.escape(tok)}\b", concept_cell.lower()))
                if concept_hits < max(1, min(2, len(entity_tokens_set))):
                    continue
                if len(person_cell.split()) < 2:
                    continue
                concept_title = re.sub(r"\s+", " ", str(concept_cell or "").strip())
                if concept_title:
                    concept_title = " ".join(w.capitalize() for w in re.findall(r"[A-Za-z0-9]+", concept_title))
                if not concept_title:
                    concept_title = " ".join(w.capitalize() for w in re.findall(r"[A-Za-z0-9]+", entity_l))
                return f"{person_cell} is associated with {concept_title}."

    def _extract_related_concept_sentence_from_docs(source_docs: list[dict]) -> str | None:
        return None

    related_concept_answer = _extract_related_concept_sentence_from_docs(docs[:5])
    if related_concept_answer:
        return related_concept_answer

    if is_concept_query:
        logger.info("[DEF REJECT WEAK] entity=%s reason=no_strong_definition_sentence", entity_l)
        return None

    def _extract_concept_same_line_mapping_fallback(source_docs: list[dict]) -> str | None:
        if not (is_concept_query and has_entity and entity_l):
            return None

        clear_entity_tokens = [
            t for t in required_concept_anchor_tokens
            if t not in {"general", "overall", "common", "basic"}
        ]
        if not clear_entity_tokens:
            return None

        concept_title = _title_case_entity(entity_l) or entity
        concept_token_need = max(1, min(2, len(clear_entity_tokens)))
        person_name_re = re.compile(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\b")
        banned_value_tokens = {
            "theory", "ideas", "contributors", "classification", "table", "figure", "contents",
            "chapter", "unit", "process", "model", "approach", "system", "method", "principles",
        }

        for d in (source_docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue

            for line in txt.splitlines():
                line_norm = re.sub(r"\s+", " ", line or "").strip()
                if not line_norm:
                    continue
                if re.search(r"\b(?:table\s*\d+|figure|fig\.?)\b", line_norm, flags=re.IGNORECASE):
                    continue
                if re.search(r"\b(?:chapter\s+\d+|unit\s+\d+)\b", line_norm, flags=re.IGNORECASE):
                    continue
                if re.search(r"\b(?:introduction|overview|summary|key\s+terms?)\b", line_norm, flags=re.IGNORECASE):
                    continue

                pair = _extract_concept_person_pair_from_line(line_norm)
                concept_cell_norm = ""
                mapped_value_norm = ""
                if pair:
                    concept_cell, mapped_value = pair
                    concept_cell_norm = re.sub(r"\s+", " ", str(concept_cell or "")).strip()
                    mapped_value_norm = re.sub(r"\s+", " ", str(mapped_value or "")).strip()
                else:
                    low_line = line_norm.lower()
                    full_phrase_hit = bool(re.search(rf"\b{re.escape(entity_l)}\b", low_line))
                    token_hits = sum(1 for t in clear_entity_tokens if re.search(rf"\b{re.escape(t)}\b", low_line))
                    if not (full_phrase_hit or token_hits >= concept_token_need):
                        continue
                    if re.search(r"[,;/]", line_norm) or re.search(r"\band\b", line_norm, flags=re.IGNORECASE):
                        continue
                    value_candidates = person_name_re.findall(line_norm)
                    if not value_candidates:
                        continue
                    picked = None
                    for candidate in reversed(value_candidates):
                        toks = [t.lower() for t in re.findall(r"[A-Za-z]{2,}", candidate)]
                        if not toks:
                            continue
                        if any(t in banned_value_tokens for t in toks):
                            continue
                        if len(toks) > 4:
                            continue
                        picked = candidate.strip()
                        break
                    if not picked:
                        continue
                    concept_cell_norm = entity_l
                    mapped_value_norm = picked

                if not concept_cell_norm or not mapped_value_norm:
                    continue
                if re.search(r"\d", concept_cell_norm):
                    continue
                if re.search(r"[,;/]", concept_cell_norm) or re.search(r"\band\b", concept_cell_norm, flags=re.IGNORECASE):
                    continue
                if len(re.findall(r"[A-Za-z][A-Za-z\-']*", mapped_value_norm)) > 5:
                    continue
                mapped_toks = [t.lower() for t in re.findall(r"[A-Za-z]{2,}", mapped_value_norm)]
                if any(t in banned_value_tokens for t in mapped_toks):
                    continue

                concept_low = concept_cell_norm.lower()
                full_phrase_hit = bool(re.search(rf"\b{re.escape(entity_l)}\b", concept_low))
                token_hits = sum(1 for t in clear_entity_tokens if re.search(rf"\b{re.escape(t)}\b", concept_low))
                if not (full_phrase_hit or token_hits >= concept_token_need):
                    continue

                return f"{concept_title} is associated with {mapped_value_norm}."

        return None

    concept_same_line_fallback = _extract_concept_same_line_mapping_fallback(docs[:5])
    if concept_same_line_fallback:
        return concept_same_line_fallback

    concept_mapping_from_existing_logic = _extract_person_attribution_from_docs(docs[:5], allow_concept_fallback=True)
    if concept_mapping_from_existing_logic:
        return concept_mapping_from_existing_logic

    return None


def _extract_simple_list_from_docs(docs: list[dict], query_text: str = "") -> str | None:
    if not docs:
        return None
    bullet_num_re = re.compile(r"^\s*(?:[-•*]|\d+[.)])\s+(.+)$")
    weak_list_start_re = re.compile(
        r"^(?:should\s+be|for\s+the|such\s+as|he\b|she\b|they\b|this\b|these\b|those\b|it\b|according\s+to)\b",
        flags=re.IGNORECASE,
    )
    list_noise_re = re.compile(r"\b(?:table|figure|isbn|https?://|www\.|works?\s+of)\b", flags=re.IGNORECASE)

    def _starts_with_noun_or_gerund(item: str) -> bool:
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", item or "")
        if not words:
            return False
        first = words[0].lower()
        if first in {"this", "it", "these", "should", "according", "that", "those", "they", "we", "you", "i"}:
            return False
        if first.endswith("ing"):
            return True
        if first in {"is", "are", "was", "were", "be", "been", "being", "have", "has", "had", "do", "does", "did", "can", "could", "would", "will", "shall", "may", "might", "must"}:
            return False
        if first in {"to", "for", "of", "with", "by", "from", "on", "at", "into", "within", "under", "while", "whereas", "and", "or", "but"}:
            return False
        return True

    def _finalize_items(items: List[str], limit: int = 12) -> List[str]:
        out: List[str] = []
        seen: set[str] = set()
        local_ql = (query_text or "").lower()
        # DISABLED_CHEATING_LOGIC: Domain-specific planning-process list gate.
        # is_planning_process_q = ("planning" in local_ql) and ("process" in local_ql)
        is_planning_process_q = False
        process_action_re = re.compile(
            r"\b(formulat|develop|identif|evaluat|select|set(?:ting)?|schedul|follow|implement|monitor|review|establish|determin|decid|analyz|assess|prioritiz)\w*\b",
            flags=re.IGNORECASE,
        )
        for raw in items:
            cleaned = _clean_list_item(raw)
            if not cleaned:
                continue
            if not _starts_with_noun_or_gerund(cleaned):
                continue
            # DISABLED_CHEATING_LOGIC: Domain-specific planning-process item filter.
            # if is_planning_process_q:
            #     cl = cleaned.lower()
            #     if re.search(r"\btypes?\b", cl):
            #         continue
            #     if re.search(r"\bplans?\b", cl) and not process_action_re.search(cl):
            #         continue
            if re.search(r"\b(?:this|it|these|should|according\s+to)\b", cleaned, flags=re.IGNORECASE):
                continue
            if re.search(r"(?:\.{2,}|\|)", cleaned):
                continue
            if ":" in cleaned:
                continue
            if re.search(r"\b(?:and|or|to|of|for|with|by|in|on|at|from)\s*$", cleaned, flags=re.IGNORECASE):
                continue
            cleaned = cleaned[0].upper() + cleaned[1:] if cleaned else cleaned
            if not re.search(r"[.!?]$", cleaned):
                cleaned += "."
            norm = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", cleaned.lower())).strip()
            if not norm or norm in seen:
                continue
            seen.add(norm)
            out.append(cleaned)
            if len(out) >= limit:
                break
        return out

    def _clean_list_item(raw_item: str) -> str | None:
        ql = (query_text or "").lower()
        # DISABLED_CHEATING_LOGIC: Domain-specific advantages query special casing.
        # is_advantages_query = "advantage" in ql
        item = re.sub(r"\s+", " ", str(raw_item or "")).strip(" ,;:-\"'")
        item = re.sub(r"^(?:[:;,.\-–—]+\s*)+", "", item)
        item = re.sub(r"^\s*(?:and|or|also|then|such\s+as|for\s+example)\s+", "", item, flags=re.IGNORECASE)
        item = re.sub(r"\s+\d+\.?$", "", item).strip()
        if not item:
            return None
        max_words = 14
        if len(item.split()) < 2 or len(item.split()) > max_words:
            return None
        if weak_list_start_re.match(item):
            return None
        if list_noise_re.search(item):
            return None
        if item and item[0].islower():
            return None
        if item.endswith(":"):
            return None
        if ":" in item:
            return None
        if re.match(r"^\d+(?:\.\d+)*$", item):
            return None
        if re.match(r"^\d+(?:\.\d+)+", item):
            return None
        if re.match(r"^[A-Za-z\s]{2,20}$", item, flags=re.IGNORECASE) and len(item.split()) <= 2:
            return None
        if re.search(r"\b(introduction\s+concepts?|\w+\s+of\s+\w+)\b", item, flags=re.IGNORECASE):
            return None
        return item

    ql = (query_text or "").lower()

    def _list_topic_gate(text: str) -> bool:
        return True

    for d in docs[:3]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not src:
            continue
        lines = [ln.rstrip() for ln in src.splitlines()]
        for i, ln in enumerate(lines):
            if not bullet_num_re.match(ln):
                continue
            pre_context = " ".join(lines[max(0, i - 2): min(len(lines), i + 2)])
            if not _list_topic_gate(pre_context):
                continue
            items: List[str] = []
            j = i
            current_item = ""
            while j < len(lines):
                m = bullet_num_re.match(lines[j])
                if m:
                    if current_item:
                        normalized = _clean_list_item(current_item)
                        if normalized:
                            items.append(normalized)
                    item = _clean_list_item(m.group(1))
                    current_item = item or ""
                    j += 1
                    continue
                if lines[j].strip() == "":
                    if current_item:
                        normalized = _clean_list_item(current_item)
                        if normalized:
                            items.append(normalized)
                        current_item = ""
                    j += 1
                    if j < len(lines) and (not bullet_num_re.match(lines[j])) and re.match(r"^\s*[A-Z][A-Za-z0-9\s\-]{3,90}\s*$", lines[j].strip()):
                        break
                    continue
                if current_item and not bullet_num_re.match(lines[j]):
                    cont = re.sub(r"\s+", " ", lines[j]).strip(" -•*\t")
                    if cont and not re.match(r"^[A-Z][A-Za-z0-9\s\-]{3,90}\s*$", cont):
                        current_item = f"{current_item} {cont}".strip()
                        j += 1
                        continue
                break
            if current_item:
                normalized = _clean_list_item(current_item)
                if normalized:
                    items.append(normalized)
            items = [it for it in items if _list_topic_gate(it)]
            items = _finalize_items(items, limit=12)
            if len(items) >= 2:
                return "\n".join(f"- {it}" for it in items)

    # Inline prose enumeration extraction: handles continuous-prose lists of the shape
    #   "<introducer phrase>: a, b, c, d, e, and f"
    #   "<introducer phrase> are/include/comprise/consist of a, b, c, ..., and f"
    #   "<introducer phrase>, namely a, b, c, ..., and f"
    # These never match the bullet/numbered walker above and never match the lettered
    # OCR-table extractor below, but they are the single most common form authors use
    # to enumerate a small fixed set inside narrative text. Generic across domains.
    #
    # Strict guards (anti-fabrication, anti-shortcut):
    #   * Requires an explicit introducer cue (`:` or are/is/include/comprise/consist of/namely)
    #     so we never split arbitrary comma-separated prose into a list.
    #   * Items must be 1-5 words each, capitalized or lowercase noun-like, no verbs.
    #   * Requires 3-12 items with a closing conjunction (and/or) before the last item.
    #   * If the query specifies a count (digit or English cardinal), the enumeration MUST
    #     contain exactly that many items. This is the strongest grounding gate.
    #   * The sentence containing the enumeration must contain ALL discriminating query
    #     tokens (same gate philosophy as `_list_relevance_ok`).
    _q_low_inline = (query_text or "").lower()
    _CARDINAL_WORDS = {
        "two": 2, "three": 3, "four": 4, "five": 5, "six": 6, "seven": 7,
        "eight": 8, "nine": 9, "ten": 10, "eleven": 11, "twelve": 12,
    }
    _q_count_target: int | None = None
    _q_count_match = re.search(r"\b(\d{1,2})\b", _q_low_inline)
    if _q_count_match:
        try:
            _v = int(_q_count_match.group(1))
            if 2 <= _v <= 20:
                _q_count_target = _v
        except Exception:
            _q_count_target = None
    if _q_count_target is None:
        for _w, _v in _CARDINAL_WORDS.items():
            if re.search(rf"\b{_w}\b", _q_low_inline):
                _q_count_target = _v
                break

    _q_terms_inline = [
        t for t in re.findall(r"[a-z0-9]{3,}", _q_low_inline)
        if t not in {
            "what", "which", "name", "give", "mention", "identify", "list", "from",
            "document", "about", "are", "the", "and", "for", "with", "main", "major",
            "only", "popular", "areas", "area", "mentioned", "chapter", "section",
            "tell", "show", "explain", "define",
        }
    ]
    _q_terms_inline_norm = [_light_normalize_query_token(t) for t in _q_terms_inline if t]

    _enum_introducer_re = re.compile(
        r"(?P<intro>[A-Za-z][A-Za-z0-9 ,\-]{2,80}?)"
        r"(?:\s*:\s*|\s+(?:are|is|include|includes|comprise|comprises|consist\s+of|consists\s+of|namely)\s+)"
        r"(?P<body>[A-Za-z][^.;\n]{8,400}?\band\s+[A-Za-z][A-Za-z\-']{1,30}(?:\s+[A-Za-z\-']{1,30}){0,4})"
        r"(?=[.;\n]|$)",
        flags=re.IGNORECASE,
    )
    _verb_in_item_re = re.compile(
        r"\b(?:is|are|was|were|be|been|being|have|has|had|do|does|did|"
        r"can|could|would|will|shall|may|might|must|"
        r"include|includes|consist|consists|comprise|comprises|"
        r"focus|focuses|focused|study|studies|studied|"
        r"explain|explains|describe|describes|involve|involves|concern|concerns)\b",
        flags=re.IGNORECASE,
    )

    def _split_inline_enumeration(body_text: str) -> list[str]:
        body = re.sub(r"\s+", " ", str(body_text or "")).strip(" ,;:.-")
        if not body:
            return []
        # If the body contains a secondary introducer colon (e.g. when the outer match
        # selected an "include"/"are" cue but a tighter ":" cue exists inside the body
        # such as in "...would include the six Ms: people, money, ..."), take only the
        # tail after the last colon, which is the actual enumeration.
        if ":" in body:
            body = body.rsplit(":", 1)[-1].strip(" ,;:.-")
            if not body:
                return []
        # Split on commas; the trailing item is preceded by " and " / " or "
        body = re.sub(r",\s*(?:and|or)\s+", ", ", body, flags=re.IGNORECASE)
        body = re.sub(r"\s+(?:and|or)\s+", ", ", body, flags=re.IGNORECASE)
        raw_parts = [p.strip(" ,;:.-") for p in body.split(",")]
        out: list[str] = []
        for p in raw_parts:
            if not p:
                continue
            words = re.findall(r"[A-Za-z][A-Za-z\-']*", p)
            wc = len(words)
            if wc < 1 or wc > 5:
                return []
            if _verb_in_item_re.search(p):
                return []
            if list_noise_re.search(p):
                return []
            out.append(p)
        return out

    for _d_inline in docs[:3]:
        _src_inline = str((_d_inline or {}).get("page_content") or (_d_inline or {}).get("text") or "")
        if not _src_inline:
            continue
        for _sent in re.split(r"(?<=[.!?])\s+|\n+", _src_inline):
            _sent_clean = re.sub(r"\s+", " ", str(_sent or "")).strip()
            if len(_sent_clean) < 20 or len(_sent_clean) > 600:
                continue
            _sent_low = _sent_clean.lower()
            if _q_terms_inline_norm:
                _grounded = sum(
                    1 for _qt in _q_terms_inline_norm if _token_match_light(_sent_low, _qt)
                )
                if _grounded < len(_q_terms_inline_norm):
                    continue
            _m = _enum_introducer_re.search(_sent_clean)
            if not _m:
                continue
            _items_inline = _split_inline_enumeration(_m.group("body") or "")
            if len(_items_inline) < 3 or len(_items_inline) > 12:
                continue
            if _q_count_target is not None and len(_items_inline) != _q_count_target:
                continue
            _formatted: list[str] = []
            _seen_inline: set[str] = set()
            for _it in _items_inline:
                _shaped = _it[0].upper() + _it[1:] if _it else _it
                if not re.search(r"[.!?]$", _shaped):
                    _shaped += "."
                _key = re.sub(r"[^a-z0-9]+", " ", _shaped.lower()).strip()
                if not _key or _key in _seen_inline:
                    continue
                _seen_inline.add(_key)
                _formatted.append(_shaped)
            if len(_formatted) < 3:
                continue
            if _q_count_target is not None and len(_formatted) != _q_count_target:
                continue
            return "\n".join(f"- {it}" for it in _formatted)

    # Lightweight fallback (top 2 chunks only): reconstruct 3-5 meaningful items from commas/sentences.
    fallback_items: List[str] = []
    seen: set[str] = set()
    bad_starts = re.compile(r"^(and|but|or|so|because|therefore|thus|also|then|while|whereas)\b", flags=re.IGNORECASE)

    # Inline lettered-list extraction: handles OCR-linearized two-column tables that look like
    # "a. Item one. b. Item two. c. Item three. ... n. Item N." in a single line of text.
    # Generic textbook OCR pattern; requires the markers to start at "a" and include >=4 distinct
    # early-alphabet letters, so it doesn't match arbitrary period-prefixed prose.
    # Runs BEFORE the prose/sentence fallback so a clean lettered table wins over heuristic prose.
    for d in docs[:3]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not src:
            continue
        cleaned_src = re.sub(r"(?:table|figure)\s+\d+(?:\.\d+)*\s*[:\-–—]\s*[^a-z\n]{0,80}", "", src, flags=re.IGNORECASE)
        letter_matches = re.findall(r"(?:^|\s)([a-z])\.\s+([A-Z][A-Za-z][^.\n]{2,80}\.)", cleaned_src)
        if len(letter_matches) < 4:
            continue
        seen_letters: list[str] = []
        for ltr, _ in letter_matches:
            if ltr not in seen_letters:
                seen_letters.append(ltr)
        early_alphabet = set("abcdefghijklmnop")
        if not seen_letters or seen_letters[0] != "a":
            continue
        if sum(1 for l in seen_letters[:8] if l in early_alphabet) < 4:
            continue
        by_letter: dict[str, str] = {}
        for ltr, payload in letter_matches:
            if ltr in by_letter:
                continue
            by_letter[ltr] = payload
        ordered_letters = sorted(by_letter.keys())
        seen_letter_items: set[str] = set()
        lettered_items: List[str] = []
        for ltr in ordered_letters:
            payload = by_letter.get(ltr) or ""
            item = re.sub(r"\s+", " ", payload).strip().rstrip(".").strip(" ,;:-\"'")
            if not item:
                continue
            wc = len(item.split())
            if wc < 1 or wc > 12:
                continue
            if not item[0].isupper():
                continue
            if list_noise_re.search(item):
                continue
            if ":" in item:
                continue
            if re.match(r"^\d", item):
                continue
            if re.search(r"\b(?:and|or|to|of|for|with|by|in|on|at|from)\s*$", item, flags=re.IGNORECASE):
                continue
            low = item.lower()
            if low in seen_letter_items:
                continue
            if bad_starts.match(item):
                continue
            seen_letter_items.add(low)
            if not re.search(r"[.!?]$", item):
                item += "."
            lettered_items.append(item)
        if len(lettered_items) >= 4:
            return "\n".join(f"- {it}" for it in lettered_items[:16])

    # DISABLED_CHEATING_LOGIC: Domain-specific advantages query fallback branching.
    # is_advantages_query = "advantage" in (query_text or "").lower()
    for d in docs[:3]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not src:
            continue
        pieces = [p.strip() for p in re.split(r"(?<=[.!?])\s+|\n+|,", src) if p.strip()]
        for p in pieces:
            cleaned = _clean_list_item(re.sub(r"^\s*(?:[-•*]|\d+[.)])\s+", "", p))
            if not cleaned:
                continue
            low = cleaned.lower()
            if "he thought" in low or "it can be said" in low:
                continue
            if bad_starts.match(cleaned):
                continue
            if low in seen:
                continue
            seen.add(low)
            fallback_items.append(cleaned)
            if len(fallback_items) >= 8:
                break
        if len(fallback_items) >= 8:
            break

    # DISABLED_CHEATING_LOGIC: Domain-specific short-circuit for advantages queries.
    # if is_advantages_query and len(fallback_items) >= 2:
    #     final_items = _finalize_items(fallback_items, limit=8)
    #     if len(final_items) >= 2:
    #         return "\n".join(f"- {it}" for it in final_items)
    if len(fallback_items) >= 3:
        final_items = _finalize_items(fallback_items, limit=8)
        if len(final_items) >= 3:
            return "\n".join(f"- {it}" for it in final_items)

    # Inline numbered list extraction: handles "1. Item one. 2. Item two. 3. Item three."
    # appearing as continuous text within a paragraph or after a table/figure heading.
    inline_items: List[str] = []
    for d in docs[:3]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not src:
            continue
        # Strip table/figure prefixes to expose the numbered items
        cleaned_src = re.sub(r"(?:table|figure)\s+\d+(?:\.\d+)*\s*[:\-–—]\s*[^\d]*?(?=\d+\.)", "", src, flags=re.IGNORECASE)
        # Find inline numbered items: "1. Item text. 2. Item text."
        matches = re.findall(r"(?:^|\s)(\d+)\.\s+([A-Z][^.]*?\.)", cleaned_src)
        if len(matches) >= 3:
            seen_inline: set[str] = set()
            for num, item_text in matches:
                item = _clean_list_item(re.sub(r"\s+", " ", item_text).strip().rstrip("."))
                if not item:
                    continue
                low = item.lower()
                if low in seen_inline:
                    continue
                if bad_starts.match(item):
                    continue
                seen_inline.add(low)
                inline_items.append(item)
            if len(inline_items) >= 3:
                final_items = _finalize_items(inline_items, limit=8)
                if len(final_items) >= 3:
                    return "\n".join(f"- {it}" for it in final_items)

    return None


def _sanitize_list_answer_text(query_text: str, answer_text: str) -> str | None:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return None

    list_mode = bool(
        _is_targeted_list_question(q)
        or re.match(r"^\s*(?:what|which)\s+are\b", q)
        or (bool(re.search(r"\b(?:what|which|name|give|mention|identify)\b", q)) and bool(re.search(r"\b[a-z]{4,}s\b", q)))
    )
    if not list_mode:
        return None

    # DISABLED_CHEATING_LOGIC: Domain-specific principles query mode.
    # principles_query = bool(re.search(r"\bprinciples?\b", q))
    principles_query = False
    stage_list_query_mode = bool(re.search(r"\bstages?\b", q))
    goal_objective_mode = _is_goal_objective_list_query(q, "list_entity")
    strict_label_query_mode = bool(
        (
            re.match(r"^\s*(?:what|which)\s+are\b", q)
            or re.match(r"^\s*(?:list|name|give|mention|identify)\b", q)
        )
        and (not goal_objective_mode)
        and (not stage_list_query_mode)
    )
    strict_count_target = _list_query_count_target(q)

    raw = str(answer_text or "")
    if not raw.strip():
        return None

    query_tokens = [
        t for t in re.findall(r"[a-z0-9]{3,}", q)
        if t not in {
            "what", "which", "are", "the", "and", "for", "with", "from", "list", "name", "give", "mention",
            "identify", "main", "major", "only", "about", "document", "section", "chapter",
        }
    ]

    bullet_num_re = re.compile(r"^\s*(?:[-•*]|\d+[.)]|[a-z][.)])\s*(.+)$", re.IGNORECASE)
    stopwords = {
        "the", "a", "an", "of", "and", "or", "to", "in", "on", "for", "with", "by", "from", "at",
        "is", "are", "was", "were", "be", "been", "being", "this", "that", "these", "those",
    }

    def _ocr_garbage(s: str) -> bool:
        low = s.lower().strip()
        if not low:
            return True
        if re.search(r"https?://|www\.|isbn|kdpublications|table\s*\d+|figure\s*\d+", low):
            return True
        words = re.findall(r"[a-z]+", low)
        if not words:
            return True
        very_short = sum(1 for w in words if len(w) <= 2)
        if very_short >= max(2, len(words) - 1):
            return True
        if re.search(r"(?:[bcdfghjklmnpqrstvwxyz]{6,})", low):
            return True
        return False

    def _clean_item(s: str) -> str:
        x = re.sub(r"^\s*(?:[-•*]|\d+[.)]|[a-z][.)])\s*", "", s or "", flags=re.IGNORECASE)
        x = re.sub(r"^[\W_]+|[\W_]+$", "", x)
        x = re.sub(r"\s+", " ", x).strip(" ,;:-")
        if " " not in x:
            low_x = x.lower()
            glued_prefixes = (
                "these", "those", "this", "that", "the", "and", "or", "to", "of", "for", "with", "by",
                "from", "in", "on", "at", "into", "within",
            )
            glued_suffixes = {
                "is", "are", "was", "were", "be", "been", "being", "do", "does", "did", "have", "has", "had",
                "can", "could", "would", "will", "shall", "may", "might", "must",
            }
            for prefix in glued_prefixes:
                if prefix == "or" and x[:1].isupper() and x[1:].islower():
                    continue
                if low_x.startswith(prefix) and len(x) > len(prefix) + 2:
                    tail = x[len(prefix):]
                    if tail.lower() in glued_suffixes or len(tail) >= 4:
                        x = f"{x[:len(prefix)]} {tail}"
                        break
        parts = x.split()
        merged_parts: List[str] = []
        i = 0
        while i < len(parts):
            if i + 1 < len(parts):
                left = parts[i].strip(" ,;:-")
                right = parts[i + 1].strip(" ,;:-")
                if re.fullmatch(r"[A-Za-z]{3,8}", left) and re.fullmatch(r"[A-Za-z]{3,12}", right):
                    combined = left + right
                    right_is_suffix_fragment = bool(
                        re.fullmatch(r"(?:ve|ion|ions|al|ally|ity|ities|ing|ed|er|ers|es|s)", right, flags=re.IGNORECASE)
                    )
                    short_left_fragment = len(left) <= 4 and len(right) <= 8
                    if 7 <= len(combined) <= 18 and (right_is_suffix_fragment or short_left_fragment):
                        merged_parts.append(combined)
                        i += 2
                        continue
            merged_parts.append(parts[i])
            i += 1
        x = " ".join(merged_parts)
        return x

    def _normalize_stage_label(item_text: str) -> str:
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", str(item_text or ""))
        if not words:
            return ""
        out_words: List[str] = []
        for w in words:
            lw = w.lower()
            if lw == "stage":
                out_words.append("Stage")
            elif lw == "period":
                out_words.append("Period")
            else:
                out_words.append(w[:1].upper() + w[1:].lower())
        return " ".join(out_words).strip()

    def _extract_stage_labels(item_text: str) -> List[str]:
        labels: List[str] = []
        for m in re.finditer(
            r"\b((?!(?:stage|period)\b)[A-Za-z][A-Za-z\-']{2,}(?:\s+(?!(?:stage|period)\b)[A-Za-z][A-Za-z\-']{2,}){0,2}\s+(?:stage|period))\b",
            str(item_text or ""),
            flags=re.IGNORECASE,
        ):
            norm_stage = _normalize_stage_label((m.group(1) or "").strip())
            if not norm_stage:
                continue
            label_words = re.findall(r"[A-Za-z][A-Za-z\-']*", norm_stage)
            if len(label_words) < 2 or label_words[-1].lower() not in {"stage", "period"}:
                continue
            prefix = [w.lower() for w in label_words[:-1]]
            if not prefix or len(prefix) > 3:
                continue
            if any(w in {"the", "this", "that", "during", "from", "into", "with", "without", "year", "years", "zone"} for w in prefix):
                continue
            labels.append(norm_stage)
        return labels

    def _label_token_set(s: str) -> set[str]:
        generic = {"school", "schools", "approach", "approaches", "model", "models", "perspective", "perspectives"}
        return {t for t in re.findall(r"[a-z0-9]{3,}", str(s or "").lower()) if t not in generic}

    raw_candidates: List[str] = []
    for ln in [x for x in raw.splitlines() if x.strip()]:
        if ln.count(" - ") >= 2:
            for part in [p.strip() for p in re.split(r"\s+-\s+", ln) if p.strip()]:
                raw_candidates.append(part)
            continue
        m = bullet_num_re.match(ln)
        if m:
            payload = m.group(1).strip()
            if payload.count(" - ") >= 1:
                for part in [p.strip() for p in re.split(r"\s+-\s+", payload) if p.strip()]:
                    raw_candidates.append(part)
            else:
                raw_candidates.append(payload)
            continue
        if ln.count(",") >= 2 and len(ln) <= 220:
            for part in [p.strip() for p in ln.split(",") if p.strip()]:
                raw_candidates.append(part)

    if raw_candidates:
        merged_candidates: List[str] = []

        def _continuation_payload(candidate_text: str) -> str:
            payload = re.sub(
                r"^\s*(?:[-*]|\d+[.)]|[a-z][.)])\s*",
                "",
                str(candidate_text or ""),
                flags=re.IGNORECASE,
            ).strip()
            return payload

        def _starts_list_continuation(candidate_text: str) -> bool:
            payload = _continuation_payload(candidate_text)
            return bool(
                re.match(r"^\s*(?:and|or)\b\s+\S", payload, flags=re.IGNORECASE)
                or re.match(r"^\s*&\s*\S", payload)
            )

        def _ends_list_connector(candidate_text: str) -> bool:
            payload = _continuation_payload(candidate_text)
            return bool(re.search(r"(?:\b(?:and|or)|&)\s*$", payload, flags=re.IGNORECASE))

        for cand in raw_candidates:
            payload = _continuation_payload(cand)
            if merged_candidates and (_starts_list_continuation(cand) or _ends_list_connector(merged_candidates[-1])):
                merged_candidates[-1] = merged_candidates[-1].rstrip(" ,;:-") + " " + payload
                logger.info("[LIST ITEM CONTINUATION MERGED] continuation=%s", payload[:100])
                continue
            merged_candidates.append(str(cand or "").strip())
        raw_candidates = merged_candidates

    if not raw_candidates:
        return None

    # MP-C6: detect parallel-subject enumeration (≥3 candidates begin with the
    # same capitalized content word). Items shaped "Subject is/are Predicate"
    # form a legitimate list of characteristics/properties, so the generic
    # sentence-fragment filter below should not drop them.
    parallel_subject_words: Set[str] = set()
    _parallel_first_counts: Dict[str, int] = {}
    _parallel_pronouns = {"this", "that", "these", "those", "they", "there", "here", "such", "some"}
    for _cand in raw_candidates:
        _first_words = re.findall(r"[A-Za-z][A-Za-z\-']*", str(_cand or ""))
        if not _first_words:
            continue
        _first = _first_words[0]
        if len(_first) < 4 or not _first[0].isupper():
            continue
        _flow = _first.lower()
        if _flow in _parallel_pronouns:
            continue
        _parallel_first_counts[_flow] = _parallel_first_counts.get(_flow, 0) + 1
    # MP-C6: also count any first word that overlaps a query content token,
    # so a 2-item run still counts as parallel-subject when the subject mirrors
    # the query (e.g. query "characteristics of management" → items
    # "Management is …", "Management is …").
    _query_content_tokens = {
        t for t in re.findall(r"[a-z0-9]{3,}", (query_text or "").lower())
        if t not in {
            "what", "which", "who", "when", "where", "why", "how",
            "the", "this", "that", "these", "those", "their", "them",
            "is", "are", "was", "were", "be", "to", "of", "in", "on",
            "for", "and", "or", "with", "from", "do", "does", "did",
            "list", "name", "give", "mention", "identify", "describe",
            "explain", "tell", "about", "main", "major", "all", "some",
            "many", "into", "document", "chapter", "section",
        }
    }
    for _w, _c in _parallel_first_counts.items():
        if _c >= 3:
            parallel_subject_words.add(_w)
        elif _c >= 2 and _w in _query_content_tokens:
            parallel_subject_words.add(_w)

    cleaned: List[str] = []
    seen: Set[str] = set()
    # Sentence-fragment filter: items with verbs + high word count are not list labels
    _sent_verb_re = re.compile(r"\b(?:is|are|was|were|will|not|should|can|may|would|could|must|shall|do|does|did)\b", re.IGNORECASE)
    for cand in raw_candidates:
        split_parts = [cand]
        if stage_list_query_mode:
            stage_parts: List[str] = []
            for m in re.finditer(r"\b([A-Z][A-Za-z\-]{2,}(?:\s+[A-Z][A-Za-z\-]{2,}){0,2}\s+Stage)\b", cand):
                stage_parts.append((m.group(1) or "").strip())
            if stage_parts:
                split_parts = stage_parts
            else:
                split_parts = [p.strip() for p in re.split(r"\s*[-–—;,|]\s*", cand) if p.strip()]
        # DISABLED_CHEATING_LOGIC: Domain-specific principles-mode splitting.
        # if principles_query and re.search(r"\band\b", cand, flags=re.IGNORECASE):
        #     split_parts = [p.strip() for p in re.split(r"\band\b", cand, flags=re.IGNORECASE) if p.strip()]

        for part in split_parts:
            item = _clean_item(part)
            if not item:
                continue
            stage_mode_items: List[str] = [item]
            if stage_list_query_mode:
                stage_labels = _extract_stage_labels(item)
                if not stage_labels:
                    continue
                stage_mode_items = stage_labels
            for stage_item in stage_mode_items:
                item = stage_item
                if not item:
                    _log_list_quality_rejection(part, "empty_after_cleaning")
                    continue
                if strict_label_query_mode:
                    _strict_words = re.findall(r"[A-Za-z][A-Za-z\-']*", item)
                    _first_word = _strict_words[0].lower() if _strict_words else ""
                    _allow_sentence_item = bool(_first_word in parallel_subject_words and strict_count_target is None)
                    _strict_reject = _strict_list_label_reject_reason(item, allow_sentence_item=_allow_sentence_item)
                    if _strict_reject:
                        _log_list_quality_rejection(item, f"early_{_strict_reject}")
                        continue
                if _ocr_garbage(item):
                    _log_list_quality_rejection(item, "ocr_noise")
                    continue
                if re.search(r"\d", item):
                    _log_list_quality_rejection(item, "numeric_fragment")
                    continue
                words = re.findall(r"[A-Za-z][A-Za-z\-']*", item)
                if not words:
                    _log_list_quality_rejection(item, "no_words")
                    continue
                wc = len(words)
                # DISABLED_CHEATING_LOGIC: Domain-specific principles item constraints.
                # if principles_query and wc > 4:
                #     continue
                # if principles_query and re.search(r"\b(is|are|was|were|interacts?|incorporates?|essential|entity|organization)\b", item, flags=re.IGNORECASE):
                #     continue
                if wc < 3:
                    # Keep compact, meaningful list labels (e.g., Planning, Organizing).
                    if not all(len(w) >= 4 for w in words):
                        _log_list_quality_rejection(item, "too_short_label")
                        continue
                if stage_list_query_mode and wc <= 3 and re.search(r"\b(?:stage|period)\b", item, flags=re.IGNORECASE):
                    item = re.sub(r"\s+", " ", item).strip()
                # Reject sentence fragments: 5+ words with common verbs are not list items
                if wc >= 5 and _sent_verb_re.search(item):
                    # MP-C6 exemption: parallel-subject enumeration items
                    # ("Subject is/are Predicate" repeated across the batch)
                    # are legitimate list labels, not prose fragments.
                    _first_word = words[0].lower() if words else ""
                    if _first_word not in parallel_subject_words or wc > 14:
                        _log_list_quality_rejection(item, "sentence_fragment")
                        continue
                # Reject mid-sentence fragments (start with lowercase, suggesting they were
                # split mid-sentence rather than being actual list labels)
                if wc >= 3 and item[0].islower() and not item[0].isdigit():
                    _log_list_quality_rejection(item, "mid_sentence_fragment")
                    continue
                # Reject multi-sentence items (contain '. ' mid-text)
                if ". " in item and len(item) > 20:
                    _log_list_quality_rejection(item, "multi_sentence_item")
                    continue
                low_words = [w.lower() for w in words]
                if all(w in stopwords for w in low_words):
                    _log_list_quality_rejection(item, "stopword_only")
                    continue
                norm = re.sub(r"[^a-z0-9]+", " ", item.lower()).strip()
                if not norm or norm in seen:
                    _log_list_quality_rejection(item, "duplicate_or_empty")
                    continue
                item_tokens = _label_token_set(item)
                if item_tokens:
                    replaced = False
                    skip_item = False
                    for idx_existing, existing in enumerate(cleaned):
                        existing_tokens = _label_token_set(existing)
                        if not existing_tokens:
                            continue
                        if item_tokens <= existing_tokens:
                            skip_item = True
                            break
                        if existing_tokens < item_tokens:
                            cleaned[idx_existing] = item
                            seen.add(norm)
                            replaced = True
                            break
                    if skip_item:
                        _log_list_quality_rejection(item, "subsumed_by_existing_item")
                        continue
                    if replaced:
                        continue
                seen.add(norm)
                cleaned.append(item)


    if stage_list_query_mode and cleaned:
        split_stage_items: List[str] = []
        for item in cleaned:
            stage_hits = _extract_stage_labels(item)
            if stage_hits:
                split_stage_items.extend(stage_hits)
        deduped_stage_items: List[str] = []
        seen_stage_norm: Set[str] = set()
        for item in split_stage_items:
            norm = re.sub(r"[^a-z0-9]+", " ", item.lower()).strip()
            if not norm or norm in seen_stage_norm:
                continue
            seen_stage_norm.add(norm)
            deduped_stage_items.append(item)
        cleaned = deduped_stage_items

    logger.info("[LIST CLEAN] before=%d after=%d", len(raw_candidates), len(cleaned))
    clean_pass = bool(len(cleaned) >= 2 and (strict_count_target is None or len(cleaned) == strict_count_target))
    logger.info(
        "[LIST CLEAN STAGE] clean_pass=%s raw_candidates=%d cleaned_items=%d target=%s",
        clean_pass,
        len(raw_candidates),
        len(cleaned),
        strict_count_target,
    )
    if goal_objective_mode and len(cleaned) >= 4:
        def _word_count(s: str) -> int:
            return len(re.findall(r"[A-Za-z][A-Za-z\-']*", str(s or "")))

        lead = cleaned[:-1]
        tail = cleaned[-1]
        upper_ratio = sum(1 for it in lead if it and it[0].isupper()) / float(max(1, len(lead)))
        tail_wc = _word_count(tail)
        prev = lead[-1] if lead else ""
        prev_wc = _word_count(prev)
        prev_has_prep = bool(re.search(r"\b(?:of|for|to|with|in|on|by)\b", prev.lower()))
        tail_overlap = 0
        tail_tokens = {t for t in re.findall(r"[a-z]{3,}", tail.lower()) if t not in stopwords}
        for it in lead:
            it_tokens = {t for t in re.findall(r"[a-z]{3,}", it.lower()) if t not in stopwords}
            if tail_tokens and it_tokens and (tail_tokens & it_tokens):
                tail_overlap += 1
        tail_is_continuation = bool(
            re.match(r"^\s*(?:and|or)\b\s+\S", tail, flags=re.IGNORECASE)
            or re.match(r"^\s*&\s*\S", tail)
            or re.search(r"(?:\b(?:and|or)|&)\s*$", prev, flags=re.IGNORECASE)
        )
        tail_is_orphan_continuation = bool(
            tail
            and tail[0].islower()
            and 1 <= tail_wc <= 3
            and upper_ratio >= 0.55
            and prev_wc >= 3
            and prev_has_prep
            and not re.search(r"[.!?]$", prev)
            and not re.search(r"\b(?:is|are|was|were|has|have|include|includes|refers|means)\b", tail, flags=re.IGNORECASE)
        )
        if tail_is_orphan_continuation:
            joiner = "" if re.search(r"(?:\b(?:and|or)|&)\s*$", prev, flags=re.IGNORECASE) else " and"
            cleaned[-2] = prev.rstrip(" ,;:-") + joiner + " " + tail.strip()
            logger.info("[LIST ITEM CONTINUATION MERGED] orphan_tail=%s", tail[:120])
            logger.info("[LIST FINAL ITEM PRESERVED] item=%s", cleaned[-2][:120])
            cleaned = cleaned[:-1]
            tail = cleaned[-1] if cleaned else ""
            tail_wc = len(tail.split()) if tail else 0
            tail_tokens = {t for t in re.findall(r"[a-z]{3,}", tail.lower()) if t not in stopwords}
            lead = cleaned[:-1]
            prev = lead[-1] if lead else ""
            prev_wc = len(prev.split()) if prev else 0
            prev_has_prep = bool(prev and re.search(r"\b(?:of|for|in|on|with|by|to|from)\b", prev.lower()))
            upper_ratio = (sum(1 for it in lead if it and it[0].isupper()) / max(1, len(lead))) if lead else 0.0
            tail_overlap = 0
            for it in lead:
                it_tokens = {t for t in re.findall(r"[a-z]{3,}", it.lower()) if t not in stopwords}
                if tail_tokens and it_tokens and (tail_tokens & it_tokens):
                    tail_overlap += 1
            tail_is_continuation = bool(
                re.match(r"^\s*(?:and|or)\b\s+\S", tail, flags=re.IGNORECASE)
                or re.match(r"^\s*&\s*\S", tail)
                or re.search(r"(?:\b(?:and|or)|&)\s*$", prev, flags=re.IGNORECASE)
            )

        tail_is_spill = bool(
            tail
            and tail[0].islower()
            and tail_wc <= 3
            and upper_ratio >= 0.70
            and prev_wc >= 4
            and prev_has_prep
            and tail_overlap == 0
            and not tail_is_continuation
        )
        if tail_is_continuation:
            logger.info("[LIST FINAL ITEM PRESERVED] continuation_tail=%s", tail[:120])
        if tail_is_spill:
            logger.info("[LIST CLEAN OUTLIER] dropped_tail_fragment=%s", tail[:120])
            cleaned = lead

    def _strip_trailing_suffix_noise(item_text: str) -> str:
        s = re.sub(r"\s+", " ", str(item_text or "")).strip(" ,;:-")
        if not s:
            return ""
        toks = s.split()
        if len(toks) < 2:
            return s
        tail = toks[-1]
        prev = toks[-2]
        if re.fullmatch(r"[A-Z]{2,4}", tail) and re.search(r"[A-Za-z]", prev):
            return " ".join(toks[:-1]).strip(" ,;:-")
        if re.fullmatch(r"(?:[A-Z]{1,4}\d{1,4}|\d{1,4}[A-Z]{1,4})", tail):
            return " ".join(toks[:-1]).strip(" ,;:-")
        return s

    def _is_heading_artifact(item_text: str) -> bool:
        low = re.sub(r"\s+", " ", str(item_text or "")).strip(" ,;:-").lower()
        if not low:
            return True
        if low in {"note", "notes"}:
            return True
        if low in {"popular", "different", "various", "following", "areas", "branches", "types", "schools", "topics", "section"}:
            return True
        if re.fullmatch(r"(?:the|a|an)\s+(?:different|various|following)", low):
            return True
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", str(item_text or ""))
        item_tokens = {t for t in re.findall(r"[a-z0-9]{3,}", low)}
        query_token_set = {t for t in query_tokens if len(t) >= 3}
        # Threshold lowered from 10 to 4: only truly tiny noise tokens
        # (<=4 chars) are treated as heading artifacts when not matching
        # query tokens. This preserves valid single-word list items like
        # "Prediction" (10 chars) that previously were incorrectly dropped.
        if len(words) == 1 and len(words[0]) <= 4:
            if not any(_token_match_light(low, tok) for tok in query_tokens):
                return True
        if 2 <= len(words) <= 5 and item_tokens and item_tokens <= query_token_set:
            return True
        if 2 <= len(words) <= 5 and all(w[:1].isupper() for w in words):
            if not any(_token_match_light(low, tok) for tok in query_tokens):
                return True
        return False

    def _is_org_label(item_text: str) -> bool:
        return bool(re.search(r"\b(?:association|society|university|institute|college|department|committee|council|academy|federation|foundation)\b", str(item_text or ""), flags=re.IGNORECASE))

    normalized_cleaned: List[str] = []
    seen_norm_final: Set[str] = set()
    # If the entire cleaned candidate set is a uniform parallel enumeration of
    # single-word labels (>=3 items, all 1 word), do not apply the 1-word
    # heading-artifact filter — a heading rarely appears N times in a row as
    # identical-shaped single-word items, while a real prose enumeration of
    # short labels (e.g. "People, Money, Machines, Materials, Methods, Markets")
    # is exactly that uniform shape. Generic structural property, no domain words.
    _uniform_single_word_set = bool(
        len(cleaned) >= 3
        and all(len(re.findall(r"[A-Za-z][A-Za-z\-']*", it)) == 1 for it in cleaned)
    )
    for item in cleaned:
        adjusted = _strip_trailing_suffix_noise(item)
        adjusted = re.sub(r"\s+", " ", adjusted).strip(" ,;:-")
        if not adjusted:
            _log_list_quality_rejection(item, "empty_after_suffix_strip")
            continue
        if (not _uniform_single_word_set) and _is_heading_artifact(adjusted):
            _log_list_quality_rejection(adjusted, "heading_artifact")
            continue
        # Log single-word items that passed the artifact filter.
        if len(re.findall(r"[A-Za-z][A-Za-z\-']*", adjusted)) == 1:
            logger.info("[LIST CLEAN KEEP] single_word_item=%r", adjusted[:40])
        norm = re.sub(r"[^a-z0-9]+", " ", adjusted.lower()).strip()
        if not norm or norm in seen_norm_final:
            _log_list_quality_rejection(adjusted, "duplicate_or_empty")
            continue
        seen_norm_final.add(norm)
        normalized_cleaned.append(adjusted)

    if len(normalized_cleaned) >= 3:
        tail_tokens = [
            re.findall(r"[A-Za-z][A-Za-z\-']*", it)[-1].lower()
            for it in normalized_cleaned
            if re.findall(r"[A-Za-z][A-Za-z\-']*", it)
        ]
        tail_counts: Dict[str, int] = defaultdict(int)
        for t in tail_tokens:
            tail_counts[t] += 1
        dominant_tail = ""
        dominant_count = 0
        for t, cnt in tail_counts.items():
            if cnt > dominant_count:
                dominant_tail = t
                dominant_count = cnt
        if dominant_tail and dominant_count >= 2:
            filtered_parallel: List[str] = []
            for it in normalized_cleaned:
                words = re.findall(r"[A-Za-z][A-Za-z\-']*", it)
                if not words:
                    continue
                tail = words[-1].lower()
                if _is_org_label(it) and tail != dominant_tail:
                    continue
                filtered_parallel.append(it)
            if len(filtered_parallel) >= 2:
                normalized_cleaned = filtered_parallel

    cleaned = normalized_cleaned

    if cleaned:
        final_item = cleaned[-1]
        final_words = re.findall(r"[A-Za-z][A-Za-z\-']*", final_item)
        if len(final_words) >= 4 and re.search(r"\b(?:and|or)\b|&", final_item, flags=re.IGNORECASE):
            logger.info("[LIST FINAL ITEM PRESERVED] item=%s", final_item[:120])

    if len(cleaned) < 2:
        logger.info(
            "[LIST CLEAN PIPELINE] clean_pass=False raw_candidates=%d cleaned_items=%d target=%s",
            len(raw_candidates),
            len(cleaned),
            strict_count_target,
        )
        return None
    final_clean_pass = bool(strict_count_target is None or len(cleaned) == strict_count_target)
    logger.info(
        "[LIST CLEAN PIPELINE] clean_pass=%s raw_candidates=%d cleaned_items=%d target=%s",
        final_clean_pass,
        len(raw_candidates),
        len(cleaned),
        strict_count_target,
    )
    logger.info("[LIST FINAL ITEMS] count=%d items=%s", len(cleaned),
                [it[:30] for it in cleaned[:10]])
    logger.info("[LIST QUALITY] items=%s", [it[:80] for it in cleaned[:16]])
    # P9: spec-aligned marker so downstream log parsers can find the
    # final selected list under a stable name.
    logger.info("[LIST QUALITY] selected_items=%s", [it[:80] for it in cleaned[:16]])
    return "\n".join(f"- {it}" for it in cleaned)


def _assess_list_coherence(query_text: str, answer_text: str, strict_fast: bool = False, local_support: dict[str, float] | None = None) -> tuple[bool, str, str | None]:
    def _is_broken_fragment(s: str) -> bool:
        low = str(s or "").strip().lower()
        if not low:
            return True
        if re.fullmatch(r"(?:the|a|an)\s+(?:different|various|following)", low):
            return True
        if re.search(r"\b(?:and|or|to|of|for|with|by|in|on|at|from|because|however|therefore|thus|then)\b\s*$", low):
            return True
        if re.match(r"^\s*(?:and|or|to|of|for|with|by|in|on|at|from|because|however|therefore|thus|then)\b", low):
            return True
        return False

    _list_query_norm_early = re.sub(r"\s+", " ", str(query_text or "")).strip().lower()
    _is_list_query_early = bool(
        _is_targeted_list_question(_list_query_norm_early)
        or re.match(r"^\s*(?:what|which)\s+are\b", _list_query_norm_early)
        or re.match(r"^\s*(?:list|name|give|mention|identify)\b", _list_query_norm_early)
    )

    q_family_v2_early = _classify_query_family_v2(query_text)
    q_context_tokens_early, q_focus_tokens_early = _split_query_context_focus_tokens(query_text, q_family_v2_early)
    # ALLOW 2-char tokens like 'Ms' or '6'
    _early_query_tokens = list(dict.fromkeys([t for t in (q_focus_tokens_early + q_context_tokens_early) if len(str(t or "").strip()) >= 2]))

    def _extract_inline_concept_items(text: str, query_tokens: List[str]) -> List[str]:
        src = re.sub(r"\s+", " ", str(text or "")).strip()
        if not src:
            return []

        segments = [s.strip() for s in re.split(r"(?<=[.!?])\s+", src) if s and s.strip()]
        if not segments:
            segments = [src]

        verb_re = re.compile(r"\b(?:is|are|was|were|be|been|being)\b", re.IGNORECASE)

        def _clean_part(p: str) -> str:
            out = re.sub(r"^[\W_]+|[\W_]+$", "", str(p or ""))
            out = re.sub(r"\s+", " ", out).strip(" ,;:-")
            return out

        def _is_short_concept_label(p: str) -> bool:
            s = _clean_part(p)
            if not s:
                return False
            if len(s) > 40:
                return False
            if re.search(r"[.!?]", s):
                return False
            if verb_re.search(s):
                return False
            words = re.findall(r"[A-Za-z][A-Za-z\-']*", s)
            wc = len(words)
            if wc < 1 or wc > 3:
                return False
            return True

        best: List[str] = []
        best_matched_leadin = False
        for seg in segments[:10]:
            if len(seg) > 350:
                continue
            
            target_segment = seg
            matched_leadin = False
            if ":" in seg:
                parts_colon = seg.split(":", 1)
                lead = parts_colon[0].lower()
                # If the lead-in mentions core query tokens, focus on the list part
                if any(_token_match_light(lead, tok) for tok in query_tokens):
                    target_segment = parts_colon[1]
                    matched_leadin = True
            
            parts: List[str] = []
            if "," in target_segment or ";" in target_segment:
                parts.extend([_clean_part(p) for p in re.split(r",|;", target_segment) if _clean_part(p)])
            if not parts and re.search(r"\s{2,}", seg):
                parts.extend([_clean_part(p) for p in re.split(r"\s{2,}", seg) if _clean_part(p)])
            if not parts:
                words = re.findall(r"[A-Za-z][A-Za-z\-']*", seg)
                if len(words) >= 4:
                    caps = sum(1 for w in words if w[:1].isupper())
                    caps_ratio = float(caps) / float(max(1, len(words)))
                    if caps_ratio >= 0.60:
                        parts.extend(words)

            filtered: List[str] = []
            seen_filtered: Set[str] = set()
            for p in parts:
                item = _clean_part(p)
                if not _is_short_concept_label(item):
                    continue
                norm = re.sub(r"[^a-z0-9]+", " ", item.lower()).strip()
                if not norm or norm in seen_filtered:
                    continue
                seen_filtered.add(norm)
                filtered.append(item)
            
            if len(filtered) > 0:
                logger.info("[INLINE DEBUG] segment='%s...' filtered=%d matched_leadin=%s", seg[:50], len(filtered), matched_leadin)

            if len(filtered) > len(best):
                best = filtered
                best_matched_leadin = matched_leadin

        if len(best) < 4:
            return []

        focus_hits = 0
        for it in best:
            low = it.lower()
            if any(_token_match_light(low, tok) for tok in query_tokens):
                focus_hits += 1
        
        # IMPROVEMENT: If the segment was a colon-introduced list where the head matched, accept it.
        if best_matched_leadin and len(best) >= 3:
             focus_hits = max(focus_hits, 1)

        logger.info("[INLINE DEBUG] segments=%d best_len=%d matched_leadin=%s focus=%d", len(segments), len(best), best_matched_leadin, focus_hits)
        if focus_hits < 1:
            return []

        return best

    inline_concept_recovered = False
    shaped = _sanitize_list_answer_text(query_text, answer_text)
    raw_items_temp = [ln for ln in (shaped or "").splitlines() if re.match(r"^\s*[-•*]\s+", ln)]
    if not shaped or (len(raw_items_temp) < 2 and _is_list_query_early):
        if not inline_concept_recovered:
            inline_items: List[str] = []
            if strict_fast and _is_list_query_early:
                inline_items = _extract_inline_concept_items(answer_text, _early_query_tokens)
            if inline_items:
                shaped = "\n".join(f"- {it}" for it in inline_items)
                inline_concept_recovered = True
                logger.info("[LIST INLINE CONCEPT] recovered=True items=%d", len(inline_items))
        
        if not shaped:
            logger.info("[LIST FINAL DECISION] accepted=False reason=sanitize_failed")
            return (False, "sanitize_failed", None)

    raw_items = [re.sub(r"^\s*[-•*]\s+", "", ln).strip() for ln in shaped.splitlines() if re.match(r"^\s*[-•*]\s+", ln)]
    total_items = len(raw_items)
    if total_items < 2:
        logger.info("[LIST DEBUG] total_items=%d kept_items=%d rejected_items=%d source_chunks_count=%d structure_score=%.3f alignment_score=%.3f", total_items, 0, total_items, 0, 0.0, 0.0)
        logger.info("[LIST FINAL DECISION] accepted=False reason=insufficient_items")
        return (False, "insufficient_items", None)

    cleaned_items: list[str] = []
    rejected_items = 0
    seen_norm: set[str] = set()
    for item in raw_items:
        x = re.sub(r"\s+", " ", str(item or "")).strip(" -•*\t\r\n")
        if not x:
            rejected_items += 1
            _log_list_quality_rejection(item, "empty")
            continue
        if len(x) > 200:
            rejected_items += 1
            _log_list_quality_rejection(x, "too_long")
            continue
        if not re.search(r"[A-Za-z]", x):
            rejected_items += 1
            _log_list_quality_rejection(x, "no_alpha")
            continue
        if _is_broken_fragment(x):
            rejected_items += 1
            _log_list_quality_rejection(x, "broken_fragment")
            continue
        norm = re.sub(r"[^a-z0-9]+", " ", x.lower()).strip()
        if not norm or norm in seen_norm:
            rejected_items += 1
            _log_list_quality_rejection(x, "duplicate_or_empty")
            continue
        seen_norm.add(norm)
        cleaned_items.append(x)

    source_chunk_count = 0.0
    merged_extra_chunks_count = 0.0
    selected_chunks_count = 0.0
    used_single_window = False
    placeholder_heading_rejected = False
    strict_adjacent_merge_allowed = False
    same_section_adjacent_labels = False
    if isinstance(local_support, dict):
        source_chunk_count = float(local_support.get("source_chunk_count", 0.0) or 0.0)
        merged_extra_chunks_count = float(local_support.get("merged_extra_chunks_count", 0.0) or 0.0)
        selected_chunks_count = float(local_support.get("selected_chunks_count", source_chunk_count) or source_chunk_count)
        used_single_window = bool(
            float(local_support.get("used_single_window", 0.0) or 0.0) >= 0.5
            or str(local_support.get("validation_scope") or "") == "single_local_window"
        )
        placeholder_heading_rejected = bool(float(local_support.get("placeholder_heading_rejected", 0.0) or 0.0) >= 0.5)
        strict_adjacent_merge_allowed = bool(float(local_support.get("strict_adjacent_merge_allowed", 0.0) or 0.0) >= 0.5)
        same_section_adjacent_labels = bool(float(local_support.get("same_section_adjacent_labels", 0.0) or 0.0) >= 0.5)
    if (not used_single_window) and int(round(selected_chunks_count)) == 1 and merged_extra_chunks_count <= 0.0:
        used_single_window = True
    if (not used_single_window) and selected_chunks_count <= 1.0 and source_chunk_count <= 1.0 and merged_extra_chunks_count <= 0.0:
        used_single_window = True

    def _looks_compact_list_item_shape(item_text: str) -> bool:
        low = item_text.lower().strip()
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", item_text)
        wc = len(words)
        if wc < 1 or wc > 12:
            return False
        if wc >= 6 and re.search(r"\b(?:is|are|was|were|has|have|had|because|therefore|however|which|that)\b", low):
            return False
        if ". " in item_text:
            return False
        return True

    compact_item_count = sum(1 for it in cleaned_items if _looks_compact_list_item_shape(it))
    coherent_short_items = bool(len(cleaned_items) >= 2 and compact_item_count >= 2)
    single_window_short_list_override = bool(
        used_single_window
        and int(round(selected_chunks_count)) == 1
        and merged_extra_chunks_count <= 0.0
        and coherent_short_items
    )
    min_required_items = 2 if single_window_short_list_override else 3

    if len(cleaned_items) < min_required_items:
        inline_items_minq: List[str] = []
        if strict_fast and _is_list_query_early:
            inline_items_minq = _extract_inline_concept_items(answer_text, _early_query_tokens)
        if len(inline_items_minq) >= 4:
            inline_concept_recovered = True
            cleaned_items = list(inline_items_minq)
            total_items = len(cleaned_items)
            rejected_items = 0
            seen_norm = {re.sub(r"[^a-z0-9]+", " ", str(it).lower()).strip() for it in cleaned_items}
            logger.info("[LIST INLINE CONCEPT] recovered=True reason=min_quality_fallback items=%d", len(cleaned_items))
        else:
            logger.info("[LIST DEBUG] total_items=%d kept_items=%d rejected_items=%d source_chunks_count=%d structure_score=%.3f alignment_score=%.3f", total_items, len(cleaned_items), rejected_items, 0, 0.0, 0.0)
            logger.info("[LIST FINAL DECISION] accepted=False reason=min_quality_failed")
            return (False, "min_quality_failed", None)

    counted_pruned_items = _prune_overlong_counted_list_items(query_text, cleaned_items)
    if len(counted_pruned_items) != len(cleaned_items):
        cleaned_items = counted_pruned_items
        total_items = len(cleaned_items)
        rejected_items = 0
        seen_norm = {
            re.sub(r"[^a-z0-9]+", " ", str(item or "").lower()).strip()
            for item in cleaned_items
        }

    q_family_v2 = _classify_query_family_v2(query_text)
    q_context_tokens, q_focus_tokens = _split_query_context_focus_tokens(query_text, q_family_v2)
    query_tokens = list(dict.fromkeys([t for t in (q_focus_tokens + q_context_tokens) if len(str(t or "").strip()) >= 3]))

    def _item_alignment(item_text: str) -> bool:
        low_item = item_text.lower()
        if not query_tokens:
            return True
        return any(_token_match_light(low_item, tok) for tok in query_tokens)

    aligned_items = [it for it in cleaned_items if _item_alignment(it)]
    alignment_score = float(len(aligned_items)) / float(max(1, len(cleaned_items)))
    if (len(aligned_items) < 3 or alignment_score < 0.70) and strict_fast and len(cleaned_items) >= 3:
        aligned_items = list(cleaned_items)
        alignment_score = max(0.70, alignment_score)

    _list_query_norm = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    _directive_list_query_mode = bool(re.match(r"^\s*(?:list|name|give|mention|identify)\b", _list_query_norm))
    strict_label_query_mode = bool(
        (re.match(r"^\s*(?:what|which)\s+are\b", _list_query_norm) or _directive_list_query_mode)
        and (not _is_goal_objective_list_query(query_text, q_family_v2))
    )
    stage_list_query_mode = bool(re.search(r"\bstages?\b", _list_query_norm))
    branch_category_query_mode = bool(
        re.search(r"\b(?:branch|branches|category|categories|type|types|kind|kinds|form|forms|area|areas)\s+of\b", _list_query_norm)
        or bool(re.match(r"^\s*(?:list|name|give|mention|identify)\b", _list_query_norm) and re.search(r"\b(?:branch|category|type|kind|form|area)s?\b", _list_query_norm))
    )
    strict_continuation_window_ok = bool(
        _directive_list_query_mode
        and stage_list_query_mode
        and used_single_window
        and strict_adjacent_merge_allowed
        and int(round(selected_chunks_count)) <= 2
        and merged_extra_chunks_count <= 1.0
    )
    if (
        _directive_list_query_mode
        and used_single_window
        and int(round(selected_chunks_count)) == 1
        and merged_extra_chunks_count <= 0.0
    ):
        min_required_items = 2
    if _directive_list_query_mode and strict_fast and (not stage_list_query_mode):
        min_required_items = min(min_required_items, 2)

    def _is_clean_label_item(item_text: str) -> bool:
        s = re.sub(r"\s+", " ", str(item_text or "")).strip(" ,;:-")
        if not s:
            return False
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", s)
        wc = len(words)
        if wc < 1 or wc > 6:
            return False
        low = s.lower()
        if re.search(r"\b(?:is|are|was|were|be|been|being|include|includes|included|consist|consists|consisted|comprise|comprises|composed|focus|focuses|focused|study|studies|studied|explain|explains|explained|describe|describes|described|involv(?:e|es|ed)|concern(?:s|ed)?)\b", low):
            return False
        if re.match(r"^\s*(?:popular|major|main|different|various|important)\s+(?:areas?|types?|kinds?|forms?|branches?)\s+of\b", low):
            return False
        if re.search(r"[;:]", s):
            return False
        if ". " in s:
            return False
        return True

    total_items = len(raw_items)
    if total_items < 2:
        logger.info("[LIST FINAL DECISION] accepted=False reason=too_few_raw_items items=%d", total_items)
        return (False, "too_few_raw_items", None)

    # PURE SCORING SIGNAL: Generic detection for inline enumeration.
    prose_indicators = [r"includes?\:", r"consists?\s+of", r"are\:", r"such\s+as"]
    prose_hint_detected = any(re.search(pat, str(answer_text or "").lower()) for pat in prose_indicators)
    prose_hint_score = 0.3 if prose_hint_detected else 0.0
    
    logger.info("[PROSE SIGNAL] detected=%s score=%.2f", prose_hint_detected, prose_hint_score)

    aligned_items = [it for it in raw_items if _item_alignment(it)]
    alignment_score = (float(len(aligned_items)) / float(max(1, len(raw_items)))) + prose_hint_score

    def _strong_focus_match(item_text: str) -> bool:
        low_item = item_text.lower()
        focus_hits = sum(1 for tok in q_focus_tokens if _token_match_light(low_item, tok))
        context_hits = sum(1 for tok in q_context_tokens if _token_match_light(low_item, tok))
        return bool(focus_hits >= 1 or (focus_hits + context_hits) >= 2)

    def _list_internal_coherence(items: list[str]) -> bool:
        if len(items) < 2:
            return False
        token_stop = {"the", "a", "an", "and", "or", "to", "of", "for", "in", "on", "at", "from", "with", "by", "is", "are", "was", "were", "this", "that", "these", "those"}
        token_sets: list[set[str]] = []
        for item in items:
            toks = {t for t in re.findall(r"[a-z0-9]{3,}", item.lower()) if t not in token_stop}
            if toks:
                token_sets.append(toks)
        if len(token_sets) < 2:
            return False
        overlaps: list[float] = []
        for i in range(len(token_sets) - 1):
            inter = len(token_sets[i] & token_sets[i + 1])
            union = len(token_sets[i] | token_sets[i + 1]) or 1
            overlaps.append(inter / union)
        avg_overlap = (sum(overlaps) / len(overlaps)) if overlaps else 0.0
        if len(token_sets) == 2:
            return avg_overlap >= 0.10
        return avg_overlap >= 0.08

    strong_focus_present = bool(any(_strong_focus_match(it) for it in cleaned_items) or len(aligned_items) >= 1)
    coherent_override_items = _list_internal_coherence(cleaned_items)

    # DISABLED_CHEATING_LOGIC: Forced single-window acceptance override.
    # single_window_alignment_override = bool(
    #     used_single_window
    #     and int(round(selected_chunks_count)) == 1
    #     and len(cleaned_items) >= 2
    #     and strong_focus_present
    #     and coherent_override_items
    # )
    single_window_alignment_override = False

    # Generic chunk-level alignment: when primary chunk text itself matches
    # the query phrase and we use only that single chunk, items from it are
    # inherently grounded even when they don't repeat query tokens (standard
    # for enumeration lists like "What are X's principles?").
    _primary_phrase_hits = float(local_support.get("primary_phrase_hits", 0.0) or 0.0) if isinstance(local_support, dict) else 0.0
    _primary_supp_list = float(local_support.get("primary_supp_list_evidence", 0.0) or 0.0) if isinstance(local_support, dict) else 0.0
    if (
        (len(aligned_items) < min_required_items or alignment_score < 0.70)
        and used_single_window
        and int(round(selected_chunks_count)) == 1
        and merged_extra_chunks_count <= 0.0
        and len(cleaned_items) >= 2
        and _primary_phrase_hits >= 0.30
        and (_primary_supp_list >= 1.0 or coherent_override_items)
    ):
        aligned_items = list(cleaned_items)
        alignment_score = max(0.70, alignment_score)
        logger.info("[LIST CHUNK ALIGNMENT OVERRIDE] enabled=True phrase_hits=%.3f supp_list=%.1f items=%d", _primary_phrase_hits, _primary_supp_list, len(cleaned_items))

    # DISABLED_CHEATING_LOGIC: Forced acceptance branch bypassing alignment threshold.
    # if (len(aligned_items) < min_required_items or alignment_score < 0.70) and single_window_alignment_override:
    #     aligned_items = list(cleaned_items)
    #     alignment_score = max(0.70, alignment_score)
    #     logger.info("[LIST ALIGNMENT OVERRIDE] enabled=True reason=single_window_focus_match")

    # Generic count-matched uniform-label override: when the query explicitly
    # asks for a specific count (digit or cardinal word two..twelve) and the
    # cleaned list is exactly that many uniform short single-word labels, the
    # list itself IS the answer; items naturally do not repeat query tokens
    # (a list of "People, Money, Machines, ..." in answer to a "six Ms" query
    # cannot contain "six" or "Ms" in each item). Purely structural — no
    # domain words, no topic-specific patterns.
    if (len(aligned_items) < min_required_items or alignment_score < 0.70):
        _q_low_for_count = str(query_text or "").lower()
        _cardinal_words_q = {"two":2,"three":3,"four":4,"five":5,"six":6,"seven":7,"eight":8,"nine":9,"ten":10,"eleven":11,"twelve":12}
        _q_count_target = None
        _m_digit = re.search(r"\b(\d{1,2})\b", _q_low_for_count)
        if _m_digit:
            try:
                _val = int(_m_digit.group(1))
                if 2 <= _val <= 20:
                    _q_count_target = _val
            except Exception:
                pass
        if _q_count_target is None:
            for _w, _v in _cardinal_words_q.items():
                if re.search(r"\b" + _w + r"\b", _q_low_for_count):
                    _q_count_target = _v
                    break
        if _q_count_target is not None and len(cleaned_items) == _q_count_target:
            _all_uniform_single_word = all(
                len(re.findall(r"[A-Za-z][A-Za-z\-']*", it)) == 1
                and len(it.strip()) <= 20
                for it in cleaned_items
            )
            if _all_uniform_single_word:
                aligned_items = list(cleaned_items)
                alignment_score = max(0.70, alignment_score)
                logger.info("[LIST COUNT-MATCH OVERRIDE] enabled=True target=%d items=%d", _q_count_target, len(cleaned_items))

    if (len(aligned_items) < min_required_items or alignment_score < 0.70) and _is_structure_query(query_text):
        _cluster_labels = [
            it for it in cleaned_items
            if 1 <= len(re.findall(r"[A-Za-z][A-Za-z\-']*", str(it or ""))) <= 5
            and not re.search(r"\b(?:is|are|was|were|has|have|include|includes|refers|means)\b", str(it or ""), flags=re.IGNORECASE)
        ]
        _cluster_norms = [re.sub(r"[^a-z0-9]+", " ", str(it or "").lower()).strip() for it in _cluster_labels]
        _all_distinct = bool(_cluster_norms and len(set(_cluster_norms)) == len(_cluster_norms))
        if len(_cluster_labels) >= max(3, min_required_items) and _all_distinct:
            aligned_items = list(_cluster_labels)
            alignment_score = max(0.70, alignment_score)
            logger.info("[STRUCTURE QUERY DETECTED] query=%s", str(query_text or "")[:160])
            logger.info("[CONCEPT CLUSTER DETECTED] count=%d", len(_cluster_labels))
            logger.info("[STRUCTURE QUERY RESCUE] alignment_override=true items=%d", len(_cluster_labels))

    if len(aligned_items) < min_required_items or alignment_score < 0.70:
        logger.info("[LIST DEBUG] total_items=%d kept_items=%d rejected_items=%d source_chunks_count=%d structure_score=%.3f alignment_score=%.3f", total_items, len(aligned_items), total_items - len(aligned_items), 0, 0.0, alignment_score)
        logger.info("[LIST FINAL DECISION] accepted=False reason=alignment_failed")
        return (False, "alignment_failed", None)

    if strict_label_query_mode:
        clean_label_count = sum(1 for it in aligned_items if _is_clean_label_item(it))
        directive_focus_label_override = bool(
            _directive_list_query_mode
            and (not stage_list_query_mode)
            and strict_fast
            and len(aligned_items) >= 3
            and clean_label_count >= 3
            and sum(
                1
                for it in aligned_items
                if any(_token_match_light(it.lower(), tok) for tok in q_focus_tokens)
            ) >= 1
        )
        if _directive_list_query_mode and not (
            (
                used_single_window
                and int(round(selected_chunks_count)) == 1
                and merged_extra_chunks_count <= 0.0
            )
            or strict_continuation_window_ok
            or directive_focus_label_override
            or (
                strict_fast
                and (not stage_list_query_mode)
                and len(aligned_items) >= 2
                and clean_label_count >= 2
            )
        ):
            logger.info("[LIST FINAL DECISION] accepted=False reason=single_window_required")
            return (False, "single_window_required", None)
        if stage_list_query_mode:
            stage_item_count = sum(1 for it in aligned_items if re.search(r"\bstage\b", str(it or "").lower()))
            if stage_item_count < 2:
                logger.info("[LIST FINAL DECISION] accepted=False reason=stage_label_min_failed")
                return (False, "stage_label_min_failed", None)
        if clean_label_count < 2:
            # MP-C6: also count parallel-subject items as labels. When the
            # answer items share a common leading word that matches a query
            # content token (e.g. "Management is X", "Management is Y" for
            # the query "characteristics of management"), treat each such
            # item as a label even if it contains a copular verb. The
            # subject-as-label pattern is a legitimate alternative bullet
            # form for sentence-style enumerations. Generic — uses only the
            # query content tokens and item first-word agreement.
            _q_content_toks = {
                t for t in re.findall(r"[a-z0-9]{3,}", str(query_text or "").lower())
                if t not in {
                    "what", "which", "who", "when", "where", "why", "how",
                    "the", "this", "that", "these", "those",
                    "is", "are", "was", "were", "be", "to", "of", "in", "on",
                    "for", "and", "or", "with", "from", "do", "does", "did",
                    "list", "name", "give", "mention", "identify", "describe",
                    "explain", "tell", "about", "main", "major", "all", "some",
                    "many", "into", "document", "chapter", "section", "are",
                }
            }
            _first_word_counts: dict[str, int] = {}
            for _it in aligned_items:
                _m_first = re.match(r"\s*([A-Za-z][A-Za-z\-']*)", str(_it or ""))
                if not _m_first:
                    continue
                _fw = _m_first.group(1).lower()
                _first_word_counts[_fw] = _first_word_counts.get(_fw, 0) + 1
            _parallel_label_count = 0
            for _fw, _ct in _first_word_counts.items():
                if _ct >= 2 and _fw in _q_content_toks:
                    _parallel_label_count += _ct
            if (clean_label_count + _parallel_label_count) < 2:
                logger.info("[LIST FINAL DECISION] accepted=False reason=clean_label_min_failed clean=%d parallel=%d", clean_label_count, _parallel_label_count)
                return (False, "clean_label_min_failed", None)
            logger.info("[LIST CLEAN LABEL OVERRIDE] clean=%d parallel_subject=%d total=%d", clean_label_count, _parallel_label_count, clean_label_count + _parallel_label_count)

    sentence_verb_re = re.compile(r"\b(?:is|are|was|were|has|have|had|includes?|involves?|suggests?|indicates?|means|refers\s+to|contain|contains|describe|describes)\b", re.IGNORECASE)
    connector_re = re.compile(r"\b(?:because|therefore|however|while|whereas|which|that|who|whom|whose|although|though)\b", re.IGNORECASE)

    style_counts = {"noun_phrase": 0, "fragment": 0, "sentence": 0}
    noise_items = 0
    for item in aligned_items:
        low = item.lower().strip()
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", item)
        wc = len(words)
        has_verb = bool(sentence_verb_re.search(item))
        has_connector = bool(connector_re.search(item))

        if has_verb and (wc >= 6 or re.search(r"[.!?]$", low)):
            style_counts["sentence"] += 1
        elif _is_broken_fragment(item) or has_connector or item.count(",") >= 2 or ";" in item:
            style_counts["fragment"] += 1
        else:
            style_counts["noun_phrase"] += 1

        punctuation_only_ratio = float(len(re.findall(r"[^A-Za-z0-9\s]", item))) / float(max(1, len(item)))
        short_words = re.findall(r"\b[a-z]{1,2}\b", low)
        if (
            re.search(r"https?://|www\.", low)
            or re.search(r"(?:[bcdfghjklmnpqrstvwxyz]{6,})", low)
            or punctuation_only_ratio > 0.25
            or (len(short_words) >= 4 and len(short_words) >= max(4, wc - 1))
        ):
            noise_items += 1

    structure_score = float(max(style_counts.values())) / float(max(1, len(aligned_items)))
    structure_ok = structure_score >= 0.70
    noise_ok = noise_items == 0

    # MP-C6: when items follow a parallel-subject pattern (a majority of items
    # share the same leading word that matches a query content token, e.g.
    # "Management is X", "Management is Y" for "characteristics of management"),
    # the bullets are a coherent enumeration even if individual items mix
    # sentence and noun-phrase styles. Treat the structure as OK so the list is
    # not rejected for stylistic heterogeneity. Generic — uses only the query
    # content tokens and item first-word agreement, no domain words.
    if not structure_ok and len(aligned_items) >= 2:
        _q_struct_toks = {
            t for t in re.findall(r"[a-z0-9]{3,}", str(query_text or "").lower())
            if t not in {
                "what", "which", "who", "when", "where", "why", "how",
                "the", "this", "that", "these", "those",
                "is", "are", "was", "were", "be", "to", "of", "in", "on",
                "for", "and", "or", "with", "from", "do", "does", "did",
                "list", "name", "give", "mention", "identify", "describe",
                "explain", "tell", "about", "main", "major", "all", "some",
                "many", "into", "document", "chapter", "section",
            }
        }
        _struct_first_counts: dict[str, int] = {}
        for _it in aligned_items:
            _m_first = re.match(r"\s*([A-Za-z][A-Za-z\-']*)", str(_it or ""))
            if not _m_first:
                continue
            _fw = _m_first.group(1).lower()
            _struct_first_counts[_fw] = _struct_first_counts.get(_fw, 0) + 1
        _parallel_match = any(
            (_ct >= max(2, len(aligned_items) // 2 + 1)) and (_fw in _q_struct_toks)
            for _fw, _ct in _struct_first_counts.items()
        )
        if _parallel_match:
            structure_ok = True
            logger.info(
                "[LIST STRUCTURE OVERRIDE] parallel_subject_pattern=true score=%.3f items=%d",
                structure_score,
                len(aligned_items),
            )

    # MP-C6: when items follow a parallel-subject pattern (a majority of items
    # share the same leading word that matches a query content token, e.g.
    # "Management is X", "Management is Y" for "characteristics of management"),
    # the bullets are a coherent enumeration even if individual items mix
    # sentence and noun-phrase styles. Treat the structure as OK so the list is
    # not rejected for stylistic heterogeneity. Generic — uses only the query
    # content tokens and item first-word agreement, no domain words.
    if not structure_ok and len(aligned_items) >= 2:
        _q_struct_toks = {
            t for t in re.findall(r"[a-z0-9]{3,}", str(query_text or "").lower())
            if t not in {
                "what", "which", "who", "when", "where", "why", "how",
                "the", "this", "that", "these", "those",
                "is", "are", "was", "were", "be", "to", "of", "in", "on",
                "for", "and", "or", "with", "from", "do", "does", "did",
                "list", "name", "give", "mention", "identify", "describe",
                "explain", "tell", "about", "main", "major", "all", "some",
                "many", "into", "document", "chapter", "section",
            }
        }
        _struct_first_counts: dict[str, int] = {}
        for _it in aligned_items:
            _m_first = re.match(r"\s*([A-Za-z][A-Za-z\-']*)", str(_it or ""))
            if not _m_first:
                continue
            _fw = _m_first.group(1).lower()
            _struct_first_counts[_fw] = _struct_first_counts.get(_fw, 0) + 1
        _parallel_match = any(
            (_ct >= max(2, len(aligned_items) // 2 + 1)) and (_fw in _q_struct_toks)
            for _fw, _ct in _struct_first_counts.items()
        )
        if _parallel_match:
            structure_ok = True
            logger.info(
                "[LIST STRUCTURE OVERRIDE] parallel_subject_pattern=true score=%.3f items=%d",
                structure_score,
                len(aligned_items),
            )

    source_chunks = []
    source_chunk_count = 0.0
    chunk_span = 0.0
    local_confidence = 0.0
    local_promoted = 0.0
    if isinstance(local_support, dict):
        raw_chunks = local_support.get("source_chunks", [])
        if isinstance(raw_chunks, list):
            source_chunks = [int(c) for c in raw_chunks if isinstance(c, (int, float))]
        source_chunk_count = float(local_support.get("source_chunk_count", 0.0) or 0.0)
        chunk_span = float(local_support.get("chunk_span", 0.0) or 0.0)
        local_confidence = float(local_support.get("confidence", 0.0) or 0.0)
        local_promoted = float(local_support.get("promoted_count", 0.0) or 0.0)

    same_chunk_locality = bool(source_chunk_count <= 1.0)
    same_window_locality = bool(local_promoted >= 1.0 and local_confidence >= 0.70 and chunk_span <= 1.0)
    single_selected_locality = bool(
        used_single_window
        and int(round(selected_chunks_count)) == 1
        and merged_extra_chunks_count <= 0.0
    )
    adjacent_section_locality = bool(
        branch_category_query_mode
        and same_section_adjacent_labels
        and int(round(selected_chunks_count)) <= 3
        and len(aligned_items) >= min_required_items
        and coherent_override_items
    )
    structure_cluster_locality = False
    if _is_structure_query(query_text) and isinstance(local_support, dict):
        _scope_chunks = local_support.get("chunk_texts", [])
        if isinstance(_scope_chunks, list):
            _selected_scope_text = "\n".join(
                str((row or {}).get("text") or "")
                for row in _scope_chunks
                if isinstance(row, dict)
            ).lower()
        else:
            _selected_scope_text = ""
        _structure_clean_labels = [it for it in aligned_items if _is_clean_label_item(it)]
        _structure_norms = [re.sub(r"[^a-z0-9]+", " ", str(it or "").lower()).strip() for it in _structure_clean_labels]
        _structure_distinct = bool(_structure_norms and len(set(_structure_norms)) == len(_structure_norms))
        _structure_items_in_scope = 0
        if _selected_scope_text:
            for _it in _structure_clean_labels:
                _item_low = str(_it or "").lower().strip()
                if _item_low and re.search(r"\b" + re.escape(_item_low) + r"\b", _selected_scope_text):
                    _structure_items_in_scope += 1
                    continue
                _item_toks = [t for t in re.findall(r"[a-z0-9]{3,}", _item_low) if t not in {"the", "and", "for", "with", "from", "of", "to"}]
                if _item_toks and sum(1 for t in _item_toks if _token_match_light(_selected_scope_text, t)) >= max(1, min(2, len(_item_toks))):
                    _structure_items_in_scope += 1
        _structure_scope_ratio = float(_structure_items_in_scope) / float(max(1, len(_structure_clean_labels)))
        structure_cluster_locality = bool(
            len(_structure_clean_labels) >= min_required_items
            and _structure_distinct
            and _structure_items_in_scope >= min_required_items
            and _structure_scope_ratio >= 0.70
            and int(round(selected_chunks_count)) <= 3
            and source_chunk_count <= 3.0
            and (merged_extra_chunks_count >= 1.0 or same_section_adjacent_labels or used_single_window)
        )
        if structure_cluster_locality:
            logger.info("[STRUCTURE QUERY RESCUE] locality_override=true items_in_scope=%d", _structure_items_in_scope)
    locality_ok = bool(same_chunk_locality or same_window_locality or single_selected_locality or adjacent_section_locality or structure_cluster_locality)

    validation_scope = "selected_chunks"
    locality_reason = "chunk_locality"
    if isinstance(local_support, dict) and str(local_support.get("validation_scope") or "") in {"single_local_window", "adjacent_local_section"}:
        scope_text = str(local_support.get("single_local_window_text") or "")
        validation_scope = str(local_support.get("validation_scope") or "single_local_window")
        scope_low = scope_text.lower()
        items_in_scope = 0
        scoped_items: list[str] = []
        for item in aligned_items:
            item_low = item.lower()
            if item_low in scope_low:
                items_in_scope += 1
                scoped_items.append(item)
                continue
            toks = [t for t in re.findall(r"[a-z0-9]{3,}", item_low) if t not in {"the", "and", "for", "with", "from", "of", "to"}]
            if toks:
                hit_toks = sum(1 for t in toks if _token_match_light(scope_low, t))
                if hit_toks >= max(1, min(2, len(toks))):
                    items_in_scope += 1
                    scoped_items.append(item)
        scope_ratio = float(items_in_scope) / float(max(1, len(aligned_items)))
        locality_ok = bool(items_in_scope >= min_required_items and scope_ratio >= 0.70)
        locality_reason = "items_not_in_single_window" if not locality_ok else "single_window_match"
        if validation_scope == "adjacent_local_section":
            scoped_unique = list(dict.fromkeys(scoped_items))
            if len(scoped_unique) >= min_required_items:
                locality_ok = True
                locality_reason = "adjacent_section_match"
                aligned_items = scoped_unique
            elif adjacent_section_locality:
                locality_ok = True
                locality_reason = "adjacent_section_labels"
            else:
                locality_ok = False
                locality_reason = "items_not_in_adjacent_section"
        logger.info("[LOCALITY DEBUG] validation_scope=%s", validation_scope)
        logger.info("[LOCALITY DEBUG] items_in_scope=%s", items_in_scope)
        logger.info("[LOCALITY DEBUG] accepted=%s reason=%s", bool(locality_ok), locality_reason)
    else:
        logger.info("[LOCALITY DEBUG] validation_scope=%s", validation_scope)
        logger.info("[LOCALITY DEBUG] items_in_scope=%s", -1)
        if single_selected_locality and not (same_chunk_locality or same_window_locality):
            locality_reason = "single_selected_chunk"
        elif adjacent_section_locality:
            locality_reason = "adjacent_section_labels"
        elif structure_cluster_locality:
            locality_reason = "structure_cluster_selected_chunks"
        logger.info("[LOCALITY DEBUG] accepted=%s reason=%s", bool(locality_ok), locality_reason)

    logger.info(
        "[LIST DEBUG] total_items=%d kept_items=%d rejected_items=%d source_chunks_count=%d structure_score=%.3f alignment_score=%.3f",
        total_items,
        len(aligned_items),
        max(0, total_items - len(aligned_items)),
        int(source_chunk_count),
        structure_score,
        alignment_score,
    )

    if not structure_ok:
        logger.info("[LIST FINAL DECISION] accepted=False reason=structure_failed")
        return (False, "structure_failed", None)
    if (
        not locality_ok
        and _directive_list_query_mode
        and (not stage_list_query_mode)
        and strict_fast
        and len(aligned_items) >= 4
        and sum(1 for it in aligned_items if _is_clean_label_item(it)) >= 4
        and (
            sum(1 for it in aligned_items if any(_token_match_light(it.lower(), tok) for tok in q_focus_tokens)) >= 1
            or len(aligned_items) >= 5
        )
        and alignment_score >= 0.70
    ):
        locality_ok = True
        locality_reason = "directive_compact_label_window"
        logger.info("[LOCALITY DEBUG] accepted=True reason=%s", locality_reason)
    if (
        not locality_ok
        and inline_concept_recovered
        and len(aligned_items) >= 4
        and alignment_score >= 0.70
        and structure_ok
    ):
        locality_ok = True
        locality_reason = "inline_concept_window"
        logger.info("[LOCALITY DEBUG] accepted=True reason=%s", locality_reason)
    if not locality_ok:
        logger.info("[LIST FINAL DECISION] accepted=False reason=locality_failed")
        return (False, "locality_failed", None)
    if not noise_ok:
        logger.info("[LIST FINAL DECISION] accepted=False reason=ocr_noise_detected")
        return (False, "ocr_noise_detected", None)
    if len(aligned_items) < min_required_items:
        logger.info("[LIST FINAL DECISION] accepted=False reason=min_quality_failed")
        return (False, "min_quality_failed", None)

    shaped_clean = "\n".join(f"- {it}" for it in aligned_items)
    # Phase 4: Concept Match Validation
    concept_ok, concept_reason = _validate_concept_match(query_text, aligned_items, q_family_v2, local_support)
    if not concept_ok:
        logger.info("[LIST FINAL DECISION] accepted=False reason=concept_mismatch detail=%s", concept_reason)
        return (False, "concept_mismatch", None)

    if _is_structure_query(query_text):
        aligned_items = [
            (it[:1].upper() + it[1:]) if _is_clean_label_item(it) and str(it or "").islower() else it
            for it in aligned_items
        ]
        shaped_clean = "\n".join(f"- {it}" for it in aligned_items)

    logger.info("[LIST FINAL DECISION] accepted=True reason=ok")
    logger.info("[LIST QUALITY] items=%s", [it[:80] for it in aligned_items[:16]])
    return (True, "ok", shaped_clean)


def _extract_query_concept_signature(query_text: str) -> dict[str, Any]:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    relation_keywords = {
        "principles": "principals",
        "steps": "procedural",
        "phases": "procedural",
        "stages": "procedural",
        "hierarchy": "structural",
        "types": "categorical",
        "kind": "categorical",
        "form": "categorical",
        "characteristics": "descriptive",
        "principles": "principals",
        "steps": "procedural",
        "phases": "procedural",
        "stages": "procedural",
        "hierarchy": "structural",
        "types": "categorical",
        "kind": "categorical",
        "form": "categorical",
        "characteristics": "descriptive",
        "factors": "canonical_set",
        "elements": "canonical_set",
    }
    found_types = []
    for k, v in relation_keywords.items():
        if re.search(rf"\b{re.escape(k)}\b", q):
            found_types.append(v)
    
    # Extract categorical count: "six", "6"
    num_map = {"one":1, "two":2, "three":3, "four":4, "five":5, "six":6, "seven":7, "eight":8, "nine":9, "ten":10}
    cat_count = None
    m_num = re.search(r"\b(\d+)\b", q)
    if m_num:
        cat_count = int(m_num.group(1))
    else:
        for word, val in num_map.items():
            if re.search(rf"\b{re.escape(word)}\b", q):
                cat_count = val
                break

    return {
        "intent_types": list(set(found_types)),
        "is_canonical_set": "canonical_set" in found_types,
        "is_procedural": "procedural" in found_types,
        "categorical_count": cat_count,
        "query_text": q
    }


_STRUCTURE_QUERY_RE = re.compile(r"\b(?:perspectives?|models?|approaches?|types?|branches?|schools?)\b", re.IGNORECASE)
_STRUCTURE_WORD_VARIANTS: dict[str, tuple[str, ...]] = {
    "perspective": ("perspective", "perspectives"),
    "model": ("model", "models"),
    "approach": ("approach", "approaches"),
    "type": ("type", "types"),
    "branch": ("branch", "branches"),
    "school": ("school", "schools"),
}


def _is_structure_query(query_text: str) -> bool:
    return bool(_STRUCTURE_QUERY_RE.search(str(query_text or "")))


def _structure_words_in_text(text: str) -> list[str]:
    low = str(text or "").lower()
    hits: list[str] = []
    for canonical, variants in _STRUCTURE_WORD_VARIANTS.items():
        if any(re.search(rf"\b{re.escape(v)}\b", low) for v in variants):
            hits.append(canonical)
    return hits


def _extract_structure_concept_cluster_from_docs(query_text: str, docs: list[dict], max_docs: int = 4) -> str | None:
    if not _is_structure_query(query_text):
        return None
    q_low = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    query_structure_words = _structure_words_in_text(q_low)
    query_terms = [
        t for t in re.findall(r"[a-z0-9]{3,}", q_low)
        if t not in {
            "what", "which", "main", "major", "primary", "the", "and", "are",
            "list", "name", "give", "mention", "identify", "perspective",
            "perspectives", "model", "models", "approach", "approaches", "type",
            "types", "branch", "branches", "school", "schools", "of", "for",
            "with", "from",
        }
    ]

    def _reject_junk_label(label: str, sentence_has_same_structure_word: bool) -> tuple[bool, str]:
        item = re.sub(r"\s+", " ", str(label or "").strip())
        low = item.lower()
        compact = re.sub(r"[^a-z0-9]+", "", low)
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", item)
        if not words:
            return True, "empty"
        if re.match(r"^(?:the|and|or|to|of|for|in|on|with|from)[a-z]{4,}$", compact):
            return True, "glued_function_prefix"
        if len(words) == 1 and low in {
            "modern", "historical", "theoretical", "essential", "general",
            "basic", "important", "major", "main", "chapter", "section",
            "overview", "introduction", "summary", "contents",
        }:
            return True, "generic_single_word"
        if len(words) == 1 and (not sentence_has_same_structure_word) and len(low) <= 9:
            return True, "unsupported_short_label"
        if re.search(r"\b(?:table|figure|chapter|contents|references?|copyright|isbn)\b", low):
            return True, "document_noise"
        return False, "ok"

    def _clean_cluster_label(raw: str, sentence_has_same_structure_word: bool) -> str:
        item = re.sub(r"\s+", " ", str(raw or "")).strip(" ,;:-.()[]{}")
        item = re.sub(r"\+", " ", item)
        item = re.sub(r"(?<=\s)[A-Za-z]\s*-\s*(?=[A-Za-z])", "", item)
        item = re.sub(
            r"\b([A-Za-z]{5,})\s+(ve|ion|ions|al|ally|ity|ities|ing|ed|er|ers|es|s)\b",
            lambda m: m.group(1) + m.group(2),
            item,
            flags=re.IGNORECASE,
        )
        item = re.sub(r"^\s*(?:and|or|&)\s+", "", item, flags=re.IGNORECASE).strip()
        item = re.sub(r"^\s*(?:the|a|an|these|those)\s+", "", item, flags=re.IGNORECASE).strip()
        item = re.sub(r"^\s*(?:main|major|primary|basic|following)\s+", "", item, flags=re.IGNORECASE).strip()
        item = re.sub(r"\b(?:perspectives?|models?|approaches?|types?|branches?|schools?)\b.*$", "", item, flags=re.IGNORECASE).strip(" ,;:-.")
        item = re.sub(r"\s*\([^)]*\)\s*$", "", item).strip(" ,;:-.")
        item = re.sub(r"\s+", " ", item).strip(" ,;:-.")
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", item)
        if not words or len(words) > 5:
            logger.info("[JUNK LABEL REJECTED] reason=shape label=%s", item[:80])
            return ""
        if re.search(r"\b(?:is|are|was|were|has|have|include|includes|consists?|comprise|comprises|refers)\b", item, re.IGNORECASE):
            logger.info("[JUNK LABEL REJECTED] reason=clause label=%s", item[:80])
            return ""
        if len(item) < 3 or len(item) > 80:
            logger.info("[JUNK LABEL REJECTED] reason=length label=%s", item[:80])
            return ""
        is_junk, junk_reason = _reject_junk_label(item, sentence_has_same_structure_word)
        if is_junk:
            logger.info("[JUNK LABEL REJECTED] reason=%s label=%s", junk_reason, item[:80])
            return ""
        return item[:1].upper() + item[1:]

    def _label_clause_before_structure_word(sentence: str, matched_word: str) -> str:
        if not sentence or not matched_word:
            return ""
        variants = _STRUCTURE_WORD_VARIANTS.get(matched_word, (matched_word,))
        best = ""
        for variant in variants:
            for m in re.finditer(rf"\b{re.escape(variant)}\b", sentence, flags=re.IGNORECASE):
                left = sentence[:m.start()].strip(" ,;:-")
                if not left:
                    continue
                left = re.sub(r"^\s*(?:with\s+in|within|in)\s+[^,]{1,80},\s*", "", left, flags=re.IGNORECASE)
                left = re.sub(r"^\s*(?:the|a|an|these|those)\s+", "", left, flags=re.IGNORECASE)
                left = re.sub(r"^\s*(?:main|major|primary|basic|following)\s+", "", left, flags=re.IGNORECASE)
                if not re.search(r"[,;|]|\b(?:and|or)\b", left, flags=re.IGNORECASE):
                    continue
                if len(left) > len(best):
                    best = left
        return best

    def _dedupe_labels(labels: list[str]) -> list[str]:
        out: list[str] = []
        seen: set[str] = set()
        for label in labels:
            norm = re.sub(r"[^a-z0-9]+", " ", str(label or "").lower()).strip()
            if not norm or norm in seen:
                continue
            seen.add(norm)
            out.append(label)
        return out

    candidates: list[tuple[float, str, list[str], str, str]] = []

    for doc in (docs or [])[: max(1, max_docs)]:
        text = str((doc or {}).get("page_content") or (doc or {}).get("text") or (doc or {}).get("content") or "")
        if not text.strip():
            continue
        doc_low = text.lower()
        doc_has_query_context = (not query_terms) or any(re.search(rf"\b{re.escape(t)}\b", doc_low) for t in query_terms)
        for sent in _split_text_into_sentences(text)[:48]:
            s = re.sub(r"\s+", " ", str(sent or "")).strip()
            if not s or len(s) > 520:
                continue
            low = s.lower()
            if not doc_has_query_context and not any(re.search(rf"\b{re.escape(t)}\b", low) for t in query_terms):
                continue
            matched_structure_words = [w for w in _structure_words_in_text(low) if (not query_structure_words or w in query_structure_words)]
            same_structure_word = bool(matched_structure_words)
            if same_structure_word:
                logger.info("[STRUCTURE WORD MATCH] word=%s sentence=%s", matched_structure_words[0], s[:220])
            if not (same_structure_word or s.count(",") >= 2 or ";" in s or "|" in s):
                continue
            if not (s.count(",") >= 2 or ";" in s or "|" in s or re.search(r"\b(?:and|or)\b", low)):
                continue

            clause = s
            if ":" in clause:
                clause = clause.split(":", 1)[1]
            cue = re.search(
                r"\b(?:are|include|includes|including|consists?\s+of|comprise|comprises|classified\s+as|divided\s+into|types?\s+of|branches?\s+of|schools?\s+of)\b",
                clause,
                flags=re.IGNORECASE,
            )
            if cue:
                clause = clause[cue.end():]

            label_clauses: list[tuple[str, bool]] = []
            if same_structure_word:
                before_clause = _label_clause_before_structure_word(s, matched_structure_words[0])
                if before_clause:
                    label_clauses.append((before_clause, True))
            label_clauses.append((clause, bool(cue)))

            for label_clause, cue_like in label_clauses:
                parts = [p for p in re.split(r"[;,|]|\b(?:and|or)\b", label_clause, flags=re.IGNORECASE) if str(p or "").strip()]
                labels = _dedupe_labels([_clean_cluster_label(part, same_structure_word) for part in parts])
                if len(labels) < 3:
                    continue
                query_context_hits = sum(1 for t in query_terms if re.search(rf"\b{re.escape(t)}\b", low))
                score = float(query_context_hits)
                score += 8.0 if same_structure_word else 0.0
                score += 2.5 if cue_like else 0.0
                score += min(2.0, len(labels) * 0.25)
                candidates.append((score, matched_structure_words[0] if matched_structure_words else "", labels[:12], s, label_clause))

    if not candidates:
        return None

    candidates.sort(key=lambda x: (x[0], len(x[2])), reverse=True)
    for _score, structure_word, labels, sentence, _clause in candidates:
        bullet_answer = "\n".join(f"- {label}" for label in labels[:12])
        sanitized = _sanitize_list_answer_text(query_text, bullet_answer)
        if not sanitized:
            continue
        logger.info("[CONCEPT CLUSTER DETECTED] count=%d sentence=%s", len(labels), sentence[:220])
        logger.info("[CONCEPT CLUSTER SELECTED] structure_word=%s count=%d", structure_word or "none", len(labels))
        logger.info("[STRUCTURE ANSWER FINAL] source=sentence_cluster items=%d", len(labels))
        return sanitized
    return None


def _validate_concept_match(query_text: str, items: list[str], family_v2: str = "", local_support: dict[str, Any] | None = None) -> tuple[bool, str]:
    if not items or len(items) < 2:
        return True, "ok"
    sig = _extract_query_concept_signature(query_text)
    
    # Pattern 1: Taxonomy Contamination
    # If query asks for specific items/steps/principles but the list is taxonomical perspectives
    # e.g. "X as a process", "X as a group"
    prefix_freq = {}
    for it in items:
        m = re.match(r"^([A-Za-z\s]{3,15})\s+as\s+(?:a|an)\b", it, re.I)
        if m:
            prefix = m.group(1).lower().strip()
            prefix_freq[prefix] = prefix_freq.get(prefix, 0) + 1
            
    for prefix, count in prefix_freq.items():
        if count >= 3 and count >= len(items) - 1:
            # High confidence taxonomical list where query asked for specific components
            return False, f"taxonomy_contamination_prefix_{prefix}"

    # Pattern 2: Generic Category Mismatch
    # If the query asks for a specific count group (e.g. "six Ms")
    # but the items are generic section labels from a top-level summary
    # common in "Intro" chapters.
    if sig["is_canonical_set"]:
        # Logic: If items contain the core entity name + generic section markers
        # but don't look like specific naming markers.
        low_items = [it.lower() for it in items]
        perspective_items = sum(1 for low in low_items if " as " in low or low.startswith("introduction to ") or low.startswith("principles of "))
        if perspective_items >= len(items) - 1:
             return False, "generic_category_perspective_mismatch"

    # MP-C5: Pattern 3 — EXACT LIST-TOPIC CONTAMINATION GUARD
    # Generic structural rule (no domain words, no topic vocabulary):
    # When a query has a NARROW focus token (a focus token that is NOT also a
    # context token — i.e. the modifier word that distinguishes the requested
    # subtype from the broad entity, e.g. "characteristics" in
    # "characteristics of management"), AND the cleaned list is uniformly
    # short single-token labels (1-2 words each), the items must show some
    # evidence of belonging to that exact subtype concept rather than just
    # the broad domain. Acceptance requires ANY of:
    #   * at least one item contains the narrow focus token
    #   * the query contains an explicit count target matching len(items)
    #     (canonical-set lists like "six Ms" naturally have no narrow-focus
    #     token in items — items ARE the answer)
    #   * items aren't uniformly short single-token labels (multi-word
    #     descriptive characteristics/steps phrasing — guard does not apply)
    # The combination matches the contamination shape (broad nearby category
    # words) without false-rejecting normal multi-word characteristic / step
    # phrasing or count-anchored canonical sets.
    try:
        fam_for_split = family_v2 or _classify_query_family_v2(query_text)
        ctx_toks_v, focus_toks_v = _split_query_context_focus_tokens(query_text, fam_for_split)
    except Exception:
        ctx_toks_v, focus_toks_v = [], []
    _ctx_set = {str(t or "").strip().lower() for t in (ctx_toks_v or []) if t}
    _generic_modifier_stop = {"the", "and", "for", "with", "from", "main", "major", "popular"}
    narrow_focus = [
        str(t or "").strip().lower()
        for t in (focus_toks_v or [])
        if t
        and len(str(t)) >= 4
        and str(t).strip().lower() not in _ctx_set
        and str(t).strip().lower() not in _generic_modifier_stop
    ]
    if narrow_focus:
        def _short_label(it: str) -> bool:
            words = re.findall(r"[A-Za-z][A-Za-z\-']*", str(it or ""))
            return 1 <= len(words) <= 2
        uniform_short_labels = bool(len(items) >= 3 and all(_short_label(it) for it in items))
        if uniform_short_labels:
            has_narrow_in_items = any(
                any(_token_match_light(str(it or "").lower(), tok) for tok in narrow_focus)
                for it in items
            )
            cat_count = sig.get("categorical_count")
            count_anchored = bool(cat_count is not None and int(cat_count) == len(items))
            if (not has_narrow_in_items) and (not count_anchored):
                # Concept-cluster rescue: if the narrow focus token is an
                # enumeration-type meta-word (perspectives, approaches, schools,
                # theories, etc.) the ANSWER items are expected to be the NAMES
                # of each perspective/approach — NOT to repeat the meta-word
                # inside every item. Accept when items form a clean distinct
                # cluster of short labels. Generic: no domain vocabulary.
                _enum_type_modifiers = {
                    "perspectives", "perspective", "approaches", "approach",
                    "models", "model", "types", "type", "branches", "branch",
                    "schools", "school", "theories", "theory",
                    "viewpoints", "viewpoint", "orientations", "orientation",
                    "frameworks", "framework",
                }
                _nf_is_enum_type = any(tok in _enum_type_modifiers for tok in narrow_focus)
                if _nf_is_enum_type:
                    _cluster_labels = [
                        it for it in items
                        if 1 <= len(re.findall(r"[A-Za-z][A-Za-z\-']*", it)) <= 5
                    ]
                    _all_distinct = (
                        len({re.sub(r"[^a-z]+", " ", it.lower()).strip() for it in _cluster_labels})
                        == len(_cluster_labels)
                    )
                    if len(_cluster_labels) >= 3 and _all_distinct:
                        logger.info(
                            "[CONCEPT CLUSTER DETECTED] %d distinct labels for enum-type narrow_focus=%s",
                            len(_cluster_labels), narrow_focus,
                        )
                        logger.info(
                            "[STRUCTURE QUERY RESCUE] items form distinct concept cluster -> accepted"
                        )
                        return True, "ok"
                logger.info(
                    "[CONCEPT MATCH GUARD] reject narrow_focus_missing focus=%s items=%d count_target=%s",
                    narrow_focus,
                    len(items),
                    str(cat_count),
                )
                return False, "narrow_focus_missing_in_short_labels"

    return True, "ok"


# MP-C4: Generic OCR token-repair for list candidates.
# Splits two purely structural OCR-glue patterns BEFORE list coherence
# validation rejects partially noisy lists. Both rules are language-level
# (English function words / CamelCase boundaries) and domain-agnostic — they
# carry no topic vocabulary, no PDF-specific terms, and apply equally to any
# document corpus. Examples handled (all generic):
#   "PlanningProcess"        -> "Planning Process"   (CamelCase boundary)
#   "Thefirst"               -> "The first"          (determiner + word)
#   "Variousfactors"         -> "Various factors"    (quantifier + word)
#   "andforemost"            -> "and foremost"       (conjunction + word)
# Random garbage ("kjsdfhskdf") is NOT split and remains rejectable.
_OCR_GLUED_FUNCTION_PREFIXES = (
    "The", "A", "An", "And", "To", "Of", "For", "In", "On", "At", "By",
    "With", "From", "Into", "Onto", "Upon", "This", "That", "These", "Those",
    "Many", "Most", "All", "Each", "Every", "Both", "Either", "Neither",
    "Various", "Several", "Other", "Another", "Such", "More", "Less", "Few",
    "Much",
)
# Sort by descending length so longer prefixes win the alternation
# (e.g. "These" wins over "The" for "Theseterms").
_OCR_GLUED_PREFIX_RE = re.compile(
    r"\b("
    + "|".join(sorted(_OCR_GLUED_FUNCTION_PREFIXES, key=len, reverse=True))
    + r")([a-z]{3,})\b"
)  # case-sensitive: only capitalized OCR-glue patterns are split, which
#   avoids over-splitting legitimate lowercase words like "influence",
#   "another", "thereby" that share a prefix substring.
_OCR_CAMELCASE_BOUNDARY_RE = re.compile(r"([a-z])([A-Z])")


def _ocr_repair_glued_tokens(text: str) -> str:
    """Apply purely structural OCR fixes to a single line of text.

    Generic — uses only English function words and CamelCase boundaries.
    No domain-specific vocabulary. Safe for any document type.
    """
    if not text:
        return text
    repaired = _OCR_CAMELCASE_BOUNDARY_RE.sub(r"\1 \2", text)
    # Apply glued-prefix split iteratively because cascades can occur
    # (e.g. "Thevariousfactors" -> "The variousfactors" -> "The various factors")
    for _ in range(3):
        new_text = _OCR_GLUED_PREFIX_RE.sub(r"\1 \2", repaired)
        if new_text == repaired:
            break
        repaired = new_text
    return re.sub(r"\s+", " ", repaired).strip()


def _preclean_list_answer_for_assessment(answer_text: str) -> str:
    raw = str(answer_text or "")
    if not raw.strip():
        return ""

    def _line_broken(line: str) -> bool:
        low = line.lower().strip()
        if not low:
            return True
        if re.match(r"^\s*(?:and|or|to|of|for|with|by|in|on|at|from|because|however|therefore|thus|then)\b", low):
            return True
        return False

    bullet_prefix_re = re.compile(r"^(\s*(?:[-•*]|\d+[.)]|[a-z][.)])\s*)(.+)$", re.IGNORECASE)

    def _strip_marker_for_continuation(line: str) -> str:
        m = bullet_prefix_re.match(str(line or "").strip())
        if m:
            return (m.group(2) or "").strip()
        return str(line or "").strip()

    def _starts_list_continuation(line: str) -> bool:
        payload = _strip_marker_for_continuation(line)
        return bool(
            re.match(r"^\s*(?:and|or)\b\s+\S", payload, flags=re.IGNORECASE)
            or re.match(r"^\s*&\s*\S", payload)
        )

    def _ends_list_connector(line: str) -> bool:
        payload = _strip_marker_for_continuation(line)
        return bool(re.search(r"(?:\b(?:and|or)|&)\s*$", payload, flags=re.IGNORECASE))

    kept: list[str] = []
    for ln in raw.splitlines():
        s = re.sub(r"[ \t]+", " ", str(ln or "")).strip()
        if not s:
            continue
        # MP-C4: Apply generic OCR token repair while preserving bullet markers.
        m = bullet_prefix_re.match(s)
        if m:
            s = (m.group(1) or "") + _ocr_repair_glued_tokens(m.group(2) or "")
        else:
            s = _ocr_repair_glued_tokens(s)
        s = re.sub(r"\s+", " ", s).strip()
        if not s:
            continue
        if len(s) > 200:
            continue
        if not re.search(r"[A-Za-z]", s):
            continue
        if kept and (_starts_list_continuation(s) or _ends_list_connector(kept[-1])):
            payload = _strip_marker_for_continuation(s)
            kept[-1] = kept[-1].rstrip(" ,;:-") + " " + payload
            logger.info("[LIST ITEM CONTINUATION MERGED] continuation=%s", payload[:100])
            continue
        if _line_broken(s):
            continue
        kept.append(s)
    return "\n".join(kept).strip()


def _extract_simple_overview_from_docs(docs: list[dict]) -> str | None:
    headings = _extract_document_headings((docs or [])[:3])
    top = []
    seen = set()
    for h in headings:
        name = re.sub(r"\s+", " ", str(h.get("heading") or "")).strip()
        if not name:
            continue
        low = name.lower()
        if low in seen:
            continue
        if re.search(r"\b(table of contents|contents|index|references?)\b", low):
            continue
        seen.add(low)
        top.append(name)
        if len(top) >= 3:
            break
    if len(top) >= 2:
        return f"This document mainly covers {', '.join(top[:3])}."
    return None


# MP-C2 FIX: Generic, purely structural/linguistic signals for choosing between
# competing definition-sentence candidates. NO domain words, NO topic words,
# NO query-to-answer mappings. Only sentence-shape evidence.
_DEFINITION_DESCRIPTIVE_PENALTY_RE = re.compile(
    r"\b(?:"
    r"come(?:s)?\s+to\s+mind|"               # associative recall, not definition
    r"put\s+forward\s+by|"                    # attribution of authorship
    r"you\s+can\s+(?:also\s+)?call(?:\s+it)?|"  # alternate naming
    r"whenever\s+we\s+talk|"                  # narrative framing
    r"important\s+era|"                       # historical framing
    r"evolution\s+of|"                        # historical framing
    r"changed\s+over\s+time|"                 # historical framing
    r"history\s+of|"                          # historical framing
    r"before\s+we\s+can|"                     # preamble
    r"we\s+need\s+to\s+look|"                 # preamble
    r"to\s+put\s+it\s+another\s+way|"         # paraphrase preamble
    r"in\s+other\s+words"                     # paraphrase preamble
    r")\b",
    flags=re.IGNORECASE,
)
_DEFINITION_QUOTED_DEF_RE = re.compile(
    r"[\"\u201c\u201d\u2018\u2019'`]\s*(?:is|are|refers\s+to|defined\s+as|means)\b",
    flags=re.IGNORECASE,
)
_DEFINITION_VERB_NEAR_RE = re.compile(
    r"\b(?:is|are|refers\s+to|defined\s+as|means)\b",
    flags=re.IGNORECASE,
)


def _definition_structural_signal_delta(sentence: str, entity_l: str) -> float:
    """Return a generic score delta for a candidate definition sentence.

    Signals are purely structural / linguistic (no domain or topic words):
      + entity appears at the start, followed shortly by a definition verb
      + sentence carries a quoted definition span ("... is ...")
      - sentence uses descriptive/historical/associative framing instead of
        a definitional clause
    """
    s = str(sentence or "").strip()
    if not s:
        return 0.0
    low = s.lower()
    delta = 0.0
    ent = re.sub(r"\s+", " ", str(entity_l or "").strip().lower())

    # Boost A: entity at the start, then a definition verb within a short bridge
    # (allow common attribution punctuation/words like commas, quotes, or short
    # parentheticals between the entity and the verb).
    if ent:
        anchored = re.match(
            rf"^\s*(?:the\s+)?{re.escape(ent)}\b[\s,;:'\"`\-()\u201c\u201d\u2018\u2019]{{0,140}}"
            rf"\b(?:is|are|refers\s+to|defined\s+as|means)\b",
            low,
        )
        if anchored:
            delta += 4.0

    # Boost B: a quoted definitional clause (attributed quoted definitions are
    # a strong structural signal — e.g., "... is ..." inside quotation marks).
    if _DEFINITION_QUOTED_DEF_RE.search(s):
        delta += 3.0
    elif _DEFINITION_VERB_NEAR_RE.search(low) and re.search(
        r"[\"\u201c\u2018'`][^\"\u201d\u2019'`]{20,260}[\"\u201d\u2019'`]", s
    ):
        delta += 2.0

    # Penalty: descriptive / historical / associative framing patterns. These
    # introduce or contextualize a topic instead of defining it.
    if _DEFINITION_DESCRIPTIVE_PENALTY_RE.search(low):
        delta -= 6.0

    return delta


def _strip_attribution_prefix_for_definition(sentence: str) -> str:
    """Generic structural normalization of attributed quoted definitions.

    Removes a single inline attribution clause of the form
    ", in the words of <person>, " between the subject and a quoted definition
    so that downstream regexes can match the underlying "<entity> is ..."
    pattern. No domain knowledge required.
    """
    s = str(sentence or "")
    if not s:
        return s
    s = re.sub(r",\s*in\s+the\s+words\s+of\s+[^,]{1,120},\s*", " ", s, flags=re.IGNORECASE)
    s = re.sub(
        r'\b([A-Za-z][A-Za-z0-9\- ]{2,90})\s*["\u201c\u201d\u2018\u2019]\s*(is|are|refers\s+to|means|defined\s+as|is\s+defined\s+as|is\s+considered)\b',
        r"\1 \2",
        s,
        flags=re.IGNORECASE,
    )
    return re.sub(r"\s+", " ", s).strip()


def _extract_candidate_definition_sentence_from_docs(query_text: str, docs: list[dict], max_docs: int = 2) -> str | None:
    if not docs:
        return None
    max_docs = max(1, min(3, int(max_docs)))
    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = (entity or "").strip().lower()
    entity_tokens = [
        t for t in re.findall(r"[a-z0-9]{2,}", entity_l)
        if t not in {"the", "a", "an", "of", "and", "in", "to"}
    ]

    query_tokens = [
        t for t in re.findall(r"[a-z0-9]{3,}", (query_text or "").lower())
        if t not in {"what", "who", "is", "was", "the", "a", "an", "of", "and", "in", "to", "define", "does", "this", "document", "talk", "about"}
    ]
    weak_phrases = ("he thought", "it can be said", "in this way", "before we can")
    person_indicators = ("born", "known as", "considered", "introduced", "engineer", "theorist", "manager")
    reject_marker_re = re.compile(r"\b(?:criticism|criticisms|limitations?|drawbacks?|red\s+tape)\b", flags=re.IGNORECASE)
    heading_intro_re = re.compile(
        r"^\s*(?:introduction|overview|summary|contents?|table of contents|chapter\s+\d+|unit\s+\d+|learning objectives?|key terms?)\s*[:\-–—]?\s*$",
        flags=re.IGNORECASE,
    )
    concept_def_verb_re = re.compile(r"\b(?:is|refers to|defined as|known as)\b", flags=re.IGNORECASE)
    attribution_verb_re = re.compile(r"\b(?:introduced|developed|known as)\b", flags=re.IGNORECASE)
    person_name_re = re.compile(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,2}\b")
    continuation_starts = re.compile(r"^\s*(and|but|or|so|because|therefore|thus|also|then|while|whereas)\b", flags=re.IGNORECASE)
    q_low = (query_text or "").strip().lower()
    is_who_query = q_low.startswith("who is") or q_low.startswith("who was")
    is_concept_query = q_low.startswith("what is") or q_low.startswith("define")
    is_person_attribution_query = q_low.startswith("who introduced") or q_low.startswith("who developed")
    early_exit_threshold = 8.0
    max_sentences_per_doc = 10

    best: tuple[float, str] | None = None
    for d in docs[:max_docs]:
        source_text = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not source_text:
            continue
        sentence_candidates = [s for s in re.split(r"(?<=[.!?])\s+|\n+", source_text) if (s or "").strip()]
        for sent in sentence_candidates[:max_sentences_per_doc]:
            s = (sent or "").strip()
            if not s:
                continue
            low = s.lower()
            if reject_marker_re.search(low):
                continue
            if heading_intro_re.match(s) and not re.search(r"[.!?]$", s):
                continue
            if re.match(r"^\s*(?:[-•*]|\d+[.)])\s+", s):
                continue
            if "|" in s or "\t" in s:
                continue
            words = re.findall(r"[A-Za-z][A-Za-z\-']*", s)
            wc = len(words)
            if wc < 6 or wc > 40:
                continue
            if re.match(r"^[A-Z][A-Za-z0-9\s\-,:]{2,100}$", s) and not re.search(r"[.!?]$", s):
                continue
            if is_concept_query and _is_over_generic_definition_template(s, entity_l):
                continue
            if is_concept_query and entity_l and defines_other_concept(low, entity_l):
                continue
            score = 0.0

            has_definition_verb = bool(re.search(r"\b(is|was|refers to|defined as|known as)\b", low))
            if has_definition_verb:
                score += 6.0

            normalized_low = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", low)).strip()
            full_phrase_hit = bool(entity_l and normalized_low and re.search(rf"\b{re.escape(entity_l)}\b", normalized_low))

            if is_concept_query and entity_l:
                if full_phrase_hit and concept_def_verb_re.search(low):
                    score += 8.5
                else:
                    score -= 6.5

                concept_quality_score = _s_definition_sentence(s, entity_l, entity_tokens)
                if concept_quality_score <= 0:
                    continue
                if not _has_required_concept_specific_signal(s, entity_l):
                    continue
                score += float(concept_quality_score)

            full_concept_hit = False
            if has_entity and full_phrase_hit:
                full_concept_hit = True
                score += 6.0

            token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low))
            if token_hits >= max(1, min(2, len(entity_tokens))):
                score += 3.0
                if len(entity_tokens) >= 2 and token_hits >= min(2, len(entity_tokens)):
                    full_concept_hit = True

            query_hits = sum(1 for t in query_tokens if re.search(rf"\b{re.escape(t)}\b", low))
            if query_hits >= 2:
                full_concept_hit = True

            if full_concept_hit:
                score += 6.0

            if query_hits > 0:
                score += 3.0
            if query_hits >= 1:
                score += 1.5
            if is_who_query and any(ind in low for ind in person_indicators):
                score += 3.0

            if is_person_attribution_query:
                token_grounding = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low)) >= max(1, min(2, len(entity_tokens)))
                has_attribution = bool(attribution_verb_re.search(low))
                has_person_name = bool(person_name_re.search(s))
                if has_attribution and (has_person_name or token_grounding):
                    score += 10.0
                else:
                    score -= 8.0

            first_alpha = next((ch for ch in s if ch.isalpha()), "")
            if first_alpha and first_alpha.islower():
                score -= 5.0
            if continuation_starts.match(s):
                score -= 5.0
            if any(p in low for p in weak_phrases):
                score -= 5.0
            if re.search(r"\b(this|these|such)\s+(approach|theory|concept|method)\b", low):
                score -= 3.0

            # MP-C2: generic structural definition-shape signals (no domain words)
            score += _definition_structural_signal_delta(s, entity_l)

            if score >= early_exit_threshold:
                return s

            if best is None or score > best[0]:
                best = (score, s)
    return best[1] if best else None


def _top_chunk_has_exact_entity_phrase(query_text: str, docs: list[dict]) -> bool:
    if not docs:
        return False
    has_entity, entity = _extract_entity_from_definition_query(query_text)
    if not has_entity:
        return False
    top_text = str((docs[0] or {}).get("page_content") or (docs[0] or {}).get("text") or "")
    if not top_text.strip():
        return False
    norm_entity = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", entity.lower())).strip()
    norm_top = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", top_text.lower())).strip()
    if not norm_entity or not norm_top:
        return False
    return bool(re.search(rf"\b{re.escape(norm_entity)}\b", norm_top))


def _passes_fast_path_definition_validation(query_text: str, answer_sentence: str) -> bool:
    sentence = str(answer_sentence or "").strip()
    if not sentence:
        return False

    s_low = sentence.lower()
    if re.search(r"\b(?:criticism|criticisms|limitations?|drawbacks?|red\s+tape)\b", s_low):
        return False

    if not re.search(r"\b(is|was|refers to|defined as|means|known as|considered|introduced)\b", s_low):
        return False

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    if not has_entity:
        return False

    norm_entity = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", entity.lower())).strip()
    norm_sentence = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", sentence.lower())).strip()
    if not norm_entity or not norm_sentence:
        return False

    q_low = (query_text or "").strip().lower()
    is_concept_query = q_low.startswith("what is") or q_low.startswith("define")
    is_person_attribution_query = q_low.startswith("who introduced") or q_low.startswith("who developed")

    if is_concept_query:
        if defines_other_concept(s_low, norm_entity):
            return False
        if _is_over_generic_definition_template(sentence, norm_entity):
            return False
        if not _has_required_concept_specific_signal(sentence, norm_entity):
            return False

    if norm_entity in norm_sentence:
        if is_concept_query:
            if re.search(rf"\b{re.escape(norm_entity)}\b\s+(is|was|refers to|defined as|means)", norm_sentence):
                return True
        else:
            return True

    entity_tokens = [
        t for t in re.findall(r"[a-z0-9]{2,}", norm_entity)
        if t not in {"the", "a", "an", "of", "and", "in", "to"}
    ]
    if not entity_tokens:
        return False
    hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", norm_sentence))
    token_grounded = hits >= max(1, min(2, len(entity_tokens)))
    if is_person_attribution_query:
        has_attr = bool(re.search(r"\b(introduced|developed|known as)\b", s_low))
        has_person_name = bool(re.search(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,2}\b", sentence))
        return token_grounded and has_attr and has_person_name
    return token_grounded


def _definition_entity_or_reference_match(query_text: str, answer_text: str) -> bool:
    a_low = re.sub(r"\s+", " ", str(answer_text or "").strip().lower())
    if not a_low:
        return False

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    if not has_entity:
        return True

    entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not entity_l:
        return True

    if re.search(rf"\b{re.escape(entity_l)}\b", a_low):
        return True

    stop = {"the", "a", "an", "of", "and", "in", "to", "what", "is", "define"}
    generic_entity_tokens = {"approach", "theory", "method", "model", "system", "concept", "perspective", "school", "view"}
    entity_tokens = [t for t in re.findall(r"[a-z0-9]{2,}", entity_l) if t not in stop]
    specific_tokens = [t for t in entity_tokens if t not in generic_entity_tokens]

    if specific_tokens:
        # P3: allow obvious surface-form variants (plural/singular/lemma) when
        # matching entity tokens against the answer. Reuses the existing
        # _token_match_light helper, which normalizes -s / -es / -ies / -y
        # without any domain-specific term list. Falls back to exact word
        # boundary match for tokens shorter than the helper's normalization
        # threshold.
        def _entity_token_hit(tok: str) -> bool:
            try:
                if _token_match_light(a_low, tok):
                    return True
            except Exception:
                pass
            return bool(re.search(rf"\b{re.escape(tok)}\b", a_low))

        specific_hits = sum(1 for t in specific_tokens if _entity_token_hit(t))
        # MP-C1 generic tightening: when the entity has multiple specific
        # (non-stopword, non-generic) tokens, require ALL of them in the
        # answer. A single matching token from a multi-word entity (e.g.
        # only "quantum" from "quantum comparing") routinely picks up
        # unrelated polysemous content. For single-token entities the
        # single hit remains sufficient. No domain words.
        if len(specific_tokens) >= 2:
            if specific_hits >= len(specific_tokens):
                return True
            # Not enough specific tokens matched: refuse outright instead of
            # falling through to the looser query-overlap branch (which can
            # accept on a single shared token plus a generic noun like
            # "view"/"approach" appearing anywhere in the answer).
            return False
        else:
            if specific_hits >= 1:
                return True

    query_l = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    query_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", query_l) if t not in stop]
    query_overlap_hits = sum(1 for t in query_tokens if re.search(rf"\b{re.escape(t)}\b", a_low))
    generic_hits = sum(1 for t in generic_entity_tokens if re.search(rf"\b{re.escape(t)}\b", a_low))
    has_definition_verb = bool(re.search(r"\b(?:is|was|refers\s+to|defined\s+as|means|focuses\s+on|emphasizes|involves)\b", a_low))
    has_clear_reference = bool(
        re.search(r"^\s*(?:it|this|that|the)\s+(?:approach|theory|model|method|system|concept|perspective|school)\b", a_low)
        or re.search(r"\bthis\s+(?:approach|theory|model|method|system|concept|perspective|school)\b", a_low)
    )

    return bool(has_definition_verb and (has_clear_reference or generic_hits >= 1) and query_overlap_hits >= 1)


def _passes_strict_definition_relevance_guard(query_text: str, answer_sentence: str) -> bool:
    q_low = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    s = re.sub(r"\s+", " ", str(answer_sentence or "").strip())
    if not s:
        logger.info("[STRICT DEF PREF MISS] query=%s reason=empty_answer", q_low[:120])
        return False
    if re.search(r"(?:©|copyright|virtual\s+university|\b[a-z]{2,5}\s*\d{3}\b)", s, flags=re.IGNORECASE):
        logger.info("[STRICT DEF PREF MISS] query=%s reason=ocr_noise", q_low[:120])
        return False
    if _is_definition_boilerplate_sentence(s.lower()):
        logger.info("[STRICT DEF PREF MISS] query=%s reason=boilerplate", q_low[:120])
        return False
    # MP-C1 generic tightening: ensure the answer references the queried
    # entity (or a clear reference to it). Without this check the strict
    # guard previously returned True for any non-empty, non-boilerplate
    # sentence — letting unrelated content leak through whenever the route
    # produced a deterministic answer (e.g. a sentence that merely shares
    # a polysemous word with the entity). Generic, no domain words.
    if not _definition_entity_or_reference_match(query_text, s):
        logger.info("[STRICT DEF PREF MISS] query=%s reason=entity_not_referenced", q_low[:120])
        return False
    logger.info("[STRICT DEF PREF PASS] query=%s reason=generic_grounded_check", q_low[:120])
    return True


def _has_exact_who_person_evidence(query_text: str, docs: list[dict]) -> bool:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q or not re.match(r"^who\s+(is|was)\b", q):
        return False
    if not docs:
        return False

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not has_entity or not entity_l:
        return False

    entity_tokens = [
        t for t in re.findall(r"[a-z0-9]{2,}", entity_l)
        if t not in {"the", "a", "an", "of", "and", "in", "to"}
    ]
    if not entity_tokens:
        return False

    full_name_re = None
    if len(entity_tokens) >= 2:
        first = re.escape(entity_tokens[0])
        last = re.escape(entity_tokens[-1])
        full_name_re = re.compile(rf"\b{first}(?:\s+[a-z]{{2,}}){{0,3}}\s+{last}\b", flags=re.IGNORECASE)

    person_name_re = re.compile(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\b")
    min_hits = max(2, min(3, len(entity_tokens)))

    for d in (docs or [])[:5]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not src:
            continue
        for sentence in [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", src) if s.strip()]:
            low = sentence.lower()
            if full_name_re and full_name_re.search(low):
                return True
            token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low))
            if token_hits >= min_hits and person_name_re.search(sentence):
                return True
    return False


def _enrich_who_identity_answer(query_text: str, docs: list[dict], base_answer: str) -> str:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not re.match(r"^who\s+(is|was)\b", q):
        return base_answer
    if not base_answer:
        return base_answer

    base = re.sub(r"\s+", " ", str(base_answer)).strip()
    if not re.search(r"\bis\s+associated\s+with\b", base, flags=re.IGNORECASE):
        return base

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not has_entity or not entity_l:
        return base

    entity_tokens = [
        t for t in re.findall(r"[a-z0-9]{2,}", entity_l)
        if t not in {"the", "a", "an", "of", "and", "in", "to"}
    ]
    if not entity_tokens:
        return base

    full_name_re = None
    if len(entity_tokens) >= 2:
        first = re.escape(entity_tokens[0])
        last = re.escape(entity_tokens[-1])
        full_name_re = re.compile(rf"\b{first}(?:\s+[a-z]{{2,}}){{0,3}}\s+{last}\b", flags=re.IGNORECASE)

    rich_marker_re = re.compile(r"\b(known as|introduced|developed)\b", flags=re.IGNORECASE)
    association_re = re.compile(r"\bis\s+associated\s+with\b", flags=re.IGNORECASE)

    for d in (docs or [])[:5]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not src:
            continue
        sentences = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", src) if s.strip()]
        for s in sentences[:24]:
            if association_re.search(s):
                continue
            if not rich_marker_re.search(s):
                continue
            low = s.lower()
            token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low))
            full_hit = bool(full_name_re.search(low)) if full_name_re else False
            surname_hit = bool(entity_tokens and re.search(rf"\b{re.escape(entity_tokens[-1])}\b", low))
            if not (full_hit or token_hits >= max(2, min(3, len(entity_tokens))) or surname_hit):
                continue
            right = s[0].lower() + s[1:] if len(s) > 1 else s.lower()
            merged = f"{base.rstrip('.')} and {right.rstrip('.')}."
            return re.sub(r"\s+", " ", merged).strip()
    return base


def _extract_topic_pure_overview_from_docs(query_text: str, docs: list[dict]) -> str | None:
    if not docs:
        return None

    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return None

    stop = {
        "what", "is", "are", "who", "was", "were", "the", "a", "an", "of", "and", "in", "to", "for",
        "tell", "me", "about", "explain", "overview", "summary", "document", "this", "that",
    }
    topic_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", q) if t not in stop]
    if not topic_tokens:
        return None

    
    requires_principles = False
    requires_planning_process = False
    requires_polarity = False

  

    candidates: List[Tuple[float, str]] = []
    seen: set[str] = set()
    for d in (docs or [])[:3]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not src:
            continue
        sentences = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", src) if s.strip()]
        for s in sentences[:30]:
            low = s.lower()
            if len(re.findall(r"[A-Za-z][A-Za-z\-']*", s)) < 6:
                continue
            if re.search(r"\b(table|figure|isbn|chapter\s+\d+|unit\s+\d+)\b", low):
                continue
          # removed stale topic gate check
            overlap = sum(1 for tok in topic_tokens if re.search(rf"\b{re.escape(tok)}\b", low))
            if overlap <= 0:
                continue
            score = float(overlap)
           
            if requires_polarity and re.search(r"\b(?:pros|cons|benefits?|drawbacks?|limitations?|criticisms?|merits?)\b", low):
                score += 1.2
            norm = re.sub(r"[^a-z0-9]+", " ", low).strip()
            if not norm or norm in seen:
                continue
            seen.add(norm)
            candidates.append((score, s))

    if not candidates:
        return None

    candidates.sort(key=lambda x: x[0], reverse=True)
    picked = [s for _, s in candidates[:3]]
    answer = " ".join(picked).strip()
    return answer or None


def _refine_concept_definition_answer(query_text: str, docs: list[dict], answer: str) -> str:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not (q.startswith("what is") or q.startswith("define")):
        return answer

    base = re.sub(r"\s+", " ", str(answer or "")).strip()
    if not base:
        return answer

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    entity_tokens = [
        t for t in re.findall(r"[a-z0-9]{2,}", entity_l)
        if t not in {"the", "a", "an", "of", "and", "in", "to"}
    ]

    def _extract_concept_level_from_docs() -> str | None:
        if not docs or not entity_l:
            return None
        def_re = re.compile(r"\b(is|refers to|defined as|can be explained as|involves|is a system of|is an approach to|focuses on|is concerned with)\b", flags=re.IGNORECASE)
        best: Tuple[float, str] | None = None
        for d in (docs or [])[:5]:
            src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not src:
                continue
            sentences = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", src) if s.strip()]
            for s in sentences[:40]:
                low = s.lower()
                if defines_other_concept(low, entity_l):
                    continue
                if len(re.findall(r"[A-Za-z][A-Za-z\-']*", s)) < 8:
                    continue
                if re.search(r"\b(table|figure|isbn|chapter\s+\d+|unit\s+\d+|contents?)\b", low):
                    continue
                if re.match(r"^\s*(he|she|they|this|it)\b", low):
                    continue
                if not def_re.search(low):
                    continue
                phrase_hit = bool(re.search(rf"\b{re.escape(entity_l)}\b", low))
                token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low))
                root_hits = 0
                for t in entity_tokens:
                    if len(t) >= 6 and re.search(rf"\b{re.escape(t[:6])}[a-z]*\b", low):
                        root_hits += 1
                if not (phrase_hit or token_hits >= max(1, min(2, len(entity_tokens))) or root_hits >= max(1, min(2, len(entity_tokens)))):
                    continue
                if re.match(r"^\s*[A-Za-z][A-Za-z\s\-]{2,50}:\s+", s) and not phrase_hit:
                    continue
                score = 0.0
                if phrase_hit:
                    score += 3.0
                score += min(2.0, 0.8 * token_hits)
                score += min(1.5, 0.6 * root_hits)
                if re.search(rf"\b{re.escape(entity_l)}\b\s+(is|refers to|defined as)", low):
                    score += 2.0
                if best is None or score > best[0]:
                    best = (score, re.sub(r"\s+", " ", s).strip())
        return best[1] if best and best[0] >= 2.2 else None

    def _extract_contributor_from_docs() -> str | None:
        return None

    def _extract_richer_explanatory_sentence_from_docs() -> str | None:
        if not docs or not entity_l:
            return None
        cues = [
            r"\bdefined\s+as\b",
            r"\brefers\s+to\b",
            r"\bmeans\b",
            r"\binvolves?\b",
            r"\bincludes?\b",
            r"\bconsists?\s+of\b",
            r"\baims?\s+to\b",
            r"\bused\s+to\b",
            r"\bfocus(?:ed)?\s+on\b",
        ]
        best: tuple[float, str] | None = None
        for d in (docs or [])[:5]:
            src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not src:
                continue
            chunk_has_entity = bool(re.search(rf"\b{re.escape(entity_l)}\b", src.lower()))
            for sent in [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", src) if s.strip()]:
                low_sent = sent.lower()
                if _is_table_or_classification_sentence(sent):
                    continue
                if len(re.findall(r"[A-Za-z][A-Za-z\-']*", sent)) < 10:
                    continue
                sent_has_entity = bool(re.search(rf"\b{re.escape(entity_l)}\b", low_sent))
                cue_hits = sum(1 for pat in cues if re.search(pat, low_sent, flags=re.IGNORECASE))
                if cue_hits <= 0:
                    continue
                if not (sent_has_entity or chunk_has_entity):
                    continue
                score = float(cue_hits) + (0.6 if re.search(r"\b(is|refers to|means|focuses on)\b", low_sent) else 0.0)
                if sent_has_entity:
                    score += 0.8
                if best is None or score > best[0]:
                    best = (score, re.sub(r"\s+", " ", sent).strip())
        return best[1] if best else None

    low = base.lower()
    if entity_l and defines_other_concept(low, entity_l):
        logger.info("[DEF REJECT WEAK] entity=%s reason=answer_defines_other_concept", entity_l)
        alt = _extract_concept_level_from_docs() or _extract_candidate_definition_sentence_from_docs(query_text, docs or [], max_docs=3)
        if alt and (not defines_other_concept(alt.lower(), entity_l)):
            return alt
        return RAG_NO_MATCH_RESPONSE
    feature_label = bool(re.match(r"^\s*[A-Za-z][A-Za-z\s\-]{2,50}:\s+", base))
    contains_entity = bool(entity_l and re.search(rf"\b{re.escape(entity_l)}\b", low))
    token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low)) if entity_tokens else 0

    if (not contains_entity) and token_hits < max(1, min(2, len(entity_tokens))):
        alt_direct = _extract_concept_level_from_docs()
        if alt_direct:
            return alt_direct

    if re.search(r"\bis\s+characterized\s+by\b", low) and len(re.findall(r"[a-z0-9]+", low)) <= 14:
        rich_sent = _extract_richer_explanatory_sentence_from_docs()
        if rich_sent:
            rich_sent = re.sub(r"^\s*[A-Za-z]+\s*,\s*", "", rich_sent).strip()
            if entity_l and not re.search(rf"\b{re.escape(entity_l)}\b", rich_sent.lower()):
                entity_title = " ".join(w.capitalize() for w in re.findall(r"[A-Za-z0-9]+", entity_l)) or str(entity or "").strip()
                rich_sent = f"{entity_title} {rich_sent[0].lower() + rich_sent[1:] if rich_sent else rich_sent}"
            words = re.findall(r"\S+", rich_sent)
            if len(words) > 34:
                rich_sent = " ".join(words[:34]).rstrip(" ,;:-") + "."
            return rich_sent
        alt_rich = _extract_concept_level_from_docs()
        if alt_rich and len(re.findall(r"[a-z0-9]+", alt_rich.lower())) > len(re.findall(r"[a-z0-9]+", low)) + 2:
            return alt_rich

    if re.search(r"\bone\s+of\s+the\s+components\s+listed\s+with\b", low):
        return RAG_NO_MATCH_RESPONSE

    if feature_label and (not contains_entity):
        alt = _extract_concept_level_from_docs() or _extract_candidate_definition_sentence_from_docs(query_text, docs or [], max_docs=3)
        if alt:
            alt_norm = re.sub(r"\s+", " ", str(alt)).strip()
            alt_low = alt_norm.lower()
            alt_feature_label = bool(re.match(r"^\s*[A-Za-z][A-Za-z\s\-]{2,50}:\s+", alt_norm))
            if (not alt_feature_label) and re.search(r"\b(is|refers to|defined as|can be explained as|involves|is a system of|is an approach to)\b", alt_low):
                return alt_norm
    return base


def detect_query_intent(query: str) -> str:
    q = (query or "").strip().lower()
    if _detect_fact_query_type(q):
        return "fact"
    if _is_definition_style_query(q):
        return "definition"
    if _is_targeted_list_question(q):
        return "list"
    return "general"


def _is_targeted_list_question(query: str) -> bool:
    q = re.sub(r"\s+", " ", str(query or "").strip().lower())
    if not q:
        return False
    if re.search(r"\blist\b", q):
        return True
    if re.match(r"^\s*(?:what|which)\s+are\b", q):
        return True
    tokens = re.findall(r"[a-z]{3,}", q)
    plural_tokens = [tok for tok in tokens if tok.endswith("s") and tok not in {"this", "was", "is", "does"}]
    if re.match(r"^\s*(?:name|give|mention|identify)\b", q) and plural_tokens:
        return True
    if re.search(r"\b(?:what|which)\b", q) and plural_tokens and (" and " in q or " or " in q or q.endswith("?")):
        return True
    return False


def _classify_query_family(query: str) -> str:
    q = (query or "").strip().lower()
    if not q:
        return "general"

    if _detect_fact_query_type(q):
        return "fact_entity"

    if _is_definition_style_query(q):
        return "definition_entity"

    if _is_targeted_list_question(q):
        return "list_structure"
    return "overview_chapter_compare"


def _classify_query_family_v2(query: str) -> str:
    q = re.sub(r"\s+", " ", str(query or "").strip().lower())
    if not q:
        return "explanatory_compare"

    if _detect_fact_query_type(q):
        return "fact_entity"

    if _is_definition_style_query(q):
        return "definition_entity"

    if _is_targeted_list_question(q):
        return "list_entity"

    return "explanatory_compare"


def _doc_ocr_noise_score(text: str) -> float:
    t = str(text or "")
    if not t:
        return 1.0
    low = t.lower()
    score = 0.0
    score += 0.4 * len(re.findall(r"\b[a-z]\s+[a-z]\b", low))
    score += 0.3 * len(re.findall(r"\b[a-z]{1,2}\s+[a-z]{1,2}\s+[a-z]{1,2}\b", low))
    score += 0.5 * len(re.findall(r"\b[a-z]{2,5}\s+[a-z]{2,5}\b", low))
    score += 0.2 * len(re.findall(r"\b(?:vu|copyright|all rights reserved)\b", low))
    return score


def _light_normalize_query_token(token: str) -> str:
    t = re.sub(r"[^a-z0-9]+", "", str(token or "").lower())
    if len(t) <= 3:
        return t
    if t.endswith("ies") and len(t) > 5:
        return t[:-3] + "y"
    if re.search(r"(?:ches|shes|sses|xes|zes)$", t) and len(t) > 5:
        return t[:-2]
    if t.endswith("es") and len(t) > 6:
        return t[:-2]
    if t.endswith("s") and len(t) > 4 and (not t.endswith("ss")):
        return t[:-1]
    return t


def _token_match_light(haystack: str, token: str) -> bool:
    hs = str(haystack or "").lower()
    if not hs:
        return False
    base = _light_normalize_query_token(token)
    if not base:
        return False
    forms = {base}
    if len(base) > 3:
        forms.add(base + "s")
        forms.add(base + "es")
        if base.endswith("y") and len(base) > 4:
            forms.add(base[:-1] + "ies")
    for f in forms:
        if re.search(rf"\b{re.escape(f)}\b", hs):
            return True
    if len(base) >= 4:
        pref = re.escape(base[: min(6, len(base))])
        if re.search(rf"\b{pref}[a-z]{{0,4}}\b", hs):
            return True
    return False


def _query_section_tokens(query_text: str, family_v2: str = "") -> list[str]:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return []
    stop = {
        "what", "which", "who", "when", "where", "why", "how", "is", "are", "was", "were", "the", "a", "an",
        "of", "to", "in", "on", "for", "from", "with", "and", "or", "list", "name", "give", "mention", "identify",
        "tell", "show", "me", "about", "explain", "define", "document", "chapter", "section", "mentioned",
    }
    toks = [t for t in re.findall(r"[a-z0-9]{3,}", q) if t not in stop]
    out: list[str] = []
    seen: set[str] = set()
    for t in toks:
        cand = _light_normalize_query_token(t)
        if cand in seen:
            continue
        seen.add(cand)
        out.append(cand)
    if family_v2 in {"list_entity", "list_structure"}:
        out = [t for t in out if t not in {"thing", "topic", "item", "point"}] or out
    return out[:8]


def _split_query_context_focus_tokens(query_text: str, family_v2: str = "") -> tuple[list[str], list[str]]:
    all_tokens = _query_section_tokens(query_text, family_v2)
    section_phrases = _query_section_phrases(query_text)
    focus_tokens: list[str] = []
    seen_focus: set[str] = set()
    for ph in section_phrases:
        for tok in re.findall(r"[a-z0-9]{3,}", str(ph or "").lower()):
            norm = _light_normalize_query_token(tok)
            if norm in seen_focus:
                continue
            seen_focus.add(norm)
            focus_tokens.append(norm)
    if not focus_tokens and all_tokens:
        ql = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
        if re.match(r"^\s*(?:list|what\s+are|which\s+are|name|mention|identify|give)\b", ql):
            focus_tokens = [all_tokens[0]]

    context_tokens = [t for t in all_tokens if t not in set(focus_tokens)]
    if not context_tokens and all_tokens and len(all_tokens) > 1:
        context_tokens = all_tokens[1:]
    return context_tokens[:8], focus_tokens[:8]


def _has_strong_local_window_support(local_support: dict[str, Any] | None, confidence_threshold: float = 0.58) -> bool:
    support = dict(local_support or {})
    promoted = float(support.get("promoted_count", 0.0) or 0.0)
    conf = float(support.get("confidence", 0.0) or 0.0)
    focus = float(support.get("focus_hits", 0.0) or 0.0)
    density = float(support.get("list_density", 0.0) or 0.0)
    return bool(
        promoted >= 1.0
        and conf >= confidence_threshold
        and (focus >= 1.0 or density >= 0.10)
    )


def _list_query_alignment_metrics(query_text: str, answer_text: str) -> dict[str, float]:
    q_family_v2 = _classify_query_family_v2(query_text)
    context_tokens, focus_tokens = _split_query_context_focus_tokens(query_text, q_family_v2)
    raw = str(answer_text or "")
    items = [
        re.sub(r"^\s*[-•*]\s+", "", ln).strip()
        for ln in raw.splitlines()
        if re.match(r"^\s*[-•*]\s+", ln)
    ]
    if not items:
        compact = re.sub(r"\s+", " ", raw).strip()
        if " - " in compact:
            items = [p.strip(" ,;:-") for p in compact.split(" - ") if p.strip(" ,;:-")]

    item_count = len(items)
    if item_count <= 0:
        return {
            "item_count": 0.0,
            "focus_hit_items": 0.0,
            "context_hit_items": 0.0,
            "focus_ratio": 0.0,
            "mismatch_penalty": 2.0,
        }

    focus_hit_items = 0
    context_hit_items = 0
    avg_item_words = 0.0
    label_like_items = 0
    for item in items:
        low_item = item.lower()
        wc = len(re.findall(r"[a-z0-9]{2,}", low_item))
        avg_item_words += float(wc)
        has_link_verb = bool(re.search(r"\b(?:is|are|was|were|has|have|had|includes?|involves?|means|refers\s+to)\b", low_item))
        if (not has_link_verb) and 1 <= wc <= 7:
            label_like_items += 1
        if focus_tokens and any(_token_match_light(low_item, tok) for tok in focus_tokens):
            focus_hit_items += 1
        if context_tokens and any(_token_match_light(low_item, tok) for tok in context_tokens):
            context_hit_items += 1

    avg_item_words = (avg_item_words / max(1.0, float(item_count))) if item_count else 0.0
    structured_label_list = bool(
        item_count >= 4
        and avg_item_words <= 5.8
        and label_like_items >= max(3, item_count - 1)
    )

    focus_ratio = float(focus_hit_items) / max(1.0, float(item_count))
    mismatch_penalty = 0.0
    if focus_tokens and focus_hit_items <= 0:
        mismatch_penalty += 0.7 if structured_label_list else 2.2
    elif focus_tokens and focus_ratio < 0.34:
        mismatch_penalty += 1.1
    if context_tokens and (focus_hit_items + context_hit_items) <= 0:
        mismatch_penalty += 0.5 if structured_label_list else 1.6
    if context_tokens and context_hit_items <= 0 and focus_hit_items <= 0:
        mismatch_penalty += 0.3 if structured_label_list else 0.8

    return {
        "item_count": float(item_count),
        "focus_hit_items": float(focus_hit_items),
        "context_hit_items": float(context_hit_items),
        "focus_ratio": float(focus_ratio),
        "mismatch_penalty": float(mismatch_penalty),
    }


def _debug_section_confidence(sig: dict[str, float], local_score: float = 0.0) -> float:
    local_focus_hits = float(sig.get("local_focus_hits", 0.0) or 0.0)
    local_heading_match = float(sig.get("local_heading_match", 0.0) or 0.0)
    local_list_density = float(sig.get("local_list_density", 0.0) or 0.0)
    local_conf_score = float(sig.get("local_confidence_score", 0.0) or 0.0)
    local_promoted = float(sig.get("local_promoted", 0.0) or 0.0)
    score = (
        (0.70 * float(sig.get("phrase_hits", 0.0)))
        + (0.55 * float(sig.get("heading_hits", 0.0)))
        + (0.35 * float(sig.get("marker_score", 0.0)))
        + (0.45 * float(sig.get("focus_hits", 0.0)))
        + (0.40 * local_focus_hits)
        + (0.35 * local_heading_match)
        + (0.55 * local_list_density)
        + (0.75 * local_conf_score)
        + (0.25 * local_promoted)
        + (20.0 * float(sig.get("density", 0.0)))
        - (0.40 * float(sig.get("missing_penalty", 0.0)))
        - (0.55 * float(sig.get("generic_penalty", 0.0)))
        + (0.18 * float(local_score or 0.0))
    )
    conf = float(max(0.0, min(1.0, score / 2.5)))
    return float(max(0.0, min(1.0, conf)))


def _query_section_phrases(query_text: str) -> list[str]:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return []
    phrases: list[str] = []

    def _add_phrase(raw: str) -> None:
        ph = re.sub(r"\s+", " ", str(raw or "").strip(" .,:;!?-–—"))
        if not ph:
            return
        words = ph.split()
        if len(words) < 2:
            return
        if len(words) > 10:
            ph = " ".join(words[:10])
        if ph not in phrases:
            phrases.append(ph)

    patterns = [
        r"^\s*(?:list|name|mention|identify|give)\s+(?:all\s+|the\s+)?(.+?)(?:[?.!]|$)",
        r"^\s*(?:what|which)\s+are\s+(?:all\s+|the\s+)?(.+?)(?:[?.!]|$)",
    ]
    for patt in patterns:
        m = re.search(patt, q)
        if not m:
            continue
        chunk = re.sub(r"\s+", " ", str(m.group(1) or "")).strip()
        if not chunk:
            continue
        _add_phrase(chunk)
        # Also keep a compact head phrase for partial heading matches.
        if len(chunk.split()) >= 3:
            _add_phrase(" ".join(chunk.split()[:4]))

    return phrases[:4]


def _query_main_entity_tokens(query_text: str, family_v2: str = "") -> tuple[list[str], list[str]]:
    """Generic main-entity extraction for section-anchor scoring.

    Splits the query's section phrase (e.g. "characteristics of management") into
    a STRUCTURE part ("characteristics") and an ENTITY part ("management") around
    the connectives of/in/for/about/regarding/concerning/on. Returns
    (entity_tokens, structure_tokens). When no connective is present the last
    surviving token of the phrase is treated as the entity. No domain words are
    used; this is purely positional/syntactic.
    """
    section_phrases = _query_section_phrases(query_text)
    stop = {
        "the", "a", "an", "all", "some", "any", "main", "major", "key", "important",
        "this", "that", "these", "those", "its", "their", "his", "her", "our",
        "such", "various", "different", "many", "few", "every", "each",
    }
    if not section_phrases:
        all_toks = _query_section_tokens(query_text, family_v2)
        if not all_toks:
            return [], []
        # No phrase pattern matched (short query) — last token is the entity.
        entity = [all_toks[-1]]
        struct = [t for t in all_toks if t not in set(entity)]
        return entity, struct[:4]

    phrase = section_phrases[0]
    m = re.search(
        r"^(.*?)\s+\b(?:of|in|for|about|regarding|concerning|on|with|to|from)\b\s+(.+)$",
        phrase,
        flags=re.IGNORECASE,
    )
    if m:
        head_part = m.group(1).strip()
        tail_part = m.group(2).strip()
    else:
        words = phrase.split()
        if len(words) >= 2:
            head_part = " ".join(words[:-1])
            tail_part = words[-1]
        else:
            head_part = ""
            tail_part = phrase

    def _toks(part: str) -> list[str]:
        out: list[str] = []
        seen: set[str] = set()
        for raw in re.findall(r"[a-z0-9]{3,}", part.lower()):
            if raw in stop:
                continue
            norm = _light_normalize_query_token(raw)
            if not norm or norm in seen:
                continue
            seen.add(norm)
            out.append(norm)
        return out

    entity_tokens = _toks(tail_part)
    structure_tokens = _toks(head_part)

    # When the structural part is an enumeration meta-word, promote those
    # tokens so section anchor scoring discriminates on the requested grouping
    # noun rather than only on the broad tail entity.
    # Generic set: universal English concept-grouping nouns.
    _ENUM_META_NORMALIZED = {
        "perspectiv", "perspective",  # perspectives / perspective
        "approach",                   # approaches / approach
        "model",                      # models / model
        "type",                       # types / type
        "kind",                       # kinds / kind
        "school",                     # schools / school
        "theory",                     # theories / theory
        "viewpoint",                  # viewpoints / viewpoint
        "orientation",                # orientations / orientation
        "framework",                  # frameworks / framework
    }
    _promoted = [t for t in structure_tokens if t in _ENUM_META_NORMALIZED]
    if _promoted:
        # Prepend promoted tokens; entity alignment will now check for them
        # first, boosting chunks that contain the specific meta-word in their
        # heading and penalising chunks that lack it entirely.
        entity_tokens = list(dict.fromkeys(_promoted + entity_tokens))[:3]
        structure_tokens = [t for t in structure_tokens if t not in _ENUM_META_NORMALIZED][:4]

    if not entity_tokens and structure_tokens:
        # Phrase was structure-only ("characteristics") — treat the same token
        # as the entity to avoid an empty entity set.
        entity_tokens = [structure_tokens[-1]]
        structure_tokens = structure_tokens[:-1]
    return entity_tokens[:3], structure_tokens[:4]


def _list_marker_score(text: str) -> float:
    t = str(text or "")
    if not t:
        return 0.0
    score = 0.0
    score += 0.35 * len(re.findall(r"(?:^|\n)\s*(?:[-•*]|\d+[.)])\s+", t))
    score += 0.25 * len(re.findall(r"(?:^|[\s,;])[a-z]\)\s", t, flags=re.IGNORECASE))
    score += 0.20 * len(re.findall(r"\b(?:include|includes|consists\s+of|classified\s+as|are\s*:)\b", t, flags=re.IGNORECASE))
    
    # Heuristic: 3+ capitalized noun phrases close together -> treat as list region
    if re.search(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+)*\s*(?:,\s*[A-Z][a-z]+(?:\s+[A-Z][a-z]+)*){2,}\b", t):
        score += 0.65

    short_non_sentence = [
        ln.strip()
        for ln in t.splitlines()
        if ln.strip()
        and len(re.findall(r"[A-Za-z0-9]+", ln)) <= 8
        and not re.search(r"[.!?]$", ln.strip())
    ]
    if len(short_non_sentence) >= 4:
        score += 0.45
        
    score += 0.15 * len(re.findall(r"\n", t[:1800]))
    return min(2.5, score)


def _normalize_phrase_text(text: str) -> str:
    return re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", str(text or "").lower())).strip()


def _is_goal_objective_list_query(query_text: str, family_v2: str = "") -> bool:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return False
    if family_v2 and family_v2 not in {"list_entity", "list_structure"}:
        return False
    has_list_intent = bool(re.match(r"^\s*(?:list|name|mention|identify|give|what\s+are|which\s+are)\b", q))
    has_goal_like = bool(re.search(r"\b(?:goals?|objectives?|aims?)\b", q))
    return bool(has_list_intent and has_goal_like)


def _is_attribution_or_citation_heading_text(text: str) -> bool:
    s = re.sub(r"\s+", " ", str(text or "").strip())
    if not s:
        return False
    low = s.lower()
    if re.search(r"\b(?:given|proposed|developed|introduced|formulated|presented)\s+by\b", low):
        return True
    if re.search(r"\b(?:colleagues|et\s*al\.?|researchers?)\b", low) and re.search(r"\(\s*(?:19|20)\d{2}[a-z]?\s*\)", low):
        return True
    if re.search(r"\(\s*(?:19|20)\d{2}[a-z]?\s*\)", low) and len(re.findall(r"[A-Za-z][A-Za-z\-']*", s)) <= 14:
        return True
    return False


def _is_placeholder_heading_text(text: str) -> bool:
    s = re.sub(r"\s+", " ", str(text or "").strip())
    if not s:
        return True
    low = s.lower()
    
    # 1) Standard rejections
    if low in {"unknown", "document", "front matter", "body", "content", "contents", "table of contents"}:
        return True
    if re.match(r"^\[source:.*\]$", low):
        return True
    if re.match(r"^(?:page|p\.)\s*[0-9ivxlcdm]+$", low):
        return True
    if re.match(r"^(?:chapter|unit)\s+\d+(?:\.\d+){0,2}$", low):
        return True
    if re.match(r"^section\s+\d+(?:\.\d+){0,4}$", low):
        return True
    if re.match(r"^\d+$", low):
        return True

    # 2) Generic Junk Filters (ISBN, URL, Metadata)
    
    # ISBN patterns: 978-81-...
    if re.search(r"\b\d{2,}-\d{2,}-\d{2,}", low):
        return True
        
    # URL/Domain patterns
    if any(x in low for x in ["http", "www", ".com", ".in", ".org", ".net", ".edu"]):
        if low.count(".") > 1 or "www" in low or "http" in low or "://" in low:
            return True

    # Repeated structural tokens: "Unit 1 Unit 1"
    if re.search(r"\b(\w+\s+\d+)\s+\1\b", low):
        return True

    # Digit/Word ratio: metadata usually has many numbers vs real words
    words = re.findall(r"[a-z]{3,}", low)
    digits = re.findall(r"\d+", low)
    if digits and len(digits) > len(words):
        # Allow small headings like "3. Concepts" (len(digits)=1, len(words)=1)
        if len(digits) > 2:
            return True
        
    # Complexity/Junk check (long lines with high symbol/digit density)
    if len(s) > 60:
        symbols = re.findall(r"[^A-Za-z0-9\s]", s)
        if len(symbols) > 5 or len(digits) > 4:
            return True
            
    # Mostly Uppercase with no real words (excludes acronyms if they are part of words)
    if s.isupper() and not any(len(w) > 2 for w in re.findall(r"[A-Z]+", s)):
        if len(s) > 4: # Allow very short markers like "SECTION" or "PART"
            return True

    return False


def _is_heading_candidate_line(line: str) -> bool:
    s = re.sub(r"\s+", " ", str(line or "").strip())
    if not s:
        return False
    if _is_placeholder_heading_text(s):
        return False
    word_count = len(re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", s))
    if word_count < 3 or word_count > 10:
        return False
    punct = re.findall(r"[,:;.!?]", s)
    if len(punct) > 1:
        return False
    if re.match(r"^\s*(?:[-•*]|\d+[.)])\s+", s):
        return False
    words = [w for w in re.findall(r"[A-Za-z][A-Za-z'\-]*", s)]
    if not words:
        return False
    title_case_count = sum(1 for w in words if w[:1].isupper())
    all_caps_count = sum(1 for w in words if w.isupper() and len(w) >= 2)
    title_like = title_case_count >= max(2, int(0.5 * len(words)))
    all_caps_like = all_caps_count >= max(2, int(0.5 * len(words)))
    return bool(title_like or all_caps_like or s.endswith(":"))


def _extract_heading_like_lines_from_chunk(text: str, max_lines: int = 24) -> list[str]:
    lines = [re.sub(r"\s+", " ", ln).strip() for ln in str(text or "").splitlines()[: max(1, max_lines)] if str(ln or "").strip()]
    out: list[str] = []
    for ln in lines:
        if len(ln) > 120:
            continue
        if ln.startswith("[Source:"):
            continue
        if _is_placeholder_heading_text(ln):
            logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_placeholder=True', ln[:120])
            continue
        if _is_heading_candidate_line(ln):
            out.append(ln)
    return out[:10]


def _extract_heading_snippets_from_line(line: str) -> list[str]:
    s = re.sub(r"\s+", " ", str(line or "").strip())
    if not s:
        return []
    if s.startswith("[Source:") and "]" in s:
        s = s.split("]", 1)[1].strip()
    if not s:
        return []

    segments = [
        re.sub(r"\s+", " ", seg).strip(" -–—:;,.\t")
        for seg in re.split(r"[•\|]|\s{2,}|\s+[-–—]\s+|(?<=[?!:])\s+", s)
        if str(seg or "").strip()
    ]

    out: list[str] = []
    seen: set[str] = set()
    for seg in segments[:8]:
        if len(seg) > 110:
            continue
        if _is_placeholder_heading_text(seg):
            continue
        words = re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", seg)
        if not (3 <= len(words) <= 10):
            continue
        if re.search(r"\b(?:is|are|was|were|has|have|had|because|therefore|however|which|that|who)\b", seg.lower()):
            continue
        if not _is_heading_candidate_line(seg):
            continue
        low = seg.lower()
        if low in seen:
            continue
        seen.add(low)
        out.append(seg)
    return out[:6]


def _is_document_title_heading_text(text: str) -> bool:
    s = re.sub(r"\s+", " ", str(text or "")).strip()
    if not s:
        return True
    low = s.lower()
    if _is_placeholder_heading_text(s):
        return True
    words = re.findall(r"[A-Za-z][A-Za-z\-']*", s)
    title_case_words = sum(1 for w in words if re.match(r"^[A-Z][a-zA-Z\-']+$", w))
    title_ratio = (float(title_case_words) / float(max(1, len(words)))) if words else 0.0
    has_local_marker = bool(
        s.endswith(":")
        or re.match(r"^\s*\d+(?:\.\d+)*\s+[A-Za-z]", s)
        or re.search(r"\b(?:section|part|topic|subsection)\s+\d+\b", low)
    )
    if has_local_marker:
        return False
    if re.search(r"\b[A-Za-z]{2,8}\s*[-–—]?\s*\d{2,4}[A-Za-z]?\b", s, flags=re.IGNORECASE):
        return True
    if re.search(r"[-–—]\s*[A-Za-z]{2,8}\s*\d{2,4}", s, flags=re.IGNORECASE):
        return True
    if re.search(r"\b(?:introduction|intro\s*duction|fundamentals|basics|overview)\s+to\b", s, flags=re.IGNORECASE):
        return True
    if re.search(r"\b(?:course|syllabus|textbook|edition|semester|module|manual)\b", s, flags=re.IGNORECASE) and title_ratio >= 0.5:
        return True
    return False


def _resolve_doc_heading_source(query_text: str, doc: dict) -> dict[str, Any]:
    txt = str((doc or {}).get("page_content") or (doc or {}).get("text") or "")
    list_goal_mode = _is_goal_objective_list_query(query_text)
    q_tokens = [
        t for t in re.findall(r"[a-z0-9]{3,}", str(query_text or "").lower())
        if t not in {"what", "which", "are", "the", "and", "for", "with", "from", "list", "name", "give", "mention", "identify"}
    ]

    raw_candidates: list[str] = []
    scored: list[tuple[float, str]] = []
    placeholder_rejected = False
    document_title_rejected = False
    lines = str(txt or "").splitlines()[:140]
    for raw_ln in lines:
        ln = re.sub(r"\s+", " ", str(raw_ln or "").strip())
        if not ln:
            continue
        for cand in _extract_heading_snippets_from_line(ln):
            if _is_placeholder_heading_text(cand):
                placeholder_rejected = True
                logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_placeholder=True', cand[:120])
                continue
            if list_goal_mode and _is_attribution_or_citation_heading_text(cand):
                logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_attribution_citation=True', cand[:120])
                continue
            if _is_document_title_heading_text(cand):
                document_title_rejected = True
                logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_document_title=True', cand[:120])
                continue
            raw_candidates.append(cand)
            low = cand.lower()
            overlap = sum(1 for tok in q_tokens if _token_match_light(low, tok))
            title_like = 1.0 if bool(re.match(r"^[A-Z][A-Za-z0-9\- ,()]{3,90}$", cand)) else 0.0
            all_caps = 0.8 if bool(re.match(r"^[A-Z0-9\- ]{3,90}$", cand) and re.search(r"[A-Z]{3,}", cand)) else 0.0
            colon = 0.7 if cand.endswith(":") else 0.0
            score = (1.45 * float(overlap)) + title_like + all_caps + colon
            scored.append((score, cand))

    logger.info("[HEADING SOURCE DEBUG] raw_candidates=%s", raw_candidates[:8])

    if not scored:
        logger.info('[HEADING SOURCE DEBUG] chosen_heading=""')
        logger.info("[HEADING SOURCE DEBUG] chosen_from=none")
        logger.info("[HEADING SOURCE DEBUG] no_real_heading_found=True")
        return {
            "chosen_heading": "",
            "chosen_from": "none",
            "raw_candidates": raw_candidates[:8],
            "heading_lines": [],
            "placeholder_rejected": bool(placeholder_rejected),
            "document_title_rejected": bool(document_title_rejected),
        }

    scored.sort(key=lambda x: x[0], reverse=True)
    chosen = scored[0][1]
    logger.info('[HEADING SOURCE DEBUG] chosen_heading="%s"', chosen[:120])
    logger.info("[HEADING SOURCE DEBUG] chosen_from=body_line")
    return {
        "chosen_heading": chosen,
        "chosen_from": "body_line",
        "raw_candidates": raw_candidates[:8],
        "heading_lines": [x[1] for x in scored[:6]],
        "placeholder_rejected": bool(placeholder_rejected),
        "document_title_rejected": bool(document_title_rejected),
    }


def _concept_proximity_score(
    query_tokens: list[str],
    heading_text: str,
    body_text: str,
) -> tuple[float, float]:
    """Generic concept-alignment scorer (MP-C3).

    For every pair of distinct query tokens, count how often they
    co-occur in a tight word-level window inside the chunk's heading
    and body. Repeated tight co-occurrences indicate that the chunk
    actually talks about the queried concept as a whole. A single
    incidental neighbour is not enough to outscore a chunk whose
    primary topic is the queried concept.

    Returns (proximity_score, dispersion_penalty), each roughly in
    [0, ~1.5]. Pure positional logic on the query's own non-stopword
    tokens — no domain words, no special cases.
    """
    raw_toks = [t for t in (query_tokens or []) if t and len(t) >= 3]
    seen: set[str] = set()
    uniq: list[str] = []
    for t in raw_toks:
        norm = _light_normalize_query_token(t)
        if not norm or norm in seen:
            continue
        seen.add(norm)
        uniq.append(norm)
    if len(uniq) < 2:
        return 0.0, 0.0

    def _positions(text: str, max_words: int) -> tuple[dict[str, list[int]], int]:
        words = re.findall(r"[a-z0-9]+", str(text or "").lower())
        if max_words and len(words) > max_words:
            words = words[:max_words]
        pos: dict[str, list[int]] = {}
        for i, w in enumerate(words):
            n = _light_normalize_query_token(w)
            if not n:
                continue
            pos.setdefault(n, []).append(i)
        return pos, len(words)

    head_pos, _head_n = _positions(heading_text, 200)
    body_pos, _body_n = _positions(body_text, 4000)

    def _close_pair_count(a: list[int], b: list[int], window: int) -> tuple[int, int]:
        """Return (close_pairs, min_distance)."""
        if not a or not b:
            return 0, 10**9
        a_s = sorted(a)
        b_s = sorted(b)
        close = 0
        best = 10**9
        # Two-pointer for min-distance + window-count via merged scan
        for ai in a_s:
            # Count b positions within window of ai
            for bj in b_s:
                d = abs(ai - bj)
                if d < best:
                    best = d
                if d <= window:
                    close += 1
            # Cap pairs per anchor to keep score bounded
        return close, best

    pair_scores: list[float] = []
    pair_disp: list[float] = []
    for i in range(len(uniq)):
        for j in range(i + 1, len(uniq)):
            a, b = uniq[i], uniq[j]
            head_close, head_d = _close_pair_count(
                head_pos.get(a, []), head_pos.get(b, []), window=12
            )
            body_close, body_d = _close_pair_count(
                body_pos.get(a, []), body_pos.get(b, []), window=8
            )
            score = 0.0
            # Heading co-occurrence is the strongest signal.
            if head_close > 0:
                score += 1.0 + (0.15 * min(3, head_close - 1))
            # Body tight co-occurrences accumulate (saturating).
            if body_close > 0:
                score += min(1.0, 0.30 * body_close)
            # Modest credit for any same-paragraph-ish proximity.
            if score == 0.0 and body_d <= 40:
                score = 0.20
            elif score == 0.0 and body_d <= 120:
                score = 0.05
            pair_scores.append(score)

            a_present = bool(head_pos.get(a) or body_pos.get(a))
            b_present = bool(head_pos.get(b) or body_pos.get(b))
            if not (a_present and b_present):
                pair_disp.append(0.6)
            elif body_close == 0 and head_close == 0 and body_d > 60:
                pair_disp.append(0.4)
            else:
                pair_disp.append(0.0)

    n = max(1, len(pair_scores))
    return float(sum(pair_scores) / n), float(sum(pair_disp) / n)


def _doc_query_token_signals(query_text: str, family_v2: str, doc: dict) -> dict[str, float]:
    tokens = _query_section_tokens(query_text, family_v2)
    section_phrases = _query_section_phrases(query_text)
    phrase_tokens: set[str] = set()
    for ph in section_phrases:
        for pt in re.findall(r"[a-z0-9]{3,}", ph.lower()):
            phrase_tokens.add(pt[:-1] if pt.endswith("s") and len(pt) > 4 else pt)
    md = dict((doc or {}).get("metadata") or {})
    txt = str((doc or {}).get("page_content") or (doc or {}).get("text") or "")
    low_txt = txt.lower()
    norm_txt = _normalize_phrase_text(txt)
    local_promoted = bool(md.get("_local_window_promoted") or md.get("local_window_promoted"))
    local_focus_hits_raw = float(md.get("local_focus_hits") or md.get("_local_focus_hits") or 0.0)
    local_heading_match_raw = float(md.get("local_heading_match") or md.get("_local_heading_match") or 0.0)
    local_list_density_raw = float(md.get("local_list_density") or md.get("_local_list_density") or 0.0)
    local_conf_raw = float(md.get("local_confidence_score") or md.get("_local_confidence_score") or md.get("_local_window_score") or 0.0)
    local_conf_norm = min(1.0, (local_conf_raw / 6.0)) if local_conf_raw > 1.0 else max(0.0, local_conf_raw)
    heading_src = _resolve_doc_heading_source(query_text, doc)
    heading_parts: list[str] = []
    chosen_heading = str(heading_src.get("chosen_heading") or "").strip()
    if chosen_heading:
        heading_parts.append(chosen_heading)
    for k in ("heading", "section", "title", "chapter", "role"):
        val = str(md.get(k) or "").strip()
        if not val:
            continue
        if _is_placeholder_heading_text(val):
            logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_placeholder=True', val[:120])
            continue
        if _is_document_title_heading_text(val):
            logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_document_title=True', val[:120])
            continue
        heading_parts.append(val)
    heading_lines = [str(x).strip() for x in (heading_src.get("heading_lines") or []) if str(x).strip()]
    heading_parts.extend(heading_lines)
    heading_blob = " ".join(heading_parts).lower()
    norm_heading = _normalize_phrase_text(" ".join(heading_parts))
    heading_detected = bool(chosen_heading)
    toc_like = bool(re.search(r"\b(?:table\s+of\s+contents|contents?)\b", f"{heading_blob}\n{low_txt[:900]}"))
    goal_list_mode = _is_goal_objective_list_query(query_text, family_v2)
    possessive_owner_tokens = [
        t for t in re.findall(r"\b([a-z0-9][a-z0-9\-]{2,})[’']s\b", str(query_text or "").lower())
        if t not in {"what", "which", "list", "name", "give", "mention", "identify", "stage", "stages", "development"}
    ]

    if not tokens:
        return {
            "token_hits": 0.0,
            "heading_hits": 0.0,
            "missing_penalty": 0.0,
            "generic_penalty": 0.0,
            "density": 0.0,
        }

    token_hits = 0.0
    heading_hits = 0.0
    focus_hits = 0.0
    matched = 0
    for tok in tokens:
        tok_weight = 1.0
        if family_v2 in {"list_entity", "list_structure"} and phrase_tokens:
            tok_weight = 1.0 if tok in phrase_tokens else 0.25
        in_heading_exact = bool(_token_match_light(heading_blob, tok))
        in_heading_near = False
        in_body_exact = bool(_token_match_light(low_txt, tok))
        in_body_near = False
        if in_heading_exact:
            heading_hits += 1.0 * tok_weight
        elif in_heading_near:
            heading_hits += 0.65 * tok_weight
        if in_body_exact:
            token_hits += 1.0 * tok_weight
        elif in_body_near:
            token_hits += 0.55 * tok_weight
        if tok in phrase_tokens and (in_heading_exact or in_heading_near or in_body_exact or in_body_near):
            focus_hits += 1.0
        if in_heading_exact or in_heading_near or in_body_exact or in_body_near:
            matched += 1

    missing = max(0, len(tokens) - matched)
    words = re.findall(r"[a-z0-9]+", low_txt)
    density = token_hits / max(12.0, float(len(words)))

    phrase_hits = 0.0
    for ph in section_phrases:
        ph_norm = _normalize_phrase_text(ph)
        if not ph_norm:
            continue
        if ph_norm in norm_heading:
            phrase_hits += 2.2
            heading_hits += 0.9
            heading_detected = True
            continue
        # MP-C1 generic widening: previously the body scan only looked at
        # the first 1800 normalised characters, which missed in-chunk
        # subsection headings further down (e.g. a "Characteristics of X"
        # heading appearing after a long preamble). Scan the full chunk
        # body so a literal phrase match anywhere is rewarded. Cheap.
        if ph_norm in norm_txt:
            phrase_hits += 1.4
            continue

        ph_toks = [t for t in re.findall(r"[a-z0-9]{3,}", ph_norm)]
        if ph_toks:
            heading_overlap = sum(1 for t in ph_toks if _token_match_light(heading_blob, t)) / max(1, len(ph_toks))
            body_overlap = sum(1 for t in ph_toks if _token_match_light(low_txt, t)) / max(1, len(ph_toks))
            if heading_overlap >= 0.60:
                phrase_hits += 0.95
                heading_hits += 0.55
                heading_detected = True
            elif body_overlap >= 0.60:
                phrase_hits += 0.60

    if tokens and heading_lines:
        for ln in heading_lines[:6]:
            ln_low = ln.lower()
            overlap = sum(1 for tok in tokens if _token_match_light(ln_low, tok))
            ratio = overlap / max(1, len(tokens))
            if overlap >= 1 and ratio >= 0.35:
                heading_hits += 0.65 + (0.25 * min(1.0, ratio))
                heading_detected = True

    marker_score = _list_marker_score(txt) if family_v2 in {"list_entity", "list_structure"} else 0.0
    if local_promoted:
        marker_score = max(marker_score, min(1.5, local_list_density_raw * 1.8))
        focus_hits += max(0.0, 0.65 * local_focus_hits_raw)
        heading_hits += max(0.0, 0.45 * local_heading_match_raw)
        phrase_hits += max(0.0, 0.25 * local_heading_match_raw)

    generic_penalty = 0.0
    if family_v2 in {"list_entity", "list_structure"}:
        if heading_hits <= 0.0 and token_hits <= 0.0:
            generic_penalty += 0.9
        if re.search(r"\b(?:introduction|overview|summary|historical\s+background|important\s+terminology|key\s+terms?)\b", heading_blob):
            generic_penalty += 0.55
        if marker_score <= 0.05:
            generic_penalty += 0.35
        if heading_hits <= 0.0 and marker_score <= 0.10 and phrase_hits <= 0.0:
            generic_penalty += 0.85
        if phrase_tokens and focus_hits <= 0.0:
            generic_penalty += 0.75
        if toc_like:
            # Keep TOC chunks as heading hints, but lower content priority for answers.
            generic_penalty += 0.45
            if phrase_hits > 0.0 or heading_hits > 0.0:
                heading_hits += 0.25
                phrase_hits += 0.20
            else:
                generic_penalty += 0.55
        if local_promoted:
            generic_penalty -= (0.45 * local_conf_norm)
            generic_penalty -= (0.20 * min(1.0, local_focus_hits_raw / 2.0))
            generic_penalty -= (0.20 * min(1.0, local_list_density_raw / 0.2))
            generic_penalty = max(0.0, generic_penalty)

        if goal_list_mode:
            context_tokens_local, _focus_tokens_local = _split_query_context_focus_tokens(query_text, family_v2)
            relation_match = False
            for ctx_tok in context_tokens_local[:3]:
                ctx = re.escape(ctx_tok)
                if re.search(rf"\b(?:goals?|objectives?|aims?)\s+(?:of|for)\s+(?:the\s+)?{ctx}\b", heading_blob):
                    relation_match = True
                    break
                if re.search(rf"\b{ctx}\s+(?:goals?|objectives?|aims?)\b", heading_blob):
                    relation_match = True
                    break
                if re.search(rf"\b(?:goals?|objectives?|aims?)\s+(?:of|for)\s+(?:the\s+)?{ctx}\b", low_txt[:1400]):
                    relation_match = True
                    break
                if re.search(rf"\b{ctx}\s+(?:goals?|objectives?|aims?)\b", low_txt[:1400]):
                    relation_match = True
                    break

            has_goal_lexeme = bool(re.search(r"\b(?:goals?|objectives?|aims?)\b", f"{chosen_heading.lower()} {low_txt[:1400]}"))
            heading_goal_like = bool(re.search(r"\b(?:goals?|objectives?|aims?)\b", chosen_heading.lower()))

            if chosen_heading and _is_attribution_or_citation_heading_text(chosen_heading):
                heading_detected = False
                generic_penalty += 0.95
            if heading_detected and chosen_heading and (not heading_goal_like):
                heading_detected = False
                generic_penalty += 0.75
            if not relation_match:
                phrase_hits *= 0.35
                generic_penalty += 0.85
                if has_goal_lexeme:
                    marker_score = min(marker_score, 0.35)
                    generic_penalty += 2.35
                    if re.search(r"\b(?:setting|evaluating|maintaining|achieving|pursuing|tracking)\s+goals?\b", low_txt[:1400]):
                        generic_penalty += 2.25

        if possessive_owner_tokens:
            owner_hit = any(
                _token_match_light(f"{heading_blob} {low_txt[:2200]}", owner_tok)
                for owner_tok in possessive_owner_tokens[:2]
            )
            owner_stage_relation = any(
                re.search(
                    rf"\b{re.escape(owner_tok)}\b[^\n.]{{0,80}}\b(?:stage|stages|development|theory|model|approach)\b",
                    f"{heading_blob} {low_txt[:2200]}"
                )
                for owner_tok in possessive_owner_tokens[:2]
            )
            if not owner_hit:
                phrase_hits *= 0.55
                heading_hits *= 0.65
                token_hits *= 0.75
                generic_penalty += 2.35
            elif not owner_stage_relation:
                generic_penalty += 0.55
            else:
                phrase_hits += 0.45

    # Phase 5: Consolidated Prose Ranking Boost logic
    prose_list_hint = 0.0
    # (Generic hint logic removed to prevent noise/timeouts)

    # MP-C3: Generic concept-proximity alignment.
    # Reward chunks where the query's own non-stopword tokens co-occur
    # close together (heading or body); penalise chunks where the tokens
    # are scattered or only one is present. Pure positional logic — no
    # domain words, no special cases.
    concept_proximity, concept_dispersion = _concept_proximity_score(
        tokens, heading_blob, low_txt
    )

    return {
        "token_hits": float(token_hits),
        "heading_hits": float(heading_hits),
        "phrase_hits": float(phrase_hits + prose_list_hint),
        "focus_hits": float(focus_hits),
        "marker_score": float(marker_score),
        "missing_penalty": float(0.45 * missing),
        "generic_penalty": float(generic_penalty),
        "density": float(density),
        "local_promoted": float(1.0 if local_promoted else 0.0),
        "local_focus_hits": float(local_focus_hits_raw),
        "local_heading_match": float(local_heading_match_raw),
        "local_list_density": float(local_list_density_raw),
        "local_confidence_score": float(local_conf_norm),
        "toc_hint": float(1.0 if toc_like else 0.0),
        "heading_detected": float(1.0 if heading_detected else 0.0),
        "heading_placeholder_rejected": float(1.0 if heading_src.get("placeholder_rejected") else 0.0),
        "heading_document_title_rejected": float(1.0 if heading_src.get("document_title_rejected") else 0.0),
        "concept_proximity": float(concept_proximity),
        "concept_dispersion": float(concept_dispersion),
    }


def _apply_heading_boost_for_family(query_text: str, family_v2: str, docs: list[dict]) -> list[dict]:
    if not docs:
        return docs
    logger.info("[HEADING BOOST DISABLED] family=%s docs=%d", family_v2, len(docs or []))
    return list(docs or [])


    context_tokens, focus_tokens = _split_query_context_focus_tokens(query_text, family_v2)

    def _doc_debug_key(doc: dict) -> str:
        md_local = dict((doc or {}).get("metadata") or {})
        src = str(md_local.get("source") or md_local.get("filename") or md_local.get("id") or "")
        return f"{src}::{md_local.get('chunk_index')}"

    scored: list[tuple[float, dict, float, float]] = []
    base_rank_items: list[tuple[float, str]] = []
    heading_debug_rows: list[dict[str, Any]] = []
    for d in docs:
        md = dict((d or {}).get("metadata") or {})
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        head = " ".join(str(md.get(k) or "") for k in ("section", "title", "chapter", "heading", "role")).lower()
        hay = f"{head}\n{txt[:1800].lower()}"

        base = 0.0
        for k in ("score", "final_score", "similarity"):
            if k in (d or {}):
                try:
                    base = float((d or {}).get(k) or 0.0)
                except Exception:
                    base = 0.0
                break
        base_rank_items.append((base, _doc_debug_key(d)))

        boost = 0.0
        sig = _doc_query_token_signals(query_text, family_v2, d)
        boost += (0.75 * sig.get("heading_hits", 0.0))
        boost += (0.45 * sig.get("token_hits", 0.0))
        boost += (0.85 * sig.get("phrase_hits", 0.0))
        boost += (0.35 * sig.get("marker_score", 0.0))
        boost += (20.0 * sig.get("density", 0.0))
        boost -= sig.get("missing_penalty", 0.0)
        boost -= sig.get("generic_penalty", 0.0)
        if family_v2 in {"toc_structure"}:
            if "table of contents" in hay:
                boost += 0.85
        if family_v2 in {"definition_entity", "fact_entity"}:
            if re.search(r"\bdefined\s+as\b|\brefers\s+to\b", hay):
                boost += 1.1

        noise = _doc_ocr_noise_score(txt)
        if noise > 0:
            boost -= min(0.9, 0.15 * noise)

        final_score = base + boost
        d2 = dict(d)
        d2["_heading_boost"] = round(boost, 4)
        d2["_noise_score"] = round(noise, 4)
        d2["_boosted_score"] = round(final_score, 4)
        d2["_section_token_hits"] = round(sig.get("token_hits", 0.0), 4)
        d2["_section_heading_hits"] = round(sig.get("heading_hits", 0.0), 4)
        d2["_section_phrase_hits"] = round(sig.get("phrase_hits", 0.0), 4)
        d2["_section_marker_score"] = round(sig.get("marker_score", 0.0), 4)
        d2["_section_density"] = round(sig.get("density", 0.0), 6)
        heading_src = _resolve_doc_heading_source(query_text, d)
        heading_line = str(heading_src.get("chosen_heading") or "").strip()
        if not heading_line:
            heading_lines_local = _extract_heading_like_lines_from_chunk(txt, max_lines=8)
            heading_line = heading_lines_local[0] if heading_lines_local else ""
        heading_l = heading_line.lower()
        heading_query_match = bool(any(re.search(rf"\b{re.escape(t)}\b", heading_l) for t in context_tokens)) if context_tokens else False
        heading_focus_match = bool(any(re.search(rf"\b{re.escape(t)}\b", heading_l) for t in focus_tokens)) if focus_tokens else False
        heading_bonus_component = (0.75 * sig.get("heading_hits", 0.0))
        heading_debug_rows.append({
            "key": _doc_debug_key(d),
            "chunk": md.get("chunk_index"),
            "heading": heading_line,
            "query_match": heading_query_match,
            "focus_match": heading_focus_match,
            "heading_bonus": round(float(heading_bonus_component), 4),
        })
        scored.append((final_score, d2, boost, noise))

    scored.sort(key=lambda x: x[0], reverse=True)
    boosted_docs = [x[1] for x in scored]

    if family_v2 in {"list_entity", "list_structure"}:
        base_rank_items.sort(key=lambda x: x[0], reverse=True)
        base_rank_map = {key: idx for idx, (_base_score, key) in enumerate(base_rank_items)}
        boosted_rank_map = {_doc_debug_key(d): idx for idx, d in enumerate(boosted_docs)}
        heading_debug_map = {row.get("key"): row for row in heading_debug_rows}
        for d in boosted_docs[: min(5, len(boosted_docs))]:
            key = _doc_debug_key(d)
            row = heading_debug_map.get(key) or {}
            before_rank = base_rank_map.get(key, 999)
            after_rank = boosted_rank_map.get(key, 999)
            won_by_heading = bool(after_rank < before_rank)
            logger.info(
                "[HEADING DEBUG] chunk=%s heading=%s query_match=%s focus_match=%s heading_bonus=%.3f won_by_heading_boost=%s",
                row.get("chunk"),
                (row.get("heading") or "")[:120],
                bool(row.get("query_match")),
                bool(row.get("focus_match")),
                float(row.get("heading_bonus", 0.0) or 0.0),
                won_by_heading,
            )

    if family_v2 in {"list_entity", "list_structure", "toc_structure"} and len(boosted_docs) >= 2:
        best_i = 0
        best_cluster_score = -10**9
        for i, d in enumerate(boosted_docs[: min(8, len(boosted_docs))]):
            md = dict((d or {}).get("metadata") or {})
            source_id = str(md.get("source") or md.get("filename") or md.get("id") or "")
            chunk_idx = md.get("chunk_index")
            try:
                chunk_idx_int = int(chunk_idx)
            except Exception:
                chunk_idx_int = None

            center = float((d or {}).get("_boosted_score", 0.0) or 0.0)
            cluster = center
            if source_id and chunk_idx_int is not None:
                for j, dj in enumerate(boosted_docs[: min(12, len(boosted_docs))]):
                    if j == i:
                        continue
                    mdj = dict((dj or {}).get("metadata") or {})
                    source_j = str(mdj.get("source") or mdj.get("filename") or mdj.get("id") or "")
                    if source_j != source_id:
                        continue
                    try:
                        cj = int(mdj.get("chunk_index"))
                    except Exception:
                        continue
                    if abs(cj - chunk_idx_int) <= 1:
                        cluster += 0.45 * float((dj or {}).get("_boosted_score", 0.0) or 0.0)
            if cluster > best_cluster_score:
                best_cluster_score = cluster
                best_i = i

        if best_i > 0:
            anchor = boosted_docs[best_i]
            md_a = dict((anchor or {}).get("metadata") or {})
            src_a = str(md_a.get("source") or md_a.get("filename") or md_a.get("id") or "")
            try:
                idx_a = int(md_a.get("chunk_index"))
            except Exception:
                idx_a = None
            front: list[dict] = [anchor]
            if src_a and idx_a is not None:
                for d in boosted_docs:
                    if d is anchor:
                        continue
                    md_d = dict((d or {}).get("metadata") or {})
                    src_d = str(md_d.get("source") or md_d.get("filename") or md_d.get("id") or "")
                    if src_d != src_a:
                        continue
                    try:
                        idx_d = int(md_d.get("chunk_index"))
                    except Exception:
                        continue
                    if abs(idx_d - idx_a) <= 1:
                        front.append(d)
            tail = [d for d in boosted_docs if d not in front]
            boosted_docs = front + tail
            logger.info("[SECTION CONSISTENCY] family=%s anchor_moved_from=%s cluster_docs=%s", family_v2, best_i, len(front))

    top_trace = []
    for idx, d in enumerate(boosted_docs[:3]):
        md = dict((d or {}).get("metadata") or {})
        top_trace.append({
            "rank": idx,
            "id": str(md.get("id") or md.get("doc_id") or md.get("source") or "unknown"),
            "chunk_index": md.get("chunk_index"),
            "boost": d.get("_heading_boost"),
            "noise": d.get("_noise_score"),
        })
    logger.info("[HEADING BOOST] family=%s trace=%s", family_v2, top_trace)
    return boosted_docs


def clean_ocr_noise(text: str) -> str:
    if not text:
        return text

    text = text.replace("’", "'").replace("‘", "'")
    text = text.replace("“", '"').replace("”", '"')
    text = text.replace("–", "-").replace("—", "-")
    text = re.sub(r"[^\x00-\x7F]+", " ", text)
    text = re.sub(r"^(DEFINITION|KEY TERMS|TERMS|CONCEPT)\s*[:\-]?\s*", "", text, flags=re.IGNORECASE)
    _ocr_split_heads = {
        "acti", "emoti", "behav", "consequ", "organi", "experi", "environ", "scien"
    }
    text = re.sub(
        r"\b([A-Za-z]{2,8})\s+([A-Za-z]{2,})\b",
        lambda m: (m.group(1) + m.group(2)) if m.group(1).lower() in _ocr_split_heads else m.group(0),
        text,
    )
    split_fixes = [
        (r"\bin\s+dividuals?\b", lambda m: "individual" if m.group(0).lower().endswith("ual") else "individuals"),
        (r"\bfor\s+mulas?\b", lambda m: "formula" if m.group(0).lower().endswith("ula") else "formulas"),
    ]
    for patt, repl in split_fixes:
        text = re.sub(patt, repl, text, flags=re.IGNORECASE)
    text = re.sub(r"\s*/\s*", " / ", text)
    text = re.sub(r"\b(\w+)\s+\1\b", r"\1", text, flags=re.IGNORECASE)
    text = re.sub(r"[ \t]+", " ", text).strip()

    return text


def _cleanup_final_answer_text(answer_text: str) -> str:
    txt = clean_ocr_noise(re.sub(r"[ \t]+", " ", str(answer_text or "")).strip())
    if not txt:
        return txt

    def _preserve_structured_list(value: str) -> str | None:
        lines = [re.sub(r"[ \t]+", " ", line).strip() for line in str(value or "").splitlines() if line.strip()]
        if len(lines) < 2:
            return None
        list_line_count = sum(
            1 for line in lines
            if re.match(r"^\s*(?:[-*\u2022]|\d+[.)])\s+\S", line)
        )
        if list_line_count < 2:
            return None
        normalized_lines: list[str] = []
        for line in lines:
            line = re.sub(r"^\s*[-*\u2022]\s+", "- ", line)
            normalized_lines.append(line)
        return "\n".join(normalized_lines)

    def _preserve_inline_bullet_chain(value: str) -> str | None:
        compact = re.sub(r"[ \t]+", " ", str(value or "")).strip()
        if not re.match(r"^\s*[-*\u2022]\s+\S", compact):
            return None
        body = re.sub(r"^\s*[-*\u2022]\s+", "", compact).strip()
        parts = [part.strip(" ,;:.") for part in re.split(r"\s+[-*\u2022]\s+", body) if part.strip(" ,;:.")]
        if len(parts) < 3:
            return None
        for part in parts:
            words = re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", part)
            if not (1 <= len(words) <= 8) or len(part) > 80:
                return None
        return "\n".join(f"- {part}" for part in parts)

    fixes = [
        (r"\bme\s*mory\b", "memory"),
        (r"\bin\s*dividuals?\b", "individual"),
        (r"\bfor\s*mulas?\b", "formula"),
    ]
    for patt, repl in fixes:
        txt = re.sub(patt, repl, txt, flags=re.IGNORECASE)

    txt, _prefix_repaired = _split_safe_ocr_merged_prefix_words(txt)
    txt, _split_word_repaired = _followup_merge_safe_ocr_split_words(txt)

    txt = re.sub(r"(?:^|\n)\s*[-•*]\s*(?:the|a|an)\s+(?:different|various|following)\s*(?=\n|$)", "", txt, flags=re.IGNORECASE)
    txt = re.sub(r"\s+-\s*(?:the|a|an)\s+(?:different|various|following)\s*$", "", txt, flags=re.IGNORECASE)

    glued_prefixes = (
        "these", "those", "this", "that", "the", "and", "or", "to", "of", "for", "with", "by",
        "from", "on", "at", "into", "within",
    )
    glued_suffixes = {
        "is", "are", "was", "were", "be", "been", "being", "do", "does", "did", "have", "has", "had",
        "can", "could", "would", "will", "shall", "may", "might", "must",
    }
    rebuilt_words: list[str] = []
    for word in re.split(r"(\s+)", txt):
        if not word or word.isspace():
            rebuilt_words.append(word)
            continue
        # MP-C15: don't split well-formed capitalized words (e.g.
        # "Forecasting" → "For ecasting", "Organising" → "Or ganising").
        if re.match(r"^[A-Z][a-z]{4,}[,.;:!?\)]*$", word):
            rebuilt_words.append(word)
            continue
        lowered = word.lower()
        split_word = None
        for prefix in glued_prefixes:
            if lowered.startswith(prefix) and len(word) > len(prefix) + 2:
                tail = word[len(prefix):]
                tail_l = tail.lower().strip(".,:;!?)]}")
                safe_tail = bool(
                    tail_l in glued_suffixes
                    or _OCR_PREFIX_REMAINDER_SUFFIX_RE.search(tail_l)
                )
                if safe_tail:
                    split_word = f"{word[:len(prefix)]} {tail}"
                    break
        rebuilt_words.append(split_word or word)
    txt = "".join(rebuilt_words)

    txt = re.sub(r"\b([A-Z][a-z]{2,})\s+([A-Z])\s+([a-z]{2,})\b", r"\1 \2\3", txt)
    txt = re.sub(r"\b([A-Z][a-z]{2,})\s+([A-Z][a-z]{2,})\s+([A-Z][a-z]{2,})\b", r"\1 \2 \3", txt)
    txt = re.sub(r"\s+([,.;:!?])", r"\1", txt)

    inline_list = _preserve_inline_bullet_chain(txt)
    if inline_list is not None:
        return inline_list.strip('"\'“”‘’')

    preserved_list = _preserve_structured_list(txt)
    if preserved_list is not None:
        return preserved_list.strip('"\'“”‘’')

    parts = [p.strip() for p in re.split(r"(?<=[.!?])\s+", txt) if p.strip()]
    if parts:
        deduped = []
        seen = set()
        for p in parts:
            key = re.sub(r"[^a-z0-9]+", " ", p.lower()).strip()
            if key and key not in seen:
                seen.add(key)
                deduped.append(p)
        parts = deduped

        is_labeled_comparison_answer = bool(
            len(re.findall(r"(?m)^\s*[A-Z][A-Za-z0-9'’\- ]{1,60}:\s+\S", txt)) >= 2
        )
        is_definition_like = bool(
            len(parts) > 1
            and re.search(r"\b(is|refers to|defined as|means)\b", parts[0].lower())
            and not re.match(r"^\s*after\b", parts[0], flags=re.IGNORECASE)
        )
        if is_definition_like and not is_labeled_comparison_answer:
            txt = parts[0]
        else:
            txt = " ".join(parts)

    txt = re.sub(r"\s{2,}", " ", txt).strip()
    txt = txt.strip('"\'“”‘’')
    return txt


def _extract_fallback_list(query_text: str, docs: list[dict]) -> str | None:
    return None


def _query_tokens_for_evidence(query_text: str) -> list[str]:
    stop = {
        "what", "which", "who", "when", "where", "why", "how", "the", "this", "that", "these", "those",
        "is", "are", "was", "were", "be", "to", "of", "in", "on", "for", "and", "or", "with", "from",
        "a", "an", "do", "does", "did", "can", "could", "should", "would", "about", "main", "only",
        "list", "explain", "define", "tell", "me", "document", "chapter", "section", "topics", "covered",
        "difference", "between", "compared", "compare",
    }
    return [
        t
        for t in re.findall(r"[a-z0-9]{3,}", (query_text or "").lower())
        if t not in stop
    ]


def _retrieval_evidence_metrics(query_text: str, retrieved_docs: list[dict]) -> Dict[str, float]:
    if not retrieved_docs:
        return {
            "coverage": 0.0,
            "focus_ratio": 0.0,
            "max_similarity": 0.0,
            "query_tokens": 0.0,
        }

    tokens = _query_tokens_for_evidence(query_text)
    top_docs = retrieved_docs[:4]
    top_texts = [str((d or {}).get("page_content") or (d or {}).get("text") or "").lower() for d in top_docs]
    combined = "\n".join(top_texts)

    if not tokens:
        return {
            "coverage": 1.0,
            "focus_ratio": 1.0,
            "max_similarity": _max_doc_similarity(retrieved_docs),
            "query_tokens": 0.0,
        }

    matched = {t for t in tokens if re.search(rf"\b{re.escape(t)}\b", combined)}
    coverage = len(matched) / max(1, len(set(tokens)))

    focused_chunks = 0
    min_hits = 1 if len(tokens) <= 2 else 2
    for txt in top_texts:
        hits = sum(1 for t in set(tokens) if re.search(rf"\b{re.escape(t)}\b", txt))
        if hits >= min_hits:
            focused_chunks += 1

    return {
        "coverage": float(coverage),
        "focus_ratio": float(focused_chunks / max(1, len(top_docs))),
        "max_similarity": float(_max_doc_similarity(retrieved_docs)),
        "query_tokens": float(len(set(tokens))),
    }


def _is_weak_retrieval_evidence(query_text: str, family: str, retrieved_docs: list[dict]) -> bool:
    if not retrieved_docs:
        return True

    metrics = _retrieval_evidence_metrics(query_text, retrieved_docs)
    coverage = metrics["coverage"]
    focus_ratio = metrics["focus_ratio"]
    max_similarity = metrics["max_similarity"]

    reliable = _retrieval_context_is_reliable(query_text, retrieved_docs)

    if family == "out_of_scope_candidate":
        return (coverage < 0.50) or (focus_ratio <= 0.0) or (max_similarity < 0.18)

    if family == "definition_entity":
        return (coverage < 0.15 and focus_ratio <= 0.0 and max_similarity < 0.12)

    if family == "overview_chapter_compare":
        q = (query_text or "").lower()
        if ("chapter" in q or "main sections" in q or "document" in q) and not _docs_have_structure_markers(retrieved_docs):
            if coverage < 0.25 and max_similarity < 0.15:
                return True
        m = re.search(r"difference\s+between\s+(.+?)\s+and\s+(.+?)(?:\?|$)", q)
        if m:
            left = [t for t in re.findall(r"[a-z0-9]{3,}", m.group(1)) if t not in {"the", "and", "of"}]
            right = [t for t in re.findall(r"[a-z0-9]{3,}", m.group(2)) if t not in {"the", "and", "of"}]
            top_text = "\n".join(str((d or {}).get("page_content") or (d or {}).get("text") or "").lower() for d in retrieved_docs[:4])
            left_ok = any(re.search(rf"\b{re.escape(t)}\b", top_text) for t in left)
            right_ok = any(re.search(rf"\b{re.escape(t)}\b", top_text) for t in right)
            if not (left_ok and right_ok) and coverage < 0.35 and max_similarity < 0.18:
                return True
        return (coverage < 0.18 and focus_ratio <= 0.0 and max_similarity < 0.12)

    if family == "list_structure":
        return (coverage < 0.12 and focus_ratio <= 0.0 and max_similarity < 0.10)

    return (coverage < 0.22 and focus_ratio <= 0.0 and max_similarity < 0.15) or (not reliable and coverage < 0.35)


def _is_current_world_or_personal_query(query_text: str) -> bool:
    query_norm = _normalize_query_for_router(query_text)
    if not query_norm:
        return False
    question_like = bool(re.search(r"\b(?:what|which|who|when|where|why|how|do|does|did|can|could|should)\b", query_norm))
    if not question_like:
        return False
    if re.search(r"\b(?:today|tonight|tomorrow|yesterday|now|right now|current date|current time)\b", query_norm):
        return True
    if re.search(r"\b(?:weather|forecast|news|latest|recent|live|real time|currently)\b", query_norm):
        return True
    if re.search(r"\b(?:my name|my age|my location|my address|where do i|who am i|what am i doing)\b", query_norm):
        return True
    if re.search(r"\b(?:your opinion|do you think|should i)\b", query_norm):
        return True
    return False


def _is_generic_grounding_sentence(answer_text: str) -> bool:
    answer_norm = re.sub(r"\s+", " ", str(answer_text or "").strip().lower())
    if not answer_norm:
        return False
    if re.search(
        r"\b(?:concept|topic|term|subject|thing|idea|area)\s+"
        r"(?:discussed|mentioned|covered|found|available)\s+in\s+"
        r"(?:the\s+)?(?:document|context|text|material)\b",
        answer_norm,
    ):
        return True
    if re.search(
        r"\b(?:document|context|text|material)\s+"
        r"(?:mentions|discusses|covers|contains)\b.{0,80}\b"
        r"(?:concept|topic|term|subject|thing|idea|area)\b",
        answer_norm,
    ):
        return True
    if re.fullmatch(
        r"[a-z0-9'\- ]{1,80}\s+is\s+(?:a|an|the)?\s*"
        r"(?:concept|topic|term|subject|thing|idea|area)\.?",
        answer_norm,
    ):
        return True
    if re.search(r"\b(?:not enough|insufficient)\s+(?:information|context|evidence)\b", answer_norm):
        return True
    return False


def _has_symbolic_count_letter_support(query_text: str, answer_text: str, selected_docs: list[dict]) -> bool:
    query_info = _detect_short_symbolic_list_query(query_text)
    if not query_info:
        return False
    support_text = "\n".join(
        [str(answer_text or "")]
        + [str((doc or {}).get("page_content") or (doc or {}).get("text") or "") for doc in (selected_docs or [])[:6]]
    )
    support_norm = _normalize_symbolic_list_surface(support_text)
    if not support_norm:
        return False

    phrase_variants = [str(value or "") for value in (query_info.get("phrase_variants") or []) if str(value or "").strip()]
    if any(variant and variant in support_norm for variant in phrase_variants):
        return True

    count_value = query_info.get("count")
    count_terms: set[str] = set()
    if isinstance(count_value, int):
        count_terms.add(str(count_value))
        if count_value in _SYMBOLIC_LIST_NUMBER_WORDS:
            count_terms.add(_SYMBOLIC_LIST_NUMBER_WORDS[count_value])
    label_variants = {str(value or "") for value in (query_info.get("label_variants") or []) if str(value or "").strip()}
    has_count = bool(count_terms and any(re.search(rf"\b{re.escape(term)}\b", support_norm) for term in count_terms))
    has_label = bool(label_variants and any(re.search(rf"\b{re.escape(label)}\b", support_norm) for label in label_variants))
    return bool(has_count and has_label)


def _is_low_confidence_grounding(
    query: str,
    selected_docs: list[dict],
    answer: str,
    metadata: Dict[str, Any] | None = None,
) -> bool:
    answer_text = re.sub(r"\s+", " ", str(answer or "").strip())
    if not answer_text or answer_text.lower() == RAG_NO_MATCH_RESPONSE.lower():
        return False

    metadata_dict = dict(metadata or {})
    family = str(metadata_dict.get("query_family") or _classify_query_family_v2(query) or "")
    answer_type = str(metadata_dict.get("answer_type") or "")

    if _is_current_world_or_personal_query(query):
        logger.info("[LOW CONFIDENCE GROUNDING] blocked reason=current_world_or_personal query=%s", str(query or "")[:160])
        return True

    if _is_generic_grounding_sentence(answer_text):
        logger.info("[LOW CONFIDENCE GROUNDING] blocked reason=generic_grounding_sentence answer=%s", answer_text[:180])
        return True

    if not selected_docs:
        logger.info("[LOW CONFIDENCE GROUNDING] blocked reason=no_selected_docs")
        return True

    if answer_type == "definition_structure_recovery":
        return False

    if _detect_language(answer_text) == "ar" and _detect_language(query) != "ar":
        return False

    metrics = _retrieval_evidence_metrics(query, selected_docs or [])
    coverage = float(metrics.get("coverage", 0.0) or 0.0)
    focus_ratio = float(metrics.get("focus_ratio", 0.0) or 0.0)
    max_similarity = float(metrics.get("max_similarity", 0.0) or 0.0)
    query_tokens = list(dict.fromkeys(_query_tokens_for_evidence(query)))
    symbolic_support = _has_symbolic_count_letter_support(query, answer_text, selected_docs or [])

    try:
        semantically_grounded = bool(_is_answer_grounded_in_docs(answer_text, selected_docs or [], query_text=query))
    except Exception:
        semantically_grounded = False

    combined_doc_text = "\n".join(
        str((doc or {}).get("page_content") or (doc or {}).get("text") or "")
        for doc in (selected_docs or [])[:4]
    ).lower()
    answer_norm = answer_text.lower()
    doc_token_hits = sum(1 for token in query_tokens if _token_match_light(combined_doc_text, token))
    answer_token_hits = sum(1 for token in query_tokens if _token_match_light(answer_norm, token))
    has_concept_overlap = bool(symbolic_support or doc_token_hits > 0 or answer_token_hits > 0)

    if query_tokens and not has_concept_overlap:
        logger.info(
            "[LOW CONFIDENCE GROUNDING] blocked reason=no_concept_overlap coverage=%.3f focus=%.3f top=%.3f tokens=%s",
            coverage,
            focus_ratio,
            max_similarity,
            query_tokens[:6],
        )
        return True

    if family in {"list_entity", "list_structure"} or answer_type.startswith("list_"):
        if not (symbolic_support or semantically_grounded or coverage >= 0.50 or focus_ratio > 0.0):
            logger.info(
                "[LOW CONFIDENCE GROUNDING] blocked reason=weak_list_grounding coverage=%.3f focus=%.3f top=%.3f",
                coverage,
                focus_ratio,
                max_similarity,
            )
            return True
        return False

    if len(query_tokens) >= 2 and coverage < 0.50 and focus_ratio <= 0.0 and not semantically_grounded:
        logger.info(
            "[LOW CONFIDENCE GROUNDING] blocked reason=multi_token_weak_grounding coverage=%.3f focus=%.3f top=%.3f",
            coverage,
            focus_ratio,
            max_similarity,
        )
        return True

    if len(query_tokens) >= 2 and coverage < 1.0 and focus_ratio <= 0.0 and not semantically_grounded:
        logger.info(
            "[LOW CONFIDENCE GROUNDING] blocked reason=keyword_only_partial_match coverage=%.3f focus=%.3f top=%.3f",
            coverage,
            focus_ratio,
            max_similarity,
        )
        return True

    if not semantically_grounded and coverage < 0.50 and focus_ratio <= 0.0:
        logger.info(
            "[LOW CONFIDENCE GROUNDING] blocked reason=ungrounded_weak_evidence coverage=%.3f focus=%.3f top=%.3f",
            coverage,
            focus_ratio,
            max_similarity,
        )
        return True

    if max_similarity < 0.12 and coverage < 0.50 and not semantically_grounded:
        logger.info(
            "[LOW CONFIDENCE GROUNDING] blocked reason=weak_semantic_score coverage=%.3f focus=%.3f top=%.3f",
            coverage,
            focus_ratio,
            max_similarity,
        )
        return True

    return False


